__d(function(a,e,o,r,s,i,t){"use strict";Object.defineProperty(i,'__esModule',{value:!0}),Object.defineProperty(i,"SPELLS_DATABASE",{enumerable:!0,get:function(){return n}});const n=[{name:"Canalizar Divindade: Voto de Inimizade",level:0,classes:["Paladino"],school:"Canalizar Divindade",castingTime:"1 a\xe7\xe3o b\xf4nus",range:"3 metros",duration:"1 minuto",description:"Com uma a\xe7\xe3o b\xf4nus, voc\xea jura inimizade contra uma criatura que possa ver a at\xe9 3 metros. Voc\xea ganha vantagem nas jogadas de ataque contra a criatura por 1 minuto ou at\xe9 ela cair a 0 pontos de vida ou cair inconsciente."},{name:"Canalizar Divindade: Abjurar Inimigo",level:0,classes:["Paladino"],school:"Canalizar Divindade",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"1 minuto",description:"Com uma a\xe7\xe3o, voc\xea apresenta seu s\xedmbolo sagrado e fala uma ora\xe7\xe3o de condena\xe7\xe3o usando seu Canalizar Divindade. Escolha uma criatura a at\xe9 18 metros de voc\xea que possa ver ou ouvi-lo. Ela deve ser bem-sucedida num teste de resist\xeancia de Sabedoria ou ficar\xe1 amedrontada e com deslocamento 0 por 1 minuto (ou at\xe9 sofrer dano)."},{name:"Destrui\xe7\xe3o Col\xe9rica (Wrathful Smite)",level:1,classes:["Paladino"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o b\xf4nus",range:"Pessoal",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"A pr\xf3xima vez que voc\xea atingir com um ataque corpo a corpo com arma durante a magia, seu ataque causa 1d6 de dano ps\xedquico extra. Al\xe9m disso, se o alvo for uma criatura, ele deve ser bem-sucedido num teste de resist\xeancia de Sabedoria ou ficar\xe1 amedrontado por voc\xea at\xe9 a magia acabar. Com uma a\xe7\xe3o, a criatura pode fazer um teste de Sabedoria contra a sua CD de magia para encerrar o feiti\xe7o."},{name:"Destrui\xe7\xe3o Divina (Divine Smite)",level:1,classes:["Paladino"],school:"Evoca\xe7\xe3o",castingTime:"Especial (ao acertar ataque)",range:"Toque/Corpo a corpo",duration:"Instant\xe2neo",description:"Quando voc\xea acerta uma criatura com um ataque corpo a corpo com arma, voc\xea pode gastar um espa\xe7o de magia para causar dano radiante extra ao alvo: 2d8 para um espa\xe7o de 1\xba n\xedvel, mais 1d8 para cada n\xedvel de espa\xe7o superior ao 1\xba (m\xe1ximo de 5d8). O dano aumenta em 1d8 se o alvo for um corruptor ou morto-vivo."},{name:"Esguicho de \xc1cido",level:0,classes:["Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea lan\xe7a uma bolha de \xe1cido. Escolha uma criatura dentro do alcance, ou escolha duas criaturas dentro do alcance que estejam a at\xe9 1,5 metro uma da outra. A deve ter sucesso em um Teste de resist\xeancia de alvo ou sofrer 1d6 dano de \xe1cido.\n\nO dano deste feiti\xe7o aumenta em 1d6 quando voc\xea atinge o 5\xba n\xedvel (2d6), 11\xba n\xedvel (3d6) e 17\xba n\xedvel (4d6)."},{name:"Alarme",level:1,classes:["Patrulheiro","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"8 horas",description:"Voc\xea define um alarme contra invas\xf5es indesejadas. Escolha uma porta, uma janela ou uma \xe1rea dentro do alcance que n\xe3o seja maior que um cubo de 6 metros. At\xe9 o final da magia, um alarme alerta voc\xea sempre que uma criatura pequena ou maior toca ou entra na \xe1rea protegida. Quando voc\xea conjura uma magia, voc\xea pode designar criaturas que n\xe3o disparar\xe3o o alarme. Voc\xea tamb\xe9m escolhe se o alarme \xe9 mental ou sonoro.\n\nUm alarme mental alerta voc\xea com um ping em sua mente se voc\xea estiver a 1,5 milha da \xe1rea protegida. Este ping acorda voc\xea se voc\xea estiver dormindo.\n\nUm alarme sonoro produz o som de uma campainha por 10 segundos a at\xe9 18 metros."},{name:"Amizade com Animais",level:1,classes:["Bardo","Druida","Patrulheiro"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"24 horas",description:"Este feiti\xe7o permite que voc\xea conven\xe7a um besta de que voc\xea n\xe3o tem inten\xe7\xe3o de fazer mal. Escolha um melhor que voc\xea possa ver dentro do alcance. Ele deve ver e ouvir voc\xea. Se a Intelig\xeancia da besta for 4 ou superior, o feiti\xe7o falha. Caso contr\xe1rio, o besta dever\xe1 ter sucesso em um Teste de resist\xeancia de Sabedoria ou ser feiti\xe7ado por voc\xea durante a dura\xe7\xe3o do feiti\xe7o. Se voc\xea ou um de seus companheiros prejudicar o alvo, a magia termina."},{name:"Perdi\xe7\xe3o",level:1,classes:["Bardo","Cl\xe9rigo","Paladino"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"At\xe9 tr\xeas criaturas de sua escolha que voc\xea possa ver dentro do alcance devem fazer Teste de resist\xeancia de Carismas. Sempre que um alvo que falha neste teste de resist\xeancia faz uma jogada de ataque ou um teste de resist\xeancia antes da magia terminar, o alvo deve rolar um d4 e subtrair o n\xfamero rolado da jogada de ataque ou teste de resist\xeancia."},{name:"Prote\xe7\xe3o contra L\xe2minas",level:0,classes:["Bardo","Feiticeiro","Bruxo","Mago","Paladino"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"1 rodada",description:"Voc\xea estende a m\xe3o e tra\xe7a um sigilo de prote\xe7\xe3o no ar. At\xe9 o final do seu pr\xf3ximo turno, voc\xea tem resist\xeancia contra concuss\xe3o, perfura\xe7\xe3o e dano cortante causado por ataques com arma."},{name:"Aben\xe7oar",level:1,classes:["Cl\xe9rigo","Paladino"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea aben\xe7oa at\xe9 tr\xeas criaturas de sua escolha dentro do alcance. Sempre que um alvo faz uma jogada de ataque ou um teste de resist\xeancia antes da magia terminar, o alvo pode rolar um d4 e adicionar o n\xfamero obtido \xe0 jogada de ataque ou teste de resist\xeancia."},{name:"M\xe3os Ardentes",level:1,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo (cone de 4,5 metros)",duration:"Instant\xe2neo",description:"Enquanto voc\xea segura as m\xe3os com os polegares se tocando e os dedos abertos, uma fina camada de chamas brota das pontas dos dedos estendidas. Cada criatura num cone de 4,5 metros dever\xe1 fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre 3d6 de dano de fogo em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso.\n\nO fogo acende quaisquer objetos inflam\xe1veis \u200b\u200bna \xe1rea que n\xe3o estejam sendo usados \u200b\u200bou carregados."},{name:"Enfeiti\xe7ar Pessoa",level:1,classes:["Bardo","Cl\xe9rigo","Druida","Feiticeiro","Bruxo","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"1 hora",description:"Voc\xea tenta encantar um humanoide que voc\xea possa ver dentro do alcance. Ele deve fazer um Teste de resist\xeancia de Sabedoria, e o faz com vantagem se voc\xea ou seus companheiros estiverem lutando contra ele. Se ele falhar no teste de resist\xeancia, ele ser\xe1 feiti\xe7ado por voc\xea at\xe9 o final da magia ou at\xe9 que voc\xea ou seus companheiros fa\xe7am algo prejudicial a ele. A criatura enfeiti\xe7ado considera voc\xea um conhecido amig\xe1vel. Quando a magia termina, a criatura sabe que foi feiti\xe7ada por voc\xea."},{name:"Toque G\xe9lido",level:0,classes:["Feiticeiro","Bruxo","Mago","Paladino"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"1 rodada",description:"Voc\xea cria uma m\xe3o esquel\xe9tica e fantasmag\xf3rica no espa\xe7o de uma criatura dentro do alcance. Fa\xe7a um ataque de magia \xe0 dist\xe2ncia contra a criatura para atac\xe1-la com o frio da sepultura. Sem sucesso, o alvo sofre 1d8 de dano necr\xf3tico e n\xe3o pode recuperar pontos de vida at\xe9 o in\xedcio do seu pr\xf3ximo turno. At\xe9 ent\xe3o, a m\xe3o agarra-se ao alvo.\n\nSe voc\xea tiver sucesso em um alvo morto-vivo, ele tamb\xe9m ter\xe1 manobras de ataque contra voc\xea at\xe9 o final do seu pr\xf3ximo turno.\n\nO dano deste feiti\xe7o aumenta em 1d8 quando voc\xea atinge o 5\xba n\xedvel (2d8), 11\xba n\xedvel (3d8) e 17\xba n\xedvel (4d8)."},{name:"Orbe Crom\xe1tico",level:1,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo (cubo de 4,5 metros)",duration:"Instant\xe2neo",description:"Voc\xea atira uma esfera de energia de 10 cent\xedmetros de di\xe2metro em uma criatura que voc\xea pode ver dentro do alcance. Voc\xea escolhe \xe1cido, frio, fogo, raio, veneno ou trov\xe3o para o tipo de orbe que voc\xea cria, e ent\xe3o faz um ataque de magia \xe0 dist\xe2ncia contra o alvo. Se o ataque for bem-sucedido, a criatura sofre 3d8 do tipo que voc\xea escolheu."},{name:"Aspers\xe3o de Cores",level:1,classes:["Feiticeiro","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo (cone de 4,5 metros)",duration:"1 rodada",description:"Uma deslumbrante variedade de luzes coloridas e piscantes brota de sua m\xe3o. Role 6d10; o total \xe9 quantos pontos de vida de criaturas esse feiti\xe7o pode efetuar. Criaturas em um cone de 4,5 metros origin\xe1rias de voc\xea s\xe3o afetadas em ordem crescente de seus pontos de vida atuais (ignorando criaturas inconscientes e criaturas que n\xe3o podem ver).\n\nCome\xe7ando pela criatura que possui os pontos de vida atuais mais baixos, cada criatura afetada por este feiti\xe7o fica cega at\xe9 a magia terminar. Subtraia os pontos de vida de cada criatura do total antes de passar para a criatura com os pr\xf3ximos pontos de vida mais baixos. Os pontos de vida de uma criatura devem ser iguais ou menores que o total restante para que essa criatura seja afetada."},{name:"Comando",level:1,classes:["Cl\xe9rigo","Paladino"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"1 rodada",description:"Voc\xea fala um comando de uma palavra para uma criatura que voc\xea pode ver dentro do alcance. O alvo deve ter sucesso em um Teste de resist\xeancia de Sabedoria ou seguir o comando no pr\xf3ximo turno. O feiti\xe7o n\xe3o tem efeito se o alvo for morto-vivo, se n\xe3o entender sua l\xedngua ou se seu comando for diretamente prejudicial a ele. \n\n Seguem alguns comandos t\xedpicos e seus efeitos. Voc\xea pode emitir um comando diferente do descrito aqui. Se voc\xea fizer isso, o Mestre determinar\xe1 como o alvo se comportar\xe1. Se o alvo n\xe3o conseguir seguir seu comando, a magia termina. \n\nAproxima\xe7\xe3o: O alvo se move em sua dire\xe7\xe3o pelo caminho mais curto e direto, encerrando seu turno caso se mova at\xe9 1,5 metro de voc\xea. \n\nDrop: O alvo deixa cair tudo o que estiver segurando e ent\xe3o termina seu turno. \n\nFugir: O alvo passa seu turno se afastando de voc\xea pelos meios mais r\xe1pidos dispon\xedveis. \n\nGrovel: O alvo cai ca\xeddo e ent\xe3o encerra seu turno. \n\nHalt: O alvo n\xe3o se move e n\xe3o realiza a\xe7\xf5es. Uma criatura voadora permanece no ar, desde que seja capaz de faz\xea-lo. Se precisar se mover para permanecer no ar, ele voar\xe1 a dist\xe2ncia m\xednima necess\xe1ria para permanecer no ar."},{name:"Duelo Compelido",level:1,classes:["Paladino"],school:"Encantamento",castingTime:"1 bonus a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea tenta obrigar uma criatura a um duelo. Uma criatura que voc\xea possa ver dentro do alcance deve fazer um Teste de resist\xeancia de Sabedoria. Em um teste de resist\xeancia falho, a criatura \xe9 atra\xedda at\xe9 voc\xea, compelida por sua exig\xeancia divina. Durante todo o per\xedodo, ele tem manobra de ataque contra criaturas que n\xe3o sejam voc\xea, e deve fazer um Teste de resist\xeancia de Sabedoria cada vez que tentar se mover para um espa\xe7o que esteja a mais de 9 metros de dist\xe2ncia de voc\xea; se obtiver sucesso neste teste de resist\xeancia, o feiti\xe7o n\xe3o restringe o movimento do alvo naquele turno.\n\nA magia termina se voc\xea atacar qualquer outra criatura, se voc\xea lan\xe7ar um feiti\xe7o que atinja uma criatura hostil que n\xe3o seja o alvo, se uma criatura amiga a voc\xea danificar o alvo ou lan\xe7ar um feiti\xe7o prejudicial sobre ele, ou se voc\xea terminar seu turno a mais de 9 metros de dist\xe2ncia do alvo."},{name:"Compreender Idiomas",level:1,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"1 hora",description:"Durante esse tempo, voc\xea entende o significado literal de qualquer idioma falado que ouve. Voc\xea tamb\xe9m entende qualquer linguagem escrita que v\xea, mas deve tocar a superf\xedcie em que as palavras est\xe3o escritas. Demora cerca de 1 minuto para ler uma p\xe1gina de texto.\n\nEsta magia n\xe3o decodifica mensagens secretas em um texto ou glifo, como um sigilo arcano, que n\xe3o fa\xe7a parte de uma linguagem escrita."},{name:"Criar ou Destruir \xc1gua",level:1,classes:["Cl\xe9rigo","Druida"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Instant\xe2neo",description:"Voc\xea cria ou destr\xf3i \xe1gua.\n\nCriar \xc1gua: Voc\xea cria at\xe9 10 gal\xf5es de \xe1gua limpa dentro do alcance em um recipiente aberto. Alternativamente, a \xe1gua cai em forma de chuva em um cubo de 9 metros dentro do alcance, extinguindo as chamas expostas na \xe1rea.\n\nDestruir \xc1gua: Voc\xea destr\xf3i at\xe9 10 gal\xf5es de \xe1gua em um recipiente aberto dentro do alcance. Alternativamente, voc\xea destr\xf3i a n\xe9voa em um cubo de 9 metros dentro do alcance."},{name:"Curar Ferimentos",level:1,classes:["Bardo","Cl\xe9rigo","Druida","Paladino","Patrulheiro"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"Uma criatura que voc\xea toca recupera um n\xfamero de pontos de vida igual a 1d8 + seu modificador de atributo de conjura\xe7\xe3o. Este feiti\xe7o n\xe3o tem efeito sobre mortos-vivos ou constructos."},{name:"Luzes Dan\xe7antes",level:0,classes:["Bardo","Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea cria at\xe9 quatro luzes do tamanho de tochas dentro do alcance, fazendo-as aparecer como tochas, lanternas ou orbes brilhantes que pairam no ar durante todo o tempo. Voc\xea tamb\xe9m pode combinar as quatro luzes em uma forma vagamente human\xf3ide brilhante de tamanho m\xe9dio. Seja qual for a forma que voc\xea escolher, cada luz emite luz fraca em um raio de 3 metros. Como a\xe7\xe3o b\xf4nus no seu turno, voc\xea pode mover as luzes at\xe9 18 metros para um novo local dentro do alcance. Uma luz deve estar a at\xe9 6 metros de outra luz criada por esta magia, e uma luz apaga se exceder o alcance da magia."},{name:"Detectar o Bem e o Mal",level:1,classes:["Cl\xe9rigo","Paladino"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Ao longo do tempo, voc\xea saber\xe1 se h\xe1 uma aberra\xe7\xe3o, celestial, elemental, fe\xe9rico, inimigo ou mortos-vivos a at\xe9 9 metros de voc\xea, bem como onde a criatura est\xe1 localizada. Da mesma forma, voc\xea sabe se existe um lugar ou objeto a at\xe9 9 metros de voc\xea que foi consagrado ou profanado magicamente.\n\nA magia pode penetrar a maioria das barreiras, mas \xe9 bloqueada por 30 cent\xedmetros de pedra, 2,5 cent\xedmetros de metal comum, uma folha fina de chumbo ou 90 cent\xedmetros de madeira ou terra."},{name:"Detectar Magia",level:1,classes:["Bardo","Cl\xe9rigo","Druida","Paladino","Patrulheiro","Feiticeiro","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Durante todo o tempo, voc\xea sente a presen\xe7a de magia a at\xe9 9 metros de voc\xea. Se voc\xea sentir magia desta forma, voc\xea pode usar sua a\xe7\xe3o para ver uma aura fraca em qualquer criatura ou objeto vis\xedvel na \xe1rea que contenha magia, e voc\xea aprender\xe1 sua escola de magia, se houver.\n\nA magia pode penetrar a maioria das barreiras, mas \xe9 bloqueada por 30 cent\xedmetros de pedra, 2,5 cent\xedmetros de metal comum, uma folha fina de chumbo ou 90 cent\xedmetros de madeira ou terra."},{name:"Detectar Veneno e Doen\xe7as",level:1,classes:["Cl\xe9rigo","Druida","Paladino","Patrulheiro"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Durante esse per\xedodo, voc\xea poder\xe1 sentir a presen\xe7a e localiza\xe7\xe3o de venenos, criaturas venenosas e doen\xe7as a at\xe9 9 metros de voc\xea. Voc\xea tamb\xe9m identifica o tipo de veneno, criatura venenosa ou doen\xe7a em cada caso.\n\nA magia pode penetrar a maioria das barreiras, mas \xe9 bloqueada por 30 cent\xedmetros de pedra, 2,5 cent\xedmetros de metal comum, uma folha fina de chumbo ou 90 cent\xedmetros de madeira ou terra."},{name:"Disfar\xe7ar a Si Mesmo",level:1,classes:["Bardo","Cl\xe9rigo","Feiticeiro","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"1 hora",description:"Voc\xea faz com que voc\xea mesmo - incluindo suas roupas, armaduras, armas e outros pertences - pare\xe7a diferente at\xe9 o fim da magia ou at\xe9 que voc\xea use sua a\xe7\xe3o para dissipa-la. Que voc\xea pode ser 30 cent\xedmetros mais baixo ou mais alto e pode parecer magro, gordo ou intermedi\xe1rio. Voc\xea n\xe3o pode mudar seu tipo de corpo, ent\xe3o deve adotar uma forma que tenha a mesma disposi\xe7\xe3o b\xe1sica dos membros. Caso contr\xe1rio, a extens\xe3o da ilus\xe3o depende de voc\xea.\n\nAs mudan\xe7as provocadas por este feiti\xe7o n\xe3o resistem \xe0 inspe\xe7\xe3o f\xedsica. Por exemplo, se voc\xea usar este feiti\xe7o para adicionar um chap\xe9u \xe0 sua roupa, os objetos passar\xe3o pelo chap\xe9u e qualquer pessoa que o tocar n\xe3o sentir\xe1 nada ou sentir\xe1 sua cabe\xe7a e seu cabelo. Se voc\xea usar esse feiti\xe7o para parecer mais magro do que \xe9, a m\xe3o de algu\xe9m que estender a m\xe3o para toc\xe1-lo ir\xe1 esbarrar em voc\xea enquanto aparentemente ainda est\xe1 no ar.\n\nPara discernir que voc\xea est\xe1 disfar\xe7ado, uma criatura pode usar sua a\xe7\xe3o para inspecionar sua apar\xeancia e deve ter sucesso em um teste de Intelig\xeancia (Investiga\xe7\xe3o) contra seu CD de resist\xeancia de magia."},{name:"Favor Divino",level:1,classes:["Paladino"],school:"Evoca\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Sua ora\xe7\xe3o capacita voc\xea com brilho divino. At\xe9 o fim da magia, seus ataques com arma causam 1d4 de dano radiante extra."},{name:"Sussurros Dissonantes",level:1,classes:["Bardo"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea sussurra uma melodia discordante que apenas uma criatura de sua escolha dentro do alcance pode ouvir, destruindo-a com uma dor terr\xedvel. O alvo deve fazer um Teste de resist\xeancia de Sabedoria. Em um teste de resist\xeancia falho, ele sofre 3d6 de dano ps\xedquico e deve usar imediatamente seus resultados, se dispon\xedveis, para se mover o mais longe que sua velocidade permitir para longe de voc\xea. A criatura n\xe3o se move para \xe1reas obviamente perigosas, como uma fogueira ou um po\xe7o. Em um teste de resist\xeancia bem-sucedido, o alvo leva metade do dano e n\xe3o precisa se afastar. Uma criatura ensurdecida \xe9 automaticamente bem-sucedida no salvamento."},{name:"Arte Dru\xeddica",level:0,classes:["Druida"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Instant\xe2neo",description:"Sussurrando para os esp\xedritos da natureza, Voc\xea cria um dos seguintes efeitos dentro do alcance: Voc\xea cria um efeito sensorial min\xfasculo e inofensivo que prev\xea como estar\xe1 o tempo em seu local nas pr\xf3ximas 24 horas. O efeito pode se manifestar como um orbe dourado para c\xe9u claro, uma nuvem para chuva, flocos de neve caindo para neve e assim por diante. Este efeito persiste por 1 rodada. Voc\xea instantaneamente faz uma flor desabrochar, uma vagem se abrir ou um bot\xe3o de folha florescer. Voc\xea cria um efeito sensorial instant\xe2neo e inofensivo, como folhas caindo, uma rajada de vento, o som de um pequeno animal ou a ordem fraca de um gamb\xe1. O efeito deve caber em um cubo de 1,5 metro. Voc\xea acende ou apaga instantaneamente uma vela, uma tocha ou uma pequena fogueira."},{name:"Rajada M\xedstica",level:0,classes:["Bruxo"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Instant\xe2neo",description:"Um raio de energia crepitante avan\xe7a em dire\xe7\xe3o a uma criatura dentro do alcance. Fa\xe7a um ataque de magia \xe0 dist\xe2ncia contra o alvo. Sem sucesso, o alvo leva 1d10 dano de for\xe7a. \n\n A magia cria mais de um feixe quando voc\xea atinge n\xedvel superior: dois feixes no 5\xba n\xedvel, tr\xeas feixes no 11\xba n\xedvel e quatro feixes no 17\xba n\xedvel. Voc\xea pode direcionar os feixes para o mesmo alvo ou para alvos diferentes. Fa\xe7a uma jogada de ataque separada para cada trave."},{name:"Golpe Enredante",level:1,classes:["Patrulheiro","Paladino"],school:"Conjura\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Na pr\xf3xima vez que voc\xea acertar uma criatura com um ataque de arma antes que a magia termine, uma massa contorcida de vinhas espinhosas aparece no ponto de impacto, e o alvo deve ter sucesso em um Teste de resist\xeancia de For\xe7a ou ser\xe1 imobilizado pelas vinhas m\xe1gicas at\xe9 o fim da magia. Uma criatura grande ou maior tem vantagem neste teste de resist\xeancia. Se o alvo conseguir salvar, as vinhas murcham.\n\nEnquanto estiver imobilizado por este feiti\xe7o, o alvo sofre 1d6 dano perfurante no in\xedcio de cada um de seus turnos. Uma criatura imobilizada pelas vinhas ou que possa tocar uma criatura pode usar sua a\xe7\xe3o para fazer um teste de For\xe7a contra seu CD de resist\xeancia de magia. Com sucesso, o alvo \xe9 libertado."},{name:"Emaranhar",level:1,classes:["Druida"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Ervas daninhas e trepadeiras brotam da solo em um quadrado de 6 metros come\xe7ando em um ponto dentro do alcance. Durante o per\xedodo, essas plantas transformam a solo da regi\xe3o em terreno dif\xedcil.\n\nUma criatura na \xe1rea quando voc\xea conjura uma magia deve ter sucesso em um Teste de resist\xeancia de For\xe7a ou ser imobilizada pelas plantas emaranhadas at\xe9 o fim da magia. Uma criatura imobilizada pelas plantas pode usar sua a\xe7\xe3o para fazer um teste de For\xe7a contra seu CD de resist\xeancia de magia. Com um sucesso, ele se liberta.\n\nQuando a magia termina, as plantas conjuradas murcham."},{name:"Fogo Fe\xe9rico",level:1,classes:["Bardo","Druida"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Cada objeto em um cubo de 6 metros dentro do alcance \xe9 contornado em luz azul, verde ou violeta (sua escolha). Qualquer criatura na \xe1rea quando o feiti\xe7o \xe9 lan\xe7ado tamb\xe9m \xe9 delineada em luz se falhar no Teste de resist\xeancia de Destreza. Durante todo o per\xedodo, objetos e criaturas afetadas emitem luz fraca em um raio de 3 metros.\n\nQualquer ataque de ataque contra uma criatura ou objeto afetado tem vantagem se o atacante puder v\xea-lo, e a criatura ou objeto afetado n\xe3o pode se beneficiar por ser invis\xedvel."},{name:"Retirada Apressada",level:1,classes:["Feiticeiro","Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Este feiti\xe7o permite que voc\xea se mova em um ritmo incr\xedvel. Quando voc\xea conjura essa magia, e ent\xe3o como uma a\xe7\xe3o b\xf4nus em cada um dos seus turnos at\xe9 o final da magia, voc\xea pode realizar a a\xe7\xe3o Dash."},{name:"Falsa Vida",level:1,classes:["Feiticeiro","Mago"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"1 hora",description:"Refor\xe7ando-se com um fac-s\xedmile necrom\xe2ntico de vida, voc\xea ganha 1d4 + 4 pontos de vida tempor\xe1rios pela dura\xe7\xe3o."},{name:"Queda de Pena",level:1,classes:["Bardo","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 rea\xe7\xe3o, tomada quando voc\xea ou uma criatura a at\xe9 18 metros de voc\xea cai",range:"18 metros",duration:"1 minuto",description:"Escolha at\xe9 cinco criaturas em queda dentro do alcance. A taxa de descida de uma criatura em queda diminui para 18 metros por rodada at\xe9 a magia terminar. Se a criatura pousar antes que a magia termine, ela n\xe3o sofrer\xe1 nenhum dano de queda e poder\xe1 cair de p\xe9, e a magia terminar\xe1 para aquela criatura."},{name:"Encontrar Familiar",level:1,classes:["Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 hora",range:"3 metros",duration:"Instant\xe2neo",description:"Voc\xea ganha o servi\xe7o de um familiar, um esp\xedrito que assume uma forma animal \xe0 sua escolha: morcego, gato, caranguejo, sapo (sapo), falc\xe3o, lagarto, polvo, coruja, cobra venenosa, peixe (quipper), rato, corvo, cavalo-marinho, aranha ou doninha. Aparecendo em um espa\xe7o desocupado dentro do alcance, o familiar possui as estat\xedsticas da forma escolhida, embora seja um celestial, fe\xe9rico ou inimigo (sua escolha) em vez de um besta. \n\n Seu familiar age independentemente de voc\xea, mas sempre obedece aos seus comandos. Em combate, ele lan\xe7a sua pr\xf3pria iniciativa e age por seu pr\xf3prio turno. Um familiar n\xe3o pode atacar, mas pode realizar outras a\xe7\xf5es normalmente.\n\nQuando o familiar cai para 0 pontos de vida, ele desaparece, n\xe3o deixando para tr\xe1s nenhuma forma f\xedsica. Ele reaparece depois que voc\xea lan\xe7a este feiti\xe7o novamente.\n\nEnquanto seu familiar estiver a at\xe9 30 metros de voc\xea, voc\xea poder\xe1 se comunicar com ele telepaticamente. Al\xe9m disso, como uma a\xe7\xe3o, voc\xea pode ver atrav\xe9s dos olhos do seu familiar e ouvir o que ele ouve at\xe9 o in\xedcio do seu pr\xf3ximo turno, ganhando os benef\xedcios de quaisquer sentidos especiais que o familiar possua. Durante esse per\xedodo, voc\xea fica surdo e cego em rela\xe7\xe3o aos seus pr\xf3prios sentidos.\n\nComo a\xe7\xe3o, voc\xea pode disfalhar temporariamente seu familiar. Ele desaparece em uma dimens\xe3o de bolso onde aguarda sua convoca\xe7\xe3o. Alternativamente, voc\xea pode disfalha-lo para sempre. Como a\xe7\xe3o enquanto ele estiver temporariamente desfalcado, voc\xea pode fazer com que ele reapare\xe7a em qualquer espa\xe7o desocupado a at\xe9 9 metros de voc\xea.\n\nVoc\xea n\xe3o pode ter mais de um familiar ao mesmo tempo. Se voc\xea conjurar esta magia enquanto j\xe1 possui um familiar, voc\xea far\xe1 com que ele adote uma nova forma. Escolha uma das formas da lista acima. Seu familiar se transforma na criatura escolhida.\n\nFinalmente, quando voc\xea conjura uma magia com alcance de toque, seu familiar pode lan\xe7ar a magia como se a tivesse lan\xe7ado. Seu familiar deve estar a at\xe9 30 metros de voc\xea e deve usar sua ocorr\xeancia para lan\xe7ar a magia quando voc\xea a lan\xe7ar. Se a magia exigir uma jogada de ataque, voc\xea usa seu modificador de a\xe7\xe3o para o teste."},{name:"Raio de Fogo",level:0,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Instant\xe2neo",description:"Voc\xea atira um cisco de fogo em uma criatura ou objeto dentro do alcance. Fa\xe7a um ataque de magia \xe0 dist\xe2ncia contra o alvo. Sem sucesso, o alvo leva 1d10 de dano de fogo. Um objeto inflam\xe1vel obtido por este feiti\xe7o acende se n\xe3o estiver sendo usado ou carregado.\n\nO dano desta magia aumenta em 1d10 quando voc\xea atinge o 5\xba n\xedvel (2d10), 11\xba n\xedvel (3d10) e 17\xba n\xedvel (4d10)."},{name:"Nuvem de N\xe9voa",level:1,classes:["Druida","Patrulheiro","Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea cria uma esfera de neblina com raio de 6 metros centrada em um ponto dentro do alcance. A esfera se espalha pelos cantos ao redorda e sua \xe1rea fica fortemente obscurecida. Dura enquanto durar ou at\xe9 que um vento de velocidade moderada ou maior (pelo menos 10 milhas por hora) o disperse."},{name:"Amigos",level:0,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Enquanto durar, voc\xea ter\xe1 vantagem em todos os testes de Carisma direcionados a uma criatura de sua escolha que n\xe3o seja hostil a voc\xea. Quando a magia termina, a criatura percebe que voc\xea usou magia para influenciar seu humor e se torna hostil com voc\xea. Uma criatura ca\xedda na viol\xeancia pode atacar voc\xea. Outra criatura pode buscar retribui\xe7\xe3o de outras maneiras (a crit\xe9rio do Mestre), dependendo da natureza de sua intera\xe7\xe3o com ela."},{name:"Boa Baga",level:1,classes:["Druida","Patrulheiro"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"At\xe9 dez frutas aparecem em sua m\xe3o e s\xe3o infundidas com magia durante todo o tempo. Uma criatura pode usar sua a\xe7\xe3o para comer uma baga. Comer uma fruta restaura 1 ponto de vida, e a fruta fornece alimento suficiente para sustentar uma criatura por um dia.\n\nAs bagas perdem sua pot\xeancia se n\xe3o forem consumidas dentro de 24 horas ap\xf3s o lan\xe7amento deste feiti\xe7o."},{name:"Graxa",level:1,classes:["Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"1 minuto",description:"A graxa escorregadia cobre a solo em um quadrado de 3 metros centrado em um ponto dentro do alcance e a transforma em terreno dif\xedcil durante todo o tempo.\n\nQuando a gordura aparecer, cada criatura que estiver em sua \xe1rea dever\xe1 passar por um Teste de resist\xeancia de Destreza ou cair\xe1. Uma criatura que entre na \xe1rea ou termine seu turno ali tamb\xe9m dever\xe1 ter sucesso em um Teste de resist\xeancia de Destreza ou cair."},{name:"Orienta\xe7\xe3o",level:0,classes:["Cl\xe9rigo","Druida"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea toca uma criatura volunt\xe1ria. Uma vez antes da magia terminar, o alvo pode rolar um d4 e adicionar o n\xfamero obtido a um teste de habilidade de sua escolha. Ele pode lan\xe7ar o dado antes ou depois de fazer o teste de habilidade. O feiti\xe7o ent\xe3o termina."},{name:"Raio Guiado",level:1,classes:["Cl\xe9rigo"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"1 rodada",description:"Um flash de luz atinge uma criatura de sua escolha dentro do alcance. Fa\xe7a um ataque de magia \xe0 dist\xe2ncia contra o alvo. Sem sucesso, o alvo leva 4d6 de dano radiante, e a pr\xf3xima jogada de ataque feita contra esse alvo antes do final do seu pr\xf3ximo turno tem vantagem, gra\xe7as \xe0 m\xedstica luz fraca que brilhava no alvo at\xe9 ent\xe3o."},{name:"Chuva de Espinhos",level:1,classes:["Patrulheiro"],school:"Conjura\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Na pr\xf3xima vez que voc\xea atacar uma criatura com um ataque \xe0 dist\xe2ncia com arma antes que a magia termine, este feiti\xe7o criar\xe1 uma chuva de espinhos que brotar\xe1 de sua arma de longo alcance ou muni\xe7\xe3o. Al\xe9m dos efeitos normais do ataque, o alvo do ataque e cada criatura a at\xe9 1,5 metro dele devem fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre 1d10 de dano perfurante em um teste de resist\xeancia falho, ou metade do dano se for bem sucedido."},{name:"Palavra de Cura",level:1,classes:["Bardo","Cl\xe9rigo","Druida"],school:"Evoca\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Uma criatura de sua escolha que voc\xea possa ver dentro do alcance recupera pontos de vida iguais a 1d4 + seu modificador de atributo de conjura\xe7\xe3o. Este feiti\xe7o n\xe3o tem efeito sobre mortos-vivos ou constructos."},{name:"Repres\xe1lia Infernal",level:1,classes:["Bruxo"],school:"Evoca\xe7\xe3o",castingTime:"1 rea\xe7\xe3o, tomada em resposta a ser danificado por uma criatura a at\xe9 18 metros de voc\xea que voc\xea possa ver.",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea aponta o dedo e a criatura que o feriu \xe9 momentaneamente cercada por chamas infernais. A criatura deve fazer um Teste de resist\xeancia de Destreza. S\xe3o necess\xe1rios 2d10 dano de fogo em um teste de resist\xeancia falho, ou metade do dano em um teste bem sucedido."},{name:"Hex",level:1,classes:["Bruxo"],school:"Encantamento",castingTime:"1 bonus a\xe7\xe3o",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea amaldi\xe7oa uma criatura que voc\xea pode ver dentro do alcance. At\xe9 o fim da magia, voc\xea causa 1d6 de dano necr\xf3tico extra ao alvo sempre que o acerta com um ataque. Escolha tamb\xe9m uma habilidade ao conjurar uma magia. O alvo tem desvantagens no teste de habilidades feito com a habilidade escolhida.\n\nSe o alvo cair para 0 pontos de vida antes que esta magia termine, voc\xea poder\xe1 usar uma a\xe7\xe3o b\xf4nus em um turno subsequente para amaldi\xe7oar uma nova criatura.\n\nUma maldi\xe7\xe3o de remo\xe7\xe3o lan\xe7ada no alvo encerra este feiti\xe7o mais cedo."},{name:"Hero\xedsmo",level:1,classes:["Bardo","Paladino"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Uma criatura volunt\xe1ria que voc\xea toca \xe9 imbu\xedda de bravura. At\xe9 o final da magia, a criatura fica imune a ser amedrontada e ganha pontos de vida tempor\xe1rios iguais ao seu modificador de atributo de conjura\xe7\xe3o no in\xedcio de cada um de seus turnos. Quando a magia termina, o alvo perde quaisquer pontos de vida tempor\xe1rios restantes desta magia."},{name:"Marca do Ca\xe7ador",level:1,classes:["Patrulheiro"],school:"Adivinha\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea escolhe uma criatura que pode ver dentro do alcance e a marca misticamente como sua presa. At\xe9 o fim da magia, voc\xea causa 1d6 de dano extra ao alvo sempre que acert\xe1-lo com um ataque com arma, e voc\xea tem vantagem em qualquer teste de Sabedoria (Percep\xe7\xe3o) ou Sabedoria (Sobreviv\xeancia) que fizer para encontr\xe1-lo. Se o alvo cair para 0 pontos de vida antes desta magia terminar, voc\xea poder\xe1 usar uma a\xe7\xe3o b\xf4nus em um turno subsequente para marcar uma nova criatura."},{name:"Identificar",level:1,classes:["Bardo","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 minuto",range:"Toque",duration:"Instant\xe2neo",description:"Voc\xea escolhe um objeto que deve tocar durante o lan\xe7amento do feiti\xe7o. Se for um item m\xe1gico ou algum outro objeto imbu\xeddo de magia, voc\xea aprende suas propriedades e como us\xe1-las, se requer sintoniza\xe7\xe3o para ser usado e quantas cargas ele possui, se houver. Voc\xea aprende se algum feiti\xe7o est\xe1 afetando o item e quais s\xe3o. Se o item foi criado por uma magia, voc\xea aprende qual magia o criou.\n\nSe, em vez disso, voc\xea tocar uma criatura durante a conjura\xe7\xe3o, voc\xea aprender\xe1 quais magias, se houver, a est\xe3o afetando no momento."},{name:"Escrita Ilus\xf3ria",level:1,classes:["Bardo","Bruxo","Mago"],school:"Ilus\xe3o",castingTime:"1 minuto",range:"Toque",duration:"10 dias",description:"Voc\xea escreve em pergaminho, papel ou algum outro material de escrita adequado e imbui-o de uma ilus\xe3o poderosa que dura enquanto durar.\n\nPara voc\xea e quaisquer criaturas que voc\xea designar quando voc\xea conjura uma magia, a escrita parece normal, escrita \xe0 sua m\xe3o e transmite qualquer significado que voc\xea pretendia quando escreveu o texto. Para todos os outros, a escrita parece ter sido escrita em uma escrita desconhecida ou m\xe1gica que \xe9 inintelig\xedvel. Alternativamente, voc\xea pode fazer com que a escrita pare\xe7a ser uma mensagem totalmente diferente, escrita em uma caligrafia e idioma diferentes, embora o idioma deva ser um que voc\xea conhe\xe7a.\n\nCaso o feiti\xe7o seja dissipado, o roteiro original e a ilus\xe3o desaparecem.\n\nUma criatura com vis\xe3o verdadeira pode ler a mensagem oculta."},{name:"Infligir Ferimentos",level:1,classes:["Cl\xe9rigo"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"Fa\xe7a um ataque de magia corpo a corpo contra uma criatura que voc\xea possa alcan\xe7ar. Sem sucesso, o alvo leva 3d10 de dano necr\xf3tico."},{name:"Saltar",level:1,classes:["Druida","Patrulheiro","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"1 minuto",description:"Voc\xea toca uma criatura. A dist\xe2ncia do salto da criatura \xe9 triplicada at\xe9 o final da magia."},{name:"Luz",level:0,classes:["Bardo","Cl\xe9rigo","Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"1 hora",description:"Voc\xea toca um objeto que n\xe3o seja maior que 3 metros em qualquer dimens\xe3o. At\xe9 a magia terminar, o objeto emite luz brilhante em um raio de 6 metros e luz fraca por mais 6 metros adicionais. A luz pode ser colorida como voc\xea quiser. Cobrir completamente o objeto com algo opaco bloqueia a luz. A magia termina se voc\xea lan\xe7\xe1-la novamente ou dissipa-la como uma a\xe7\xe3o.\n\nSe voc\xea atingir um objeto segurado ou usado por uma criatura hostil, essa criatura dever\xe1 ter sucesso em um Teste de resist\xeancia de Destreza para evitar o feiti\xe7o."},{name:"Passo Longo",level:1,classes:["Bardo","Druida","Patrulheiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"1 hora",description:"Voc\xea toca uma criatura. A velocidade do alvo aumenta em 3 metros at\xe9 a magia terminar."},{name:"Armadura de Mago",level:1,classes:["Feiticeiro","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"8 horas",description:"Voc\xea toca uma criatura volunt\xe1ria que n\xe3o est\xe1 usando armadura, e uma for\xe7a m\xe1gica protetora a substitui at\xe9 o fim da magia. A CA base do alvo passa a ser 13 + seu Modificador de Destreza. A magia termina se o alvo vestir uma armadura ou se voc\xea falhar o feiti\xe7o como uma a\xe7\xe3o."},{name:"M\xe3o M\xe1gica",level:0,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"1 minuto",description:"Uma m\xe3o espectral e flutuante aparece em um ponto escolhido dentro do alcance. A m\xe3o dura pela dura\xe7\xe3o ou at\xe9 voc\xea dissipa-la como uma a\xe7\xe3o. A m\xe3o desaparece se estiver a mais de 9 metros de dist\xe2ncia de voc\xea ou se voc\xea lan\xe7ar este feiti\xe7o novamente.\n\nVoc\xea pode usar sua a\xe7\xe3o para controlar a m\xe3o. Voc\xea pode usar a m\xe3o para manipular um objeto, abrir uma porta ou recipiente destrancado, guardar ou recuperar um item de um recipiente aberto ou despejar o conte\xfado de um frasco. Voc\xea pode mover a m\xe3o at\xe9 9 metros cada vez que us\xe1-la.\n\nA m\xe3o n\xe3o pode atacar, ativar itens m\xe1gicos ou carregar mais de 4,5 quilos."},{name:"M\xedssil M\xe1gico",level:1,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Instant\xe2neo",description:"Voc\xea cria tr\xeas dardos brilhantes de for\xe7a m\xe1gica. Cada dardo tem uma criatura de sua escolha que voc\xea pode ver dentro do alcance. Um dardo causa 1d4 + 1 dano de for\xe7a ao seu alvo. Todos os dardos atacam simultaneamente e voc\xea pode direcion\xe1-los para o sucesso de uma criatura ou de v\xe1rias."},{name:"Remendar",level:0,classes:["Bardo","Cl\xe9rigo","Druida","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 minuto",range:"Toque",duration:"Instant\xe2neo",description:"Este feiti\xe7o repara uma \xfanica quebra ou rasgo em um objeto que voc\xea toca, como uma chave quebrada, uma capa rasgada ou um odre de vinho vazando. Contanto que a ruptura ou rasgo n\xe3o ultrapasse 30 cent\xedmetros em qualquer dimens\xe3o, voc\xea a conserta, sem deixar vest\xedgios do dano anterior.\n\nEste feiti\xe7o pode reparar fisicamente um item ou constructo m\xe1gico, mas o feiti\xe7o n\xe3o pode restaurar a magia de tal objeto."},{name:"Mensagem",level:0,classes:["Bardo","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"1 rodada",description:"Voc\xea aponta o dedo para uma criatura dentro do alcance e sussurra uma mensagem. O alvo (e apenas o alvo) ouve a mensagem e pode responder num sussurro que s\xf3 voc\xea consegue ouvir.\n\nVoc\xea pode lan\xe7ar este feiti\xe7o atrav\xe9s de objetos s\xf3lidos se estiver familiarizado com o alvo e souber que ele est\xe1 al\xe9m da barreira. Sil\xeancio m\xe1gico, 30 cent\xedmetros de pedra, 2,5 cent\xedmetros de metal comum, uma folha fina de chumbo ou 90 cent\xedmetros de madeira bloqueiam a magia. O feiti\xe7o n\xe3o precisa seguir uma linha reta e pode percorrer livremente cantos ao redorda ou atrav\xe9s de aberturas."},{name:"Ilus\xe3o Menor",level:0,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"1 minuto",description:"Voc\xea cria um som ou uma imagem de um objeto dentro do alcance que dura toda a dura\xe7\xe3o. A ilus\xe3o tamb\xe9m termina se voc\xea dissipa-la como uma a\xe7\xe3o ou conjurar esse feiti\xe7o novamente.\n\nSe Voc\xea cria um som, seu volume pode variar de um sussurro a um grito. Pode ser a sua voz, a voz de outra pessoa, o rugido de um le\xe3o, a batida de um tambor ou qualquer outro som que voc\xea escolher. O som continua inabal\xe1vel durante toda a dura\xe7\xe3o, ou voc\xea pode emitir sons discretos em momentos diferentes antes que a magia termine.\n\nSe Voc\xea criar a imagem de um objeto \u2013 como uma cadeira, pegadas enlameadas ou um pequeno ba\xfa \u2013 ele n\xe3o deve ser maior que um cubo de 1,5 metro. A imagem n\xe3o pode criar som, luz, cheiro ou qualquer outro efeito sensorial. A intera\xe7\xe3o f\xedsica com a imagem revela que ela \xe9 uma ilus\xe3o, pois coisas podem passar por ela.\n\nSe uma criatura usar sua a\xe7\xe3o para examinar o som ou imagem, a criatura pode determinar que se trata de uma ilus\xe3o com um teste bem-sucedido de Intelig\xeancia (Investiga\xe7\xe3o) contra seu CD de resist\xeancia de magia. Se uma criatura discerne a ilus\xe3o pelo que ela \xe9, a ilus\xe3o se torna fraca para a criatura."},{name:"Borrifo de Veneno",level:0,classes:["Druida","Feiticeiro","Bruxo","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"3 metros",duration:"Instant\xe2neo",description:"Voc\xea estende sua m\xe3o em dire\xe7\xe3o a uma criatura que voc\xea pode ver dentro do alcance e projeta uma nuvem de g\xe1s nocivo da palma da m\xe3o. A criatura deve ter sucesso em um Teste de resist\xeancia de Constitui\xe7\xe3o ou sofrer\xe1 1d12 dano de veneno.\n\nO dano deste feiti\xe7o aumenta em 1d12 quando voc\xea atinge o 5\xba n\xedvel (2d12), 11\xba n\xedvel (3d12) e 17\xba n\xedvel (4d12)."},{name:"Prestidigita\xe7\xe3o",level:0,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"3 metros",duration:"At\xe9 1 hora",description:"Este feiti\xe7o \xe9 um pequeno truque m\xe1gico que os conjuradores novatos usam para praticar. Voc\xea cria um dos seguintes efeitos m\xe1gicos dentro do alcance: Voc\xea cria um efeito sensorial instant\xe2neo e inofensivo, como uma chuva de fa\xedscas, uma rajada de vento, notas musicais fracas ou um odor estranho. Voc\xea acende ou apaga instantaneamente uma vela, uma tocha ou uma pequena fogueira. um s\xedmbolo aparece em um objeto ou superf\xedcie por 1 hora.Voc\xea cria uma bugiganga n\xe3o m\xe1gica ou uma imagem ilus\xf3ria que pode caber na sua m\xe3o e que dura at\xe9 o final do seu pr\xf3ximo turno.Se voc\xea lan\xe7ar este feiti\xe7o v\xe1rias vezes, voc\xea pode ter at\xe9 tr\xeas de seus efeitos n\xe3o instant\xe2neos ativos por vez, e voc\xea pode disfalha tal efeito como uma a\xe7\xe3o."},{name:"Produzir Chamas",level:0,classes:["Druida"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"10 minutos",description:"Uma chama bruxuleante aparece em sua m\xe3o. A chama permanece l\xe1 durante todo o tempo e n\xe3o prejudica voc\xea nem seu equipamento. A chama emite luz brilhante em um raio de 3 metros e luz fraca por mais 3 metros adicionais. A magia termina se voc\xea dissipa-la como uma a\xe7\xe3o ou se voc\xea a lan\xe7a novamente.\n\nVoc\xea tamb\xe9m pode atacar com a chama, embora isso encerre o feiti\xe7o. Quando voc\xea conjura essa magia, ou como uma a\xe7\xe3o em um turno posterior, voc\xea pode lan\xe7ar a chama em uma criatura a at\xe9 9 metros de voc\xea. Fa\xe7a um ataque de magia \xe0 dist\xe2ncia. Sem sucesso, o alvo leva 1d8 de dano de fogo.\n\nO dano deste feiti\xe7o aumenta em 1d8 quando voc\xea atinge o 5\xba n\xedvel (2d8), 11\xba n\xedvel (3d8) e 17\xba n\xedvel (4d8)."},{name:"Prote\xe7\xe3o contra o Bem e o Mal",level:1,classes:["Cl\xe9rigo","Paladino","Bruxo","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo (raio de 9 metros)",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"At\xe9 o fim da magia, uma criatura volunt\xe1ria que voc\xea toca fica protegida contra certos tipos de criaturas: aberra\xe7\xf5es, celestiais, elementais, fe\xe9ricos, inimigos e mortos-vivos.\n\nA prote\xe7\xe3o concede v\xe1rios benef\xedcios. Criaturas desse tipo t\xeam manobras de ataque contra o alvo. O alvo tamb\xe9m n\xe3o pode ser enfeiti\xe7ado, amedrontado, ou possu\xeddo por eles. Se o alvo j\xe1 estiver enfeiti\xe7ado, amedrontado ou possu\xeddo por tal criatura, o alvo ter\xe1 vantagem em qualquer novo teste de resist\xeancia contra o efeito relevante."},{name:"Purificar Comida e \xc1gua",level:1,classes:["Cl\xe9rigo","Druida","Paladino"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"3 metros",duration:"Instant\xe2neo",description:"Toda comida e bebida n\xe3o m\xe1gica dentro de uma esfera de 1,5 metro de raio centrada em um ponto de sua escolha dentro do alcance \xe9 purificada e fica livre de veneno e doen\xe7a."},{name:"Raio de Gelo",level:0,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Um feixe fr\xedgido de luz azulada atinge uma criatura dentro do alcance. Fa\xe7a um ataque de magia \xe0 dist\xe2ncia contra o alvo. Sem sucesso, ele leva 1d8 dano de frio e sua velocidade \xe9 reduzida em 3 metros at\xe9 o in\xedcio do seu pr\xf3ximo turno.\n\nO dano da magia aumenta em 1d8 quando voc\xea atinge o 5\xba n\xedvel (2d8), 11\xba n\xedvel (3d8) e 17\xba n\xedvel (4d8)."},{name:"Raio de Doen\xe7a",level:1,classes:["Feiticeiro","Mago"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Um raio de energia esverdeada e repugnante ataca uma criatura dentro do alcance. Fa\xe7a um ataque de magia \xe0 dist\xe2ncia contra o alvo. Sem sucesso, o alvo sofre 2d8 de dano de veneno e deve fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, tamb\xe9m \xe9 envenenado at\xe9 o final do seu pr\xf3ximo turno."},{name:"Remover Maldi\xe7\xe3o",level:3,classes:["Cl\xe9rigo","Paladino","Bruxo","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"Ao seu toque, todas as maldi\xe7\xf5es que afetam uma criatura ou objeto terminam. Se o objeto for um item m\xe1gico amaldi\xe7oado, sua maldi\xe7\xe3o permanece, mas o feiti\xe7o quebra a sintonia de seu dono com o objeto para que ele possa ser removido ou descartado."},{name:"Resist\xeancia",level:0,classes:["Cl\xe9rigo","Druida"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea toca uma criatura volunt\xe1ria. Uma vez antes da magia terminar, o alvo pode rolar um d4 e adicionar o n\xfamero obtido a um teste de resist\xeancia de sua escolha. Pode-se rolar a matriz antes ou depois de fazer o teste de resist\xeancia. O feiti\xe7o ent\xe3o termina."},{name:"Chama Sagrada",level:0,classes:["Cl\xe9rigo"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"O brilho semelhante a uma chama desce sobre uma criatura que voc\xea pode ver dentro do alcance. O jogador deve ter sucesso em um Teste de Resist\xeancia de Destreza ou sofrer 1d8 dano radiante. O alvo n\xe3o ganha nenhum benef\xedcio com a cobertura desse teste de resist\xeancia.\n\nO dano da magia aumenta em 1d8 quando voc\xea atinge o 5\xba n\xedvel (2d8), 11\xba n\xedvel (3d8) e 17\xba n\xedvel (4d8)."},{name:"Santu\xe1rio",level:1,classes:["Cl\xe9rigo"],school:"Abjura\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"9 metros",duration:"1 minuto",description:"Voc\xea protege uma criatura dentro do alcance contra ataques. At\xe9 o final da magia, qualquer criatura que atingir a criatura protegida com um ataque ou feiti\xe7o prejudicial deve primeiro fazer um Teste de resist\xeancia de Sabedoria. Em um teste de resist\xeancia falho, a criatura deve escolher um novo alvo ou perder\xe1 o ataque ou feiti\xe7o. Esta magia n\xe3o protege a criatura protegida de efeitos de \xe1rea, como a explos\xe3o de uma bola de fogo.\n\nSe a criatura protegida fizer um ataque ou lan\xe7ar uma magia que afete uma criatura inimiga, esta magia termina."},{name:"Escudo da F\xe9",level:1,classes:["Cl\xe9rigo","Paladino"],school:"Abjura\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Um campo cintilante aparece e envolve uma criatura de sua escolha dentro do alcance, concedendo-lhe um b\xf4nus de +2 na CA durante a dura\xe7\xe3o."},{name:"Golpe Ardente",level:1,classes:["Paladino"],school:"Evoca\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Na pr\xf3xima vez que voc\xea acertar uma criatura com um ataque corpo a corpo com arma durante a dura\xe7\xe3o do feiti\xe7o, sua arma brilha com intensidade wsucessoe-hot, e o ataque causa 1d6 de dano de fogo extra ao alvo e faz com que o alvo se incendeie em chamas. No in\xedcio de cada um de seus turnos at\xe9 a magia terminar, o alvo deve fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, s\xe3o necess\xe1rios 1d6 de dano de fogo. Em um teste de resist\xeancia bem sucedido, a magia termina. Se o alvo ou uma criatura a at\xe9 1,5 metro dele usar uma a\xe7\xe3o para apagar as chamas, ou se algum outro efeito apagar as chamas (como o alvo ser submerso na \xe1gua), a magia termina."},{name:"Escudo",level:1,classes:["Feiticeiro","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 rea\xe7\xe3o, tomada quando voc\xea \xe9 atingido por um ataque ou alvo do feiti\xe7o m\xedssil m\xe1gico",range:"Si mesmo",duration:"1 rodada",description:"Uma barreira invis\xedvel de for\xe7a m\xe1gica aparece e protege voc\xea. At\xe9 o in\xedcio do seu pr\xf3ximo turno, voc\xea tem um b\xf4nus de +5 na CA, inclusive contra o ataque desencadeador, e n\xe3o sofre dano de falha m\xe1gica."},{name:"Bast\xe3o M\xedstico",level:0,classes:["Druida"],school:"Transmuta\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Toque",duration:"1 minuto",description:"A madeira de um porrete ou bast\xe3o que voc\xea est\xe1 segurando est\xe1 imbu\xedda do poder da natureza. Durante a dura\xe7\xe3o, voc\xea pode usar seu atributo de conjura\xe7\xe3o em vez de For\xe7a para as jogadas de ataque e dano de ataques corpo a corpo usando aquela arma, e o dado de dano da arma se torna um d8. A arma tamb\xe9m se torna m\xe1gica, se ainda n\xe3o o for. A magia termina se voc\xea lan\xe7\xe1-la novamente ou se voc\xea largar a arma."},{name:"Toque Chocante",level:0,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"Um raio brota de sua m\xe3o para causar um choque em uma criatura que voc\xea tenta tocar. Fa\xe7a um ataque de magia corpo a corpo contra o alvo. Voc\xea tem vantagem na jogada de ataque se o alvo estiver usando uma armadura de metal. Sem sucesso, o alvo sofre 1d8 de dano de raio e n\xe3o pode sofrer ocorr\xeancias at\xe9 o in\xedcio do pr\xf3ximo turno.\n\nO dano da magia aumenta em 1d8 quando voc\xea atinge o 5\xba n\xedvel (2d8), 11\xba n\xedvel (3d8) e 17\xba n\xedvel (4d8)."},{name:"Imagem Silenciosa",level:1,classes:["Bardo","Feiticeiro","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea cria a imagem de um objeto, uma criatura, ou algum outro fen\xf4meno vis\xedvel que n\xe3o seja maior que um cubo de 4,5 metros. A imagem aparece em um ponto dentro do alcance e perdura por toda a dura\xe7\xe3o. A imagem \xe9 puramente visual; n\xe3o \xe9 acompanhado por som, cheiro ou outros efeitos sensoriais.\n\nVoc\xea pode usar sua a\xe7\xe3o para fazer com que a imagem se mova para qualquer local dentro do alcance. \xc0 medida que a imagem muda de local, voc\xea pode alterar sua apar\xeancia para que seus movimentos pare\xe7am naturais para a imagem. Por exemplo, se voc\xea criar a imagem de uma criatura e mov\xea-la, poder\xe1 alterar a imagem para que ela pare\xe7a estar andando.\n\nA intera\xe7\xe3o f\xedsica com a imagem revela que ela \xe9 uma ilus\xe3o, pois coisas podem passar por ela. Uma criatura que use sua a\xe7\xe3o para examinar a imagem pode determinar que se trata de uma ilus\xe3o com um teste bem-sucedido de Intelig\xeancia (Investiga\xe7\xe3o) contra seu CD de resist\xeancia de magia. Se uma criatura discernir a ilus\xe3o pelo que ela \xe9, a criatura poder\xe1 ver atrav\xe9s da imagem."},{name:"Sono",level:1,classes:["Bardo","Feiticeiro","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"27 metros",duration:"1 minuto",description:"Este feiti\xe7o coloca as criaturas em um sono m\xe1gico. Role 5d8; o total \xe9 quantos pontos de vida de criaturas esse feiti\xe7o pode afetar. Criaturas dentro de um raio de 6 metros de um ponto que voc\xea escolher dentro do alcance s\xe3o afetadas em ordem crescente de seus pontos de vida atuais (ignorando criaturas inconscientes).\n\nCome\xe7ando com a criatura que tem os pontos de vida atuais mais baixos, cada criatura afetada por este feiti\xe7o cai inconsciente at\xe9 o fim da magia, o adormecido sofre dano ou algu\xe9m usa uma a\xe7\xe3o para sacudir ou dar um tapa no adormecido para acord\xe1-lo. Subtraia os pontos de vida de cada criatura do total antes de passar para a criatura com os pr\xf3ximos pontos de vida mais baixos. Os pontos de vida de uma criatura devem ser iguais ou menores que o total restante para que essa criatura seja afetada.\n\nMortos-vivos e criaturas imunes a serem enfeiti\xe7ados n\xe3o s\xe3o afetados por este feiti\xe7o."},{name:"Salvar os Moribundos",level:0,classes:["Cl\xe9rigo"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"Voc\xea toca uma criatura viva que possui 0 pontos de vida. A criatura torna-se est\xe1vel. Este feiti\xe7o n\xe3o tem efeito sobre mortos-vivos ou constructos."},{name:"Falar com Animais",level:1,classes:["Bardo","Druida","Patrulheiro"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"10 minutos",description:"Voc\xea ganha a habilidade de compreender e se comunicar verbalmente com os bestas durante o per\xedodo. O conhecimento e a consci\xeancia de muitos bestas s\xe3o limitados por sua intelig\xeancia, mas, no m\xednimo, os bestas podem fornecer informa\xe7\xf5es sobre locais e monstros pr\xf3ximos, incluindo tudo o que eles podem perceber ou ter percebido no dia anterior. Voc\xea pode persuadir um besta a fazer um pequeno favor para voc\xea, a crit\xe9rio do Mestre."},{name:"Taumaturgia",level:0,classes:["Cl\xe9rigo"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"At\xe9 1 minuto",description:"Voc\xea manifesta uma pequena maravilha, um sinal de poder sobrenatural, dentro do alcance. Voc\xea cria um dos seguintes efeitos m\xe1gicos dentro do alcance: Sua voz ressoa at\xe9 tr\xeas vezes mais alto que o normal por 1 minuto. Voc\xea faz com que as chamas pisquem, brilhem, diminuam ou mudem de cor por 1 minuto. porta ou janela destrancada para abrir ou fechar. Voc\xea altera a apar\xeancia de seus olhos por 1 minuto. Se voc\xea lan\xe7ar este feiti\xe7o v\xe1rias vezes, voc\xea pode ter at\xe9 tr\xeas de seus efeitos de 1 minuto ativos por vez, e voc\xea pode disfalhar tal efeito como uma a\xe7\xe3o."},{name:"Chicote de Espinhos",level:0,classes:["Druida"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Instant\xe2neo",description:"Voc\xea cria um longo chicote em forma de videira coberto de espinhos que ataca ao seu comando uma criatura ao alcance. Fa\xe7a um ataque de magia corpo a corpo contra o alvo. Se o ataque for bem-sucedido, a criatura sofre 1d6 de dano perfurante, e se a criatura for Grande ou menor, voc\xea puxa a criatura at\xe9 3 metros para mais perto de voc\xea.\n\nO dano deste feiti\xe7o aumenta em 1d6 quando voc\xea atinge o 5\xba n\xedvel (2d6), 11\xba n\xedvel (3d6) e 17\xba n\xedvel (4d6)."},{name:"Golpe Trovejante",level:1,classes:["Paladino"],school:"Evoca\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Na primeira vez que voc\xea tiver sucesso com um ataque corpo a corpo com arma durante a dura\xe7\xe3o deste feiti\xe7o, sua arma soa com um trov\xe3o que \xe9 aud\xedvel a at\xe9 90 metros de voc\xea, e o ataque causa 2d6 de dano s\xf4nico extra ao alvo. Al\xe9m disso, se o alvo for uma criatura, ele dever\xe1 ter sucesso em um Teste de resist\xeancia de For\xe7a ou ser\xe1 empurrado a 3 metros de dist\xe2ncia de voc\xea e derrubado."},{name:"Onda Trovejante",level:1,classes:["Bardo","Druida","Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo (cone de 4,5 metros)",duration:"Instant\xe2neo",description:"Uma onda de for\xe7a estrondosa sai de voc\xea. Cada criatura num cubo de 4,5 metros proveniente de voc\xea dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, uma criatura sofre 2d8 de dano s\xf4nico e \xe9 empurrada 3 metros para longe de voc\xea. Em um teste de resist\xeancia bem-sucedido, a criatura leva metade do dano e n\xe3o \xe9 empurrada. Al\xe9m disso, objetos desprotegidos que est\xe3o completamente dentro da \xe1rea de efeito s\xe3o automaticamente empurrados a 3 metros de dist\xe2ncia de voc\xea pelo efeito do feiti\xe7o, e o feiti\xe7o emite um estrondo estrondoso aud\xedvel a at\xe9 90 metros."},{name:"Golpe Certeiro",level:0,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 round",description:"Voc\xea estende a m\xe3o e aponta o dedo para um alvo ao alcance. Sua magia lhe concede uma breve vis\xe3o das defesas do alvo. No seu pr\xf3ximo turno, voc\xea ganha vantagem na sua primeira jogada de ataque contra o alvo, desde que este feiti\xe7o n\xe3o tenha terminado."},{name:"Servo Invis\xedvel",level:1,classes:["Bardo","Bruxo","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"1 hora",description:"Este feiti\xe7o cria uma for\xe7a invis\xedvel, est\xfapida e disforme que executa tarefas simples sob seu comando at\xe9 o fim da magia. O servo surge em um espa\xe7o desocupado na solo dentro do alcance. Possui AC 10, 1 ponto de vida e For\xe7a 2, e n\xe3o pode atacar. Se cair para 0 pontos de vida, a magia termina.\n\nUma vez em cada um dos seus turnos, como b\xf4nus de a\xe7\xe3o, voc\xea pode comandar mentalmente o servo para se mover at\xe9 4,5 metros e interagir com um objeto. O servo pode realizar tarefas simples que um servo humano poderia realizar, como buscar coisas, limpar, remendar, dobrar roupas, acender fogueiras, servir comida e servir vinho. Depois de dar o comando, o servo executa a tarefa da melhor maneira poss\xedvel at\xe9 conclu\xed-la e, em seguida, aguarda seu pr\xf3ximo comando.\n\nSe voc\xea ordenar que o servo execute uma tarefa que o afaste mais de 18 metros de voc\xea, a magia termina."},{name:"Zombaria Viciosa",level:0,classes:["Bardo"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea libera uma s\xe9rie de insultos misturados com encantamentos sutis em uma criatura que voc\xea pode ver dentro do alcance. Se o alvo puder ouvi-lo (embora n\xe3o precise entend\xea-lo), ele dever\xe1 ter sucesso em um Teste de resist\xeancia de Sabedoria ou sofrer 1d4 de dano ps\xedquico e ter desvantagem na pr\xf3xima jogada de ataque que fizer antes do final de seu pr\xf3ximo turno.\n\nO dano deste feiti\xe7o aumenta em 1d4 quando voc\xea atinge o 5\xba n\xedvel (2d4), 11\xba n\xedvel (3d4) e 17\xba n\xedvel (4d4)."},{name:"Raio da Bruxa",level:1,classes:["Feiticeiro","Bruxo","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Um feixe de energia azul crepitante \xe9 lan\xe7ado em dire\xe7\xe3o a uma criatura dentro do alcance, formando um arco sustentado de rel\xe2mpago entre voc\xea e o alvo. Fa\xe7a um ataque de magia \xe0 dist\xe2ncia contra essa criatura. Sem sucesso, o alvo leva 1d12 dano de raio, e em cada um de seus turnos durante o per\xedodo, voc\xea pode usar sua a\xe7\xe3o para causar 1d12 dano de raio ao alvo automaticamente. A magia termina se voc\xea usar sua a\xe7\xe3o para fazer qualquer outra coisa. A magia tamb\xe9m termina se o alvo estiver fora do alcance da magia ou se tiver cobertura total de voc\xea."},{name:"Golpe Irado",level:1,classes:["Paladino"],school:"Evoca\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Na pr\xf3xima vez que voc\xea tiver sucesso com um ataque corpo a corpo com arma durante a dura\xe7\xe3o deste feiti\xe7o, seu ataque causar\xe1 1d6 de dano ps\xedquico extra. Al\xe9m disso, se o alvo for uma criatura, ele dever\xe1 fazer um Teste de resist\xeancia de Sabedoria ou ser amedrontado por voc\xea at\xe9 o fim da magia. Como uma a\xe7\xe3o, a criatura pode fazer um teste de Sabedoria contra seu CD de resist\xeancia de magia para fortalecer sua determina\xe7\xe3o e encerrar este feiti\xe7o."},{name:"Aux\xedlio",level:2,classes:["Cl\xe9rigo","Paladino"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"8 horas",description:"Seu feiti\xe7o fortalece seus aliados com resist\xeancia e determina\xe7\xe3o. Escolha at\xe9 tr\xeas criaturas dentro do alcance. O ponto de vida m\xe1ximo e os pontos de vida atuais de cada alvo aumentam em 5 durante a dura\xe7\xe3o."},{name:"Mensageiro Animal",level:2,classes:["Bardo","Druida","Patrulheiro"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"24 horas",description:"Por meio deste feiti\xe7o, voc\xea usa um animal para entregar uma mensagem. Escolha um animal min\xfasculo que voc\xea possa ver dentro do alcance, como um esquilo, um gaio azul ou um morcego. Voc\xea especifica um local que deve ter visitado e um destinat\xe1rio que corresponda a uma descri\xe7\xe3o geral, como \u201cum homem ou mulher vestido com o uniforme da guarda da cidade\u201d ou \u201cum an\xe3o ruivo usando um chap\xe9u pontudo\u201d. Voc\xea tamb\xe9m fala uma mensagem de at\xe9 vinte e cinco palavras. O alvo besta viaja durante a dura\xe7\xe3o da magia em dire\xe7\xe3o ao local especificado, cobrindo cerca de 80 quil\xf4metros por 24 horas para um mensageiro voador, ou 40 quil\xf4metros para outros animais.\n\nQuando o mensageiro chega, ele entrega sua mensagem \xe0 criatura que voc\xea descreveu, replicando o som da sua voz. O mensageiro fala apenas com uma criatura que corresponda \xe0 descri\xe7\xe3o que voc\xea deu. Se o mensageiro n\xe3o chegar ao seu destino antes do t\xe9rmino da magia, a mensagem ser\xe1 perdida e o besta retornar\xe1 para onde voc\xea lan\xe7ou o feiti\xe7o."},{name:"Cegueira/Surdez",level:2,classes:["Bardo","Cl\xe9rigo","Feiticeiro","Mago"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"1 minuto",description:"Voc\xea pode cegar ou ensurdecer um inimigo. Escolha uma criatura que voc\xea possa ver dentro do alcance para fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Se falhar, o alvo fica cego ou ensurdecido (sua escolha) durante a dura\xe7\xe3o. Ao final de cada um de seus turnos, o alvo pode fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Com um sucesso, a magia termina."},{name:"Aug\xfario",level:2,classes:["Cl\xe9rigo"],school:"Adivinha\xe7\xe3o",castingTime:"1 minute",range:"Si mesmo",duration:"Instant\xe2neo",description:"Ao lan\xe7ar varas incrustadas com pedras preciosas, rolar ossos de drag\xe3o, dispor cartas ornamentadas ou empregar alguma outra ferramenta de adivinha\xe7\xe3o, voc\xea recebe um press\xe1gio de uma entidade de outro mundo sobre os resultados de um curso espec\xedfico de a\xe7\xe3o que voc\xea planeja realizar nos pr\xf3ximos 30 minutos. O Mestre escolhe entre os seguintes press\xe1gios poss\xedveis: Bem, para bons resultados Ai, para resultados ruins Bem e ai*, para resultados bons e ruins Nada, para resultados que n\xe3o s\xe3o especialmente bons ou ruins A magia n\xe3o leva em considera\xe7\xe3o quaisquer circunst\xe2ncias poss\xedveis que possam alterar o resultado, como o lan\xe7amento de magias adicionais ou a perda ou ganho de um companheiro.\n\nSe voc\xea conjurar uma magia duas ou mais vezes antes de completar seu pr\xf3ximo descanso longo, h\xe1 uma chance cumulativa de 25% para cada lan\xe7amento ap\xf3s o primeiro de voc\xea obter uma leitura aleat\xf3ria. O Mestre faz esse teste em segredo."},{name:"Acalmar Emo\xe7\xf5es",level:2,classes:["Bardo","Cl\xe9rigo"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea tenta suprimir emo\xe7\xf5es fortes em um grupo de pessoas. Cada human\xf3ide em uma esfera de 6 metros de raio centrada em um ponto que voc\xea escolher dentro do alcance deve fazer um Teste de resist\xeancia de Carisma; uma criatura pode optar por falhar neste teste de resist\xeancia se desejar. Se uma criatura falhar no teste de resist\xeancia, escolha um dos dois efeitos a seguir. Voc\xea pode suprimir qualquer efeito fazendo com que um alvo fique enfeiti\xe7ado ou amedrontado. Quando esta magia termina, qualquer efeito suprimido \xe9 retomado, desde que sua dura\xe7\xe3o n\xe3o tenha expirado nesse meio tempo.\n\nAlternativamente, voc\xea pode tornar um alvo indiferente sobre criaturas de sua escolha \xe0s quais ele \xe9 hostil. Essa indiferen\xe7a termina se o alvo for atacado ou ferido por um feiti\xe7o ou se presenciar algum de seus amigos sendo ferido. Quando a magia termina, a criatura torna-se hostil novamente, a menos que o Mestre determine o contr\xe1rio."},{name:"Paralisar Pessoa",level:2,classes:["Bardo","Cl\xe9rigo","Druida","Feiticeiro","Bruxo","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Escolha um humanoide que voc\xea possa ver dentro do alcance. O deve ser aprovado em Teste de resist\xeancia de Sabedoria ou ficar paralisado durante o per\xedodo. Ao final de cada um de seus turnos, o alvo pode fazer outro Teste de resist\xeancia de Sabedoria. Com um sucesso, a magia termina no alvo."},{name:"Restaura\xe7\xe3o Menor",level:2,classes:["Bardo","Cl\xe9rigo","Druida","Paladino","Patrulheiro"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"Voc\xea toca uma criatura e pode acabar com uma doen\xe7a ou condi\xe7\xe3o que a aflige. A condi\xe7\xe3o pode ser cega, ensurdecida, paralisada ou envenenada."},{name:"Ora\xe7\xe3o de Cura",level:2,classes:["Cl\xe9rigo"],school:"Evoca\xe7\xe3o",castingTime:"10 minutes",range:"9 metros",duration:"Instant\xe2neo",description:"At\xe9 seis criaturas de sua escolha que voc\xea possa ver dentro do alcance, cada uma recupera pontos de vida iguais a 2d8 + seu modificador de atributo de conjura\xe7\xe3o. Este feiti\xe7o n\xe3o tem efeito sobre mortos-vivos ou constructos."},{name:"Sil\xeancio",level:2,classes:["Bardo","Cl\xe9rigo","Patrulheiro"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Durante a dura\xe7\xe3o, nenhum som pode ser criado dentro ou passar atrav\xe9s de uma esfera de 6 metros de raio centrada em um ponto escolhido dentro do alcance. Qualquer criatura ou objeto inteiramente dentro da esfera \xe9 imune ao dano s\xf4nico, e as criaturas ficam ensurdecidas enquanto estiverem inteiramente dentro dela."},{name:"Arma Espiritual",level:2,classes:["Cl\xe9rigo"],school:"Evoca\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"18 metros",duration:"1 minuto",description:"Voc\xea cria uma arma espectral flutuante dentro do alcance que dura enquanto voc\xea lan\xe7ar este feiti\xe7o novamente. Quando voc\xea conjura uma magia, voc\xea pode fazer um ataque de magia corpo a corpo contra uma criatura a at\xe9 1,5 metro da arma. Sem sucesso, o alvo leva dano de for\xe7a igual a 1d8 + seu modificador de atributo de conjura\xe7\xe3o.\n\nComo a\xe7\xe3o b\xf4nus no seu turno, voc\xea pode mover a arma at\xe9 20 p\xe9s e repetir o ataque contra uma criatura a at\xe9 1,5 metro dela. A arma pode assumir a forma que voc\xea escolher. Cl\xe9rigos de divindades que est\xe3o associados a uma arma espec\xedfica (como St. Cuthbert \xe9 conhecido por sua ma\xe7a e Thor por seu martelo) fazem com que o efeito deste feiti\xe7o se assemelhe a essa arma."},{name:"V\xednculo de Prote\xe7\xe3o",level:2,classes:["Cl\xe9rigo"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"1 hora",description:"Este feiti\xe7o protege uma criatura volunt\xe1ria que voc\xea toca e cria uma conex\xe3o m\xedstica entre voc\xea e o alvo at\xe9 a magia terminar. Enquanto o alvo estiver a at\xe9 18 metros de voc\xea, ele ganha +1 de b\xf4nus na CA e testes de resist\xeancia, al\xe9m de ter resist\xeancia a todos os danos. Al\xe9m disso, cada vez que sofre dano, voc\xea sofre a mesma quantidade de dano.\n\nA magia termina se voc\xea cair para 0 pontos de vida ou se voc\xea e o alvo ficarem separados por mais de 18 metros. Tamb\xe9m termina se o feiti\xe7o for lan\xe7ado novamente em qualquer uma das criaturas conectadas. Voc\xea tamb\xe9m pode disfalhar o feiti\xe7o como uma a\xe7\xe3o."},{name:"Animar os Mortos",level:3,classes:["Cl\xe9rigo","Mago"],school:"Necromancia",castingTime:"1 minuto",range:"3 metros",duration:"Instant\xe2neo",description:"Este feiti\xe7o cria um servo morto-vivos. Escolha uma pilha de ossos ou um cad\xe1ver de um human\xf3ide M\xe9dio ou Pequeno dentro do alcance. Seu feiti\xe7o imbui o alvo com uma imita\xe7\xe3o asquerosa da vida, elevando-o a uma criatura morto-vivo. O alvo se torna um esqueleto se voc\xea escolher ossos ou um zumbi se voc\xea escolher um cad\xe1ver (o Mestre tem as estat\xedsticas de jogo da criatura).\n\nEm cada um de seus turnos, voc\xea pode usar uma a\xe7\xe3o b\xf4nus para comandar mentalmente qualquer criatura que voc\xea criou com este feiti\xe7o se a criatura estiver a at\xe9 18 metros de voc\xea (se voc\xea controlar m\xfaltiplas criaturas, voc\xea pode comandar uma ou todas elas ao mesmo tempo, emitindo o mesmo comando para cada uma). Voc\xea decide qual a\xe7\xe3o a criatura realizar\xe1 e para onde ela se mover\xe1 durante seu pr\xf3ximo turno, ou pode emitir um comando geral, como guardar uma c\xe2mara ou corredor espec\xedfico. Se voc\xea n\xe3o der nenhum comando, a criatura apenas se defender\xe1 contra criaturas hostis. Uma vez dada uma ordem, a criatura continua a segui-la at\xe9 que sua tarefa seja conclu\xedda.\n\nA criatura fica sob seu controle por 24 horas, ap\xf3s as quais ela deixa de obedecer a qualquer comando que voc\xea tenha dado. Para manter o controle da criatura por mais 24 horas, voc\xea deve lan\xe7ar este feiti\xe7o na criatura novamente antes que o per\xedodo atual de 24 horas termine. Este uso da magia reafirma seu controle sobre at\xe9 quatro criaturas que voc\xea animou com esta magia, em vez de animar uma nova."},{name:"Olho Arcano",level:4,classes:["Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea cria um olho invis\xedvel e m\xe1gico dentro do alcance que paira durante todo o tempo.\n\nVoc\xea recebe mentalmente informa\xe7\xf5es visuais do olho, que tem vis\xe3o normal e vis\xe3o no escuro de at\xe9 9 metros. O olho pode olhar em todas as dire\xe7\xf5es.\n\nComo a\xe7\xe3o, voc\xea pode mover o olho at\xe9 9 metros em qualquer dire\xe7\xe3o. N\xe3o h\xe1 limite para o qu\xe3o longe de voc\xea o olho pode se mover, mas ele n\xe3o pode entrar em outro plano de exist\xeancia. Uma barreira s\xf3lida bloqueia o movimento do olho, mas o olho pode passar por uma abertura de at\xe9 2,5 cm de di\xe2metro."},{name:"Aura de Vida",level:4,classes:["Paladino"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (30-foot radius)",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"A energia que preserva a vida irradia de voc\xea em uma aura com raio de 9 metros. At\xe9 a magia terminar, a aura se move com voc\xea, centrada em voc\xea. Cada criatura n\xe3o hostil na aura (incluindo voc\xea) tem resist\xeancia ao dano necr\xf3tico e seu ponto de vida m\xe1ximo n\xe3o pode ser reduzido. Al\xe9m disso, uma criatura viva e n\xe3o hostil recupera 1 ponto de vida quando inicia seu turno na aura com 0 pontos de vida."},{name:"Aura de Pureza",level:4,classes:["Paladino"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (30-foot radius)",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"A energia purificadora irradia de voc\xea em uma aura com raio de 9 metros. At\xe9 a magia terminar, a aura se move com voc\xea, centrada em voc\xea. Cada criatura n\xe3o hostil na aura (incluindo voc\xea) n\xe3o pode ficar doente, tem resist\xeancia a dano de veneno e tem vantagem em testes de resist\xeancia contra efeitos que causam qualquer uma das seguintes condi\xe7\xf5es: cego, enfeiti\xe7ado, ensurdecido, amedrontado, paralisado, envenenado e atordoado."},{name:"Aura de Vitalidade",level:3,classes:["Paladino"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo (raio de 9 metros)",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"A energia curativa irradia de voc\xea em uma aura com raio de 9 metros. At\xe9 a magia terminar, a aura se move com voc\xea, centrada em voc\xea. Voc\xea pode usar uma a\xe7\xe3o b\xf4nus para fazer com que uma criatura na aura (incluindo voc\xea) recupere 2d6 pontos de vida."},{name:"Banimento",level:4,classes:["Cl\xe9rigo","Paladino","Feiticeiro","Bruxo","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea tenta enviar uma criatura que voc\xea possa ver dentro do alcance para outro plano de exist\xeancia. O alvo deve ter sucesso em um Teste de resist\xeancia de Carisma ou ser\xe1 banido.\n\nSe o alvo for nativo do plano de exist\xeancia em que voc\xea est\xe1, voc\xea banir\xe1 o alvo para um semiplano inofensivo. Enquanto estiver l\xe1, o alvo fica incapacitado. O alvo permanece l\xe1 at\xe9 a magia terminar, momento em que o alvo reaparece no espa\xe7o que deixou ou no espa\xe7o desocupado mais pr\xf3ximo, se esse espa\xe7o estiver ocupado.\n\nSe o alvo for nativo de um plano de exist\xeancia diferente daquele em que voc\xea est\xe1, o alvo \xe9 banido com um leve estalo, retornando ao seu plano natal. Se a magia terminar antes de decorrido 1 minuto, o alvo reaparece no espa\xe7o que deixou ou no espa\xe7o desocupado mais pr\xf3ximo, se esse espa\xe7o estiver ocupado. Caso contr\xe1rio, o alvo n\xe3o retorna."},{name:"Balizador da Esperan\xe7a",level:3,classes:["Cl\xe9rigo"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Este feiti\xe7o confere esperan\xe7a e vitalidade. Escolha qualquer n\xfamero de criaturas dentro do alcance. Durante a dura\xe7\xe3o, cada alvo tem vantagem em Teste de resist\xeancia de Sabedorias e testes de resist\xeancia de morte, e recupera o n\xfamero m\xe1ximo de pontos de vida poss\xedveis de qualquer cura."},{name:"Praga",level:4,classes:["Druida","Feiticeiro","Bruxo","Mago"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Instant\xe2neo",description:"A energia necrom\xe2ntica lava uma criatura de sua escolha que voc\xea possa ver dentro do alcance, drenando a umidade e a vitalidade dela. O alvo dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. O alvo leva 8d8 dano necr\xf3tico em um teste de resist\xeancia falho, ou metade do dano em um teste bem-sucedido. O feiti\xe7o n\xe3o tem efeito sobre mortos-vivos ou constructos.\n\nSe voc\xea atingir uma planta criatura ou uma planta m\xe1gica, ela faz o teste de resist\xeancia com desvantagem, e o feiti\xe7o causa dano m\xe1ximo a ela.\n\nSe voc\xea atingir uma planta n\xe3o-m\xe1gica que n\xe3o seja uma criatura, como uma \xe1rvore ou um arbusto, ela n\xe3o far\xe1 um teste de resist\xeancia; simplesmente murcha e morre."},{name:"Impor Maldi\xe7\xe3o",level:3,classes:["Bardo","Cl\xe9rigo","Mago"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea toca uma criatura, e essa criatura deve ter sucesso em um Teste de resist\xeancia de Sabedoria ou ser\xe1 amaldi\xe7oada durante a dura\xe7\xe3o da magia. Quando voc\xea conjura essa magia, escolha a natureza da maldi\xe7\xe3o entre as seguintes op\xe7\xf5es:\n\n* Escolha uma pontua\xe7\xe3o de habilidade. Enquanto amaldi\xe7oado, o alvo tem manobras em testes de habilidades e testes de resist\xeancia feitos com esse valor de habilidade.\n* Enquanto amaldi\xe7oado, o alvo tem manobras de ataque contra voc\xea.\n* Enquanto amaldi\xe7oado, o alvo dever\xe1 fazer um Teste de resist\xeancia de Sabedoria no in\xedcio de cada um de seus turnos. Se falhar, desperdi\xe7a sua a\xe7\xe3o naquele turno sem fazer nada.\n* Enquanto o alvo estiver amaldi\xe7oado, seus ataques e feiti\xe7os causam 1d8 de dano necr\xf3tico extra ao alvo.\n\nUma magia de remo\xe7\xe3o de maldi\xe7\xe3o encerra esse efeito. A crit\xe9rio do Mestre, voc\xea pode escolher um efeito de maldi\xe7\xe3o alternativo, mas n\xe3o deve ser mais poderoso do que os descritos acima. O Mestre tem a palavra final sobre o efeito de tal maldi\xe7\xe3o."},{name:"Golpe Cegante",level:3,classes:["Paladino"],school:"Evoca\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Na pr\xf3xima vez que voc\xea acertar uma criatura com um ataque corpo a corpo com arma durante a dura\xe7\xe3o desta magia, sua arma brilhar\xe1 com uma luz brilhante e o ataque causar\xe1 3d8 de dano radiante extra ao alvo. Al\xe9m disso, o alvo deve ser aprovado em Teste de resist\xeancia de Constitui\xe7\xe3o ou ser cego at\xe9 a magia terminar.\n\nUma criatura cega por este feiti\xe7o faz outro Teste de resist\xeancia de Constitui\xe7\xe3o ao final de cada um de seus turnos. Em um teste de resist\xeancia bem sucedido, n\xe3o \xe9 mais cego."},{name:"Piscar",level:3,classes:["Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"1 minuto",description:"Role um d20 no final de cada um de seus turnos enquanto durar o feiti\xe7o. Com um resultado 11 ou superior, voc\xea desaparece do seu plano de exist\xeancia atual e aparece no Plano Et\xe9reo (o feiti\xe7o falha e a conjura\xe7\xe3o \xe9 desperdi\xe7ada se voc\xea j\xe1 estiver naquele plano). No in\xedcio do seu pr\xf3ximo turno, e quando a magia terminar se voc\xea estiver no Plano Et\xe9reo, voc\xea retorna para um espa\xe7o desocupado de sua escolha que voc\xea pode ver a at\xe9 3 metros do espa\xe7o de onde voc\xea desapareceu. Se nenhum espa\xe7o desocupado estiver dispon\xedvel dentro desse intervalo, voc\xea aparece no espa\xe7o desocupado mais pr\xf3ximo (escolhido aleatoriamente se mais de um espa\xe7o estiver igualmente pr\xf3ximo). Voc\xea pode disfalhar esse feiti\xe7o como uma a\xe7\xe3o.\n\nEnquanto estiver no Plano Et\xe9reo, voc\xea poder\xe1 ver e ouvir o plano de onde voc\xea veio, que \xe9 moldado em tons de cinza, e voc\xea n\xe3o consegue ver nada l\xe1 a mais de 18 metros de dist\xe2ncia. Voc\xea s\xf3 pode afetar e ser afetado por outras criaturas do Plano Et\xe9reo. Criaturas que n\xe3o est\xe3o l\xe1 n\xe3o podem perceber voc\xea ou interagir com voc\xea, a menos que tenham a capacidade de faz\xea-lo."},{name:"Invocar Rel\xe2mpago",level:3,classes:["Druida"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Uma nuvem de tempestade aparece na forma de um cilindro com 3 metros de altura e 18 metros de raio, centrado em um ponto que voc\xea pode ver 100 p\xe9s diretamente acima de voc\xea. A magia falha se voc\xea n\xe3o conseguir ver um ponto no ar onde a nuvem de tempestade possa aparecer (por exemplo, se voc\xea estiver em uma sala que n\xe3o possa acomodar a nuvem).\n\nQuando voc\xea conjurar uma magia, escolha um ponto que voc\xea possa ver dentro do alcance. Um raio desce da nuvem at\xe9 aquele ponto. Cada criatura a at\xe9 1,5 metro desse ponto deve fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre 3d10 dano de raio em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso. Em cada um de seus turnos at\xe9 o final da magia, voc\xea pode usar sua a\xe7\xe3o para invocar rel\xe2mpagos desta forma novamente, visando o mesmo ponto ou um ponto diferente.\n\nSe voc\xea estiver ao ar livre em condi\xe7\xf5es de tempestade Quando voc\xea conjura essa magia, o feiti\xe7o lhe d\xe1 controle sobre a tempestade existente em vez de criar uma nova. Sob tais condi\xe7\xf5es, o dano do feiti\xe7o aumenta em 1d10."},{name:"Clarivid\xeancia",level:3,classes:["Bardo","Cl\xe9rigo","Feiticeiro","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"10 minutos",range:"1,6 quil\xf4metro",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea cria um sensor invis\xedvel dentro do alcance em um local familiar para voc\xea (um lugar que voc\xea visitou ou viu antes) ou em um local \xf3bvio que n\xe3o \xe9 familiar para voc\xea (como atr\xe1s de uma porta, em um canto ou em um bosque). O sensor permanece no lugar durante todo o per\xedodo e n\xe3o pode ser atacado ou interagir de outra forma.\n\nQuando voc\xea conjura uma magia, voc\xea escolhe ver ou ouvir. Voc\xea pode usar o sentido escolhido atrav\xe9s do sensor como se estivesse em seu espa\xe7o. Conforme sua a\xe7\xe3o, voc\xea pode alternar entre ver e ouvir.\n\nUma criatura que pode ver o sensor (como uma criatura que se beneficia da invisibilidade (n\xedvel 2) ou da vis\xe3o verdadeira v\xea um orbe luminoso e intang\xedvel do tamanho do seu punho."},{name:"Nuvem de Adagas",level:2,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea preenche o ar com adagas girat\xf3rias em um cubo de 1,5 metro de cada lado, centrado em um ponto que voc\xea escolher dentro do alcance. Uma criatura sofre 4d4 de dano cortante quando entra na \xe1rea da magia pela primeira vez em um turno ou inicia seu turno l\xe1."},{name:"Compuls\xe3o",level:4,classes:["Bardo"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Criaturas de sua escolha que voc\xea possa ver dentro do alcance e que possam ouvir voc\xea deve fazer um Teste de resist\xeancia de Sabedoria. Um alvo automaticamente obt\xe9m sucesso neste teste de resist\xeancia se n\xe3o puder ser feiti\xe7ado. Em um teste de resist\xeancia falho, um alvo \xe9 afetado por este feiti\xe7o. At\xe9 o fim da magia, voc\xea pode usar um b\xf4nus de a\xe7\xe3o em cada um de seus turnos para designar uma dire\xe7\xe3o que seja horizontal para voc\xea. Cada alvo afetado deve usar o m\xe1ximo de movimento poss\xedvel para se mover naquela dire\xe7\xe3o no pr\xf3ximo turno. Pode ser necess\xe1ria qualquer a\xe7\xe3o antes de se mover. Depois de se mover dessa forma, ele pode fazer outro salvamento de Sabedoria para tentar encerrar o efeito.\n\nUm alvo n\xe3o \xe9 obrigado a se mover em dire\xe7\xe3o a um perigo obviamente mortal, como um inc\xeandio ou um po\xe7o, mas provocar\xe1 um ataque de oportunidades para se mover na dire\xe7\xe3o designada."},{name:"Convocar Animais",level:3,classes:["Druida","Patrulheiro"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea convoca esp\xedritos fe\xe9ricos que assumem a forma de bestas e aparecem em espa\xe7os desocupados que voc\xea pode ver dentro do alcance. Escolha uma das seguintes op\xe7\xf5es para o que aparece:Uma besta com classifica\xe7\xe3o de desafio 2 ou inferior\nDois bestas de n\xedvel de desafio 1 ou inferior\nQuatro bestas de classifica\xe7\xe3o de desafio 1/2 ou inferior\nOito bestas com classifica\xe7\xe3o de desafio 1/4 ou inferior Cada besta tamb\xe9m \xe9 considerado fe\xe9rico e desaparece quando cai para 0 pontos de vida ou quando a magia termina.\n\nAs criaturas convocadas s\xe3o amig\xe1veis \u200b\u200bcom voc\xea e seus companheiros. Role a iniciativa para as criaturas convocadas como um grupo, que tem seus pr\xf3prios turnos. Eles obedecem a quaisquer comandos verbais que voc\xea emite a eles (nenhuma a\xe7\xe3o exigida por voc\xea). Se voc\xea n\xe3o der nenhum comando a eles, eles se defender\xe3o de criaturas hostis, mas por outro lado n\xe3o tomar\xe3o nenhuma atitude.\n\nO Mestre possui as estat\xedsticas das criaturas."},{name:"Convocar Barragem",level:3,classes:["Patrulheiro"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (60-foot cone)",duration:"Instant\xe2neo",description:"Voc\xea joga uma arma n\xe3o-m\xe1gica ou dispara uma muni\xe7\xe3o n\xe3o-m\xe1gica no ar para criar um cone de armas id\xeanticas que disparam para frente e depois desaparecem. Cada criatura em um cone de 18 metros dever\xe1 passar em um Teste de resist\xeancia de Destreza. Uma criatura sofre 3d8 de dano em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso. O tipo de dano \xe9 o mesmo da arma ou muni\xe7\xe3o usada como componente."},{name:"Contramagia",level:3,classes:["Feiticeiro","Bruxo","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 rea\xe7\xe3o, which you take when you see a creature within 60 feet of you casting a spell.",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea tenta interromper uma criatura no processo de lan\xe7ar um feiti\xe7o. Se a criatura estiver lan\xe7ando uma magia de 3\xba n\xedvel ou inferior, sua magia falha e n\xe3o tem efeito. Caso esteja conjurando um feiti\xe7o de 4\xba n\xedvel ou superior, fa\xe7a um teste de habilidade utilizando seu atributo de conjura\xe7\xe3o. A CD \xe9 igual a 10 + o n\xedvel da magia. Se obtiver sucesso, o feiti\xe7o da criatura falha e n\xe3o tem efeito."},{name:"Criar Comida e \xc1gua",level:3,classes:["Cl\xe9rigo","Paladino"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Instant\xe2neo",description:"Voc\xea cria 45 quilos de comida e 30 gal\xf5es de \xe1gua na solo ou em recipientes dentro do alcance, o suficiente para sustentar at\xe9 quinze human\xf3ides ou cinco corc\xe9is por 24 horas. A comida \xe9 ins\xedpida, mas nutritiva, e estraga se n\xe3o for consumida ap\xf3s 24 horas. A \xe1gua \xe9 limpa e n\xe3o estraga."},{name:"Manto do Cruzado",level:3,classes:["Paladino"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"O poder sagrado irradia de voc\xea em uma aura com raio de 9 metros, despertando ousadia em criaturas amig\xe1veis. At\xe9 a magia terminar, a aura se move com voc\xea, centrada em voc\xea. Enquanto estiver na aura, cada criatura n\xe3o hostil na aura (incluindo voc\xea) causa 1d4 de dano radiante extra quando obt\xe9m sucesso com um ataque com arma."},{name:"Luz do Dia",level:3,classes:["Cl\xe9rigo","Druida","Patrulheiro","Feiticeiro"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"1 hora",description:"Uma esfera de luz com raio de 18 metros se espalha a partir de um ponto que voc\xea escolher dentro do alcance. A esfera tem luz brilhante e emite luz fraca por mais 18 metros.\n\nSe voc\xea escolheu um ponto em um objeto que est\xe1 segurando ou que n\xe3o est\xe1 sendo usado ou carregado, a luz brilha no objeto e se move com ele. Cobrir completamente o objeto afetado com um objeto opaco, como uma tigela ou um elmo, bloqueia a luz.\n\nSe alguma \xe1rea desta magia se sobrepuser a uma \xe1rea de escurid\xe3o criada por uma magia de 3\xba n\xedvel ou inferior, a magia que criou a escurid\xe3o ser\xe1 dissipada."},{name:"Dissipar Magia",level:3,classes:["Bardo","Cl\xe9rigo","Druida","Paladino","Feiticeiro","Bruxo","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Instant\xe2neo",description:"Escolha uma criatura, objeto ou efeito m\xe1gico dentro do alcance. Qualquer magia de 3\xba n\xedvel ou inferior no alvo termina. Para cada feiti\xe7o de 4\xba n\xedvel ou superior no alvo, fa\xe7a um teste de habilidade utilizando seu atributo de conjura\xe7\xe3o. A CD \xe9 igual a 10 + o n\xedvel da magia. Com um teste bem-sucedido, a magia termina."},{name:"Arma Elemental",level:3,classes:["Paladino"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Uma arma n\xe3o m\xe1gica que voc\xea toca se torna uma arma m\xe1gica. Escolha um dos seguintes tipos de dano: \xe1cido, frio, fogo, raio ou trov\xe3o. Durante a dura\xe7\xe3o, a arma tem um b\xf4nus de +1 para ataque de ataques e causa 1d4 de dano extra do tipo escolhido quando \xe9 bem-sucedida."},{name:"Medo",level:3,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (30-foot cone)",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea projeta uma imagem fantasmag\xf3rica dos piores medos de uma criatura. Cada criatura em um cone de 9 metros deve ter sucesso em um Teste de resist\xeancia de Sabedoria ou largar o que estiver segurando e ficar amedrontado durante o per\xedodo.\n\nEnquanto amedrontado por este feiti\xe7o, uma criatura deve pegar a a\xe7\xe3o Dash e se afastar de voc\xea pela rota mais segura dispon\xedvel em cada um de seus turnos, a menos que n\xe3o haja para onde se mover. Se a criatura terminar seu turno em um local onde n\xe3o tenha linha de vis\xe3o para voc\xea, a criatura poder\xe1 fazer um Teste de resist\xeancia de Sabedoria. Em um teste de resist\xeancia bem-sucedido, a magia termina para aquela criatura."},{name:"Fingir a Morte",level:3,classes:["Bardo","Cl\xe9rigo","Druida","Mago"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"1 hora",description:"Voc\xea toca uma criatura volunt\xe1ria e a coloca em um estado catal\xe9ptico que \xe9 indistingu\xedvel da morte.\n\nDurante a dura\xe7\xe3o do feiti\xe7o, ou at\xe9 que voc\xea use uma a\xe7\xe3o para tocar o alvo e disfalha o feiti\xe7o, o alvo parece morto para toda inspe\xe7\xe3o externa e para os feiti\xe7os usados \u200b\u200bpara determinar o status do alvo. O alvo \xe9 cego e incapacitado, e sua velocidade cai para 0. O alvo tem resist\xeancia a todos os danos exceto dano ps\xedquico. Se o alvo estiver doente ou envenenado quando voc\xea conjurar uma magia, ou ficar doente ou envenenado enquanto estiver sob o efeito da magia, a doen\xe7a e o veneno n\xe3o ter\xe3o efeito at\xe9 o fim da magia."},{name:"Bola de Fogo",level:3,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Instant\xe2neo",description:"Uma faixa brilhante brilha do seu dedo indicador at\xe9 um ponto que voc\xea escolhe dentro do alcance e ent\xe3o floresce com um rugido baixo em uma explos\xe3o de chamas. Cada criatura em uma esfera de 6 metros de raio centrada nesse ponto deve fazer um Teste de resist\xeancia de Destreza. Um alvo leva 8d6 de dano de fogo em um teste de resist\xeancia falho, ou metade do dano se for bem-sucedido.\n\nO fogo se espalha pelos cantos da ao redorda. Ele acende objetos inflam\xe1veis \u200b\u200bna \xe1rea que n\xe3o est\xe3o sendo usados \u200b\u200bou carregados."},{name:"Voar",level:3,classes:["Feiticeiro","Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea toca uma criatura volunt\xe1ria. O alvo ganha uma velocidade de v\xf4o de 18 metros durante toda a dura\xe7\xe3o. Quando a magia termina, o alvo cai se ainda estiver no ar, a menos que consiga impedir a queda."},{name:"Forma Gasosa",level:3,classes:["Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea transforma uma criatura volunt\xe1ria que voc\xea toca, junto com tudo que ela est\xe1 vestindo e carregando, em uma nuvem nebulosa enquanto durar. A magia termina se a criatura cair para 0 pontos de vida. Uma criatura incorp\xf3rea n\xe3o \xe9 afetada.\n\nEnquanto estiver nesta forma, o \xfanico m\xe9todo de movimento do alvo \xe9 uma velocidade voadora de 3 metros. O alvo pode entrar e ocupar o espa\xe7o de outra criatura. O alvo possui resist\xeancia a danos n\xe3o m\xe1gicos e possui vantagem em For\xe7a, Destreza e Teste de resist\xeancia de Constitui\xe7\xf5es. O alvo pode passar por pequenos buracos, aberturas estreitas e at\xe9 meras rachaduras, embora trate os l\xedquidos como se fossem superf\xedcies s\xf3lidas. O alvo n\xe3o pode cair e permanece pairando no ar mesmo quando atordoado ou incapacitado.\n\nEnquanto estiver na forma de uma nuvem nebulosa, o alvo n\xe3o pode falar ou manipular objetos, e quaisquer objetos que ele estava carregando ou segurando n\xe3o podem ser derrubados, usados \u200b\u200bou interagir de outra forma. O alvo n\xe3o pode atacar ou lan\xe7ar feiti\xe7os."},{name:"Acelera\xe7\xe3o",level:3,classes:["Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Escolha uma criatura volunt\xe1ria que voc\xea possa ver dentro do alcance. At\xe9 a magia terminar, a velocidade do alvo \xe9 duplicada, ele ganha +2 de b\xf4nus na CA, tem vantagem em Teste de resist\xeancia de Destrezas e ganha uma a\xe7\xe3o adicional em cada um de seus turnos. Essa a\xe7\xe3o pode ser usada apenas para executar a a\xe7\xe3o Ataque (apenas um ataque com arma), Correr, Desengajar, Esconder-se ou Usar um Objeto.\n\nQuando a magia termina, o alvo n\xe3o pode se mover ou realizar a\xe7\xf5es at\xe9 depois do pr\xf3ximo turno, enquanto uma onda de letargia o atinge."},{name:"Padr\xe3o Hipn\xf3tico",level:3,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea cria um padr\xe3o retorcido de cores que serpenteia pelo ar dentro de um cubo de 9 metros dentro do alcance. O padr\xe3o aparece por um momento e desaparece. Cada criatura da \xe1rea que vir o padr\xe3o dever\xe1 fazer um Teste de resist\xeancia de Sabedoria. Em um teste de resist\xeancia falho, a criatura torna-se enfeitada durante todo o tempo. Enquanto enfeitada por este feiti\xe7o, a criatura fica incapacitada e tem velocidade 0.\n\nA magia termina para uma criatura afetada se ela sofrer algum dano ou se algu\xe9m usar uma a\xe7\xe3o para tirar a criatura de seu estupor."},{name:"Flecha de Rel\xe2mpago",level:3,classes:["Patrulheiro"],school:"Transmuta\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Na pr\xf3xima vez que voc\xea fizer um ataque com arma \xe0 dist\xe2ncia durante a dura\xe7\xe3o da magia, a muni\xe7\xe3o da arma, ou a pr\xf3pria arma, se for uma arma de arremesso, se transforma em um raio. Fa\xe7a o jogo de ataque normalmente. A arma sofre 4d8 dano de alvo raio No sucesso, ou metade do dano em uma falha, em vez do dano normal da arma.\n\nSeja com sucesso ou falha, cada criatura a at\xe9 3 metros do alvo deve fazer um Teste de resist\xeancia de Destreza. Cada uma dessas criaturas sofre 2d8 dano de raio em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso.\n\nA muni\xe7\xe3o ou arma retorna ent\xe3o \xe0 sua forma normal."},{name:"C\xedrculo M\xe1gico",level:3,classes:["Cl\xe9rigo","Paladino","Bruxo","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 minute",range:"3 metros",duration:"1 hora",description:"Voc\xea cria um cilindro de energia m\xe1gica com raio de 3 metros e 6 metros de altura centrado em um ponto da solo que voc\xea pode ver dentro do alcance. Runas brilhantes aparecem onde quer que o cilindro cruze o ch\xe3o ou outra superf\xedcie.\n\n* A criatura n\xe3o pode entrar voluntariamente no cilindro por meios n\xe3o m\xe1gicos. Se a criatura tentar usar teletransporte ou viagem interplanar para faz\xea-lo, ela dever\xe1 primeiro ter sucesso em um Teste de resist\xeancia de Carisma.\n\n* A criatura tem manobra de ataque contra alvos dentro do cilindro.\n\n*Alvos dentro do cilindro n\xe3o podem ser enfeiti\xe7ados, amedrontados ou possu\xeddos pela criatura.\n\nQuando voc\xea conjura essa magia, voc\xea pode optar por fazer com que sua magia opere na dire\xe7\xe3o inversa, evitando que uma criatura do tipo especificado saia do cilindro e protegendo alvos fora dele."},{name:"Imagem Maior",level:3,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea cria a imagem de um objeto, uma criatura ou algum outro fen\xf4meno vis\xedvel que n\xe3o seja maior que um cubo de 6 metros. A imagem aparece em um local que voc\xea pode ver dentro do alcance e dura enquanto durar. Parece completamente real, incluindo sons, cheiros e temperatura apropriados \xe0 coisa retratada. Voc\xea n\xe3o pode criar calor ou frio suficiente para causar dano, um som alto o suficiente para causar dano s\xf4nico ou ensurdecer uma criatura, ou um cheiro que possa adoecer uma criatura (como o fedor de um troglodita).\n\nContanto que voc\xea esteja dentro do alcance da ilus\xe3o, voc\xea pode usar sua a\xe7\xe3o para fazer com que a imagem se mova para qualquer outro local dentro do alcance. \xc0 medida que a imagem muda de local, voc\xea pode alterar sua apar\xeancia para que seus movimentos pare\xe7am naturais para a imagem. Por exemplo, se voc\xea criar uma imagem de uma criatura e mov\xea-la, poder\xe1 alterar a imagem para que ela pare\xe7a estar andando. Da mesma forma, voc\xea pode fazer com que a ilus\xe3o emita sons diferentes em momentos diferentes, at\xe9 mesmo fazendo com que ela continue uma conversa, por exemplo.\n\nA intera\xe7\xe3o f\xedsica com a imagem revela que ela \xe9 uma ilus\xe3o, pois coisas podem passar por ela. Uma criatura que use sua a\xe7\xe3o para examinar a imagem pode determinar que se trata de uma ilus\xe3o com um teste bem-sucedido de Intelig\xeancia (Investiga\xe7\xe3o) contra seu CD de resist\xeancia de magia. Se uma criatura discernir a ilus\xe3o pelo que ela \xe9, a criatura poder\xe1 ver atrav\xe9s da imagem, e suas outras qualidades sensoriais tornar-se-\xe3o fracas para a criatura."},{name:"Palavra de Cura em Massa",level:3,classes:["Cl\xe9rigo"],school:"Evoca\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Conforme voc\xea pronuncia palavras de restaura\xe7\xe3o, at\xe9 seis criaturas de sua escolha que voc\xea possa ver dentro do alcance recuperam pontos de vida iguais a 1d4 + seu modificador de atributo de conjura\xe7\xe3o. Este feiti\xe7o n\xe3o tem efeito sobre mortos-vivos ou constructos."},{name:"Alterar a Si Mesmo",level:2,classes:["Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea assume uma forma diferente. Ao conjurar uma magia, escolha uma das seguintes op\xe7\xf5es, cujos efeitos duram enquanto durar a magia. Enquanto o feiti\xe7o durar, voc\xea pode encerrar uma op\xe7\xe3o como uma a\xe7\xe3o para obter os benef\xedcios de outra diferente. \n\nAdapta\xe7\xe3o Aqu\xe1tica:\n Voc\xea adapta seu corpo a um ambiente aqu\xe1tico, criando guelras e teias entre os dedos. Voc\xea pode respirar debaixo d'\xe1gua e ganhar uma velocidade de nata\xe7\xe3o igual \xe0 sua velocidade de caminhada. \nAlterar apar\xeancia:\n Voc\xea transforma sua apar\xeancia. Voc\xea decide sua apar\xeancia, incluindo altura, peso, caracter\xedsticas faciais, som da sua voz, comprimento do cabelo, colora\xe7\xe3o e caracter\xedsticas distintivas, se houver. Voc\xea pode aparecer como membro de outra ra\xe7a, embora nenhuma de suas estat\xedsticas mude. Voc\xea tamb\xe9m n\xe3o pode aparecer como uma criatura de tamanho diferente do seu, e sua forma b\xe1sica permanece a mesma; se voc\xea for b\xedpede, n\xe3o poder\xe1 usar esse feiti\xe7o para se tornar quadr\xfapede, por exemplo. A qualquer momento durante a dura\xe7\xe3o do feiti\xe7o, voc\xea pode usar sua a\xe7\xe3o para mudar sua apar\xeancia dessa forma novamente. \nArmas Naturais:\nVoc\xea cria garras, presas, espinhos, chifres ou uma arma natural diferente de sua escolha. Seus ataques desarmados causam 1d6 concuss\xe3o, perfurante ou dano cortante, conforme apropriado para a arma natural que voc\xea escolheu, e voc\xea \xe9 proficiente com seus ataques desarmados. Finalmente, a arma natural \xe9 m\xe1gica e voc\xea tem um b\xf4nus de +1 nas jogadas de ataque e dano que fizer usando-a."},{name:"Fechadura Arcana",level:2,classes:["Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"At\xe9 ser dissipada",description:"Voc\xea toca uma porta, janela, port\xe3o, ba\xfa ou outra entrada fechada e ela fica trancada enquanto durar. Voc\xea e as criaturas que voc\xea designa Quando voc\xea conjura essa magia podem abrir o objeto normalmente. Voc\xea tamb\xe9m pode definir uma senha que, quando falada a at\xe9 1,5 metro do objeto, suprime esse feiti\xe7o por 1 minuto. Caso contr\xe1rio, fica intranspon\xedvel at\xe9 que seja quebrado ou o feiti\xe7o seja dissipado ou suprimido. Lan\xe7ar golpe no objeto suprime o bloqueio arcano por 10 minutos.\n\nEnquanto afetado por este feiti\xe7o, o objeto \xe9 mais dif\xedcil de quebrar ou abrir \xe0 for\xe7a; a CD para quebr\xe1-lo ou arrombar qualquer fechadura aumenta em 10."},{name:"Pele de Casca",level:2,classes:["Druida","Patrulheiro"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea toca uma criatura volunt\xe1ria. At\xe9 a magia terminar, a pele do alvo tem uma apar\xeancia \xe1spera, semelhante a uma casca de \xe1rvore, e a CA do alvo n\xe3o pode ser inferior a 16, independentemente do tipo de armadura que ele esteja vestindo."},{name:"Indetect\xe1vel",level:3,classes:["Bardo","Cl\xe9rigo","Patrulheiro"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"8 horas",description:"Enquanto isso, voc\xea esconde um alvo que voc\xea toca da magia de adivinha\xe7\xe3o. O alvo pode ser uma criatura volunt\xe1ria ou um local ou objeto n\xe3o maior que 3 metros em qualquer dimens\xe3o. O alvo n\xe3o pode ser alvo de nenhuma magia de adivinha\xe7\xe3o ou percebido atrav\xe9s de sensores m\xe1gicos de vid\xeancia."},{name:"Fundir-se com a Pedra",level:3,classes:["Cl\xe9rigo","Druida"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"8 horas",description:"Voc\xea pisa em um objeto ou superf\xedcie de pedra grande o suficiente para conter totalmente seu corpo, fundindo-se e todo o equipamento que voc\xea carrega com a pedra durante o per\xedodo. Usando seu movimento, voc\xea pisa na pedra em um ponto que pode tocar. Nada de sua presen\xe7a permanece vis\xedvel ou detect\xe1vel por sentidos n\xe3o-m\xe1gicos.\n\nEnquanto estiver fundido com a pedra, voc\xea n\xe3o pode ver o que ocorre fora dela, e quaisquer testes de Sabedoria (Percep\xe7\xe3o) que voc\xea fizer para ouvir sons fora dela ser\xe3o feitos com desvantagem. Voc\xea permanece consciente da passagem do tempo e pode lan\xe7ar feiti\xe7os sobre si mesmo enquanto est\xe1 fundido na pedra. Voc\xea pode usar seu movimento para deixar a pedra por onde voc\xea entrou, o que encerra o feiti\xe7o. Caso contr\xe1rio, voc\xea n\xe3o poder\xe1 se mover.\n\nPequenos danos f\xedsicos \xe0 pedra n\xe3o prejudicam voc\xea, mas sua destrui\xe7\xe3o parcial ou uma mudan\xe7a em sua forma (na medida em que voc\xea n\xe3o cabe mais dentro dela) expulsa voc\xea e causa 6d6 de dano de concuss\xe3o a voc\xea. A destrui\xe7\xe3o completa da pedra (ou transmuta\xe7\xe3o em uma subst\xe2ncia diferente) expulsa voc\xea e causa 50 de dano de concuss\xe3o a voc\xea. Se expulso, voc\xea cai ca\xeddo em um espa\xe7o desocupado mais pr\xf3ximo de onde entrou pela primeira vez."},{name:"Corcel Fantasmag\xf3rico",level:3,classes:["Mago"],school:"Ilus\xe3o",castingTime:"1 minute",range:"9 metros",duration:"1 hora",description:"Uma grande criatura semelhante a um cavalo, quase real, aparece na solo em um espa\xe7o desocupado de sua escolha dentro do alcance. Voc\xea decide a apar\xeancia da criatura, mas ela est\xe1 equipada com sela, freio e freio. Qualquer equipamento criado pelo feiti\xe7o desaparece em uma nuvem de fuma\xe7a se for carregado a mais de 3 metros de dist\xe2ncia do corcel.\n\nEnquanto isso, voc\xea ou uma criatura de sua escolha podem montar no corcel. A criatura usa as estat\xedsticas de um cavalo de montaria, exceto que tem uma velocidade de 30 metros e pode viajar 16 quil\xf4metros em uma hora, ou 21 quil\xf4metros em ritmo acelerado. Quando a magia termina, o corcel desaparece gradualmente, dando ao cavaleiro 1 minuto para desmontar. A magia termina se voc\xea usar uma a\xe7\xe3o para dissipa-la ou se o corcel sofrer algum dano."},{name:"Crescimento Vegetal",level:3,classes:["Bardo","Druida","Patrulheiro"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o or 8 hours",range:"45 metros",duration:"Instant\xe2neo",description:"Este feiti\xe7o canaliza vitalidade para plantas dentro de uma \xe1rea espec\xedfica. Existem dois usos poss\xedveis para o feiti\xe7o, garantindo benef\xedcios imediatos ou de longo prazo.\n\nSe voc\xea conjurar esse feiti\xe7o usando 1 a\xe7\xe3o, escolha um ponto dentro do alcance. Todas as plantas normais em um raio de 30 metros centrado nesse ponto tornam-se espessas e cobertas de vegeta\xe7\xe3o. Uma criatura se movendo pela \xe1rea deve gastar 1,2 metro de movimento para cada 30 cent\xedmetros que se mover.\n\nVoc\xea pode excluir uma ou mais \xe1reas de qualquer tamanho dentro da \xe1rea da magia de serem afetadas.\n\nSe voc\xea lan\xe7ar este feiti\xe7o durante 8 horas, voc\xea enriquecer\xe1 a terra. Todas as plantas num raio de oitocentos metros centrado em um ponto dentro do alcance ficam enriquecidas por 1 ano. As plantas produzem o dobro da quantidade normal de alimento quando colhidas."},{name:"Prote\xe7\xe3o da Energia",level:3,classes:["Cl\xe9rigo","Druida","Patrulheiro","Feiticeiro","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Enquanto durar, a criatura volunt\xe1ria que voc\xea toca tem resist\xeancia a um tipo de dano de sua escolha: \xe1cido, frio, fogo, raio ou trov\xe3o."},{name:"Revivificar",level:3,classes:["Cl\xe9rigo","Paladino"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"Voc\xea toca uma criatura que morreu no \xfaltimo minuto. Essa criatura volta \xe0 vida com 1 ponto de vida. Este feiti\xe7o n\xe3o pode trazer de volta \xe0 vida uma criatura que morreu de velhice, nem pode restaurar qualquer parte do corpo defeituosa."},{name:"Mensagem",level:3,classes:["Bardo","Cl\xe9rigo","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Unlimited",duration:"1 rodada",description:"Voc\xea envia uma mensagem curta de vinte e cinco palavras ou menos para uma criatura com a qual voc\xea est\xe1 familiarizado. A criatura ouve a mensagem em sua mente, reconhece voc\xea como o remetente, se o conhece, e pode responder da mesma maneira imediatamente. A magia permite que criaturas com valores de Intelig\xeancia de pelo menos 1 entendam o significado de sua mensagem.\n\nVoc\xea pode enviar a mensagem a qualquer dist\xe2ncia e at\xe9 mesmo para outros planos de exist\xeancia, mas se o alvo estiver em um plano diferente do seu, h\xe1 5% de chance de a mensagem n\xe3o chegar."},{name:"Tempestade de Granizo",level:3,classes:["Druida","Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"At\xe9 o fim da magia, chuva congelante e granizo caem em um cilindro de 6 metros de altura com um raio de 12 metros centrado em um ponto que voc\xea escolher dentro do alcance. A \xe1rea est\xe1 fortemente obscurecida e as chamas expostas na \xe1rea s\xe3o apagadas.\n\nA solo da regi\xe3o \xe9 coberta por gelo escorregadio, tornando o terreno dif\xedcil. Quando uma criatura entra na \xe1rea da magia pela primeira vez em um turno ou inicia seu turno l\xe1, ela deve realizar um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, ele cai ca\xeddo.\n\nSe uma criatura estiver se concentrando na \xe1rea da magia, a criatura dever\xe1 realizar um Teste de resist\xeancia de Constitui\xe7\xe3o com sucesso contra seu CD de resist\xeancia de magia ou perder\xe1 concentra\xe7\xe3o."},{name:"Lentid\xe3o",level:3,classes:["Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea altera o tempo ao redorda at\xe9 seis criaturas de sua escolha em um cubo de 12 metros dentro do alcance. Cada um deve ter sucesso em um teste de resist\xeancia de alvo de Sabedoria ou ser afetado por este feiti\xe7o enquanto durar.\n\nA velocidade de um alvo afetado \xe9 reduzida \xe0 metade, ele sofre -2 de penalidade na CA e no Teste de resist\xeancia de Destrezas e n\xe3o pode usar ocorr\xeancias. Por sua vez, pode utilizar uma a\xe7\xe3o ou uma a\xe7\xe3o b\xf4nus, e n\xe3o ambas. Independentemente das habilidades ou itens m\xe1gicos da criatura, ela n\xe3o pode realizar mais de um ataque corpo a corpo ou \xe0 dist\xe2ncia durante seu turno.\n\nSe a criatura tentar lan\xe7ar um feiti\xe7o com tempo de lan\xe7amento de 1 a\xe7\xe3o, jogue um d20. Com 11 ou superior, o feiti\xe7o n\xe3o entra em vigor at\xe9 o pr\xf3ximo turno da criatura, e a criatura deve usar sua a\xe7\xe3o naquele turno para completar o feiti\xe7o. Se n\xe3o puder, o feiti\xe7o ser\xe1 desperdi\xe7ado.\n\nUma criatura afetada por este feiti\xe7o faz outro Teste de resist\xeancia de Sabedoria no final do seu turno. Em um teste de resist\xeancia bem-sucedido, o efeito acaba por isso."},{name:"Falar com os Mortos",level:3,classes:["Bardo","Cl\xe9rigo"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"3 metros",duration:"10 minutos",description:"Voc\xea concede a apar\xeancia de vida e intelig\xeancia a um cad\xe1ver de sua escolha dentro do alcance, permitindo que ele responda \xe0s perguntas que voc\xea fizer. O cad\xe1ver ainda deve ter boca e n\xe3o pode ser morto-vivo. A magia falha se o cad\xe1ver foi alvo desta magia nos \xfaltimos 10 dias.\n\nAt\xe9 a magia terminar, voc\xea pode fazer at\xe9 cinco perguntas ao cad\xe1ver. O cad\xe1ver sabe apenas o que conheceu em vida, incluindo as l\xednguas que conheceu. As respostas geralmente s\xe3o breves, enigm\xe1ticas ou repetitivas, e o cad\xe1ver n\xe3o \xe9 obrigado a oferecer uma resposta verdadeira se voc\xea for hostil a ele ou se ele o reconhecer como inimigo. Este feiti\xe7o n\xe3o devolve a alma da criatura ao seu corpo, apenas ao seu esp\xedrito animador. Assim, o cad\xe1ver n\xe3o consegue aprender novas informa\xe7\xf5es, n\xe3o compreende nada do que aconteceu desde que morreu e n\xe3o pode especular sobre acontecimentos futuros."},{name:"Falar com Plantas",level:3,classes:["Bardo","Druida","Patrulheiro"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (30-foot radius",duration:"10 minutos",description:"Voc\xea imbui plantas a at\xe9 9 metros de voc\xea com senci\xeancia e anima\xe7\xe3o limitadas, dando-lhes a capacidade de se comunicar com voc\xea e seguir seus comandos simples. Voc\xea pode questionar plantas sobre eventos ocorridos na \xe1rea da magia no dia anterior, obtendo informa\xe7\xf5es sobre criaturas que passaram, clima e outras circunst\xe2ncias.\n\nVoc\xea tamb\xe9m pode transformar terrenos dif\xedceis causados \u200b\u200bpelo crescimento de plantas (como matagais e vegeta\xe7\xe3o rasteira) em terrenos comuns que perduram por toda a dura\xe7\xe3o. Ou voc\xea pode transformar um terreno comum onde h\xe1 plantas em um terreno dif\xedcil que dura o tempo todo, fazendo com que vinhas e galhos atrapalhem os perseguidores, por exemplo.\n\nPlantaas pode realizar outras tarefas em seu nome, a crit\xe9rio do Mestre. O feiti\xe7o n\xe3o permite que as plantas se desenra\xedzem e se movam, mas elas podem mover livremente galhos, gavinhas e caules.\n\nSe uma planta criatura estiver na \xe1rea, voc\xea poder\xe1 se comunicar com ela como se compartilhasse uma linguagem comum, mas n\xe3o ganha nenhuma habilidade m\xe1gica para influenci\xe1-la.\n\nEste feiti\xe7o pode fazer com que as plantas criadas pelo feiti\xe7o emaranhar liberem uma criatura imobilizada."},{name:"Guardi\xf5es Espirituais",level:3,classes:["Cl\xe9rigo"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (15-foot radius)",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea invoca esp\xedritos para proteg\xea-lo. Eles voam ao redorda a uma dist\xe2ncia de 4,5 metros durante a dura\xe7\xe3o. Se voc\xea for bom ou neutro, sua forma espectral parecer\xe1 angelical ou fe\xe9rico (sua escolha). Se voc\xea \xe9 mau, eles parecem inimigos.\n\nQuando voc\xea conjura essa magia, voc\xea pode designar qualquer n\xfamero de criaturas que voc\xea possa ver para n\xe3o serem afetadas por ela. A velocidade de uma criatura afetada \xe9 reduzida pela metade na \xe1rea, e quando a criatura entra na \xe1rea pela primeira vez em um turno ou inicia seu turno l\xe1, ela deve fazer um Teste de resist\xeancia de Sabedoria. Em um teste de resist\xeancia falho, a criatura sofre 3d8 de dano radiante (se voc\xea for bom ou neutro) ou 3d8 de dano necr\xf3tico (se voc\xea for mau). Em um teste de resist\xeancia bem-sucedido, a criatura leva metade do dano."},{name:"Nuvem Fedorenta",level:3,classes:["Bardo","Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea cria uma esfera de g\xe1s amarelo e nauseante com 6 metros de raio, centrada em um ponto dentro do alcance. A nuvem se espalha pelos cantos ao redorda e sua \xe1rea fica fortemente obscurecida. A nuvem permanece no ar durante todo o tempo.\n\nCada criatura que estiver completamente dentro da nuvem no in\xedcio do seu turno deve fazer um Teste de resist\xeancia de Constitui\xe7\xe3o contra veneno. Em um teste de resist\xeancia falho, a criatura passa sua a\xe7\xe3o vomitando e cambaleando. Criaturas que n\xe3o precisam respirar ou que s\xe3o imunes ao veneno s\xe3o automaticamente bem-sucedidas neste teste de resist\xeancia.\n\nUm vento moderado (pelo menos 10 milhas por hora) dispersa a nuvem ap\xf3s 4 rodadas. Um vento forte (pelo menos 20 milhas por hora) dispersa-o ap\xf3s 1 rodada."},{name:"Confus\xe3o",level:4,classes:["Bardo","Druida","Feiticeiro","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Este feiti\xe7o ataca e distorce a mente das criaturas, gerando del\xedrios e provocando a\xe7\xe3o descontrolada. Cada criatura em uma esfera de raio de 3 metros centrada em um ponto que voc\xea escolher dentro do alcance deve ter sucesso em um Teste de resist\xeancia de Sabedoria quando voc\xea conjura essa magia ou \xe9 afetado por ela.\n\nUm alvo afetado n\xe3o pode aceitar ocorr\xeancias e deve rolar um d10 no in\xedcio de cada um de seus turnos para determinar seu comportamento naquele turno.\n    d10 Comportamento 1 A criatura usa todo o seu movimento para se mover em uma dire\xe7\xe3o aleat\xf3ria. Para determinar a dire\xe7\xe3o, jogue um d8 e atribua uma dire\xe7\xe3o a cada face do dado. A criatura n\xe3o realiza a\xe7\xe3o neste turno.    2-6 A criatura n\xe3o se move nem realiza a\xe7\xf5es neste turno.    7-8 A criatura usa sua a\xe7\xe3o para realizar um ataque corpo a corpo contra uma criatura determinada aleatoriamente ao seu alcance. Se n\xe3o houver nenhuma criatura ao seu alcance, a criatura n\xe3o faz nada neste turno.    9-10 A criatura pode agir e se mover normalmente.    \nAo final de cada um de seus turnos, um alvo afetado pode fazer um Teste de resist\xeancia de Sabedoria. Se tiver sucesso, este efeito termina para aquele alvo"},{name:"Convocar Elementais Menores",level:4,classes:["Druida","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 minute",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea convoca elementais que aparecem em espa\xe7os desocupados que voc\xea pode ver dentro do alcance. Voc\xea escolhe uma das seguintes op\xe7\xf5es para o que aparece: Um elemental de n\xedvel de desafio 2 ou inferior Dois elementais de n\xedvel de desafio 1 ou inferior Quatro elementais de n\xedvel de desafio 1/2 ou inferior Oito elementais de n\xedvel de desafio 1/4 ou inferior. Um elemental invocado por este feiti\xe7o desaparece quando chega a 0 pontos de vida ou quando a magia termina. \n\n As criaturas convocadas s\xe3o amig\xe1veis \u200b\u200bcom voc\xea e seus companheiros. Role a iniciativa para as criaturas convocadas como um grupo, que tem seus pr\xf3prios turnos. Eles obedecem a quaisquer comandos verbais que voc\xea emite a eles (nenhuma a\xe7\xe3o exigida por voc\xea). Se voc\xea n\xe3o der nenhum comando a eles, eles se defender\xe3o de criaturas hostis, mas por outro lado n\xe3o tomar\xe3o nenhuma atitude. \n\n O GM possui as estat\xedsticas das criaturas."},{name:"Controlar \xc1gua",level:4,classes:["Cl\xe9rigo","Druida","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"90 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"At\xe9 o fim da magia, voc\xea controla qualquer \xe1gua independente dentro de uma \xe1rea que voc\xea escolher, que seja um cubo de at\xe9 30 metros de lado. Voc\xea pode escolher qualquer um dos seguintes efeitos Quando voc\xea conjura essa magia. Como a\xe7\xe3o no seu turno, voc\xea pode repetir o mesmo efeito ou escolher um diferente. \n\nInunda\xe7\xe3o: Voc\xea faz com que o n\xedvel de todas as \xe1guas paradas na \xe1rea suba at\xe9 6 metros. Se a \xe1rea incluir uma costa, a \xe1gua da inunda\xe7\xe3o transborda para terra seca. \n\n Se voc\xea escolher uma \xe1rea em um grande corpo de \xe1gua, em vez disso, voc\xea criar\xe1 uma onda de 6 metros de altura que viaja de um lado a outro da \xe1rea e depois cai. Quaisquer ve\xedculos enormes ou menores no caminho da onda s\xe3o carregados com ela para o outro lado. Qualquer ve\xedculo enorme ou menor atingido pela onda tem 25% de chance de virar. \n\n O n\xedvel da \xe1gua permanece elevado at\xe9 a magia terminar ou voc\xea escolher um efeito diferente. Se este efeito produzir uma onda, a onda se repetir\xe1 no in\xedcio do seu pr\xf3ximo turno enquanto durar o efeito da inunda\xe7\xe3o. \n\nParte \xc1gua: Voc\xea faz com que a \xe1gua da \xe1rea se separe e crie uma trincheira. A trincheira se estende pela \xe1rea do feiti\xe7o e a \xe1gua separada forma uma parede em ambos os lados. A trincheira permanece at\xe9 a magia terminar ou voc\xea escolhe um efeito diferente. A \xe1gua ent\xe3o enche lentamente a vala ao longo da pr\xf3xima rodada at\xe9 que o n\xedvel normal da \xe1gua seja restaurado. \n\nFluxo de redirecionamento: Voc\xea faz com que a \xe1gua corrente na \xe1rea se mova na dire\xe7\xe3o que voc\xea escolher, mesmo que a \xe1gua tenha que fluir sobre obst\xe1culos, subir paredes ou em outras dire\xe7\xf5es improv\xe1veis. A \xe1gua na \xe1rea se move conforme voc\xea a direciona, mas uma vez que ela se move al\xe9m da \xe1rea da magia, ela retoma seu fluxo com base nas condi\xe7\xf5es do terreno. A \xe1gua continua a se mover na dire\xe7\xe3o que voc\xea escolheu at\xe9 a magia terminar ou voc\xea escolher um efeito diferente. \n\nRedemoinho: Este efeito requer um corpo de \xe1gua com pelo menos 15 metros quadrados e 21,5 metros de profundidade. Voc\xea faz com que um redemoinho se forme no centro da \xe1rea. O redemoinho forma um v\xf3rtice com 1,5 metro de largura na base, at\xe9 50 p\xe9s de largura no topo e 21,5 metros de altura. Qualquer criatura ou objeto na \xe1gua e dentro de 21,5 metros do v\xf3rtice \xe9 puxado 3 metros em sua dire\xe7\xe3o. Uma criatura pode nadar para longe do v\xf3rtice fazendo um teste de For\xe7a (Atletismo) contra seu CD de resist\xeancia de magia. \n\n Quando uma criatura entra no v\xf3rtice pela primeira vez em um turno ou inicia seu turno ali, ela deve fazer um Teste de resist\xeancia de For\xe7a. Em um teste de resist\xeancia falho, a criatura sofre 2d8 de dano de concuss\xe3o e \xe9 pega no v\xf3rtice at\xe9 o fim da magia. Em um teste de resist\xeancia bem-sucedido, a criatura sofre metade do dano e n\xe3o fica presa no v\xf3rtice. Uma criatura pega no v\xf3rtice pode usar sua a\xe7\xe3o para tentar nadar para longe do v\xf3rtice como descrito acima, mas tem desvantagem no teste de For\xe7a (Atletismo) para fazer isso. \n\n Na primeira vez em cada turno que um objeto entra no v\xf3rtice, o objeto sofre 2d8 dano de concuss\xe3o; esse dano ocorre a cada rodada que permanece no v\xf3rtice."},{name:"Convocar Seres Florestais",level:4,classes:["Druida","Patrulheiro"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea convoca criaturas fe\xe9ricas que aparecem em espa\xe7os desocupados que voc\xea pode ver dentro do alcance. Escolha uma das seguintes op\xe7\xf5es para o que aparece: Uma criatura fe\xe9rico de n\xedvel de desafio 2 ou inferior Duas criaturas fe\xe9ricos de n\xedvel de desafio 1 ou inferior Quatro criaturas fe\xe9ricos de n\xedvel de desafio 1/2 ou inferior Oito criaturas fe\xe9ricos de n\xedvel de desafio 1/4 ou inferior Uma criatura invocada desaparece quando cai para 0 pontos de vida ou quando a magia termina. \n\n As criaturas convocadas s\xe3o amig\xe1veis \u200b\u200bcom voc\xea e seus companheiros. Role a iniciativa para as criaturas convocadas como um grupo, que tem seus pr\xf3prios turnos. Eles obedecem a quaisquer comandos verbais que voc\xea emite a eles (nenhuma a\xe7\xe3o exigida por voc\xea). Se voc\xea n\xe3o der nenhum comando a eles, eles se defender\xe3o de criaturas hostis, mas por outro lado n\xe3o tomar\xe3o nenhuma atitude. \n\n O GM possui as estat\xedsticas das criaturas."},{name:"Prote\xe7\xe3o Mortal",level:4,classes:["Cl\xe9rigo","Paladino"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"8 horas",description:"Voc\xea toca uma criatura e concede a ela certa prote\xe7\xe3o contra a morte.\n\nNa primeira vez que o alvo cairia para 0 pontos de vida como resultado de receber dano, o alvo cairia para 1 ponto de vida e a magia terminaria.\n\nSe o feiti\xe7o ainda estiver em vigor quando o alvo for submetido a um efeito que o mataria instantaneamente sem causar dano, esse efeito ser\xe1 negado contra o alvo e a magia terminar\xe1."},{name:"L\xednguas",level:3,classes:["Bardo","Cl\xe9rigo","Feiticeiro","Bruxo","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"1 hora",description:"Este feiti\xe7o concede \xe0 criatura que voc\xea toca a habilidade de compreender qualquer idioma falado que ouvir. Al\xe9m disso, quando o alvo fala, qualquer criatura que conhe\xe7a pelo menos uma l\xedngua e possa ouvir o alvo entende o que ele diz."},{name:"Sentido de Besta",level:2,classes:["Druida","Patrulheiro"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea toca um besta disposto. Durante a dura\xe7\xe3o da magia, voc\xea pode usar sua a\xe7\xe3o para ver atrav\xe9s dos olhos do besta e ouvir o que ele ouve, e continuar fazendo isso at\xe9 usar sua a\xe7\xe3o para retornar aos seus sentidos normais.\n\nAo perceber atrav\xe9s dos sentidos da besta, voc\xea ganha os benef\xedcios de quaisquer sentidos especiais possu\xeddos por aquela criatura, embora voc\xea seja cego e ensurdecido aos seus pr\xf3prios arredores."},{name:"Borrar",level:2,classes:["Feiticeiro","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Seu corpo fica emba\xe7ado, mudando e oscilando para todos que podem v\xea-lo. Enquanto isso, qualquer criatura ter\xe1 oportunidade de agir de ataques contra voc\xea. Um atacante \xe9 imune a este efeito se n\xe3o depender da vis\xe3o, como no caso da vis\xe3o \xe0s cegas, ou se puder ver atrav\xe9s de ilus\xf5es, como no caso da vis\xe3o verdadeira."},{name:"Golpe de Marca",level:2,classes:["Paladino"],school:"Evoca\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Na pr\xf3xima vez que voc\xea acertar uma criatura com um ataque com arma antes que a magia termine, a arma brilhar\xe1 com brilho astral enquanto voc\xea ataca. O ataque causa 2d6 de dano radiante extra ao alvo, que se torna vis\xedvel se for invis\xedvel, e o alvo emite luz fraca em um raio de 1,5 metro e n\xe3o pode se tornar invis\xedvel at\xe9 o fim da magia."},{name:"Cordon Of Arrows",level:2,classes:["Patrulheiro"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"2 metros",duration:"8 horas",description:"Voc\xea planta quatro pe\xe7as de muni\xe7\xe3o n\xe3o-m\xe1gica \u2014 flechas ou virotes de besta \u2014 na solo dentro do alcance e lan\xe7a magia sobre elas para proteger uma \xe1rea. At\xe9 a magia terminar, sempre que uma criatura que n\xe3o seja voc\xea chega a at\xe9 9 metros de muni\xe7\xe3o pela primeira vez em um turno ou termina seu turno ali, um peda\xe7o de muni\xe7\xe3o voa para atingi-la. A criatura deve ter sucesso em um Teste de Resist\xeancia de Destreza ou sofrer\xe1 1d6 dano perfurante. A muni\xe7\xe3o \xe9 ent\xe3o destru\xedda. A magia termina quando n\xe3o resta mais muni\xe7\xe3o.\n\nQuando voc\xea conjura essa magia, voc\xea pode designar quaisquer criaturas que escolher, e a magia as ignora."},{name:"Coroa da Loucura",level:2,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Um humanoide de sua escolha que voc\xea possa ver dentro do alcance deve ser bem sucedido em um Teste de resist\xeancia de Sabedoria ou ser enfeiti\xe7ado por voc\xea durante esse per\xedodo. \n\n Enquanto o alvo \xe9 assim enfeiti\xe7ado, uma coroa retorcida de ferro denteado aparece em sua cabe\xe7a, e uma loucura brilha em seus olhos. \n\n O alvo enfeiti\xe7ado deve usar sua a\xe7\xe3o antes de passar em cada um de seus turnos para realizar um ataque corpo a corpo contra uma criatura diferente de si mesmo que voc\xea escolher mentalmente. O alvo pode agir normalmente no seu turno se voc\xea n\xe3o escolher nenhuma criatura ou se nenhuma estiver ao seu alcance. \n\n Nos turnos subsequentes, voc\xea deve usar sua a\xe7\xe3o para manter o controle sobre o alvo, ou a magia termina. Al\xe9m disso, o alvo pode fazer um Teste de resist\xeancia de Sabedoria ao final de cada um de seus turnos. Com um sucesso, a magia termina."},{name:"Escurid\xe3o",level:2,classes:["Feiticeiro","Bruxo","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"A escurid\xe3o m\xe1gica se espalha a partir de um ponto que voc\xea escolher dentro do alcance para preencher uma esfera de 4,5 metros de raio durante toda a dura\xe7\xe3o. A escurid\xe3o espalha cantos ao redorda. Uma criatura com vis\xe3o no escuro n\xe3o pode ver atrav\xe9s desta escurid\xe3o, e a luz n\xe3o-m\xe1gica n\xe3o pode ilumin\xe1-la. Se o ponto escolhido estiver em um objeto que voc\xea est\xe1 segurando ou que n\xe3o esteja sendo usado ou carregado, a escurid\xe3o emanar\xe1 do objeto e se mover\xe1 com ele. Cobrir completamente a fonte da escurid\xe3o com um objeto opaco, como uma tigela ou um elmo, bloqueia a escurid\xe3o. Se alguma \xe1rea desta magia se sobrep\xf5e a uma \xe1rea de luz criada por uma magia de 2\xba n\xedvel ou inferior, a magia que criou a luz \xe9 dissipada."},{name:"Vis\xe3o no Escuro",level:2,classes:["Druida","Patrulheiro","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"8 horas",description:"Voc\xea toca uma criatura volunt\xe1ria para conceder-lhe a habilidade de ver no escuro. Durante todo o per\xedodo, essa criatura tem vis\xe3o no escuro em um alcance de 18 metros."},{name:"Detectar Pensamentos",level:2,classes:["Bardo","Feiticeiro","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Enquanto isso, voc\xea pode ler os pensamentos de certas criaturas. Quando voc\xea conjura uma magia e como sua a\xe7\xe3o em cada turno at\xe9 a magia terminar, voc\xea pode focar sua mente em qualquer criatura que voc\xea possa ver a at\xe9 9 metros de voc\xea. Se a criatura que voc\xea escolher tiver Intelig\xeancia 3 ou inferior ou n\xe3o falar nenhum idioma, a criatura n\xe3o ser\xe1 afetada.\n\nVoc\xea inicialmente aprende os pensamentos superficiais da criatura \u2013 o que est\xe1 mais em sua mente naquele momento. Como a\xe7\xe3o, voc\xea pode desviar sua aten\xe7\xe3o para os pensamentos de outra criatura ou tentar investigar mais profundamente a mente da mesma criatura. Se voc\xea investigar mais fundo, o alvo dever\xe1 fazer um Teste de resist\xeancia de Sabedoria. Se falhar, voc\xea obter\xe1 insights sobre seu racioc\xednio (se houver), seu estado emocional e algo que paira em sua mente (como algo que o preocupa, ama ou odeia). Se tiver sucesso, a magia termina. De qualquer forma, o alvo sabe que voc\xea est\xe1 investigando sua mente e, a menos que voc\xea mude sua aten\xe7\xe3o para os pensamentos de outra criatura, a criatura pode usar sua a\xe7\xe3o no seu turno para fazer um teste de Intelig\xeancia contestado pelo seu teste de Intelig\xeancia; se tiver sucesso, a magia termina.\n\nPerguntas dirigidas verbalmente ao alvo criatura moldam naturalmente o curso de seus pensamentos, portanto este feiti\xe7o \xe9 particularmente eficaz como parte de um interrogat\xf3rio. Voc\xea tamb\xe9m pode usar esta magia para detectar a presen\xe7a de criaturas pensantes que voc\xea n\xe3o pode ver. Quando voc\xea conjura uma magia ou como sua a\xe7\xe3o durante a dura\xe7\xe3o, voc\xea pode procurar pensamentos a at\xe9 9 metros de voc\xea. A magia pode penetrar barreiras, mas 60 cent\xedmetros de rocha, 5 cent\xedmetros de qualquer metal que n\xe3o seja chumbo ou uma fina folha de chumbo bloqueiam voc\xea. Voc\xea n\xe3o pode detectar uma criatura com Intelig\xeancia 3 ou inferior ou que n\xe3o fale nenhum idioma.\n\nDepois de detectar a presen\xe7a de uma criatura dessa forma, voc\xea poder\xe1 ler seus pensamentos pelo resto da dura\xe7\xe3o conforme descrito acima, mesmo que n\xe3o possa v\xea-la, mas ela ainda deve estar dentro do alcance."},{name:"Formas Animais",level:8,classes:["Druida"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 dia",description:"Sua magia transforma outros em bestas. Escolha qualquer n\xfamero de criaturas volunt\xe1rias que voc\xea possa ver dentro do alcance. Voc\xea transforma cada alvo na forma de um besta Grande ou menor com uma taxa de desafio de 4 ou menos.  Nos turnos subsequentes, voc\xea pode usar sua a\xe7\xe3o para transformar as criaturas afetadas em novas formas.\n\nA transforma\xe7\xe3o dura a dura\xe7\xe3o de cada alvo, ou at\xe9 que o alvo caia para 0 pontos de vida ou morra.  Voc\xea pode escolher um formul\xe1rio diferente para cada alvo. As estat\xedsticas de jogo de um alvo s\xe3o substitu\xeddas pelas estat\xedsticas do besta escolhido, embora o alvo mantenha seu alinhamento e pontua\xe7\xf5es de Intelig\xeancia, Sabedoria e Carisma. O alvo assume os pontos de vida da sua nova forma, e quando volta \xe0 sua forma normal, volta ao n\xfamero de pontos de vida que tinha antes de se transformar. Se reverter como resultado de cair para 0 pontos de vida, qualquer dano excessivo ser\xe1 transferido para sua forma normal. Contanto que o dano excessivo n\xe3o reduza a forma normal da criatura a 0 pontos de vida, ela n\xe3o ser\xe1 derrubada inconsciente. A criatura \xe9 limitada nas a\xe7\xf5es que pode realizar pela natureza de sua nova forma e n\xe3o pode falar ou lan\xe7ar feiti\xe7os.\n\nO equipamento do alvo se funde \xe0 nova forma. O alvo n\xe3o pode ativar, empunhar ou de outra forma se beneficiar de qualquer um de seus equipamentos."},{name:"Campo Antim\xe1gico",level:8,classes:["Cl\xe9rigo","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (10-foot-radius sphere)",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Uma esfera invis\xedvel de 3 metros de raio antimagia surrodadas voc\xea. Esta \xe1rea est\xe1 divorciada da energia m\xe1gica que permeia o multiverso. Dentro da esfera, os feiti\xe7os n\xe3o podem ser lan\xe7ados, as criaturas invocadas desaparecem e at\xe9 os itens m\xe1gicos tornam-se mundanos. At\xe9 a magia terminar, a esfera se move com voc\xea, centrada em voc\xea. \n\n Feiti\xe7os e outros efeitos m\xe1gicos, exceto aqueles criados por um artefato ou divindade, s\xe3o suprimidos na esfera e n\xe3o podem se projetar nela. Um espa\xe7o gasto para conjurar uma magia suprimida \xe9 consumido. Enquanto um efeito \xe9 suprimido, ele n\xe3o funciona, mas o tempo que ele passa suprimido conta em rela\xe7\xe3o \xe0 sua dura\xe7\xe3o. \n\nEfeitos Alvo: Feiti\xe7os e outros efeitos m\xe1gicos, como falha m\xe1gica e encantar pessoa, que atingem uma criatura ou um objeto na esfera n\xe3o t\xeam efeito sobre esse alvo. \n\n\xc1reas de Magia: A \xe1rea de outra magia ou efeito m\xe1gico, como bola de fogo, n\xe3o pode se estender para dentro da esfera. Se a esfera se sobrep\xf5e a uma \xe1rea de magia, a parte da \xe1rea coberta pela esfera \xe9 suprimida. Por exemplo, as chamas criadas por uma parede de fogo s\xe3o suprimidas dentro da esfera, criando uma lacuna na parede se a sobreposi\xe7\xe3o for grande o suficiente. \n\nFeiti\xe7os: Qualquer magia ativa ou outro efeito m\xe1gico em uma criatura ou objeto na esfera \xe9 suprimido enquanto a criatura ou objeto estiver nela. \n\nItens M\xe1gicos: As propriedades e poderes dos itens m\xe1gicos s\xe3o suprimidos na esfera. Por exemplo, uma espada longa +1 na esfera funciona como uma espada longa n\xe3o m\xe1gica. \n\n As propriedades e poderes de uma arma m\xe1gica s\xe3o suprimidos se ela for usada contra um alvo na esfera ou empunhada por um atacante na esfera. Se uma arma m\xe1gica ou uma muni\xe7\xe3o m\xe1gica sair completamente da esfera (por exemplo, se voc\xea disparar uma flecha m\xe1gica ou lan\xe7ar uma lan\xe7a m\xe1gica em um alvo fora da esfera), a magia do item deixa de ser suprimida assim que ele sai. \n\nViagem M\xe1gica: O teletransporte e a viagem plana n\xe3o funcionam na esfera, seja a esfera o destino ou o ponto de partida para tal viagem m\xe1gica. Um portal para outro local, mundo ou plano de exist\xeancia, bem como uma abertura para um espa\xe7o extradimensional como aquele criado pela magia truque da corda, fecha temporariamente enquanto estiver na esfera. \n\nCriaturas e Objetos: Uma criatura ou objeto invocado ou criado por magia desaparece temporariamente da exist\xeancia na esfera. Tal criatura reaparece instantaneamente assim que o espa\xe7o que a criatura ocupava n\xe3o estiver mais dentro da esfera. \n\nDissipar Magia: Feiti\xe7os e efeitos m\xe1gicos como dissipar magia n\xe3o t\xeam efeito na esfera. Da mesma forma, as esferas criadas por diferentes feiti\xe7os de campo antim\xe1gico n\xe3o se anulam."},{name:"Antipatia/Simpatia",level:8,classes:["Druida","Mago"],school:"Encantamento",castingTime:"1 hour",range:"18 metros",duration:"10 dias",description:"Este feiti\xe7o atrai ou repele criaturas \xe0 sua escolha. Voc\xea almeja algo dentro do alcance, seja um objeto ou criatura enorme ou menor ou uma \xe1rea que n\xe3o seja maior que um cubo de 60 metros. Em seguida, especifique um tipo de criatura inteligente, como drag\xf5es vermelhos, goblins ou vampiros. Voc\xea investe no alvo uma aura que atrai ou repele as criaturas especificadas durante o per\xedodo. Escolha antipatia ou simpatia como efeito da aura.\n\nSe o alvo danificar ou de outra forma prejudicar uma criatura afetada, a criatura afetada pode fazer um Teste de resist\xeancia de Sabedoria para encerrar o efeito, conforme descrito abaixo.\n\nUma criatura que consiga resistir contra esse efeito fica imune a ele por 1 minuto, ap\xf3s o qual poder\xe1 ser afetada novamente."},{name:"Proje\xe7\xe3o Astral",level:9,classes:["Cl\xe9rigo","Bruxo","Mago"],school:"Necromancia",castingTime:"1 hour",range:"3 metros",duration:"Especial",description:"Voc\xea e at\xe9 oito criaturas volunt\xe1rias dentro do alcance projetam seus corpos astrais no Plano Astral (o feiti\xe7o falha e o lan\xe7amento \xe9 desperdi\xe7ado se voc\xea j\xe1 estiver naquele plano). O corpo material que voc\xea deixa para tr\xe1s \xe9 inconsciente e est\xe1 em estado de anima\xe7\xe3o suspensa; n\xe3o precisa de comida nem de ar e n\xe3o envelhece.\n\nSeu corpo astral se assemelha \xe0 sua forma mortal em quase todos os aspectos, replicando as estat\xedsticas e posses do jogo. A principal diferen\xe7a \xe9 a adi\xe7\xe3o de um cord\xe3o prateado que se estende entre as omoplatas e segue atr\xe1s de voc\xea, tornando-se invis\xedvel ap\xf3s 30 cent\xedmetros. Este cord\xe3o \xe9 a sua liga\xe7\xe3o ao seu corpo material. Contanto que a corda permane\xe7a intacta, voc\xea poder\xe1 encontrar o caminho de casa. Se o cord\xe3o for cortado \u2013 algo que s\xf3 pode acontecer quando um efeito afirma especificamente que isso acontece \u2013 sua alma e seu corpo ser\xe3o separados, matando voc\xea instantaneamente.\n\nSua forma astral pode viajar livremente pelo Plano Astral e passar por portais que levam a qualquer outro plano. Se voc\xea entrar em um novo plano ou retornar ao plano em que estava quando lan\xe7ou este feiti\xe7o, seu corpo e seus pertences ser\xe3o transportados ao longo do cord\xe3o prateado, permitindo que voc\xea entre novamente em seu corpo ao entrar no novo plano. Sua forma astral \xe9 uma encarna\xe7\xe3o separada. Quaisquer danos ou outros efeitos que se apliquem a ele n\xe3o ter\xe3o efeito em seu corpo f\xedsico, nem persistir\xe3o quando voc\xea retornar a ele.\n\nA magia termina para voc\xea e seus companheiros quando voc\xea usa sua a\xe7\xe3o para disfalha-la. Quando a magia termina, a criatura afetada retorna ao seu corpo f\xedsico e desperta.\n\nO feiti\xe7o tamb\xe9m pode terminar mais cedo para voc\xea ou um de seus companheiros. Um feiti\xe7o _dissipar magia_ bem-sucedido usado contra um corpo astral ou f\xedsico encerra o feiti\xe7o para aquela criatura. Se o corpo original de uma criatura ou sua forma astral cair para 0 pontos de vida, a magia termina para aquela criatura. Se a magia terminar e o cord\xe3o prateado estiver intacto, o cord\xe3o puxa a forma astral da criatura de volta ao seu corpo, encerrando seu estado de anima\xe7\xe3o suspensa.\n\nSe voc\xea retornar ao seu corpo prematuramente, seus companheiros permanecer\xe3o em suas formas astrais e dever\xe3o encontrar seu pr\xf3prio caminho de volta aos seus corpos, geralmente caindo para 0 pontos de vida."},{name:"Clonar",level:8,classes:["Mago"],school:"Necromancia",castingTime:"1 hour",range:"Toque",duration:"Instant\xe2neo",description:"Este feiti\xe7o cria uma duplicata inerte de uma criatura viva como uma salvaguarda contra a morte. Este clone se forma dentro de um recipiente lacrado e atinge seu tamanho m\xe1ximo e maturidade ap\xf3s 120 dias; voc\xea tamb\xe9m pode optar por fazer com que o clone seja uma vers\xe3o mais jovem da mesma criatura. Permanece inerte e dura indefinidamente, enquanto o seu recipiente permanecer intacto.\n\nA qualquer momento ap\xf3s o clone amadurecer, se a criatura original morrer, sua alma ser\xe1 transferida para o clone, desde que a alma esteja livre e disposta a retornar. O clone \xe9 fisicamente id\xeantico ao original e tem a mesma personalidade, mem\xf3rias e habilidades, mas nenhum equipamento do original. Os restos f\xedsicos da criatura original, se ainda existirem, tornam-se inertes e n\xe3o podem mais ser restaurados \xe0 vida, uma vez que a alma da criatura est\xe1 em outro lugar."},{name:"Controlar o Clima",level:8,classes:["Cl\xe9rigo","Druida","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"10 minutes",range:"Self (5-mile radius)",duration:"Concentra\xe7\xe3o, at\xe9 8 horas",description:"Voc\xea assume o controle do clima em um raio de 8 quil\xf4metros de voc\xea durante todo o per\xedodo. Voc\xea deve estar ao ar livre para lan\xe7ar este feiti\xe7o. Mover-se para um lugar onde voc\xea n\xe3o tenha um caminho claro para o c\xe9u encerra o feiti\xe7o mais cedo.\n\n Quando voc\xea conjura uma magia, voc\xea altera as condi\xe7\xf5es clim\xe1ticas atuais, que s\xe3o determinadas pelo Mestre com base no clima e na esta\xe7\xe3o. Voc\xea pode alterar a precipita\xe7\xe3o, a temperatura e o vento. S\xe3o necess\xe1rios 1d4 \xd7 10 minutos para que as novas condi\xe7\xf5es entrem em vigor. Depois que eles fizerem isso, voc\xea poder\xe1 alterar as condi\xe7\xf5es novamente. Quando a magia termina, o tempo volta gradualmente ao normal. \n\n Quando voc\xea altera as condi\xe7\xf5es clim\xe1ticas, encontre uma condi\xe7\xe3o atual nas tabelas a seguir e altere seu est\xe1gio em um, para cima ou para baixo. Ao mudar o vento, voc\xea pode mudar sua dire\xe7\xe3o.\n\nTemperaturaEst\xe1gioCondi\xe7\xe3o1Calor insuport\xe1vel2Quente3Quente4Frio5Frio6Frio \xe1rticoVentoEst\xe1gioCondi\xe7\xe3o1Calma2Vento moderado3Vento forte4Vento forte4TempestadePrecipita\xe7\xe3oEst\xe1gioCondi\xe7\xe3o1Claro2Nuvens claras3N\xe9voa nublada ou solo4Chuva, granizo ou neve5Chuva torrencial, granizo ou nevasca"},{name:"Demiplano",level:8,classes:["Bruxo","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"1 hora",description:"Voc\xea cria uma porta sombria em uma superf\xedcie plana e s\xf3lida que voc\xea pode ver dentro do alcance. A porta \xe9 grande o suficiente para permitir que criaturas M\xe9dias passem sem impedimentos. Quando aberta, a porta leva a um semiplano que parece ser uma sala vazia de 9 metros em cada dimens\xe3o, feita de madeira ou pedra. Quando a magia termina, a porta desaparece, e quaisquer criaturas ou objetos dentro do semiplano permanecem presos ali, assim como a porta tamb\xe9m desaparece do outro lado.\n\nCada vez que voc\xea lan\xe7a este feiti\xe7o, voc\xea pode criar um novo semiplano ou fazer com que a porta sombria se conecte a um semiplano Voc\xea criou com um lan\xe7amento anterior deste feiti\xe7o.  Al\xe9m disso, se voc\xea conhece a natureza e o conte\xfado de um semiplano criado pela conjura\xe7\xe3o desta magia por outra criatura, voc\xea pode fazer com que a porta sombria se conecte ao seu semiplano."},{name:"Dominar Monstro",level:8,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea tenta enganar uma criatura que voc\xea pode ver dentro do alcance. Deve ser aprovado em Teste de resist\xeancia de Sabedoria ou ser feiti\xe7ado por voc\xea durante todo o per\xedodo. Se voc\xea ou criaturas que lhe s\xe3o amigas est\xe3o lutando contra isso, tem vantagem no teste de resist\xeancia.\n\nEnquanto a criatura estiver enfeitada, voc\xea ter\xe1 uma liga\xe7\xe3o telep\xe1tica com ela enquanto voc\xeas dois estiverem no mesmo plano de exist\xeancia. Voc\xea pode usar esse link telep\xe1tico para emitir comandos \xe0 criatura enquanto estiver consciente (nenhuma a\xe7\xe3o necess\xe1ria), aos quais ela far\xe1 o poss\xedvel para obedecer. Voc\xea pode especificar um curso de a\xe7\xe3o simples e geral, como Atacar aquela criatura, Correr at\xe9 l\xe1 ou Buscar aquele objeto. Se a criatura completar a ordem e n\xe3o receber mais orienta\xe7\xf5es suas, ela se defender\xe1 e se preservar\xe1 da melhor maneira poss\xedvel.\n\nVoc\xea pode usar sua a\xe7\xe3o para assumir o controle total e preciso do alvo. At\xe9 o final do seu pr\xf3ximo turno, a criatura realiza apenas as a\xe7\xf5es que voc\xea escolher e n\xe3o faz nada que voc\xea n\xe3o permita. Durante esse tempo, voc\xea tamb\xe9m pode fazer com que a criatura use uma ocorr\xeancia, mas isso exige que voc\xea use sua pr\xf3pria ocorr\xeancia tamb\xe9m.\n\nCada vez que o alvo sofre dano, ele faz um novo Teste de resist\xeancia de Sabedoria contra o feiti\xe7o. Se o teste de resist\xeancia for bem-sucedido, a magia termina."},{name:"Terremoto",level:8,classes:["Cl\xe9rigo","Druida","Feiticeiro"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"150 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea cria um dist\xfarbio s\xedsmico em um ponto da superf\xedcie que voc\xea pode ver dentro do alcance. Durante esse tempo, um tremor intenso rasga a solo em um c\xedrculo de 30 metros de raio centrado naquele ponto e sacode criaturas e estruturas em contato com a solo naquela \xe1rea. \n\n A solo da regi\xe3o torna-se terreno dif\xedcil. Cada criatura da solo que estiver se concentrando dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, a concentra\xe7\xe3o da criatura \xe9 quebrada. \n\n Quando voc\xea conjura essa magia e ao final de cada turno voc\xea passa concentrado nela, cada criatura da solo na \xe1rea deve fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, a criatura \xe9 derrubada. \n\n Este feiti\xe7o pode ter efeitos adicionais dependendo do terreno da \xe1rea, conforme determinado pelo Mestre. \n\nFissuras: Fissuras se abrem em toda a \xe1rea do feiti\xe7o no in\xedcio do seu pr\xf3ximo turno ap\xf3s voc\xea conjurar uma magia. Um total de 1d6 dessas fissuras se abrem em locais escolhidos pelo Mestre. Cada um tem 1d10 \xd7 3 metros de profundidade, 3 metros de largura e se estende de uma borda da \xe1rea da magia at\xe9 o lado oposto. Uma criatura parada em um local onde uma fissura se abre deve ter sucesso em um Teste de resist\xeancia de Destreza ou cair\xe1. Uma criatura que consegue salvar se move com a borda da fissura conforme ela se abre. \n\n Uma fissura que se abre abaixo de uma estrutura faz com que ela desmorone automaticamente (veja abaixo). \n\nEstruturas: O tremor causa 50 de dano de concuss\xe3o a qualquer estrutura em contato com a solo na \xe1rea quando voc\xea conjura uma magia e no in\xedcio de cada um de seus turnos at\xe9 a magia terminar. Se uma estrutura cair para 0 pontos de vida, ela entra em colapso e potencialmente danifica as criaturas pr\xf3ximas. Uma criatura que esteja a meia dist\xe2ncia da altura de uma estrutura deve fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, a criatura sofre 5d6 de dano de concuss\xe3o, \xe9 derrubada e enterrada nos escombros, exigindo um teste de For\xe7a CD 20 (Atletismo) como uma a\xe7\xe3o para escapar. O Mestre pode ajustar a CD para mais ou para menos, dependendo da natureza dos escombros. Em um teste de resist\xeancia bem-sucedido, a criatura leva metade do dano e n\xe3o cai nem \xe9 soterrada."},{name:"Debilitar Mente",level:8,classes:["Bardo","Druida","Bruxo","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Instant\xe2neo",description:"Voc\xea explode a mente de uma criatura que voc\xea pode ver dentro do alcance, tentando destruir seu intelecto e personalidade. O alvo sofre 4d6 de dano ps\xedquico e deve fazer um Teste de resist\xeancia de Intelig\xeancia. \n\n Em um teste de resist\xeancia falho, os valores de Intelig\xeancia e Carisma da criatura tornam-se 1. A criatura n\xe3o pode lan\xe7ar feiti\xe7os, ativar itens m\xe1gicos, entender a linguagem ou se comunicar de qualquer maneira intelig\xedvel. A criatura pode, entretanto, identificar seus amigos, segui-los e at\xe9 mesmo proteg\xea-los. \n\n Ao final de cada 30 dias, a criatura poder\xe1 repetir seu teste de resist\xeancia contra este feiti\xe7o. Se obtiver sucesso no teste de resist\xeancia, a magia termina. \n\n O feiti\xe7o tamb\xe9m pode ser encerrado com uma restaura\xe7\xe3o maior, cura ou desejo."},{name:"Presci\xeancia",level:9,classes:["Bardo","Druida","Bruxo","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 minute",range:"Toque",duration:"8 horas",description:"Voc\xea toca uma criatura volunt\xe1ria e concede uma capacidade limitada de ver o futuro imediato. Durante o tempo o alvo n\xe3o pode ser surpreendido e tem vantagem em ataque de ataques, teste de habilidades e testes de resist\xeancia. Al\xe9m disso, outras criaturas t\xeam manobras de ataque contra o alvo durante o per\xedodo.\n\nEste feiti\xe7o termina imediatamente se voc\xea lan\xe7\xe1-lo novamente antes que sua dura\xe7\xe3o termine."},{name:"Portal",level:9,classes:["Cl\xe9rigo","Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea invoca um portal ligando um espa\xe7o desocupado que voc\xea pode ver at\xe9 um local preciso em um plano de exist\xeancia diferente. O portal \xe9 uma abertura circular, que pode ser feita com 1,5 a 6 metros de di\xe2metro. Voc\xea pode orientar o portal em qualquer dire\xe7\xe3o que desejar. O portal dura enquanto durar.\n\nO portal possui uma frente e um verso em cada plano onde aparece. Viajar pelo portal s\xf3 \xe9 poss\xedvel passando pela sua frente. Qualquer coisa que fa\xe7a isso \xe9 instantaneamente transportada para o outro plano, aparecendo no espa\xe7o desocupado mais pr\xf3ximo do portal.\n\nDivindades e outros governantes planares podem impedir que portais criados por esta magia se abram em sua presen\xe7a ou em qualquer lugar dentro de seus dom\xednios.\n\nQuando voc\xea conjura essa magia, voc\xea pode falar o nome de uma criatura espec\xedfica (um pseud\xf4nimo, t\xedtulo ou apelido n\xe3o funciona). Se aquela criatura estiver em um plano diferente daquele em que voc\xea est\xe1, o portal se abre nas imedia\xe7\xf5es da criatura nomeada e atrai a criatura atrav\xe9s dele at\xe9 o espa\xe7o desocupado mais pr\xf3ximo do seu lado do portal. Voc\xea n\xe3o ganha nenhum poder especial sobre a criatura, e ela \xe9 livre para agir como o Mestre considerar apropriado. Pode sair, atac\xe1-lo ou ajud\xe1-lo."},{name:"Flu\xeancia",level:8,classes:["Bardo","Bruxo"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"1 hora",description:"At\xe9 o fim da magia, quando voc\xea faz um teste de Carisma, voc\xea pode substituir o n\xfamero obtido por 15. Al\xe9m disso, n\xe3o importa o que voc\xea diga, a magia que determinaria se voc\xea est\xe1 dizendo a verdade indica que voc\xea est\xe1 sendo verdadeiro."},{name:"Aura Sagrada",level:8,classes:["Cl\xe9rigo"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"A luz divina sai de voc\xea e se funde em um brilho suave em um raio de 9 metros ao seu redor. Criaturas de sua escolha naquele raio Quando voc\xea conjura essa magia lan\xe7a luz fraca em um raio de 1,5 metro e tem vantagem sobre todos os testes de resist\xeancia, e outras criaturas t\xeam interfer\xeancia no jogo de ataques contra eles at\xe9 a magia terminar. Al\xe9m disso, quando um inimigo ou um morto-vivo vence uma criatura afetada com um ataque corpo a corpo, a aura brilha com uma luz brilhante. O atacante deve ter sucesso em um Teste de resist\xeancia de Constitui\xe7\xe3o ou ficar\xe1 cego at\xe9 a magia terminar."},{name:"Aprisionamento",level:9,classes:["Bruxo","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 minute",range:"9 metros",duration:"At\xe9 ser dissipada",description:"Voc\xea cria uma restri\xe7\xe3o m\xe1gica para segurar uma criatura que voc\xea pode ver dentro do alcance. O deve ter sucesso em um Teste de resist\xeancia de Sabedoria ou ficar preso ao feiti\xe7o; se tiver sucesso, ele ficar\xe1 imune a esta magia se voc\xea lan\xe7\xe1-la novamente. Enquanto afetada por este feiti\xe7o, a criatura n\xe3o precisa respirar, comer ou beber e n\xe3o envelhece. Feiti\xe7os de adivinha\xe7\xe3o n\xe3o conseguem localizar ou perceber o alvo. \n\n Ao conjurar uma magia, voc\xea escolhe uma das seguintes formas de pris\xe3o. \n\nEnterro: O alvo \xe9 sepultado bem abaixo da terra em uma esfera de for\xe7a m\xe1gica que \xe9 grande o suficiente para conter o alvo. Nada pode passar pela esfera, nem qualquer criatura pode se teletransportar ou usar viagens planas para entrar ou sair dela. \n\n O componente especial para esta vers\xe3o do feiti\xe7o \xe9 um pequeno orbe de mitral. \n\nAcorrentamento: Correntes pesadas, firmemente enraizadas na solo, mant\xeam o alvo no lugar. O alvo fica imobilizado at\xe9 o final da magia, e n\xe3o pode se mover ou ser movido de forma alguma at\xe9 ent\xe3o. \n\n O componente especial desta vers\xe3o do feiti\xe7o \xe9 uma fina corrente de metal precioso. \n\nPris\xe3o Hedged: O feiti\xe7o transporta o alvo para um pequeno semiplano que \xe9 protegido contra teletransporte e viagens planares. O semiplano pode ser um labirinto, uma gaiola, uma torre ou qualquer estrutura ou \xe1rea confinada semelhante de sua escolha. \n\n O componente especial desta vers\xe3o do feiti\xe7o \xe9 uma representa\xe7\xe3o em miniatura da pris\xe3o feita de jade. \n\nConten\xe7\xe3o M\xednima: O alvo encolhe at\xe9 uma altura de 2,5 cm e fica aprisionado dentro de uma pedra preciosa ou objeto similar. A luz pode passar atrav\xe9s da gema normalmente (permitindo que o alvo veja para fora e outras criaturas vejam para dentro), mas nada mais pode passar, mesmo por meio de teletransporte ou viagem planar. A pedra preciosa n\xe3o pode ser cortada ou quebrada enquanto o feiti\xe7o permanecer em vigor. \n\n O componente especial para esta vers\xe3o do feiti\xe7o \xe9 uma pedra preciosa grande e transparente, como corindo, diamante ou rubi. \n\nSono: O alvo adormece e n\xe3o consegue ser acordado. O componente especial desta vers\xe3o do feiti\xe7o consiste em ervas sopor\xedficas raras. \n\nFinalizando o Feiti\xe7o: Durante o lan\xe7amento do feiti\xe7o, em qualquer uma de suas vers\xf5es, voc\xea pode especificar uma condi\xe7\xe3o que far\xe1 com que o feiti\xe7o termine e libere o alvo. A condi\xe7\xe3o pode ser t\xe3o espec\xedfica ou elaborada quanto voc\xea escolher, mas o Mestre deve concordar que a condi\xe7\xe3o \xe9 razo\xe1vel e tem probabilidade de se concretizar. As condi\xe7\xf5es podem ser baseadas no nome, identidade ou divindade de uma criatura, mas de outra forma devem ser baseadas em a\xe7\xf5es ou qualidades observ\xe1veis \u200b\u200be n\xe3o baseadas em intang\xedveis como n\xedvel, classe ou pontos de vida. \n\n Uma magia dissipar magia s\xf3 pode encerrar a magia se for lan\xe7ada como uma magia de 9\xba n\xedvel, visando a pris\xe3o ou o componente especial usado para cri\xe1-la. \n\n Voc\xea pode usar um componente especial espec\xedfico para criar apenas uma pris\xe3o por vez. Se voc\xea conjurar uma magia novamente usando o mesmo componente, o alvo da primeira conjura\xe7\xe3o \xe9 imediatamente liberado de sua liga\xe7\xe3o."},{name:"Nuvem Incendi\xe1ria",level:8,classes:["Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Uma nuvem rodopiante de fuma\xe7a atravessada por brasas quentes aparece a uma dist\xe2ncia de 6 metros. A nuvem se espalha pelos cantos ao redorda e fica fortemente obscurecida. Dura enquanto durar ou at\xe9 que um vento de velocidade moderada ou maior (pelo menos 10 milhas por hora) o disperse.\n\nQuando a nuvem aparece, cada criatura nela contida deve fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre 10d8 de dano de fogo em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso. Uma criatura tamb\xe9m deve realizar este teste de resist\xeancia quando entrar na \xe1rea da magia pela primeira vez em um turno ou terminar seu turno ali.\n\nA nuvem se move 3 metros diretamente para longe de voc\xea, na dire\xe7\xe3o que voc\xea escolher no in\xedcio de cada um dos seus turnos."},{name:"Curar em Massa",level:9,classes:["Cl\xe9rigo"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Uma inunda\xe7\xe3o de energia curativa flui de voc\xea para criaturas feridas que o cercam. Voc\xea restaura at\xe9 700 pontos de vida, divididos como quiser entre qualquer n\xfamero de criaturas que voc\xea pode ver dentro do alcance. As criaturas curadas por este feiti\xe7o tamb\xe9m s\xe3o curadas de todas as doen\xe7as e de qualquer efeito que as torne cegas ou ensurdecidas. Este feiti\xe7o n\xe3o tem efeito sobre mortos-vivos ou constructos."},{name:"Labirinto",level:8,classes:["Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea bane uma criatura que voc\xea pode ver dentro do alcance para um semiplano labir\xedntico. O alvo permanece l\xe1 durante ou at\xe9 escapar do labirinto.\n\nO alvo pode usar sua a\xe7\xe3o para tentar escapar. Quando isso acontece, ele faz um teste de Intelig\xeancia CD 20. Se tiver sucesso, ele escapa e a magia termina (um minotauro ou dem\xf4nio goristro obt\xe9m sucesso automaticamente).\n\nQuando a magia termina, o alvo reaparece no espa\xe7o que deixou ou, se esse espa\xe7o estiver ocupado, no espa\xe7o desocupado mais pr\xf3ximo."},{name:"Chuva de Meteoros",level:9,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"1 mile",duration:"Instant\xe2neo",description:"Orbes ardentes de fogo despencam at\xe9 a solo em quatro pontos diferentes que voc\xea pode ver dentro do alcance. Cada criatura em uma esfera de 12 metros de raio centrada em cada ponto escolhido deve fazer um Teste de resist\xeancia de Destreza. A esfera espalha cantos ao redorda. Uma criatura sofre 20d6 de dano de fogo e 20d6 de dano de concuss\xe3o em um teste de resist\xeancia falho, ou metade do dano em um teste bem sucedido. Uma criatura na \xe1rea de mais de uma explos\xe3o de fogo \xe9 afetada apenas uma vez.\n\nO feiti\xe7o danifica objetos na \ufffd\ufffdrea e incendeia objetos inflam\xe1veis \u200b\u200bque n\xe3o est\xe3o sendo usados \u200b\u200bou carregados."},{name:"Mente em Branco",level:8,classes:["Bardo","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"24 horas",description:"At\xe9 o final da magia, uma criatura volunt\xe1ria que voc\xea tocar \xe9 imune a dano ps\xedquico, qualquer efeito que possa sentir suas emo\xe7\xf5es ou ler seus pensamentos, feiti\xe7os de adivinha\xe7\xe3o e a condi\xe7\xe3o enfeiti\xe7ado. O feiti\xe7o frustra at\xe9 mesmo feiti\xe7os e feiti\xe7os ou efeitos de poder semelhante usados \u200b\u200bpara afetar a mente do alvo ou para obter informa\xe7\xf5es sobre o alvo."},{name:"Palavra de Poder: Curar",level:9,classes:["Bardo"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"Uma onda de energia curativa envolve a criatura que voc\xea toca. O recupera todos os seus pontos de vida. Se a criatura estiver enfeitada, amedrontada, paralisada ou atordoada, o quadro termina. Se a criatura cair, ela poder\xe1 usar sua ocorr\xeancia para se levantar. Este feiti\xe7o n\xe3o tem efeito sobre mortos-vivos ou constructos."},{name:"Palavra de Poder: Matar",level:9,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea pronuncia uma palavra de poder que pode obrigar uma criatura que voc\xea possa ver dentro do alcance a morrer instantaneamente. Se a criatura escolhida tiver 100 pontos de vida ou menos, ela morre. Caso contr\xe1rio, o feiti\xe7o n\xe3o ter\xe1 efeito."},{name:"Palavra de Poder: Atordoar",level:8,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea fala uma palavra de poder que pode dominar a mente de uma criatura que voc\xea possa ver dentro do alcance, deixando-a pasma. Se o alvo tiver 150 pontos de vida ou menos, est\xe1 atordoado. Caso contr\xe1rio, o feiti\xe7o n\xe3o ter\xe1 efeito.\n\nO alvo atordoado dever\xe1 realizar um Teste de resist\xeancia de Constitui\xe7\xe3o ao final de cada um de seus turnos.  Em um teste de resist\xeancia bem-sucedido, esse efeito deslumbrante termina."},{name:"Muro Prism\xe1tico",level:9,classes:["Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"10 minutos",description:"Um plano de luz brilhante e multicolorido forma uma parede vertical opaca - de at\xe9 27 metros de comprimento, 9 metros de altura e 1 polegada de espessura - centrada em um ponto que voc\xea pode ver dentro do alcance. Alternativamente, voc\xea pode moldar a parede em uma esfera de at\xe9 9 metros de di\xe2metro centrada em um ponto escolhido dentro do alcance. A parede permanece no lugar durante todo o per\xedodo. Se voc\xea posicionar a parede de forma que ela passe por um espa\xe7o ocupado por uma criatura, o feiti\xe7o falha e sua a\xe7\xe3o e espa\xe7o de magia s\xe3o desperdi\xe7ados. \n\n A parede emite luz brilhante at\xe9 um alcance de 30 metros e luz fraca por mais 30 metros adicionais. Voc\xea e as criaturas que voc\xea designar no momento em que voc\xea conjurar uma magia podem passar e permanecer perto da parede sem danos. Se outra criatura que possa ver a parede se mover para at\xe9 6 metros dela ou come\xe7ar seu turno ali, a criatura dever\xe1 ter sucesso em um Teste de Resist\xeancia de Constitui\xe7\xe3o ou ficar\xe1 cega por 1 minuto. \n\n A parede consiste em sete camadas, cada uma com uma cor diferente. Quando uma criatura tenta alcan\xe7ar ou atravessar a parede, ela o faz, uma camada de cada vez, atrav\xe9s de todas as camadas da parede. \xc0 medida que passa ou alcan\xe7a cada camada, a criatura deve fazer um Teste de resist\xeancia de Destreza ou ser\xe1 afetada pelas propriedades daquela camada conforme descrito abaixo. \n\n A parede pode ser destru\xedda, tamb\xe9m uma camada de cada vez, na ordem do vermelho ao violeta, por meios espec\xedficos para cada camada. Uma vez que uma camada \xe9 destru\xedda, ela permanece assim durante a dura\xe7\xe3o do feiti\xe7o. O campo antimagia n\xe3o tem efeito na parede e dissipar magia pode afetar apenas a camada violeta. Vermelho A criatura sofre 10d6 de dano de fogo em um teste de resist\xeancia falho, ou metade do dano em um teste bem sucedido. Enquanto esta camada estiver no lugar, ataques \xe0 dist\xe2ncia n\xe3o m\xe1gicos n\xe3o podem atravessar a parede. A camada pode ser destru\xedda causando pelo menos 25 de dano de frio a ela. Laranja A criatura sofre 10d6 de dano de \xe1cido em um teste de resist\xeancia falho, ou metade do dano em um teste bem-sucedido. Enquanto esta camada estiver no lugar, ataques m\xe1gicos de longo alcance n\xe3o poder\xe3o atravessar a parede. A camada \xe9 destru\xedda por um vento forte. Amarelo A criatura sofre 10d6 dano de raio em um teste de resist\xeancia falho, ou metade do dano em um teste bem-sucedido. Esta camada pode ser destru\xedda causando pelo menos 60 de dano de for\xe7a a ela. Verde A criatura sofre 10d6 de dano de veneno em um teste de resist\xeancia falho, ou metade do dano em um teste bem sucedido. Um feiti\xe7o de passagem, ou outro feiti\xe7o de n\xedvel igual ou superior que possa abrir um portal em uma superf\xedcie s\xf3lida, destr\xf3i esta camada. Azul A criatura sofre 10d6 de dano de frio em um teste de resist\xeancia de falho, ou metade do dano em um teste bem sucedido. Esta camada pode ser destru\xedda causando pelo menos 25 de dano de fogo a ela.Indigo Em um teste de resist\xeancia falho, a criatura fica imobilizada. Deve ent\xe3o fazer um Teste de resist\xeancia de Constitui\xe7\xe3o ao final de cada um de seus turnos. Se salvar com sucesso tr\xeas vezes, a magia termina. Se falhar tr\xeas vezes no salvamento, ele se transforma permanentemente em pedra e fica sujeito \xe0 condi\xe7\xe3o petrificado. Os sucessos e fracassos n\xe3o precisam ser consecutivos; acompanhe ambos at\xe9 que a criatura colete tr\xeas do mesmo tipo. Enquanto esta camada estiver no lugar, os feiti\xe7os n\xe3o podem ser lan\xe7ados atrav\xe9s da parede. A camada \xe9 destru\xedda pela luz brilhante emitida por um feiti\xe7o luz do dia ou um feiti\xe7o similar de n\xedvel igual ou superior. Violeta Em um teste de resist\xeancia falho, a criatura \xe9 cega. Ele dever\xe1 ent\xe3o fazer um Teste de resist\xeancia de Sabedoria no in\xedcio do seu pr\xf3ximo turno. Uma defesa bem-sucedida acaba com a cegueira. Se falhar no teste, a criatura \xe9 transportada para outro plano \xe0 escolha do Mestre e n\xe3o fica mais cega. (Normalmente, uma criatura que est\xe1 em um plano que n\xe3o \xe9 seu plano natal \xe9 banida para casa, enquanto outras criaturas s\xe3o geralmente lan\xe7adas nos planos Astral ou Et\xe9reo.) Esta camada \xe9 destru\xedda por um feiti\xe7o dissipar magia ou um feiti\xe7o similar de n\xedvel igual ou superior que pode encerrar feiti\xe7os e efeitos m\xe1gicos."},{name:"Metamorfose",level:9,classes:["Druida","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea assume a forma de uma criatura diferente durante o jogo. A nova forma pode ser de qualquer criatura com n\xedvel de desafio igual ao seu n\xedvel ou inferior. A criatura n\xe3o pode ser um constructo ou um morto-vivo, e voc\xea deve ter visto esse tipo de criatura pelo menos uma vez. Voc\xea se transforma em um exemplo comum dessa criatura, sem nenhum n\xedvel de classe ou a caracter\xedstica Conjura\xe7\xe3o. \n\n Suas estat\xedsticas de jogo s\xe3o substitu\xeddas pelas estat\xedsticas da criatura escolhida, embora voc\xea mantenha sua tend\xeancia e valores de Intelig\xeancia, Sabedoria e Carisma. Voc\xea tamb\xe9m mant\xe9m todas as suas habilidades e profici\xeancias em teste de resist\xeancia, al\xe9m de ganhar as da criatura. Se a criatura tiver a mesma profici\xeancia que voc\xea e o b\xf4nus listado em suas estat\xedsticas for maior que o seu, use o b\xf4nus da criatura no lugar do seu. Voc\xea n\xe3o pode usar nenhuma a\xe7\xe3o lend\xe1ria ou a\xe7\xe3o covil da nova forma. \n\n Voc\xea assume os pontos de vida e Sucesso Dice da nova forma. Ao voltar \xe0 sua forma normal, voc\xea retorna ao n\xfamero de pontos de vida que tinha antes de se transformar. Se voc\xea reverter como resultado de cair para 0 pontos de vida, qualquer dano excessivo ser\xe1 transferido para sua forma normal. Contanto que o dano excessivo n\xe3o reduza sua forma normal a 0 pontos de vida, voc\xea n\xe3o ser\xe1 nocauteado inconsciente. \n\n Voc\xea ret\xe9m o benef\xedcio de quaisquer recursos de sua classe, ra\xe7a ou outra fonte e pode us\xe1-los, desde que sua nova forma seja fisicamente capaz de faz\xea-lo. Voc\xea n\xe3o pode usar nenhum sentido especial que possua (por exemplo, vis\xe3o no escuro), a menos que sua nova forma tamb\xe9m tenha esse sentido. Voc\xea s\xf3 pode falar se a criatura puder falar normalmente. \n\n Ao se transformar, voc\xea escolhe se seu equipamento cair\xe1 na solo, se fundir\xe1 na nova forma ou ser\xe1 usado por ela. Equipamentos gastos funcionam normalmente. O Mestre determina se \xe9 pr\xe1tico para a nova forma usar um equipamento, baseado na forma e tamanho da criatura. Seu equipamento n\xe3o muda de forma ou tamanho para combinar com a nova forma, e qualquer equipamento que a nova forma n\xe3o possa usar deve cair na solo ou se fundir em sua nova forma. Equipamentos que se fundem n\xe3o t\xeam efeito nesse estado. \n\n Durante a dura\xe7\xe3o desta magia, voc\xea pode usar sua a\xe7\xe3o para assumir uma forma diferente seguindo as mesmas restri\xe7\xf5es e regras da forma original, com uma exce\xe7\xe3o: se sua nova forma tiver mais pontos de vida que a atual, seus pontos de vida permanecer\xe3o com o valor atual."},{name:"Tempestade de Vingan\xe7a",level:9,classes:["Druida"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Sight",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Uma nuvem de tempestade agitada se forma, centrada em um ponto que voc\xea possa ver e se espalhando por um raio de 318 metros. Rel\xe2mpagos brilham na \xe1rea, trov\xf5es estrondosos e ventos fortes rugem. Cada criatura sob a nuvem (n\xe3o mais que 5.000 p\xe9s abaixo da nuvem) quando aparecer dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, uma criatura sofre 2d6 de dano s\xf4nico e fica ensurdecida por 5 minutos. \n\n A cada rodada que voc\xea mant\xe9m concentra\xe7\xe3o neste feiti\xe7o, a tempestade produz efeitos diferentes no seu turno. \n\nRodada 2: Chuva \xe1cida cai da nuvem. Cada criatura e objeto sob a nuvem sofre 1d6 dano de \xe1cido. \n\nRodada 3: Voc\xea invoca seis raios da nuvem para atingir seis criaturas ou objetos de sua escolha sob a nuvem. Uma determinada criatura ou objeto n\xe3o pode ser atingido por mais de um raio. Uma criatura atingida deve fazer um Teste de resist\xeancia de Destreza. A criatura sofre 10d6 dano de raio em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso. \n\nRodada 4: Chuvas de granizo caem da nuvem. Cada criatura sob a nuvem sofre 2d6 de dano de concuss\xe3o. \n\nRodada 5\u201310: Rajadas e chuva congelante assolam a \xe1rea sob a nuvem. A \xe1rea se torna um terreno dif\xedcil e est\xe1 fortemente obscurecida. Cada criatura sofre 1d6 dano de frio. Ataque \xe0 dist\xe2ncia com armas na \xe1rea \xe9 imposs\xedvel. O vento e a chuva contam como uma distra\xe7\xe3o severa para fins de manuten\xe7\xe3o da concentra\xe7\xe3o nos per\xedodos. Finalmente, rajadas de vento forte (variando de 32 a 80 quil\xf4metros por hora) dispersam automaticamente neblina, neblina e fen\xf4menos similares na \xe1rea, sejam eles mundanos ou m\xe1gicos."},{name:"Telepatia",level:8,classes:["Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Unlimited",duration:"24 horas",description:"Voc\xea cria uma liga\xe7\xe3o telep\xe1tica entre voc\xea e uma criatura volunt\xe1ria com a qual voc\xea est\xe1 familiarizado. A criatura pode estar em qualquer lugar do mesmo plano de exist\xeancia que voc\xea. A magia termina se voc\xea ou o alvo n\xe3o estiverem mais no mesmo plano.\n\nAt\xe9 a magia terminar, voc\xea e o alvo podem compartilhar instantaneamente palavras, imagens, sons e outras mensagens sensoriais atrav\xe9s do link, e o alvo reconhece voc\xea como a criatura com quem est\xe1 se comunicando. A magia permite que uma criatura com um valor de Intelig\xeancia de pelo menos 1 entenda o significado de suas palavras e capte o alcance de quaisquer mensagens sensoriais que voc\xea enviar a ela."},{name:"Explos\xe3o Solar",level:8,classes:["Druida","Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Instant\xe2neo",description:"A luz solar brilhante brilha em um raio de 18 metros centrado em um ponto que voc\xea escolher dentro do alcance. Cada criatura sob esse prisma deve fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, a criatura sofre 12d6 de dano radiante e fica cega por 1 minuto. Em um teste de resist\xeancia bem-sucedido, ele leva metade do dano e n\xe3o fica cego por esse feiti\xe7o. Mortos-vivos e gosmas t\xeam desvantagem nesse teste de resist\xeancia.\n\nUma criatura cega por este feiti\xe7o faz outro Teste de resist\xeancia de Constitui\xe7\xe3o ao final de cada um de seus turnos. Em um teste de resist\xeancia bem sucedido, n\xe3o \xe9 mais cego.\n\nEste feiti\xe7o dissipa qualquer escurid\xe3o em sua \xe1rea que tenha sido criada por um feiti\xe7o."},{name:"Parar o Tempo",level:9,classes:["Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Instant\xe2neo",description:"Voc\xea interrompe brevemente o fluxo do tempo para todos, menos para voc\xea. Nenhum tempo passa para outras criaturas, enquanto voc\xea realiza 1d4 + 1 turnos consecutivos, durante os quais voc\xea pode usar a\xe7\xf5es e se mover normalmente.\n\nEsta magia termina se uma das a\xe7\xf5es que voc\xea usa durante este per\xedodo, ou qualquer efeito que Voc\xea cria durante este per\xedodo, afetar uma criatura que n\xe3o seja voc\xea ou um objeto sendo usado ou carregado por algu\xe9m que n\xe3o seja voc\xea. Al\xe9m disso, a magia termina se voc\xea se mover para um local a mais de 300 metros do local onde voc\xea a lan\xe7ou."},{name:"Polimorfismo Verdadeiro",level:9,classes:["Bardo","Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Escolha uma criatura ou objeto n\xe3o m\xe1gico que voc\xea possa ver dentro do alcance. Voc\xea transforma a criatura em uma criatura diferente, a criatura em um objeto n\xe3o m\xe1gico ou o objeto em uma criatura (o objeto n\xe3o deve ser usado nem carregado por outra criatura). A magia dura pela dura\xe7\xe3o, ou at\xe9 que o alvo caia para 0 pontos de vida ou morra. Se voc\xea se concentrar neste feiti\xe7o por toda a dura\xe7\xe3o, o feiti\xe7o durar\xe1 at\xe9 ser dissipado. \n\n Este feiti\xe7o n\xe3o tem efeito em um metamorfo ou criatura com 0 pontos de vida. Uma incriatura volunt\xe1ria pode fazer um Teste de resist\xeancia de Sabedoria, e se tiver sucesso, n\xe3o \xe9 afetado por este feiti\xe7o. \n\nCriatura em Criatura: Se voc\xea transformar uma criatura em outro tipo de criatura, a nova forma pode ser qualquer tipo que voc\xea escolher cujo n\xedvel de desafio seja igual ou menor que o do alvo (ou seu n\xedvel, se o alvo n\xe3o tiver um n\xedvel de desafio). As estat\xedsticas de jogo do alvo, incluindo pontua\xe7\xf5es de habilidade mental, s\xe3o substitu\xeddas pelas estat\xedsticas da nova forma. Ele mant\xe9m seu alinhamento e personalidade. \n\n O alvo assume os pontos de vida de sua nova forma, e quando volta \xe0 sua forma normal, a criatura retorna ao n\xfamero de pontos de vida que tinha antes de se transformar. Se reverter como resultado de cair para 0 pontos de vida, qualquer dano excessivo ser\xe1 transferido para sua forma normal. Contanto que o dano excessivo n\xe3o reduza a forma normal da criatura a 0 pontos de vida, ela n\xe3o ser\xe1 derrubada inconsciente. \n\n A criatura \xe9 limitada nas a\xe7\xf5es que pode realizar pela natureza de sua nova forma e n\xe3o pode falar, lan\xe7ar feiti\xe7os ou executar qualquer outra a\xe7\xe3o que exija m\xe3os ou fala, a menos que sua nova forma seja capaz de tais a\xe7\xf5es. \n\n O equipamento do alvo se funde na nova forma. A criatura n\xe3o pode ativar, usar, empunhar ou de qualquer outra forma se beneficiar de qualquer um de seus equipamentos. \n\nObjeto em Criatura: Voc\xea pode transformar um objeto em qualquer tipo de criatura, desde que o tamanho da criatura n\xe3o seja maior que o tamanho do objeto e o n\xedvel de desafio da criatura seja 9 ou inferior. A criatura \xe9 amig\xe1vel com voc\xea e seus companheiros. Ele atua em cada um dos seus turnos. Voc\xea decide qual a\xe7\xe3o ser\xe1 necess\xe1ria e como ela se move. O Mestre possui as estat\xedsticas da criatura e resolve todas as suas a\xe7\xf5es e movimentos. \n\n Se a magia se tornar permanente, voc\xea n\xe3o controlar\xe1 mais a criatura. Pode permanecer amig\xe1vel com voc\xea, dependendo de como voc\xea o tratou. \n\nCria\xe7\xe3o em Objeto: Se voc\xea transformar uma criatura em um objeto, ela se transforma junto com tudo o que estiver vestindo e carregando naquela forma, desde que o tamanho do objeto n\xe3o seja maior que o tamanho da criatura. As estat\xedsticas da criatura tornam-se as do objeto, e a criatura n\xe3o tem mem\xf3ria do tempo passado nesta forma, depois que a magia termina e ela retorna \xe0 sua forma normal."},{name:"Tsunami",level:8,classes:["Druida"],school:"Conjura\xe7\xe3o",castingTime:"1 minute",range:"Sight",duration:"Concentra\xe7\xe3o, at\xe9 6 rodadas",description:"Uma parede de \xe1gua surge em um ponto que voc\xea escolhe dentro do alcance. Voc\xea pode fazer a parede com at\xe9 90 metros de comprimento, 90 metros de altura e 15 metros de espessura. A parede dura enquanto durar.\n\nQuando a parede aparecer, cada criatura dentro de sua \xe1rea dever\xe1 fazer um Teste de resist\xeancia de For\xe7a. Em um teste de resist\xeancia falho, uma criatura sofre 6d10 dano de concuss\xe3o, ou metade do dano em um teste de resist\xeancia bem-sucedido.\n\nNo in\xedcio de cada um dos seus turnos ap\xf3s o aparecimento da parede, a parede, junto com quaisquer criaturas nela contidas, se move 15 metros para longe de voc\xea. Qualquer criatura Enorme ou menor dentro da muralha ou em cujo espa\xe7o a muralha entra quando se move deve ter sucesso em um Teste de resist\xeancia de For\xe7a ou sofrer 5d10 dano de concuss\xe3o. Uma criatura pode sofrer esse dano apenas uma vez por rodada. No final do turno, a altura da muralha \xe9 reduzida em 15 metros, e o dano que as criaturas recebem do feiti\xe7o nas rodadas subsequentes \xe9 reduzido em 1d10. Quando a parede atinge 0 metro de altura, a magia termina.\n\nUma criatura presa na parede pode se mover nadando. Por\xe9m, por causa da for\xe7a da onda, a criatura deve fazer um teste bem-sucedido de For\xe7a (Atletismo) contra seu CD de resist\xeancia de magia para poder se mover. Se falhar no teste, ele n\xe3o poder\xe1 se mover. Uma criatura que sai da \xe1rea cai nas m\xe3os da solo."},{name:"Ressurrei\xe7\xe3o Verdadeira",level:9,classes:["Cl\xe9rigo","Druida"],school:"Necromancia",castingTime:"1 hour",range:"Toque",duration:"Instant\xe2neo",description:"Voc\xea toca uma criatura que n\xe3o est\xe1 morta h\xe1 mais de 200 anos e que morreu por qualquer motivo, exceto velhice. Se a alma da criatura for livre e volunt\xe1ria, a criatura ser\xe1 restaurada \xe0 vida com todos os seus pontos de vida.\n\nEste feiti\xe7o fecha todas as feridas, neutraliza qualquer veneno, cura todas as doen\xe7as e elimina qualquer maldi\xe7\xe3o que afetasse a criatura quando ela morresse. O feiti\xe7o substitui \xf3rg\xe3os e membros danificados ou com defeito.\n\nO feiti\xe7o pode at\xe9 fornecer um novo corpo se o original n\xe3o existir mais, caso em que voc\xea dever\xe1 falar o nome da criatura. A criatura ent\xe3o aparece em um espa\xe7o desocupado \xe0 sua escolha a at\xe9 3 metros de voc\xea."},{name:"Pesadelo",level:9,classes:["Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Baseando-se nos medos mais profundos de um grupo de criaturas, Voc\xea cria criaturas ilus\xf3rias em suas mentes, vis\xedveis apenas para elas. Cada criatura em uma esfera de 9 metros de raio centrada em um ponto de sua escolha dentro do alcance deve fazer um Teste de resist\xeancia de Sabedoria. Em um teste de resist\xeancia falho, uma criatura fica amedrontada durante todo o tempo. A ilus\xe3o invoca os medos mais profundos da criatura, manifestando os seus piores pesadelos como uma amea\xe7a implac\xe1vel. No in\xedcio de cada turno da criatura amedrontada, ela deve ter sucesso em um Teste de resist\xeancia de Sabedoria ou sofrer 4d10 de dano ps\xedquico. Em um teste de resist\xeancia bem-sucedido, a magia termina para aquela criatura."},{name:"Desejo",level:9,classes:["Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Instant\xe2neo",description:"Desejo \xe9 o feiti\xe7o mais poderoso que uma criatura mortal pode lan\xe7ar. Simplesmente falando em voz alta, voc\xea pode alterar os pr\xf3prios fundamentos da realidade de acordo com seus desejos.\n\nO uso b\xe1sico desta magia \xe9 duplicar qualquer outra magia de 8\xba n\xedvel ou inferior. Voc\xea n\xe3o precisa atender a nenhum requisito desse feiti\xe7o, incluindo componentes caros. O feiti\xe7o simplesmente entra em vigor. Voc\xea cria um objeto de valor de at\xe9 25.000 po que n\xe3o seja um item m\xe1gico. O objeto n\xe3o pode ter mais de 300 p\xe9s em qualquer dimens\xe3o e aparece em um espa\xe7o desocupado que voc\xea possa ver na solo. Voc\xea permite que at\xe9 vinte criaturas que voc\xea possa ver recuperem todos os pontos de vida e encerre todos os efeitos sobre elas descritos no feiti\xe7o de restaura\xe7\xe3o maior. Voc\xea concede at\xe9 dez criaturas que voc\xea possa ver resist\xeancia a um tipo de dano que voc\xea escolher. Por exemplo, voc\xea pode tornar voc\xea e todos os seus companheiros imunes ao ataque de drenagem de vida de um lich. Voc\xea desfaz um \xfanico evento recente for\xe7ando uma nova rolagem de qualquer rolagem feita na \xfaltima rodada (incluindo seu \xfaltimo turno). A realidade se remodela para acomodar o novo resultado. Por exemplo, um feiti\xe7o de desejo pode desfazer um salvamento bem-sucedido de um oponente, um sucesso cr\xedtico de um inimigo ou um salvamento fracassado de um amigo. Voc\xea pode for\xe7ar que a rerrolagem seja feita com vantagem ou desvantagem, podendo escolher entre usar a rerrolagem ou a rolagem original. Voc\xea pode conseguir algo al\xe9m do escopo dos exemplos acima. Declare seu desejo ao Mestre com a maior precis\xe3o poss\xedvel. O Mestre tem grande liberdade para decidir o que ocorre em tal caso; quanto maior o desejo, maior a probabilidade de algo dar errado. Este feiti\xe7o pode simplesmente falhar, o efeito que voc\xea deseja pode ser alcan\xe7ado apenas parcialmente ou voc\xea pode sofrer alguma consequ\xeancia imprevista como resultado de como formulou o desejo. Por exemplo, desejar que um vil\xe3o estivesse morto pode impulsion\xe1-lo para um per\xedodo em que esse vil\xe3o n\xe3o esteja mais vivo, removendo-o efetivamente do jogo. Da mesma forma, desejar um item m\xe1gico ou artefato lend\xe1rio pode transport\xe1-lo instantaneamente para a presen\xe7a do atual propriet\xe1rio do item.\n\nO estresse de lan\xe7ar esta magia para produzir qualquer efeito que n\xe3o seja duplicar outra magia enfraquece voc\xea. Depois de suportar esse estresse, cada vez que voc\xea conjurar uma magia at\xe9 terminar um descanso longo, voc\xea sofre 1d10 de dano necr\xf3tico por n\xedvel daquela magia. Este dano n\xe3o pode ser reduzido ou evitado de forma alguma. Al\xe9m disso, sua For\xe7a cai para 3, se ainda n\xe3o for 3 ou menos, por 2d4 dias. Para cada um dos dias que voc\xea passa descansando e n\xe3o fazendo nada al\xe9m de atividades leves, o tempo restante de recupera\xe7\xe3o diminui em 2 dias. Finalmente, h\xe1 33% de chance de voc\xea nunca mais conseguir realizar o desejo se sofrer esse estresse."},{name:"Convocar Celestial",level:7,classes:["Cl\xe9rigo"],school:"Conjura\xe7\xe3o",castingTime:"1 minute",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea convoca um celestial com classifica\xe7\xe3o de desafio 4 ou inferior, que aparece em um espa\xe7o desocupado que voc\xea pode ver dentro do alcance. O celestial desaparece quando cai para 0 pontos de vida ou quando a magia termina.\n\nO Celestial \xe9 amig\xe1vel com voc\xea e seus companheiros durante todo o tempo. Role a iniciativa para o celestial, que tem seus pr\xf3prios turnos. Ele obedece a quaisquer comandos verbais que voc\xea emitir (nenhuma a\xe7\xe3o exigida por voc\xea), desde que eles n\xe3o violem seu alinhamento. Se voc\xea n\xe3o der nenhum comando ao celestial, ele se defender\xe1 de criaturas hostis, mas de outra forma n\xe3o tomar\xe1 nenhuma atitude.\n\nO Mestre tem as estat\xedsticas do celestial."},{name:"Bola de Fogo de Explos\xe3o Retardada",level:7,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Um feixe de luz amarela pisca do dedo que aponta e depois se condensa para permanecer em um ponto escolhido dentro do alcance como uma conta brilhante durante todo o tempo. Quando a magia termina, seja porque sua concentra\xe7\xe3o foi quebrada ou porque voc\xea decidiu encerr\xe1-la, a conta floresce com um rugido baixo em uma explos\xe3o de chama que espalha cantos ao redorda. Cada criatura em uma esfera de 6 metros de raio centrada nesse ponto deve fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre dano de fogo igual ao dano total acumulado em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso.\n\nO dano base do feiti\xe7o \xe9 12d6. Se no final do seu turno a conta ainda n\xe3o tiver detonado, o dano aumenta em 1d6.\n\nSe a conta brilhante for tocada antes do intervalo expirar, a criatura que a tocar dever\xe1 fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, a magia termina imediatamente, fazendo a conta explodir em chamas. Em um teste de resist\xeancia bem-sucedido, a criatura pode lan\xe7ar a conta a at\xe9 12 metros de altura. Quando atinge uma criatura ou objeto s\xf3lido, a magia termina e a conta explode.\n\nO dano de fogo dispara objetos na \xe1rea e incendeia objetos inflam\xe1veis \u200b\u200bque n\xe3o est\xe3o sendo usados \u200b\u200bou carregados."},{name:"Porta Dimensional",level:4,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"150 metros",duration:"Instant\xe2neo",description:"Voc\xea se teletransporta de sua localiza\xe7\xe3o atual para qualquer outro local dentro do alcance. Voc\xea chega exatamente ao local desejado. Pode ser um lugar que voc\xea possa ver, que voc\xea possa visualizar ou que voc\xea possa descrever declarando a dist\xe2ncia e a dire\xe7\xe3o, como 200 p\xe9s em linha reta para baixo ou para cima em dire\xe7\xe3o noroeste em um \xe2ngulo de 45 graus, 300 p\xe9s.\n\nVoc\xea pode trazer objetos desde que o peso deles n\xe3o exceda o que voc\xea pode carregar. Voc\xea tamb\xe9m pode trazer uma criatura volunt\xe1ria do seu tamanho ou menor que carregue equipamentos at\xe9 sua capacidade de carga. A criatura deve estar a at\xe9 1,5 metro de voc\xea quando voc\xea conjura essa magia.\n\nSe voc\xea chegar em um local j\xe1 ocupado por um objeto ou criatura, voc\xea e qualquer criatura viajando com voc\xea sofrer\xe3o 4d6 de dano de for\xe7a cada, e a magia n\xe3o conseguir\xe1 teletransport\xe1-lo."},{name:"Palavra Divina",level:7,classes:["Cl\xe9rigo"],school:"Evoca\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"9 metros",duration:"Instant\xe2neo",description:"Voc\xea pronuncia uma palavra divina, imbu\xedda do poder que moldou o mundo no in\xedcio da cria\xe7\xe3o. Escolha qualquer n\xfamero de criaturas que voc\xea possa ver dentro do alcance. Cada criatura que puder te ouvir dever\xe1 fazer um Teste de resist\xeancia de Carisma. Em um teste de resist\xeancia falho, uma criatura sofre um efeito com base em seus pontos de vida atuais: 50 pontos de vida ou menos: ensurdecido por 1 minuto40 pontos de vida ou menos: ensurdecido e cego por 10 minutos30 pontos de vida ou menos: cego, ensurdecido e atordoado por 1 hora20 pontos de vida ou menos: morto instantaneamente Independentemente de seus pontos de vida atuais, um celestial, um elemental, um fe\xe9rico ou um inimigo que falhar em seu salvamento \xe9 for\xe7ado a voltar ao seu plano de origem (se ainda n\xe3o estiver l\xe1) e n\xe3o pode retornar ao seu plano atual por 24 horas por qualquer meio que n\xe3o seja um feiti\xe7o de desejo."},{name:"Etereidade",level:7,classes:["Bardo","Cl\xe9rigo","Feiticeiro","Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"At\xe9 8 horas",description:"Voc\xea entra nas regi\xf5es fronteiri\xe7as do Plano Et\xe9reo, na \xe1rea onde ele se sobrep\xf5e ao seu plano atual. Voc\xea permanece na Fronteira Et\xe9rea enquanto durar ou at\xe9 usar sua a\xe7\xe3o para dissipar o feiti\xe7o. Durante esse tempo, voc\xea pode se mover em qualquer dire\xe7\xe3o. Se voc\xea subir ou descer, cada metro de movimento custar\xe1 um metro extra. Voc\xea pode ver e ouvir o avi\xe3o de onde veio, mas tudo l\xe1 parece cinza e voc\xea n\xe3o consegue ver nada a mais de 18 metros de dist\xe2ncia.\n\nEnquanto estiver no Plano Et\xe9reo, voc\xea s\xf3 pode afetar e ser afetado por outras criaturas daquele plano. Criaturas que n\xe3o est\xe3o no Plano Et\xe9reo n\xe3o podem perceber voc\xea e n\xe3o podem interagir com voc\xea, a menos que uma habilidade especial ou magia lhes d\xea a habilidade para fazer isso.\n\nVoc\xea ignora todos os objetos e efeitos que n\xe3o est\xe3o no Plano Et\xe9reo, permitindo que voc\xea se mova atrav\xe9s de objetos que voc\xea percebe no plano de origem.\n\nQuando a magia termina, voc\xea retorna imediatamente ao plano de origem no local que ocupa atualmente.  Se voc\xea ocupar o mesmo lugar que um objeto s\xf3lido ou criatura quando isso acontecer, voc\xea ser\xe1 imediatamente desviado para o espa\xe7o desocupado mais pr\xf3ximo que voc\xea possa ocupar e sofrer\xe1 dano de for\xe7a igual ao dobro do n\xfamero de p\xe9s que voc\xea moveu.\n\nEste feiti\xe7o n\xe3o tem efeito se voc\xea o conjurar enquanto estiver no Plano Et\xe9reo ou em um plano que n\xe3o o fa\xe7a fronteira, como um dos Planos Exteriores."},{name:"Dedo da Morte",level:7,classes:["Feiticeiro","Bruxo","Mago"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea envia energia negativa percorrendo uma criatura que voc\xea pode ver dentro do alcance, causando-lhe uma dor lancinante. O alvo dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. S\xe3o necess\xe1rios 7d8 + 30 de dano necr\xf3tico em um teste de resist\xeancia falho, ou metade do dano em um teste bem-sucedido.\n\nUm human\xf3ide morto por esta magia surge no in\xedcio do seu pr\xf3ximo turno como um zumbi que est\xe1 permanentemente sob seu comando, seguindo suas ordens verbais da melhor maneira poss\xedvel."},{name:"Tempestade de Fogo",level:7,classes:["Cl\xe9rigo","Druida","Feiticeiro"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Instant\xe2neo",description:"Uma tempestade composta por camadas de chamas crepitantes aparece em um local escolhido dentro do alcance. A \xe1rea da tempestade consiste em at\xe9 dez cubos de 3 metros, que voc\xea pode organizar como desejar. Cada cubo deve ter pelo menos uma face adjacente \xe0 face de outro cubo. Cada criatura da \xe1rea dever\xe1 fazer um Teste de resist\xeancia de Destreza. S\xe3o necess\xe1rios 7d10 dano de fogo em um teste de resist\xeancia falho, ou metade do dano em um teste bem sucedido.\n\nO dano de fogo incendeia objetos na \xe1rea e incendeia objetos inflam\xe1veis \u200b\u200bque n\xe3o est\xe3o sendo usados \u200b\u200bou carregados. Se voc\xea escolher, a vida das plantas na \xe1rea n\xe3o ser\xe1 afetada por esta magia."},{name:"Gaiola de For\xe7a",level:7,classes:["Bardo","Bruxo","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"30 metros",duration:"1 hora",description:"Uma pris\xe3o im\xf3vel, invis\xedvel e em forma de cubo composta de for\xe7a m\xe1gica surge em uma \xe1rea que voc\xea escolhe dentro do alcance. A pris\xe3o pode ser uma jaula ou uma caixa s\xf3lida, conforme voc\xea escolher.\n\nUma pris\xe3o em forma de gaiola pode ter at\xe9 6 metros de lado e \xe9 feita de barras de 1/2 polegada de di\xe2metro espa\xe7adas de 1/2 polegada.\n\nUma pris\xe3o em forma de caixa pode ter at\xe9 3 metros de tamanho, criando uma barreira s\xf3lida que impede qualquer mat\xe9ria de passar por ela e bloqueia quaisquer feiti\xe7os lan\xe7ados dentro ou fora da \xe1rea.\n\nQuando voc\xea conjura uma magia, qualquer criatura que esteja completamente dentro da \xe1rea da jaula fica presa. Criaturas apenas parcialmente dentro da \xe1rea, ou aquelas grandes demais para caber dentro da \xe1rea, s\xe3o empurradas para longe do centro da \xe1rea at\xe9 ficarem completamente fora da \xe1rea.\n\nUma criatura dentro da jaula n\xe3o pode sair dela por meios n\xe3o m\xe1gicos. Se a criatura tentar usar teletransporte ou viagem interplanar para sair da jaula, ela dever\xe1 primeiro fazer um Teste de resist\xeancia de Carisma. Se obtiver sucesso, a criatura pode usar essa magia para sair da jaula. Em caso de falha, a criatura n\xe3o consegue sair da jaula e desperdi\xe7a o uso da magia ou efeito. A jaula tamb\xe9m se estende at\xe9 o Plano Et\xe9reo, bloqueando a viagem et\xe9rea.\n\nEste feiti\xe7o n\xe3o pode ser dissipado por dissipar magia."},{name:"Miragem Arcana",level:7,classes:["Bardo","Druida","Mago"],school:"Ilus\xe3o",castingTime:"10 minutes",range:"Sight",duration:"10 dias",description:"Voc\xea faz com que um terreno em uma \xe1rea de at\xe9 1,5 milha quadrada tenha apar\xeancia, som, cheiro e at\xe9 mesmo pare\xe7a algum outro tipo de terreno. A forma geral do terreno permanece a mesma, entretanto. Campos abertos ou estradas podem ser transformados em p\xe2ntanos, colinas, fendas ou outros terrenos dif\xedceis ou intransit\xe1veis. Um lago pode parecer um prado gramado, um precip\xedcio como uma encosta, ou um barranco coberto de pedras como uma estrada larga e lisa.\n\nDa mesma forma, voc\xea pode alterar a apar\xeancia das estruturas e adicion\xe1-las onde n\xe3o houver nenhuma. O feiti\xe7o n\xe3o disfar\xe7a, oculta ou acrescenta criaturas.\n\nA ilus\xe3o inclui elementos sonoros, visuais, t\xe1teis e olfativos, de modo que pode transformar uma solo clara em terreno dif\xedcil (ou vice-versa) ou impedir o movimento pela \xe1rea. Qualquer peda\xe7o do terreno ilus\xf3rio (como uma pedra ou um peda\xe7o de pau) removido da \xe1rea da magia desaparece imediatamente.\n\nCriaturas com vis\xe3o verdadeira podem ver atrav\xe9s da ilus\xe3o a verdadeira forma do terreno; entretanto, todos os outros elementos da ilus\xe3o permanecem, portanto, embora a criatura esteja ciente da presen\ufffd\ufffda da ilus\xe3o, a criatura ainda pode interagir fisicamente com a ilus\xe3o."},{name:"Aspers\xe3o Prism\xe1tica",level:7,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (60-foot cone)",duration:"Instant\xe2neo",description:"Oito raios de luz multicoloridos brilham em sua m\xe3o. Cada raio tem uma cor diferente e tem um poder e prop\xf3sito diferentes. Cada criatura num cone de 18 metros dever\xe1 fazer um Teste de resist\xeancia de Destreza. Para cada alvo, jogue um d8 para determinar qual raio colorido o afeta. Vermelho: O alvo sofre 10d6 de dano de fogo em um teste de resist\xeancia falho, ou metade do dano em um teste bem-sucedido. Laranja: O alvo sofre 10d6 dano de \xe1cido em um teste de resist\xeancia falho, ou metade do dano em um teste de resist\xeancia falho, ou metade do dano em um teste de resist\xeancia falho, ou metade do dano em um teste de resist\xeancia falho, ou metade do dano em um teste de resist\xeancia falho, ou metade do dano em um teste de resist\xeancia falho, ou metade do dano em um teste de resist\xeancia falho, ou metade do dano em um teste de resist\xeancia falho, ou metade do dano. em um sucesso.Indigo: Em um teste de resist\xeancia falho, o alvo fica imobilizado. Deve ent\xe3o fazer um Teste de resist\xeancia de Constitui\xe7\xe3o ao final de cada um de seus turnos. Se salvar com sucesso tr\xeas vezes, a magia termina. Se falhar tr\xeas vezes no salvamento, ele se transforma permanentemente em pedra e fica sujeito \xe0 condi\xe7\xe3o petrificado. Os sucessos e fracassos n\xe3o precisam ser consecutivos; acompanhe ambos at\xe9 que o alvo colete uma trinca. Violeta: Em um teste de resist\xeancia falho, o alvo \xe9 cego. Ele dever\xe1 ent\xe3o fazer um Teste de resist\xeancia de Sabedoria no in\xedcio do seu pr\xf3ximo turno. Uma defesa bem-sucedida acaba com a cegueira. Se falhar no teste, a criatura \xe9 transportada para outro plano de exist\xeancia \xe0 escolha do Mestre e n\xe3o fica mais cega. (Normalmente, uma criatura que est\xe1 em um plano que n\xe3o \xe9 seu plano natal \xe9 banida para casa, enquanto outras criaturas s\xe3o geralmente lan\xe7adas nos planos Astral ou Et\xe9reo.) Especial: O alvo \xe9 atingido por dois raios. Role mais duas vezes, rolando novamente qualquer 8."},{name:"Projetar Imagem",level:7,classes:["Bardo","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"500 miles",duration:"Concentra\xe7\xe3o, at\xe9 1 dia",description:"Voc\xea cria uma c\xf3pia ilus\xf3ria de si mesmo que dura o tempo todo. A c\xf3pia pode aparecer em qualquer local dentro do alcance que voc\xea j\xe1 tenha visto, independentemente dos obst\xe1culos intervenientes. A ilus\xe3o parece e soa como voc\xea, mas \xe9 intang\xedvel. Se a ilus\xe3o sofrer algum dano, ela desaparece e a magia termina.\n\nVoc\xea pode usar sua a\xe7\xe3o para mover essa ilus\xe3o at\xe9 o dobro da sua velocidade e faz\xea-la gesticular, falar e se comportar da maneira que voc\xea escolher. Ele imita seus maneirismos perfeitamente.\n\nQue voc\xea possa ver atrav\xe9s de seus olhos e ouvir atrav\xe9s de seus ouvidos como se estivesse em seu espa\xe7o. No seu turno, como b\xf4nus de a\xe7\xe3o, voc\xea pode passar do uso dos sentidos para o uso dos seus pr\xf3prios sentidos ou vice-versa. Enquanto voc\xea usa seus sentidos, voc\xea fica cego e ensurdecido em rela\xe7\xe3o aos seus pr\xf3prios arredores.\n\nA intera\xe7\xe3o f\xedsica com a imagem revela que ela \xe9 uma ilus\xe3o, pois coisas podem passar por ela. Uma criatura que use sua a\xe7\xe3o para examinar a imagem pode determinar que se trata de uma ilus\xe3o com um teste bem-sucedido de Intelig\xeancia (Investiga\xe7\xe3o) contra seu CD de resist\xeancia de magia. Se uma criatura discernir a ilus\xe3o pelo que ela \xe9, a criatura poder\xe1 ver atrav\xe9s da imagem, e qualquer ru\xeddo que ela fizer soar\xe1 vazio para a criatura."},{name:"Mudan\xe7a Planar",level:7,classes:["Cl\xe9rigo","Druida","Feiticeiro","Bruxo","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"Voc\xea e at\xe9 oito criaturas volunt\xe1rias que d\xe3o as m\xe3os em um c\xedrculo s\xe3o transportados para um plano de exist\xeancia diferente. Voc\xea pode especificar um destino alvo em termos gerais, como a Cidade de Bronze no Plano Elemental do Fogo ou o pal\xe1cio de Dispater no segundo n\xedvel dos Nove Infernos, e voc\xea aparece nesse destino ou pr\xf3ximo a ele. Se voc\xea est\xe1 tentando chegar \xe0 Cidade de Bronze, por exemplo, voc\xea pode chegar pela Rua de A\xe7o, antes do Port\xe3o das Cinzas, ou olhar a cidade do outro lado do Mar de Fogo, a crit\xe9rio do Mestre.\n\nAlternativamente, se voc\xea conhece a sequ\xeancia de sigilos de um c\xedrculo de teletransporte em outro plano de exist\xeancia, esta magia pode lev\xe1-lo a esse c\xedrculo. Se o c\xedrculo de teletransporte for muito pequeno para conter todas as criaturas que voc\xea transportou, elas aparecer\xe3o nos espa\xe7os desocupados mais pr\xf3ximos do c\xedrculo.\n\nVoc\xea pode usar este feiti\xe7o para banir uma incriatura volunt\xe1ria para outro plano.  Escolha uma criatura ao seu alcance e fa\xe7a um ataque de magia corpo a corpo contra ela. Sem sucesso, a criatura dever\xe1 fazer um Teste de resist\xeancia de Carisma. Se a criatura falhar neste teste, ela ser\xe1 transportada para um local aleat\xf3rio no plano de exist\xeancia que voc\xea especificar. Uma criatura assim transportada deve encontrar seu pr\xf3prio caminho de volta ao seu atual plano de exist\xeancia."},{name:"Regenerar",level:7,classes:["Bardo","Cl\xe9rigo","Druida"],school:"Transmuta\xe7\xe3o",castingTime:"1 minute",range:"Toque",duration:"1 hora",description:"Voc\xea toca uma criatura e estimula sua capacidade natural de cura. O alvo recupera 4d8 + 15 pontos de vida. Durante a magia, o alvo recupera 1 ponto de vida no in\xedcio de cada um de seus turnos (10 pontos de vida a cada minuto).\n\nOs membros decepados do corpo do alvo (dedos, pernas, cauda e assim por diante), se houver, s\xe3o restaurados ap\xf3s 2 minutos. Se voc\xea tiver a parte cortada e segur\xe1-la contra o coto, o feiti\xe7o faz com que o membro se junte instantaneamente ao coto."},{name:"Ressurrei\xe7\xe3o",level:7,classes:["Bardo","Cl\xe9rigo","Druida"],school:"Necromancia",castingTime:"1 hour",range:"Toque",duration:"Instant\xe2neo",description:"Voc\xea toca uma criatura morta que n\xe3o morreu h\xe1 mais de um s\xe9culo, que n\xe3o morreu de velhice e que n\xe3o \xe9 morto-vivo. Se a sua alma for livre e disposta, o alvo volta \xe0 vida com todos os seus pontos de vida.\n\nEste feiti\xe7o neutraliza quaisquer venenos e cura doen\xe7as normais que afligiam a criatura quando ela morria. No entanto, n\xe3o remove doen\xe7as m\xe1gicas, maldi\xe7\xf5es e coisas do g\xeanero; se tais efeitos n\xe3o forem removidos antes de lan\xe7ar o feiti\xe7o, eles afligir\xe3o o alvo quando ele retornar \xe0 vida.\n\nEste feiti\xe7o fecha todas as feridas mortais e restaura quaisquer partes do corpo defeituosas.\n\nVoltar dos mortos \xe9 uma prova\xe7\xe3o. O alvo sofre uma penalidade de -4 em todas as jogadas de ataques, testes de resist\xeancia e testes de habilidades. Cada vez que o alvo termina um descanso longo, a penalidade \xe9 reduzida em 1 at\xe9 desaparecer.\n\nLan\xe7ar este feiti\xe7o para restaurar a vida de uma criatura que est\xe1 morta h\xe1 um ano ou mais \xe9 muito dif\xedcil para voc\xea. At\xe9 terminar um descanso longo, voc\xea n\xe3o poder\xe1 lan\xe7ar feiti\xe7os novamente e ter\xe1 manobras de ataque, teste de habilidades e testes de resist\xeancia."},{name:"Inverter a Gravidade",level:7,classes:["Druida","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"30 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Este feiti\xe7o reverte a gravidade em um cilindro de 15 metros de raio e 30 metros de altura centrado em um ponto dentro do alcance. Todas as criaturas e objetos que n\xe3o est\xe3o de alguma forma ancorados na solo da \xe1rea caem para cima e alcan\xe7am o topo da \xe1rea Quando voc\xea conjura essa magia. Uma criatura pode fazer um Teste de resist\xeancia de Destreza para agarrar-se a um objeto fixo que possa alcan\xe7ar, evitando assim a queda.\n\nSe algum objeto s\xf3lido (como um teto) for encontrado nesta queda, os objetos e criaturas em queda o atingir\xe3o exatamente como fariam durante uma queda normal. Se um objeto ou criatura chegar ao topo da \xe1rea sem atingir nada, ele permanecer\xe1 l\xe1, oscilando levemente, durante todo o tempo.\n\nAo final da dura\xe7\xe3o, os objetos e criaturas afetados caem novamente."},{name:"Sequestrar",level:7,classes:["Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"At\xe9 ser dissipada",description:"Por meio deste feiti\xe7o, uma criatura volunt\xe1ria ou um objeto pode ser escondido, protegido da detec\xe7\xe3o durante todo o tempo. Quando voc\xea conjura uma magia e toca o alvo, ele se torna invis\xedvel e n\xe3o pode ser alvo de feiti\xe7os de adivinha\xe7\xe3o ou percebido atrav\xe9s de sensores de vid\xeancia criados por feiti\xe7os de adivinha\xe7\xe3o.\n\nSe o alvo for uma criatura, ele entra em estado de anima\xe7\xe3o suspensa. O tempo deixa de fluir para ele e ele n\xe3o envelhece.\n\nVoc\xea pode definir uma condi\xe7\xe3o para que o feiti\xe7o termine mais cedo. A condi\xe7\xe3o pode ser qualquer que voc\xea escolher, mas deve ocorrer ou ser vis\xedvel dentro de 1,5 milha do alvo.  Os exemplos incluem ap\xf3s 1.000 anos ou quando o tarrasque despertar. Este feiti\xe7o tamb\xe9m termina se o alvo sofrer algum dano."},{name:"Simulacro",level:7,classes:["Mago"],school:"Ilus\xe3o",castingTime:"12 hours",range:"Toque",duration:"At\xe9 ser dissipada",description:"Voc\xea molda uma duplicata ilus\xf3ria de um besta ou humanoide que esteja dentro do alcance durante todo o tempo de lan\xe7amento da magia. A duplicata \xe9 uma criatura, parcialmente real e formada de gelo ou neve, e pode realizar a\xe7\xf5es e ser afetada como uma criatura normal. Parece igual ao original, mas tem metade do ponto de vida m\xe1ximo da criatura e \xe9 formado sem nenhum equipamento. Caso contr\xe1rio, a ilus\xe3o utiliza todas as estat\xedsticas da criatura que duplica.\n\nO simulacro \xe9 amig\xe1vel com voc\xea e com as criaturas que voc\xea designa. Ele obedece aos seus comandos falados, movendo-se e agindo de acordo com seus desejos e agindo no seu turno em combate. O simulacro n\xe3o possui a habilidade de aprender ou se tornar mais poderoso, ent\xe3o ele nunca aumenta seu n\xedvel ou outras habilidades, nem pode recuperar espa\xe7os de magia gastos.\n\nSe o simulacro estiver danificado, voc\xea pode consert\xe1-lo em um laborat\xf3rio alqu\xedmico, usando ervas e minerais raros no valor de 100gp por ponto de vida que ele recupera. O simulacro dura at\xe9 cair para 0 pontos de vida, momento em que reverte para neve e derrete instantaneamente.\n\nSe voc\xea lan\xe7ar este feiti\xe7o novamente, quaisquer duplicatas atualmente ativas que voc\xea criou com este feiti\xe7o ser\xe3o destru\xeddas instantaneamente."},{name:"S\xedmbolo",level:7,classes:["Bardo","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 minute",range:"Toque",duration:"At\xe9 ser dissipada ou acionada",description:"Quando voc\xea conjura essa magia, voc\xea inscreve um glifo prejudicial em uma superf\xedcie (como uma se\xe7\xe3o do ch\xe3o, uma parede ou uma mesa) ou dentro de um objeto que pode ser fechado para ocultar o glifo (como um livro, um pergaminho ou um ba\xfa de tesouro). Se voc\xea escolher uma superf\xedcie, o glifo poder\xe1 cobrir uma \xe1rea da superf\xedcie com no m\xe1ximo 3 metros de di\xe2metro. Se voc\xea escolher um objeto, esse objeto dever\xe1 permanecer em seu lugar; se o objeto for movido mais de 3 metros de onde voc\xea lan\xe7ou este feiti\xe7o, o glifo ser\xe1 quebrado e a magia terminar\xe1 sem ser acionada. \n\n O glifo \xe9 quase invis\xedvel, exigindo um teste de Intelig\xeancia (Investiga\xe7\xe3o) em seu CD de resist\xeancia de magia para encontr\xe1-lo. \n\n Voc\xea decide o que aciona o glifo quando voc\xea conjura uma magia. Para glifos inscritos em uma superf\xedcie, os gatilhos mais t\xedpicos incluem tocar ou pisar no glifo, remover outro objeto que o cobre, aproximar-se a uma certa dist\xe2ncia dele ou manipular o objeto que o cont\xe9m. Para glifos inscritos em um objeto, os gatilhos mais comuns s\xe3o abrir o objeto, aproximar-se a uma certa dist\xe2ncia dele ou ver ou ler o glifo. \n\n Voc\xea pode refinar ainda mais o gatilho para que o feiti\xe7o seja ativado apenas sob certas circunst\xe2ncias ou de acordo com as caracter\xedsticas f\xedsicas da criatura (como altura ou peso) ou tipo f\xedsico (por exemplo, a prote\xe7\xe3o pode ser configurada para afetar bruxas ou metamorfos). Voc\xea tamb\xe9m pode especificar criaturas que n\xe3o acionem o glifo, como aquelas que dizem uma determinada senha. \n\n Ao inscrever o glifo, escolha uma das op\xe7\xf5es abaixo para seu efeito. Uma vez acionado, o glifo brilha, preenchendo uma esfera de raio de 18 metros com luz fraca por 10 minutos, ap\xf3s o qual a magia termina. Cada criatura na esfera quando o glifo \xe9 ativado \xe9 alvo de seu efeito, assim como uma criatura que entra na esfera pela primeira vez em um turno ou termina seu turno l\xe1. \n\nMorte: Cada alvo deve fazer um Teste de resist\xeancia de Constitui\xe7\xe3o, levando 10d10 dano necr\xf3tico em um teste de resist\xeancia falho, ou metade do dano em um teste de resist\xeancia bem sucedido. \n\nDisc\xf3rdia: Cada alvo dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, um alvo briga e discute com outras criaturas por 1 minuto. Durante esse per\xedodo, ele \xe9 incapaz de comunica\xe7\xe3o significativa e tem manobras de ataque e teste de habilidades. \n\nMedo: Cada alvo deve fazer um Teste de resist\xeancia de Sabedoria e fica amedrontado por 1 minuto em um teste de resist\xeancia falho. Enquanto estiver amedrontado, o alvo larga tudo o que estiver segurando e deve se afastar pelo menos 9 metros do glifo em cada um de seus turnos, se puder. \n\nDesesperan\xe7a: Cada alvo deve fazer um Teste de resist\xeancia de Carisma. Em um teste de resist\xeancia falho, o alvo fica desesperado por 1 minuto. Durante este tempo, ele n\xe3o pode atacar ou atingir qualquer criatura com habilidades prejudiciais, feiti\xe7os ou outros efeitos m\xe1gicos. \n\nInsanidade: Cada alvo deve fazer um Teste de resist\xeancia de Intelig\xeancia. Em um teste de resist\xeancia falho, o alvo fica louco por 1 minuto. Uma criatura insana n\xe3o consegue realizar a\xe7\xf5es, n\xe3o consegue entender o que outras criaturas dizem, n\xe3o sabe ler e fala apenas coisas sem sentido. O GM controla seu movimento, que \xe9 err\xe1tico. \n\nDor: Cada alvo deve fazer um Teste de resist\xeancia de Constitui\xe7\xe3o e fica incapacitado com dor excruciante por 1 minuto em um teste de resist\xeancia de falho. \n\nSono: Cada alvo deve fazer um Teste de resist\xeancia de Sabedoria e cai inconsciente por 10 minutos em um teste de resist\xeancia falho. Uma criatura desperta se sofrer dano ou se algu\xe9m usar uma a\xe7\xe3o para sacudi-la ou esbofete\xe1-la. \n\nImpressionante: Cada alvo deve fazer um Teste de resist\xeancia de Sabedoria e fica atordoado por 1 minuto em um teste de resist\xeancia falho."},{name:"Teletransporte",level:7,classes:["Bardo","Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"3 metros",duration:"Instant\xe2neo",description:"Este feiti\xe7o transporta instantaneamente voc\xea e at\xe9 oito criaturas volunt\xe1rias de sua escolha que voc\xea possa ver dentro do alcance, ou um \xfanico objeto que voc\xea possa ver dentro do alcance, para um destino que voc\xea selecionar. Se voc\xea atingir um objeto, ele deve caber inteiramente dentro de um cubo de 3 metros, e n\xe3o pode ser segurado ou carregado por uma cria\xe7\xe3o volunt\xe1ria. \n\n O destino que voc\xea escolher deve ser conhecido por voc\xea e deve estar no mesmo plano de exist\xeancia que voc\xea. Sua familiaridade com o destino determina se voc\xea chegar\xe1 l\xe1 com sucesso. O Mestre rola d100 e consulta a tabela. FamiliaridadeAcidente\xc1rea semelhanteOff AlvoOn AlvoC\xedrculo permanente---01-100Objeto associado---01-100Muito familiar01-0506-1314-2425-100Visto casualmente01-3334-4344-5354-100Visualizado uma vez01-4344-5354-7374-100Descri\xe7\xe3o01-4344-5354-7374-100Destino falso01-5051-100--Familiaridade: C\xedrculo permanente significa um c\xedrculo de teletransporte permanente cuja sequ\xeancia de sigilo voc\xea conhece.\n Objeto associado significa que voc\xea possui um objeto retirado do destino desejado nos \xfaltimos seis meses, como um livro da biblioteca de um mago, roupa de cama de uma su\xedte real ou um peda\xe7o de m\xe1rmore da tumba secreta de um lich. \n Muito familiar \xe9 um lugar onde voc\xea esteve com frequ\xeancia, um lugar que voc\xea estudou cuidadosamente ou um lugar que voc\xea pode ver quando conjura uma magia.\nVisto casualmente \xe9 algum lugar que voc\xea viu mais de uma vez, mas com o qual n\xe3o est\xe1 muito familiarizado.\nVisto uma vez \xe9 um lugar que voc\xea viu uma vez, possivelmente usando magia.\nDescri\xe7\xe3o \xe9 um lugar cuja localiza\xe7\xe3o e apar\xeancia voc\xea conhece atrav\xe9s da descri\xe7\xe3o de outra pessoa, talvez de um mapa.\nO falso destino \xe9 um lugar que n\xe3o existe. Talvez voc\xea tenha tentado visualizar o santu\xe1rio de um inimigo, mas em vez disso viu uma ilus\xe3o, ou est\xe1 tentando se teletransportar para um local familiar que n\xe3o existe mais. \n\nNo Alvo: Voc\xea e seu grupo (ou o objeto alvo) aparecem onde quiserem. \n\nOff Alvo: Voc\xea e seu grupo (ou o objeto alvo) aparecem a uma dist\xe2ncia aleat\xf3ria do destino em uma dire\xe7\xe3o aleat\xf3ria. A dist\xe2ncia do alvo \xe9 1d10 \xd7 1d10 por cento da dist\xe2ncia que deveria ser percorrida. Por exemplo, se voc\xea tentasse viajar 190 quil\xf4metros, pousasse no alvo e obtivesse um 5 e 3 nos dois d10s, ent\xe3o voc\xea estaria 15% fora do alvo, ou 18 quil\xf4metros. O Mestre determina a dire\xe7\xe3o do alvo aleatoriamente rolando um d8 e designando 1 como norte, 2 como nordeste, 3 como leste e assim por diante, ao redorda nos pontos cardeais. Se voc\xea estivesse se teletransportando para uma cidade costeira e acabasse a 29 quil\xf4metros no mar, poderia estar em apuros. \n\n\xc1rea semelhante: Voc\xea e seu grupo (ou o objeto alvo) acabam em uma \xe1rea diferente que \xe9 visual ou tematicamente semelhante \xe0 \xe1rea alvo. Se voc\xea estiver indo para o seu laborat\xf3rio dom\xe9stico, por exemplo, voc\xea pode acabar no laborat\xf3rio de outro mago ou em uma loja de suprimentos alqu\xedmicos que tenha muitas das mesmas ferramentas e implementos do seu laborat\xf3rio. Geralmente, voc\xea aparece no local mais pr\xf3ximo, mas como o feiti\xe7o n\xe3o tem limite de alcance, voc\xea pode acabar em qualquer lugar do avi\xe3o. \n\nAcidente: A magia imprevis\xedvel do feiti\xe7o resulta em uma jornada dif\xedcil. Cada criatura teletransportada (ou objeto alvo) sofre 3d10 de dano de for\xe7a, e o Mestre rola novamente na mesa para ver onde voc\xea vai parar (m\xfaltiplos acidentes podem ocorrer, causando dano a cada vez)."},{name:"Sugest\xe3o",level:2,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 8 horas",description:"Voc\xea sugere um curso de atividade (limitado a uma frase ou duas) e influencia magicamente uma criatura que voc\xea pode ver dentro do alcance que pode ouvi-lo e compreend\xea-lo. Criaturas que n\xe3o podem ser feiti\xe7adas ficam imunes a esse efeito. A sugest\xe3o deve ser formulada de forma a fazer com que o curso da a\xe7\xe3o pare\xe7a razo\xe1vel. Pedir \xe0 criatura que se esfaqueie, se jogue em uma lan\xe7a, se imole ou fa\xe7a algum outro ato obviamente prejudicial encerra o feiti\xe7o.\n\nO alvo deve fazer um Teste de resist\xeancia de Sabedoria. Em um teste de resist\xeancia falho, ele prossegue o curso de a\xe7\xe3o que voc\xea descreveu da melhor maneira poss\xedvel. O curso de a\xe7\xe3o sugerido pode continuar durante todo o per\xedodo. Se a atividade sugerida puder ser conclu\xedda em menos tempo, a magia termina quando o sujeito terminar o que foi solicitado.\n\nVoc\xea tamb\xe9m pode especificar condi\xe7\xf5es que desencadear\xe3o uma atividade especial durante a dura\xe7\xe3o. Por exemplo, voc\xea pode sugerir que um cavaleiro d\xea seu cavalo de guerra ao primeiro mendigo que encontrar. Se a condi\xe7\xe3o n\xe3o for atendida antes da magia expirar, a atividade n\xe3o ser\xe1 realizada.\n\nSe voc\xea ou algum de seus companheiros danificar o alvo, a magia termina."},{name:"Invisibilidade",level:2,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Uma criatura que voc\xea toca fica invis\xedvel at\xe9 o fim da magia. Qualquer coisa que o alvo esteja vestindo ou carregando \xe9 invis\xedvel, desde que esteja na pessoa do alvo. A magia termina para um alvo que ataca ou lan\xe7a um feiti\xe7o."},{name:"Animar Objetos",level:5,classes:["Bardo","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Os objetos ganham vida ao seu comando. Escolha at\xe9 dez objetos n\xe3o m\xe1gicos dentro do alcance que n\xe3o est\xe3o sendo usados \u200b\u200bou carregados. Alvos M\xe9dios contam como dois objetos, Alvos Grandes contam como quatro objetos, Alvos Enormes contam como oito objetos. Voc\xea n\xe3o pode animar nenhum objeto maior que Enorme. Cada um se anima e se torna uma criatura sob seu controle at\xe9 o fim da magia ou at\xe9 ser reduzido a 0 pontos de vida.\n\nComo b\xf4nus de a\xe7\xe3o, voc\xea pode comandar mentalmente qualquer criatura que voc\xea criou com este feiti\xe7o se a criatura estiver a at\xe9 150 metros de voc\xea (se voc\xea controlar m\xfaltiplas criaturas, voc\xea pode comandar uma ou todas elas ao mesmo tempo, emitindo o mesmo comando para cada uma). Voc\xea decide qual a\xe7\xe3o a criatura realizar\xe1 e para onde ela se mover\xe1 durante seu pr\xf3ximo turno, ou pode emitir um comando geral, como guardar uma c\xe2mara ou corredor espec\xedfico. Se voc\xea n\xe3o der nenhum comando, a criatura apenas se defender\xe1 contra criaturas hostis. Uma vez dada uma ordem, a criatura continua a segui-la at\xe9 que sua tarefa seja conclu\xedda. TamanhoHPACStrDexAttackTiny2018418+8 para sucesso, 1d4 + 4 danosPequeno2516614+6 para sucesso, 1d8 + 2 danosM\xe9dio40131012+5 para sucesso, 2d6 + 1 danoGrande50101410+6 para sucesso, 2d10 + 2 danosEnorme8010186+8 para sucesso, 2d12 + 4 de dano Um objeto animado \xe9 um constructo com CA, pontos de vida, ataques, For\xe7a e Destreza determinados por seu tamanho. Sua Constitui\xe7\xe3o \xe9 10 e sua Intelig\xeancia e Sabedoria s\xe3o 3, e seu Carisma \xe9 1. Sua velocidade \xe9 de 9 metros; se o objeto n\xe3o tiver pernas ou outros ap\xeandices que possa usar para locomo\xe7\xe3o, ele ter\xe1 uma velocidade de v\xf4o de 9 metros e poder\xe1 pairar. Se o objeto estiver firmemente preso a uma superf\xedcie ou a um objeto maior, como uma corrente aparafusada a uma parede, sua velocidade \xe9 0. Ele tem vis\xe3o cega com um raio de 9 metros e fica cego al\xe9m dessa dist\xe2ncia. Quando o objeto animado chega a 0 pontos de vida, ele reverte \xe0 sua forma de objeto original e qualquer dano restante \xe9 transferido para sua forma de objeto original.\n\nSe voc\xea comandar um objeto para atacar, ele poder\xe1 realizar um \xfanico ataque corpo a corpo contra uma criatura a at\xe9 1,5 metro dela. Ele faz um ataque slam com b\xf4nus de ataque e dano de concuss\xe3o determinados pelo seu tamanho. O Mestre pode determinar que um objeto espec\xedfico inflija corte ou dano perfurante com base em sua forma."},{name:"Escudo Anticriaturas Vivas",level:5,classes:["Druida"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (10-foot radius)",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Uma barreira cintilante se estende a partir de voc\xea em um raio de 3 metros e se move com voc\xea, permanecendo centrada em voc\xea e protegendo outras criaturas al\xe9m de mortos-vivos e constructos. A barreira dura enquanto durar.\n\nA barreira impede que uma criatura afetada passe ou alcance. Uma criatura afetada pode lan\xe7ar feiti\xe7os ou fazer ataques com armas de longo alcance ou de alcance atrav\xe9s da barreira.\n\nSe voc\xea se mover de forma que uma criatura afetada seja for\xe7ada a passar pela barreira, a magia termina."},{name:"Portal Arcano",level:6,classes:["Feiticeiro","Bruxo","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"150 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea cria portais de teletransporte vinculados que permanecem abertos durante todo o per\xedodo. Escolha dois pontos na solo que voc\xea possa ver, um ponto a at\xe9 3 metros de voc\xea e um ponto a 500 p\xe9s de voc\xea. Um portal circular, com 3 metros de di\xe2metro, abre-se sobre cada ponto. Se o portal se abrir no espa\xe7o ocupado por uma criatura, o feiti\xe7o falha e a conjura\xe7\xe3o \xe9 perdida.\n\nOs portais s\xe3o an\xe9is brilhantes bidimensionais cheios de n\xe9voa, pairando a cent\xedmetros da solo e perpendiculares a ela nos pontos que voc\xea escolher. Um anel \xe9 vis\xedvel apenas de um lado (\xe0 sua escolha), que \xe9 o lado que funciona como portal.\n\nQualquer criatura ou objeto que entre no portal sai do outro portal como se os dois fossem adjacentes; passar por um portal do lado n\xe3o-portal n\xe3o tem efeito. A n\xe9voa que preenche cada portal \xe9 opaca e bloqueia a vis\xe3o atrav\xe9s dele. No seu turno, voc\xea pode girar os an\xe9is como uma a\xe7\xe3o b\xf4nus para que o lado ativo fique voltado em uma dire\xe7\xe3o diferente."},{name:"Despertar",level:5,classes:["Bardo","Druida"],school:"Transmuta\xe7\xe3o",castingTime:"8 hours",range:"Toque",duration:"Instant\xe2neo",description:"Depois de passar o tempo de conjura\xe7\xe3o tra\xe7ando caminhos m\xe1gicos dentro de uma pedra preciosa, voc\xea toca uma besta ou planta enorme ou menor. O alvo n\xe3o deve ter nenhum valor de Intelig\xeancia ou ter Intelig\xeancia 3 ou menos. O alvo ganha Intelig\xeancia 10. O alvo tamb\xe9m ganha a habilidade de falar um idioma que voc\xea conhece. Se o alvo for uma planta, ele ganha a habilidade de mover seus galhos, ra\xedzes, trepadeiras, trepadeiras e assim por diante, e ganha sentidos semelhantes aos de um humano. Seu Mestre escolhe as estat\xedsticas apropriadas para a planta despertada, como as estat\xedsticas do arbusto despertado ou da \xe1rvore despertada.\n\nA besta ou planta despertada \xe9 enfeitada por voc\xea por 30 dias ou at\xe9 que voc\xea ou seus companheiros fa\xe7am algo prejudicial a ela. Quando a condi\xe7\xe3o enfeiti\xe7ado termina, a criatura desperta escolhe se deseja permanecer amig\xe1vel com voc\xea, com base em como voc\xea a tratou enquanto ela estava enfeiti\xe7ado."},{name:"Golpe do Banimento",level:5,classes:["Paladino"],school:"Abjura\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Na pr\xf3xima vez que voc\xea acertar uma criatura com um ataque com arma antes que a magia termine, sua arma estala com for\xe7a e o ataque causa 5d10 de dano de for\xe7a extra ao alvo. Al\xe9m disso, se este ataque reduzir o alvo a 50 pontos de vida ou menos, voc\xea o bane. Se o alvo for nativo de um plano de exist\xeancia diferente daquele em que voc\xea est\xe1, o alvo desaparece, retornando ao seu plano natal. Se o alvo for nativo do plano em que voc\xea est\xe1, a criatura desaparece em um semiplano inofensivo. Enquanto estiver l\xe1, o alvo fica incapacitado. Ele permanece l\xe1 at\xe9 a magia terminar, momento em que o alvo reaparece no espa\xe7o que deixou ou no espa\xe7o desocupado mais pr\xf3ximo, se esse espa\xe7o estiver ocupado."},{name:"Rel\xe2mpago em Cadeia",level:6,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Instant\xe2neo",description:"Voc\xea cria um raio que se move em dire\xe7\xe3o a um alvo de sua escolha que voc\xea pode ver dentro do alcance. Tr\xeas dardos saltam ent\xe3o desse alvo para at\xe9 tr\xeas outros alvos, cada um dos quais deve estar a at\xe9 9 metros do primeiro alvo. Um alvo pode ser uma criatura ou um objeto e pode ser atingido por apenas um dos raios.\n\nUm alvo deve fazer um Teste de resist\xeancia de Destreza. O alvo leva 10d8 dano de raio em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso."},{name:"Barreira de L\xe2minas",level:6,classes:["Cl\xe9rigo"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea cria uma parede vertical de l\xe2minas girat\xf3rias e afiadas feitas de energia m\xe1gica. A parede aparece dentro do alcance e dura enquanto durar. Voc\xea pode fazer uma parede reta de at\xe9 30 metros de comprimento, 6 metros de altura e 1,5 metro de espessura, ou uma parede circular de at\xe9 18 metros de di\xe2metro, 20 metros de altura e 1,5 metro de espessura. A parede fornece tr\xeas quartos de cobertura para as criaturas atr\xe1s dela, e seu espa\xe7o \xe9 um terreno dif\xedcil.\n\nQuando uma criatura entra na \xe1rea da parede pela primeira vez em um turno ou inicia seu turno l\xe1, a criatura deve fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, a criatura sofre 6d10 de dano cortante. Em um teste de resist\xeancia bem-sucedido, a criatura leva metade do dano."},{name:"C\xedrculo da Morte",level:6,classes:["Feiticeiro","Bruxo","Mago"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Instant\xe2neo",description:"Uma esfera de energia negativa ondula em uma esfera de raio de 18 metros a partir de um ponto dentro do alcance. Cada criatura daquela \xe1rea dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Um alvo leva 8d6 de dano necr\xf3tico em um teste de resist\xeancia falho, ou metade do dano em um teste bem sucedido."},{name:"C\xedrculo de Poder",level:5,classes:["Paladino"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (30-foot radius)",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"A energia divina irradia de voc\xea, distorcendo e difundindo a energia m\xe1gica a at\xe9 9 metros de voc\xea. At\xe9 a magia terminar, a esfera se move com voc\xea, centrada em voc\xea. Durante a dura\xe7\xe3o, cada criatura amiga na \xe1rea (incluindo voc\xea) tem vantagem em testes de resist\xeancia contra feiti\xe7os e outros efeitos m\xe1gicos. Al\xe9m disso, quando uma criatura afetada \xe9 bem-sucedida em um teste de resist\xeancia feito contra um feiti\xe7o ou efeito m\xe1gico que lhe permite fazer um teste de resist\xeancia para receber apenas metade do dano, ela n\xe3o sofre nenhum dano se for bem-sucedida no teste de resist\xeancia."},{name:"Matar na Nuvem",level:5,classes:["Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea cria uma esfera de n\xe9voa venenosa verde-amarelada com 6 metros de raio centrada em um ponto que voc\xea escolher dentro do alcance. A neblina espalha cantos ao redorda. Dura pela dura\xe7\xe3o ou at\xe9 que um vento forte disperse a neblina, encerrando o feiti\xe7o. Sua \xe1rea est\xe1 fortemente obscurecida.\n\nQuando uma criatura entra na \xe1rea da magia pela primeira vez em um turno ou inicia seu turno l\xe1, aquela criatura deve fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. A criatura sofre 5d8 de dano de veneno em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso. As criaturas s\xe3o afetadas mesmo que prendam a respira\xe7\xe3o ou n\xe3o precisem respirar.\n\nA neblina se afasta 3 metros de voc\xea no in\xedcio de cada um dos seus turnos, rolando pela superf\xedcie da solo. Os vapores, por serem mais pesados \u200b\u200bque o ar, descem at\xe9 o n\xedvel mais baixo do terreno, chegando at\xe9 mesmo a escorrer por aberturas."},{name:"Comungar com a Natureza",level:5,classes:["Druida","Patrulheiro"],school:"Adivinha\xe7\xe3o",castingTime:"1 minute",range:"Si mesmo",duration:"Instant\xe2neo",description:"Voc\xea brevemente se torna um com a natureza e ganha conhecimento do territ\xf3rio circundante. Ao ar livre, a magia lhe d\xe1 conhecimento da terra a at\xe9 3 milhas de voc\xea. Em cavernas e outros ambientes naturais subterr\xe2neos, o raio \xe9 limitado a 300 p\xe9s. O feiti\xe7o n\xe3o funciona onde a natureza foi substitu\xedda pela constru\xe7\xe3o, como em masmorras e cidades. terreno e corpos de \xe1gua plantas predominantes, minerais, animais ou pessoas poderosas celestiais, fe\xe9ricos, inimigos, elementais ou mortos-vivos influ\xeancia de outros planos de exist\xeancia edif\xedcios Por exemplo, voc\xea pode determinar a localiza\xe7\xe3o de poderosos mortos-vivos na \xe1rea, a localiza\xe7\xe3o das principais fontes de \xe1gua pot\xe1vel e a localiza\xe7\xe3o de quaisquer cidades pr\xf3ximas."},{name:"Comungar",level:5,classes:["Cl\xe9rigo"],school:"Adivinha\xe7\xe3o",castingTime:"1 minute",range:"Si mesmo",duration:"1 minuto",description:"Voc\xea entra em contato com sua divindade ou um procurador divino e faz at\xe9 tr\xeas perguntas que podem ser respondidas com sim ou n\xe3o. Voc\xea deve fazer suas perguntas antes que a magia termine. Voc\xea recebe uma resposta correta para cada pergunta.\n\nOs seres divinos n\xe3o s\xe3o necessariamente oniscientes, ent\xe3o voc\xea pode receber uma resposta pouco clara se uma pergunta se referir a informa\xe7\xf5es que est\xe3o al\xe9m do conhecimento da divindade. Num caso em que uma resposta de uma palavra possa ser enganosa ou contr\xe1ria aos interesses da divindade, o Mestre pode oferecer uma frase curta como resposta.\n\nSe voc\xea conjurar uma magia duas ou mais vezes antes de terminar seu pr\xf3ximo descanso longo, h\xe1 uma chance cumulativa de 25% para cada lan\xe7amento ap\xf3s o primeiro de voc\xea n\xe3o obter resposta. O Mestre faz esse teste em segredo."},{name:"Cone de Frio",level:5,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (60-foot cone)",duration:"Instant\xe2neo",description:"Uma rajada de ar frio sai de suas m\xe3os. Cada criatura num cone de 18 metros dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Uma criatura sofre 8d8 de dano de frio em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso.\n\nUma criatura morta por este feiti\xe7o se torna uma est\xe1tua congelada at\xe9 descongelar."},{name:"Convocar Elemental",level:5,classes:["Druida","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 minute",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea invoca um servo elemental. Escolha uma \xe1rea de ar, terra, fogo ou \xe1gua que preencha um cubo de 3 metros dentro do alcance. Um elemental de n\xedvel de desafio 5 ou inferior apropriado \xe0 \xe1rea que voc\xea escolheu aparece em um espa\xe7o desocupado a at\xe9 3 metros dele. Por exemplo, um elemental do fogo emerge de uma fogueira e um elemental da terra surge da solo. O elemental desaparece quando cai para 0 pontos de vida ou quando a magia termina.\n\nO elemental \xe9 amig\xe1vel com voc\xea e seus companheiros durante todo o per\xedodo. Role a iniciativa para o elemental, que tem seus pr\xf3prios turnos. Ele obedece a quaisquer comandos verbais que voc\xea emitir (nenhuma a\xe7\xe3o exigida por voc\xea). Se voc\xea n\xe3o der nenhum comando ao elemental, ele se defender\xe1 de criaturas hostis, mas n\xe3o realizar\xe1 nenhuma a\xe7\xe3o.\n\nSe sua concentra\xe7\xe3o for quebrada, o elemental n\xe3o desaparece. Em vez disso, voc\xea perde o controle do elemental, ele se torna hostil com voc\xea e seus companheiros e pode atacar. Um elemental descontrolado n\xe3o pode ser desfalcado por voc\xea, e ele desaparece 1 hora depois que voc\xea o convocou.\n\nO Mestre possui as estat\xedsticas do elemental."},{name:"Convocar o Fe\xe9rico",level:6,classes:["Druida","Bruxo"],school:"Conjura\xe7\xe3o",castingTime:"1 minute",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea convoca uma criatura fe\xe9rica com n\xedvel de desafio 6 ou inferior, ou um esp\xedrito fe\xe9rico que assume a forma de uma besta com n\xedvel de desafio 6 ou inferior. Aparece em um espa\xe7o desocupado que voc\xea pode ver dentro do alcance. A criatura fe\xe9rico desaparece quando cai para 0 pontos de vida ou quando a magia termina.\n\nA criatura fe\xe9rico \xe9 amig\xe1vel com voc\xea e seus companheiros durante todo o tempo. Role a iniciativa para a criatura, que tem seus pr\xf3prios turnos. Ele obedece a quaisquer comandos verbais que voc\xea emitir (nenhuma a\xe7\xe3o exigida por voc\xea), desde que eles n\xe3o violem seu alinhamento. Se voc\xea n\xe3o der nenhum comando \xe0 criatura fe\xe9rica, ela se defender\xe1 de criaturas hostis, mas n\xe3o realizar\xe1 nenhuma a\xe7\xe3o.\n\nSe sua concentra\xe7\xe3o for prejudicada, a criatura fe\xe9rica n\xe3o desaparece. Em vez disso, voc\xea perde o controle da criatura fe\xe9rica, ela se torna hostil com voc\xea e seus companheiros e pode atacar. Uma criatura fe\xe9rico descontrolada n\xe3o pode ser desfalcada por voc\xea e desaparece 1 hora depois que voc\xea a convocou.\n\nO Mestre possui as estat\xedsticas da criatura fe\xe9rico."},{name:"Convocar Salva",level:5,classes:["Patrulheiro"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Instant\xe2neo",description:"Voc\xea dispara uma muni\xe7\xe3o n\xe3o-m\xe1gica de uma arma de longo alcance ou joga uma arma n\xe3o-m\xe1gica no ar e escolhe um ponto dentro do alcance. Centenas de duplicatas da muni\xe7\xe3o ou arma caem de cima e depois desaparecem. Cada criatura em um cilindro de 12 metros de raio e 6 metros de altura centrado nesse ponto deve fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre 8d8 de dano em um teste de resist\xeancia falho, ou metade do dano em um teste bem-sucedido. O tipo de dano \xe9 o mesmo da muni\xe7\xe3o ou arma."},{name:"Contatar Outro Plano",level:5,classes:["Bruxo","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 minute",range:"Si mesmo",duration:"1 minuto",description:"Voc\xea contata mentalmente um semideus, o esp\xedrito de um s\xe1bio falecido h\xe1 muito tempo ou alguma outra entidade misteriosa de outro plano. Entrar em contato com essa intelig\xeancia extraplanar pode sobrecarregar ou at\xe9 quebrar sua mente. Quando voc\xea conjurar essa magia, fa\xe7a um Teste de resist\xeancia de Intelig\xeancia DC 15. Em caso de falha, voc\xea sofre 6d6 de dano ps\xedquico e fica louco at\xe9 terminar um descanso longo. Enquanto estiver louco, voc\xea n\xe3o consegue realizar a\xe7\xf5es, n\xe3o consegue entender o que outras criaturas dizem, n\xe3o consegue ler e fala apenas coisas sem sentido. Um feiti\xe7o de restaura\xe7\xe3o maior lan\xe7ado em voc\xea encerra esse efeito.\n\nEm um teste de resist\xeancia bem-sucedido, voc\xea pode fazer at\xe9 cinco perguntas \xe0 entidade. Voc\xea deve fazer suas perguntas antes que a magia termine. O Mestre responde a cada pergunta com uma palavra, como sim, n\xe3o, talvez, nunca, irrelevante ou pouco claro (se a entidade n\xe3o souber a resposta para a pergunta). Se uma resposta de uma palavra for enganosa, o Mestre pode, em vez disso, oferecer uma frase curta como resposta."},{name:"Cont\xe1gio",level:5,classes:["Cl\xe9rigo","Druida"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"7 dias",description:"Seu toque inflige doen\xe7as. Fa\xe7a um ataque de magia corpo a corpo contra uma criatura ao seu alcance. Sem sucesso, o alvo est\xe1 envenenado. \n\n No final de cada um dos turnos do alvo envenenado, o alvo dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Se o alvo obtiver sucesso em tr\xeas desses testes, ele n\xe3o ser\xe1 mais envenenado e a magia terminar\xe1. Se o alvo falhar em tr\xeas desses salvamentos, o alvo n\xe3o ser\xe1 mais envenenado, mas sim escolhido uma das doen\xe7as abaixo. O alvo fica sujeito \xe0 doen\xe7a escolhida durante a dura\xe7\xe3o da magia. \n\n Como esta magia induz uma doen\xe7a natural em seu alvo, qualquer efeito que remova uma doen\xe7a ou melhore os efeitos de uma doen\xe7a se aplica a ela. \n\nDoen\xe7a Cegante: A dor toma conta da mente da criatura e seus olhos ficam com uma apar\xeancia leitosa. A criatura tem desvantagem em testes de Sabedoria e Teste de resist\xeancia de Sabedorias e \xe9 cega. \n\nFebre da Sujeira: Uma febre violenta varre o corpo da criatura. A criatura tem desvantagem em testes de For\xe7a, Teste de resist\xeancia de For\xe7as e jogo de ataques que utilizam For\xe7a. \n\nPodrid\xe3o da Carne: A carne da criatura se deteriora. A criatura tem desvantagem em testes de Carisma e vulnerabilidade a todos os danos. \n\nMindfire: A mente da criatura fica febril. A criatura tem desvantagem em testes de Intelig\xeancia e Teste de resist\xeancia de Intelig\xeancias, e a criatura se comporta como se estivesse sob os efeitos do feiti\xe7o confus\xe3o durante o combate. \n\nConvuls\xe3o: A criatura \xe9 dominada pela agita\xe7\xe3o. A criatura tem desvantagem em testes de Destreza, Teste de resist\xeancia de Destrezas e ataque de ataques que utilizam Destreza. \n\nSlimy Doom: A criatura come\xe7a a sangrar incontrolavelmente. A criatura tem desvantagem em verifica\xe7\xf5es de Constitui\xe7\xe3o e Teste de resist\xeancia de Constitui\xe7\xf5es. Al\xe9m disso, sempre que a criatura sofrer dano, ela ficar\xe1 atordoada at\xe9 o final do pr\xf3ximo turno."},{name:"Conting\xeancia",level:6,classes:["Mago"],school:"Evoca\xe7\xe3o",castingTime:"10 minutes",range:"Si mesmo",duration:"10 dias",description:"Escolha uma magia de 5\xba n\xedvel ou inferior que voc\xea possa lan\xe7ar, que tenha um tempo de lan\xe7amento de 1 a\xe7\xe3o, e que possa atingir voc\xea. Voc\xea conjura esse feiti\xe7o \u2013 chamado de feiti\xe7o contingente \u2013 como parte do lan\xe7amento de conting\xeancia, gastando espa\xe7os de magia para ambos, mas o feiti\xe7o contingente n\xe3o entra em vigor. Em vez disso, entra em vigor quando ocorre uma determinada circunst\xe2ncia. Voc\xea descreve essa circunst\xe2ncia quando lan\xe7a os dois feiti\xe7os. Por exemplo, uma conting\xeancia lan\xe7ada com respira\xe7\xe3o na \xe1gua (n\xedvel 3) pode estipular que a respira\xe7\xe3o na \xe1gua entra em vigor quando voc\xea \xe9 engolfado por \xe1gua ou l\xedquido semelhante.\n\nA magia contingente entra em vigor imediatamente ap\xf3s a circunst\xe2ncia ser encontrada pela primeira vez, quer voc\xea queira ou n\xe3o. E ent\xe3o a conting\xeancia termina.\n\nA magia contingente tem efeito apenas em voc\xea, mesmo que normalmente possa atingir outras pessoas. Voc\xea pode usar apenas um feiti\xe7o de conting\xeancia por vez. Se voc\xea lan\xe7ar esta magia novamente, o efeito de outra magia de conting\xeancia em voc\xea termina. Al\xe9m disso, a conting\xeancia termina com voc\xea se o componente material n\xe3o estiver com voc\xea."},{name:"Criar Morto-Vivo",level:6,classes:["Cl\xe9rigo","Bruxo","Mago"],school:"Necromancia",castingTime:"1 minute",range:"3 metros",duration:"Instant\xe2neo",description:"Voc\xea s\xf3 pode lan\xe7ar este feiti\xe7o \xe0 noite. Escolha at\xe9 tr\xeas cad\xe1veres de human\xf3ides M\xe9dios ou Pequenos dentro do alcance. Cada cad\xe1ver se torna um ghoul sob seu controle. (O Mestre tem estat\xedsticas de jogo para essas criaturas.)\n\nComo b\xf4nus de a\xe7\xe3o em cada um de seus turnos, voc\xea pode comandar mentalmente qualquer criatura que voc\xea animou com esta magia se a criatura estiver a 36 metros de voc\xea (se voc\xea controlar m\xfaltiplas criaturas, voc\xea pode comandar uma ou todas elas ao mesmo tempo, emitindo o mesmo comando para cada uma). Voc\xea decide qual a\xe7\xe3o a criatura realizar\xe1 e para onde ela se mover\xe1 durante seu pr\xf3ximo turno, ou pode emitir um comando geral, como guardar uma c\xe2mara ou corredor espec\xedfico. Se voc\xea n\xe3o der nenhum comando, a criatura apenas se defender\xe1 contra criaturas hostis. Uma vez dada uma ordem, a criatura continua a segui-la at\xe9 que sua tarefa seja conclu\xedda.\n\nA criatura fica sob seu controle por 24 horas, ap\xf3s as quais ela deixa de obedecer a qualquer comando que voc\xea tenha dado. Para manter o controle da criatura por mais 24 horas, voc\xea deve lan\xe7ar este feiti\xe7o na criatura antes que o per\xedodo atual de 24 horas termine. Este uso da magia reafirma seu controle sobre at\xe9 tr\xeas criaturas que voc\xea animou com esta magia, em vez de animar novas."},{name:"Chama Cont\xednua",level:2,classes:["Cl\xe9rigo","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"At\xe9 ser dissipada",description:"Uma chama, equivalente em brilho a uma tocha, brota de um objeto que voc\xea toca. O efeito se parece com uma chama normal, mas n\xe3o cria calor e n\xe3o utiliza oxig\xeanio. Uma chama cont\xednua pode ser coberta ou escondida, mas n\xe3o sufocada ou extinta."},{name:"Cria\xe7\xe3o",level:5,classes:["Feiticeiro","Mago"],school:"Ilus\xe3o",castingTime:"1 minute",range:"9 metros",duration:"Especial",description:"Voc\xea puxa fragmentos de material sombreado do Pendor das Sombras para criar um objeto inanimado de mat\xe9ria vegetal dentro do alcance: produtos leves, corda, madeira ou algo semelhante. Voc\xea tamb\xe9m pode usar este feiti\xe7o para criar objetos minerais como pedra, cristal ou metal. O objeto criado n\xe3o deve ser maior que um metrocubo de 1,5 metro e deve ter uma forma e material que voc\xea j\xe1 tenha visto antes.\n\nA dura\xe7\xe3o depende do material do objeto. Se o objeto for composto por v\xe1rios materiais, use o de menor dura\xe7\xe3o. MaterialDura\xe7\xe3oMat\xe9ria vegetal1 dia\xa0Pedra ou cristal12 horas\xa0Metais preciosos1 hora\xa0Gemas10 minutos\xa0Adamantino ou mithral1 minuto\xa0 Usar qualquer material criado por este feiti\xe7o como componente material de outro feiti\xe7o faz com que o feiti\xe7o falhe."},{name:"Onda Destrutiva",level:5,classes:["Paladino"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (30-foot radius)",duration:"Instant\xe2neo",description:"Voc\xea atinge a solo, criando uma explos\xe3o de energia divina que se espalha para fora de voc\xea. Cada criatura que voc\xea escolher a at\xe9 9 metros de voc\xea deve ter sucesso em um Teste de resist\xeancia de Constitui\xe7\xe3o ou sofrer 5d6 dano s\xf4nico, bem como 5d6 dano radiante ou necr\xf3tico (sua escolha), e ser derrubado. Uma criatura que consegue seu teste de resist\xeancia leva metade do dano e n\xe3o cai."},{name:"Desintegrar",level:6,classes:["Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Um fino raio verde brota do seu dedo apontador para um alvo que voc\xea possa ver dentro do alcance. O alvo pode ser uma criatura, um objeto ou uma cria\xe7\xe3o de for\xe7a m\xe1gica, como a parede criada por parede de for\xe7a (n\xedvel 5).\n\nUma criatura atingida por este feiti\xe7o deve fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, o alvo leva 10d6 + 40 dano de for\xe7a. Se esse dano reduzir o alvo a 0 pontos de vida, ele se desintegra.\n\nUma criatura desintegrada e tudo o que ela veste e carrega, exceto itens m\xe1gicos, s\xe3o reduzidos a uma pilha de p\xf3 cinza e fino. A criatura s\xf3 pode ser restaurada \xe0 vida por meio de um feiti\xe7o de ressurrei\xe7\xe3o verdadeira (n\xedvel 9) ou de desejo (n\xedvel 9).\n\nEste feiti\xe7o desintegra automaticamente um objeto n\xe3o m\xe1gico grande ou menor ou uma cria\xe7\xe3o de for\xe7a m\xe1gica. Se o alvo for um objeto Enorme ou maior ou cria\xe7\xe3o de for\xe7a, este feiti\xe7o desintegra uma por\xe7\xe3o de 3 metros c\xfabicos dele. Um item m\xe1gico n\xe3o \xe9 afetado por este feiti\xe7o."},{name:"Adivinha\xe7\xe3o",level:4,classes:["Cl\xe9rigo"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Instant\xe2neo",description:"Sua magia e uma oferenda colocam voc\xea em contato com um deus ou com os servos de um deus. Voc\xea faz uma \xfanica pergunta sobre um objetivo, evento ou atividade espec\xedfica que ocorrer\xe1 dentro de 7 dias. O Mestre oferece uma resposta verdadeira. A resposta pode ser uma frase curta, uma rima enigm\xe1tica ou um press\xe1gio.\n\nA magia n\xe3o leva em considera\xe7\xe3o quaisquer circunst\xe2ncias poss\xedveis que possam alterar o resultado, como o lan\xe7amento de magias adicionais ou a perda ou ganho de um companheiro.\n\nSe voc\xea lan\xe7ar este feiti\xe7o duas ou mais vezes antes de terminar seu pr\xf3ximo descanso longo, h\xe1 uma chance cumulativa de 25% para cada lan\xe7amento ap\xf3s o primeiro de voc\xea obter uma leitura aleat\xf3ria. O Mestre faz esse teste em segredo."},{name:"Dissipar o Bem e o Mal",level:5,classes:["Cl\xe9rigo","Paladino"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"A energia cintilante protege voc\xea de fe\xe9ricos, mortos-vivos e criaturas origin\xe1rias de al\xe9m do Plano Material. Enquanto isso, celestiais, elementais, fe\xe9ricos, inimigos e mortos-vivos ter\xe3o manobras de ataque contra voc\xea.\n\nVoc\xea pode encerrar o feiti\xe7o mais cedo usando qualquer uma das seguintes fun\xe7\xf5es especiais. \n\nQuebrar Encantamento: Como sua a\xe7\xe3o, voc\xea toca uma criatura que voc\xea pode alcan\xe7ar que est\xe1 enfeiti\xe7ado, amedrontado ou possu\xedda por um celestial, um elemental, um fe\xe9rico, um inimigo ou um morto-vivo. A criatura que voc\xea toca n\xe3o est\xe1 mais enfeitada, amedrontada ou possu\xedda por tais criaturas. \n\nDisfalhaal: Como sua a\xe7\xe3o, fa\xe7a um ataque de magia corpo a corpo contra um celestial, um elemental, um fe\xe9rico, um inimigo ou um morto-vivo que voc\xea possa alcan\xe7ar. Sem sucesso, voc\xea tenta levar a criatura de volta ao seu plano natal. A criatura deve ser bem-sucedida em um Teste de resist\xeancia de Carisma ou ser\xe1 enviada de volta ao seu plano natal (se ainda n\xe3o estiver l\xe1). Se n\xe3o estiverem em seu plano natal, os mortos-vivos s\xe3o enviados para Shadowfell e os fe\xe9ricos s\xe3o enviados para Fe\xe9ricowild."},{name:"Dominar Besta",level:4,classes:["Druida","Feiticeiro"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea tenta enganar a melhor coisa que voc\xea pode ver dentro do alcance. Deve ser aprovado em Teste de resist\xeancia de Sabedoria ou ser feiti\xe7ado por voc\xea durante todo o per\xedodo. Se voc\xea ou criaturas que lhe s\xe3o amigas est\xe3o lutando contra isso, tem vantagem no teste de resist\xeancia.\n\nEnquanto a besta estiver enfeitada, voc\xea mant\xe9m uma liga\xe7\xe3o telep\xe1tica com ela desde que voc\xeas dois estejam no mesmo plano de exist\xeancia. Voc\xea pode usar esse link telep\xe1tico para emitir comandos \xe0 criatura enquanto estiver consciente (nenhuma a\xe7\xe3o necess\xe1ria), aos quais ela far\xe1 o poss\xedvel para obedecer. Voc\xea pode especificar um curso de a\xe7\xe3o simples e geral, como Atacar aquela criatura, Correr at\xe9 l\xe1 ou Buscar aquele objeto. Se a criatura completar a ordem e n\xe3o receber mais orienta\xe7\xf5es suas, ela se defender\xe1 e se preservar\xe1 da melhor maneira poss\xedvel.\n\nVoc\xea pode usar sua a\xe7\xe3o para assumir o controle total e preciso do alvo. At\xe9 o final do seu pr\xf3ximo turno, a criatura realiza apenas as a\xe7\xf5es que voc\xea escolher e n\xe3o faz nada que voc\xea n\xe3o permita. Durante esse tempo, voc\xea tamb\xe9m pode fazer com que a criatura use uma ocorr\xeancia, mas isso exige que voc\xea use sua pr\xf3pria ocorr\xeancia tamb\xe9m. Cada vez que o alvo sofre dano, ele faz um novo Teste de resist\xeancia de Sabedoria contra o feiti\xe7o. Se o teste de resist\xeancia for bem-sucedido, a magia termina."},{name:"Dominar Pessoa",level:5,classes:["Bardo","Feiticeiro","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea tenta enganar um humanoide que voc\xea possa ver dentro do alcance. Deve ser aprovado em Teste de resist\xeancia de Sabedoria ou ser feiti\xe7ado por voc\xea durante todo o per\xedodo. Se voc\xea ou criaturas que lhe s\xe3o amigas est\xe3o lutando contra isso, tem vantagem no teste de resist\xeancia.\n\nEnquanto o alvo estiver enfeiti\xe7ado, voc\xea ter\xe1 uma liga\xe7\xe3o telep\xe1tica com ele desde que voc\xeas dois estejam no mesmo plano de exist\xeancia. Voc\xea pode usar esse link telep\xe1tico para emitir comandos \xe0 criatura enquanto estiver consciente (nenhuma a\xe7\xe3o necess\xe1ria), aos quais ela far\xe1 o poss\xedvel para obedecer. Voc\xea pode especificar um curso de a\xe7\xe3o simples e geral, como Atacar aquela criatura, Correr at\xe9 l\xe1 ou Buscar aquele objeto. Se a criatura completar a ordem e n\xe3o receber mais orienta\xe7\xf5es suas, ela se defender\xe1 e se preservar\xe1 da melhor maneira poss\xedvel.\n\nVoc\xea pode usar sua a\xe7\xe3o para assumir o controle total e preciso do alvo. At\xe9 o final do seu pr\xf3ximo turno, a criatura realiza apenas as a\xe7\xf5es que voc\xea escolher e n\xe3o faz nada que voc\xea n\xe3o permita. Durante esse tempo voc\xea tamb\xe9m pode fazer com que a criatura use uma ocorr\xeancia, mas isso requer que voc\xea use sua pr\xf3pria ocorr\xeancia tamb\xe9m. Cada vez que o alvo sofre dano, ele faz um novo Teste de resist\xeancia de Sabedoria contra o feiti\xe7o. Se o teste de resist\xeancia for bem-sucedido, a magia termina."},{name:"Sonho",level:5,classes:["Bardo","Bruxo","Mago"],school:"Ilus\xe3o",castingTime:"1 minute",range:"Special",duration:"8 horas",description:"Este feiti\xe7o molda os sonhos de uma criatura. Escolha uma criatura conhecida por voc\xea como o alvo desta magia. O alvo deve estar no mesmo plano de exist\xeancia que voc\xea. Criaturas que n\xe3o dormem, como elfos, n\xe3o podem ser contatadas por esta magia. Voc\xea, ou uma criatura volunt\xe1ria que voc\xea toca, entra em estado de transe, agindo como um mensageiro. Enquanto est\xe1 em transe, o mensageiro est\xe1 ciente de suas subordina\xe7\xf5es, mas n\xe3o pode realizar a\xe7\xf5es ou se mover.\n\nSe o alvo estiver dormindo, o mensageiro aparece nos sonhos do alvo e pode conversar com o alvo enquanto ele permanecer dormindo, durante a dura\xe7\xe3o do feiti\xe7o. O mensageiro tamb\xe9m pode moldar o ambiente do sonho, criando paisagens, objetos e outras imagens. O mensageiro pode sair do transe a qualquer momento, encerrando o efeito do feiti\xe7o mais cedo. O alvo lembra perfeitamente do sonho ao acordar. Se o alvo estiver acordado quando voc\xea conjurar uma magia, o mensageiro sabe disso e pode encerrar o transe (e o feiti\xe7o) ou esperar que o alvo adorme\xe7a, momento em que o mensageiro aparece nos sonhos do alvo.\n\nVoc\xea pode fazer o mensageiro parecer monstruoso e assustador para o alvo. Se o fizer, o mensageiro poder\xe1 entregar uma mensagem de no m\xe1ximo dez palavras e ent\xe3o o alvo dever\xe1 fazer um Teste de resist\xeancia de Sabedoria. Em um teste de resist\xeancia falho, ecos da monstruosidade fantasmag\xf3rica geram um pesadelo que dura a dura\xe7\xe3o do sono do alvo e impede que o alvo obtenha qualquer benef\xedcio desse descanso. Al\xe9m disso, quando o alvo acorda, ele sofre 3d6 de dano ps\xedquico.\n\nSe voc\xea tiver uma parte do corpo, mecha de cabelo, recorte de unha, ou por\xe7\xe3o similar do corpo do alvo, o alvo faz seu teste de resist\xeancia com interfer\xeancia."},{name:"Aprimorar Habilidade",level:2,classes:["Bardo","Cl\xe9rigo","Druida","Feiticeiro"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea toca uma criatura e concede a ela um aprimoramento m\xe1gico. Escolha um dos seguintes efeitos; o ganha esse efeito at\xe9 a magia terminar. \n\nResist\xeancia do Urso: O alvo tem vantagem em testes de Constitui\xe7\xe3o. Ele tamb\xe9m ganha 2d6 pontos de vida tempor\xe1rios, que s\xe3o perdidos quando a magia termina. \n\nFor\xe7a do Touro: O alvo tem vantagem em testes de For\xe7a e sua capacidade de carga dobra. \n\nGra\xe7a do Gato: O alvo tem vantagem em testes de Destreza. Ele tamb\xe9m n\xe3o sofre danos ao cair de 6 metros ou menos se n\xe3o estiver incapacitado. \n\nEsplendor da \xc1guia: O alvo tem vantagem em testes de Carisma. \n\nAst\xfacia da Raposa: O alvo tem vantagem em testes de Intelig\xeancia. \n\nSabedoria da Coruja: O alvo tem vantagem em testes de Sabedoria."},{name:"Aumentar/Reduzir",level:2,classes:["Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea faz com que uma criatura ou objeto que voc\xea possa ver dentro do alcance cres\xe7a ou diminua com o passar do tempo. Escolha uma criatura ou um objeto que n\xe3o seja usado nem carregado. Se o alvo n\xe3o quiser, pode fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Caso obtenha sucesso, o feiti\xe7o n\xe3o tem efeito. \n\n Se o alvo for uma criatura, tudo o que ele veste e carrega muda de tamanho junto com ele. Qualquer item largado por uma criatura afetada retorna ao tamanho normal imediatamente. \n\nAmpliar: O tamanho do alvo dobra em todas as dimens\xf5es e seu peso \xe9 multiplicado por oito. Esse crescimento aumenta seu tamanho em uma categoria \u2013 de M\xe9dio a Grande, por exemplo. Se n\xe3o houver espa\xe7o suficiente para o alvo dobrar de tamanho, a criatura ou objeto atinge o tamanho m\xe1ximo poss\xedvel no espa\xe7o dispon\xedvel. At\xe9 a magia terminar, o alvo tamb\xe9m tem vantagem em testes de For\xe7a e Teste de resist\xeancia de For\xe7as. As armas do alvo tamb\xe9m crescem para corresponder ao seu novo tamanho. Embora essas armas sejam ampliadas, os ataques do alvo com elas causam 1d4 de dano extra. \n\nReduzir: O tamanho do alvo \xe9 reduzido pela metade em todas as dimens\xf5es e seu peso \xe9 reduzido a um oitavo do normal. Esta redu\xe7\xe3o diminui o seu tamanho em uma categoria \u2013 de M\xe9dio para Pequeno, por exemplo. At\xe9 a magia terminar, o alvo tamb\xe9m possui interfer\xeancia em testes de For\xe7a e Teste de resist\xeancia de For\xe7as. As armas do alvo tamb\xe9m encolhem para corresponder ao seu novo tamanho. Embora essas armas sejam reduzidas, os ataques do alvo com elas causam 1d4 a menos de dano (isso n\xe3o pode reduzir o dano abaixo de 1)."},{name:"Fascinar",level:2,classes:["Bardo","Bruxo"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"1 minuto",description:"Voc\xea tece uma s\xe9rie de palavras que distraem, fazendo com que criaturas de sua escolha, que voc\xea possa ver dentro do alcance e que possam ouvi-lo, fa\xe7am um Teste de resist\xeancia de Sabedoria. Qualquer criatura que n\xe3o possa ser enfeitada ter\xe1 sucesso neste teste de resist\xeancia automaticamente, e se voc\xea ou seus companheiros estiverem lutando contra uma criatura, ela ter\xe1 vantagem no teste de resist\xeancia. Em um teste de resist\xeancia falho, o alvo tem desvantagem em testes de Sabedoria (Percep\xe7\xe3o) feitos para perceber qualquer criatura que n\xe3o seja voc\xea at\xe9 o final da magia ou at\xe9 que o alvo n\xe3o possa mais ouvi-lo. A magia termina se voc\xea estiver incapacitado ou n\xe3o puder mais falar."},{name:"Fabricar",level:4,classes:["Mago"],school:"Transmuta\xe7\xe3o",castingTime:"10 minutes",range:"36 metros",duration:"Instant\xe2neo",description:"Voc\xea converte mat\xe9rias-primas em produtos do mesmo material. Por exemplo, voc\xea pode fabricar uma ponte de madeira com um grupo de \xe1rvores, uma corda com um peda\xe7o de c\xe2nhamo e roupas com linho ou l\xe3.\n\nEscolha mat\xe9rias-primas que voc\xea possa ver dentro do alcance. Voc\xea pode fabricar um objeto Grande ou menor (contido dentro de um cubo de 3 metros, ou oito cubos de 1,5 metro conectados), desde que haja quantidade suficiente de mat\xe9ria-prima. Se voc\xea estiver trabalhando com metal, pedra ou outra subst\xe2ncia mineral, entretanto, o objeto fabricado n\xe3o poder\xe1 ser maior que M\xe9dio (contido em um \xfanico cubo de 1,5 metro). A qualidade dos objetos feitos pelo feiti\xe7o \xe9 proporcional \xe0 qualidade das mat\xe9rias-primas.\n\nCriaturas ou itens m\xe1gicos n\xe3o podem ser criados ou transmutados por este feiti\xe7o. Voc\xea tamb\xe9m n\xe3o pode us\xe1-lo para criar itens que normalmente exijam um alto grau de habilidade, como joias, armas, vidro ou armaduras, a menos que voc\xea tenha profici\xeancia com o tipo de ferramenta de artes\xe3o usada para fabricar tais objetos."},{name:"Mordida do Olhar",level:6,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Durante a dura\xe7\xe3o do feiti\xe7o, seus olhos se tornam um vazio escuro imbu\xeddo de poder pavoroso. Uma criatura de sua escolha a at\xe9 18 metros de voc\xea que voc\xea possa ver deve ter sucesso em um Teste de resist\xeancia de Sabedoria ou ser afetada por um dos seguintes efeitos de sua escolha durante a dura\xe7\xe3o. Em cada um de seus turnos at\xe9 o final da magia, voc\xea pode usar sua a\xe7\xe3o para atacar outra criatura, mas n\xe3o poder\xe1 atacar uma criatura novamente se ela tiver obtido sucesso em um teste de resist\xeancia contra esse lan\xe7amento de mordida ocular. \n\nAdormecido: O alvo cai inconsciente. Ele acorda se sofrer algum dano ou se outra criatura usar sua a\xe7\xe3o para acordar o dorminhoco. \n\nEm p\xe2nico: O alvo est\xe1 amedrontado de voc\xea. Em cada um de seus turnos, a criatura amedrontada deve pegar a a\xe7\xe3o Dash e se afastar de voc\xea pela rota mais segura e curta dispon\xedvel, a menos que n\xe3o haja para onde se mover. Se o alvo se deslocar para um local a pelo menos 18 metros de dist\xe2ncia de voc\xea, onde n\xe3o possa mais v\xea-lo, esse efeito termina. \n\nEnjoado: O alvo tem manobra de ataque e teste de habilidades. Ao final de cada um de seus turnos, ele poder\xe1 realizar outro Teste de resist\xeancia de Sabedoria. Se tiver sucesso, o efeito termina."},{name:"Encontrar Corcel",level:2,classes:["Paladino"],school:"Conjura\xe7\xe3o",castingTime:"10 minutes",range:"9 metros",duration:"Instant\xe2neo",description:"Voc\xea convoca um esp\xedrito que assume a forma de um corcel extraordinariamente inteligente, forte e leal, criando um v\xednculo duradouro com ele. Aparecendo em um espa\xe7o desocupado dentro do alcance, o corcel assume a forma que voc\xea escolher, como um cavalo de guerra, um p\xf4nei, um camelo, um alce ou um mastim. (Seu Mestre pode permitir que outros animais sejam convocados como corc\xe9is.) O corcel tem as estat\xedsticas da forma escolhida, embora seja um celestial, fe\xe9rico ou inimigo (sua escolha) em vez de seu tipo normal. Al\xe9m disso, se o seu cavalo tiver Intelig\xeancia 5 ou menos, sua Intelig\xeancia se torna 6 e ele ganha a habilidade de entender um idioma de sua escolha que voc\xea fale.\n\nSeu corcel serve como montaria, tanto em combate quanto fora dele, e voc\xea tem um v\xednculo instintivo com ele que lhe permite lutar como uma unidade perfeita. Enquanto montado em seu corcel, voc\xea pode fazer qualquer feiti\xe7o que lan\xe7ar que atinja apenas voc\xea tamb\xe9m alvo de seu corcel.\n\nQuando o corcel cai para 0 pontos de vida, ele desaparece, n\xe3o deixando para tr\xe1s nenhuma forma f\xedsica. Voc\xea tamb\xe9m pode dissipar seu corcel a qualquer momento como uma a\xe7\xe3o, fazendo com que ele desapare\xe7a. Em ambos os casos, lan\xe7ar este feiti\xe7o invoca novamente o mesmo corcel, restaurado ao seu ponto de vida m\xe1ximo.\n\nEnquanto seu cavalo estiver a 1,5 milha de voc\xea, voc\xea poder\xe1 se comunicar com ele telepaticamente.\n\nVoc\xea n\xe3o pode ter mais de um cavalo vinculado por este feiti\xe7o ao mesmo tempo. Como a\xe7\xe3o, voc\xea pode liberar o corcel de seu v\xednculo a qualquer momento, fazendo com que ele desapare\xe7a."},{name:"Encontrar o Caminho",level:6,classes:["Bardo","Cl\xe9rigo","Druida"],school:"Adivinha\xe7\xe3o",castingTime:"1 minute",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 dia",description:"Este feiti\xe7o permite que voc\xea encontre a rota f\xedsica mais curta e direta para um local fixo espec\xedfico com o qual voc\xea est\xe1 familiarizado no mesmo plano de exist\xeancia. Se voc\xea nomear um destino em outro plano de exist\xeancia, um destino que se mova (como uma fortaleza m\xf3vel) ou um destino que n\xe3o seja espec\xedfico (como o covil de um drag\xe3o verde), a magia falha.\n\nDurante todo o tempo, enquanto voc\xea estiver no mesmo plano de exist\xeancia do destino, voc\xea saber\xe1 a que dist\xe2ncia ele est\xe1 e em que dire\xe7\xe3o est\xe1. Enquanto voc\xea viaja para l\xe1, sempre que lhe \xe9 apresentada uma escolha de caminhos ao longo do caminho, voc\xea determina automaticamente qual caminho \xe9 o caminho mais curto e direto (mas n\xe3o necessariamente o mais seguro) para o destino."},{name:"Encontrar Armadilhas",level:2,classes:["Cl\xe9rigo","Druida","Patrulheiro"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Instant\xe2neo",description:"Voc\xea sente a presen\xe7a de qualquer armadilha dentro do alcance que esteja dentro da linha de vis\xe3o. Uma armadilha, para o prop\xf3sito desta magia, inclui qualquer coisa que possa infligir um efeito repentino ou inesperado que voc\xea considere prejudicial ou indesej\xe1vel, que foi especificamente concebido como tal por seu criador. Assim, o feiti\xe7o sentiria uma \xe1rea afetada pelo feiti\xe7o de alarme (n\xedvel 1), um glifo de prote\xe7\xe3o (n\xedvel 3) ou uma armadilha mec\xe2nica, mas n\xe3o revelaria uma fraqueza natural no ch\xe3o, um teto inst\xe1vel ou um buraco escondido.\n\nEste feiti\xe7o apenas revela que uma armadilha est\xe1 presente. Voc\xea n\xe3o aprende a localiza\xe7\xe3o de cada armadilha, mas aprende a natureza geral do perigo representado por uma armadilha que voc\xea sente."},{name:"Escudo de Fogo",level:4,classes:["Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"10 minutos",description:"Chamas finas e finas envolvem seu corpo durante toda a dura\xe7\xe3o, lan\xe7ando luz brilhante em um raio de 3 metros e luz fraca por mais 3 metros adicionais. Voc\xea pode encerrar o feiti\xe7o mais cedo usando uma a\xe7\xe3o para disfalha-lo.\n\nAs chamas fornecem um escudo quente ou um escudo frio, conforme voc\xea escolher. O escudo quente concede resist\xeancia ao dano de frio, e o escudo frio concede resist\xeancia ao dano de fogo.\n\nAl\xe9m disso, sempre que uma criatura a at\xe9 1,5 metro de voc\xea acerta um ataque corpo a corpo, o escudo explode em chamas. O atacante sofre 2d8 dano de fogo de um escudo quente, ou 2d8 dano de frio de um escudo frio."},{name:"L\xe2mina Flamejante",level:2,classes:["Druida"],school:"Evoca\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea evoca uma l\xe2mina de fogo em sua m\xe3o livre. A l\xe2mina \xe9 semelhante em tamanho e formato a uma cimitarra e dura o tempo todo. Se voc\xea soltar a l\xe2mina, ela desaparece, mas voc\xea pode evoc\xe1-la novamente como uma a\xe7\xe3o b\xf4nus.\n\nVoc\xea pode usar sua a\xe7\xe3o para fazer um ataque de magia corpo a corpo com a l\xe2mina de fogo. Sem sucesso, o alvo leva 3d6 de dano de fogo.\n\nA l\xe2mina flamejante emite luz brilhante em um raio de 3 metros e luz fraca por mais 3 metros adicionais."},{name:"Golpe de Chama",level:5,classes:["Cl\xe9rigo"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Uma coluna vertical de fogo divino desce dos c\xe9us em um local que voc\xea especificar. Cada criatura em um cilindro de raio de 3 metros e 40 p\xe9s de altura centrado em um ponto dentro do alcance deve fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre 4d6 de dano de fogo e 4d6 de dano radiante em um teste de resist\xeancia falho, ou metade do dano em um teste bem sucedido."},{name:"Esfera Flamejante",level:2,classes:["Druida","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Uma esfera de fogo de 1,5 metro de di\xe2metro aparece em um espa\xe7o desocupado de sua escolha dentro do alcance e dura enquanto durar. Qualquer criatura que termine seu turno a at\xe9 1,5 metro da esfera dever\xe1 fazer um Teste de resist\xeancia de Destreza. A criatura sofre 2d6 de dano de fogo em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso.\n\nComo a\xe7\xe3o b\xf4nus, voc\xea pode mover a esfera at\xe9 9 metros. Se voc\xea bater a esfera em uma criatura, essa criatura dever\xe1 fazer o teste de resist\xeancia contra o dano da esfera, e a esfera para de se mover neste turno.\n\nAo mover a esfera, voc\xea pode direcion\xe1-la sobre barreiras de at\xe9 1,5 metro de altura e saltar sobre po\xe7os de at\xe9 3 metros de largura. A esfera acende objetos inflam\xe1veis \u200b\u200bque n\xe3o est\xe3o sendo usados \u200b\u200bou carregados e emite luz brilhante em um raio de 6 metros e luz fraca por mais 6 metros adicionais."},{name:"Carne em Pedra",level:6,classes:["Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea tenta transformar uma criatura que voc\xea pode ver dentro do alcance em pedra. Se o corpo do alvo for de carne, a criatura dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, ele \xe9 imobilizado \xe0 medida que sua carne come\xe7a a endurecer. Em um teste de resist\xeancia bem sucedido, a criatura n\xe3o \xe9 afetada.\n\nUma criatura imobilizada por este feiti\xe7o dever\xe1 realizar outro teste de Constitui\xe7\xe3o de resist\xeancia ao final de cada um de seus turnos. Se ele conseguir salvar essa magia tr\xeas vezes, a magia termina. Se falhar no salvamento tr\xeas vezes, ele ser\xe1 transformado em pedra e submetido \xe0 condi\xe7\xe3o petrificado durante todo o tempo. Os sucessos e fracassos n\xe3o precisam ser consecutivos; acompanhe ambos at\xe9 que o alvo colete uma trinca.\n\nSe a criatura for fisicamente quebrada enquanto petrificada, ela sofrer\xe1 deformidades semelhantes se reverter ao seu estado original.\n\nSe voc\xea mantiver sua concentra\xe7\xe3o neste feiti\xe7o por toda a dura\xe7\xe3o poss\xedvel, a criatura se transformar\xe1 em pedra at\xe9 que o efeito seja removido."},{name:"Proibi\xe7\xe3o",level:6,classes:["Cl\xe9rigo"],school:"Abjura\xe7\xe3o",castingTime:"10 minutes",range:"Toque",duration:"1 day",description:"Voc\xea cria uma prote\xe7\xe3o contra viagens m\xe1gicas que protege at\xe9 40.000 p\xe9s quadrados de espa\xe7o a uma altura de 9 metros acima do ch\xe3o. Enquanto durar, as criaturas n\xe3o podem se teletransportar para a \xe1rea ou usar portais, como aqueles criados pelo feiti\xe7o port\xe3o (n\xedvel 9), para entrar na \xe1rea. O feiti\xe7o protege a \xe1rea contra viagens planares e, portanto, evita que criaturas acessem a \xe1rea por meio do feiti\xe7o Plano Astral, Plano Et\xe9reo, Fe\xe9ricowild, Shadowfell ou mudan\xe7a de plano (n\xedvel 7).\n\nAl\xe9m disso, o feiti\xe7o causa danos a tipos de criaturas que voc\xea escolhe ao conjur\xe1-lo. Escolha um ou mais dos seguintes: celestiais, elementais, fe\xe9ricos, inimigos e mortos-vivos. Quando uma criatura escolhida entra na \xe1rea da magia pela primeira vez em um turno ou come\xe7a seu turno l\xe1, a criatura sofre 5d10 de dano radiante ou necr\xf3tico (voc\xea escolhe quando voc\xea conjura essa magia).\n\nQuando voc\xea conjura essa magia, voc\xea pode designar uma senha. Uma criatura que pronuncie a senha ao entrar na \xe1rea n\xe3o sofre dano do feiti\xe7o.\n\nA \xe1rea da magia n\xe3o pode se sobrepor \xe0 \xe1rea de outra magia *proibi\xe7\xe3o*. Se voc\xea lan\xe7ar *proibi\xe7\xe3o* todos os dias durante 30 dias no mesmo local, o feiti\xe7o dura at\xe9 ser dissipado e os componentes materiais s\xe3o consumidos no \xfaltimo lan\xe7amento."},{name:"Liberdade de Movimentos",level:4,classes:["Bardo","Cl\xe9rigo","Druida","Patrulheiro"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"1 hora",description:"Voc\xea toca uma criatura volunt\xe1ria. Durante esse per\xedodo, o movimento do alvo n\xe3o \xe9 afetado por terreno dif\xedcil, e feiti\xe7os e outros efeitos m\xe1gicos n\xe3o podem reduzir a velocidade do alvo nem fazer com que o alvo fique paralisado ou imobilizado.\n\nO alvo tamb\xe9m pode gastar 1,5 metro de movimento para escapar automaticamente de restri\xe7\xf5es n\xe3o-m\xe1gicas, como algemas ou uma criatura que o tenha agarrado. Finalmente, estar submerso n\xe3o imp\xf5e penalidades ao movimento ou aos ataques do alvo."},{name:"Compromisso",level:5,classes:["Cl\xe9rigo","Mago","Paladino","Druida","Bardo"],school:"Encantamento",castingTime:"1 minute",range:"18 metros",duration:"30 dias",description:"Voc\xea coloca um comando m\xe1gico em uma criatura que voc\xea pode ver dentro do alcance, for\xe7ando-a a realizar algum servi\xe7o ou abster-se de alguma a\xe7\xe3o ou curso de atividade conforme voc\xea decidir. Se a criatura puder entend\xea-lo, ela dever\xe1 ter sucesso em um Teste de resist\xeancia de Sabedoria ou ser enfeiti\xe7ada por voc\xea durante esse per\xedodo. Enquanto a criatura for enfeitada por voc\xea, ela sofrer\xe1 5d10 de dano ps\xedquico cada vez que ela agir de maneira diretamente contr\xe1ria \xe0s suas instru\xe7\xf5es, mas n\xe3o mais do que uma vez por dia. Uma criatura que n\xe3o consegue entender voc\xea n\xe3o \xe9 afetada pelo feiti\xe7o.\n\nVoc\xea pode emitir qualquer comando que escolher, exceto uma atividade que resultaria em morte certa. Se voc\xea emitir um comando suicida, a magia termina.\n\nVoc\xea pode encerrar o feiti\xe7o mais cedo usando uma a\xe7\xe3o para disfalha-lo. Um feiti\xe7o remover maldi\xe7\xe3o (n\xedvel 3), restaura\xe7\xe3o maior (n\xedvel 5) ou desejo (n\xedvel 9) tamb\xe9m o encerra."},{name:"Repouso Gentil",level:2,classes:["Cl\xe9rigo","Mago"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"10 dias",description:"Voc\xea toca um cad\xe1ver ou outros restos mortais. Enquanto durar, o alvo fica protegido da decomposi\xe7\xe3o e n\xe3o pode se tornar morto-vivo.\n\nO feiti\xe7o tamb\xe9m estende efetivamente o limite de tempo para ressuscitar o alvo dos mortos, j\xe1 que os dias passados \u200b\u200bsob a influ\xeancia deste feiti\xe7o n\xe3o contam para o limite de tempo de feiti\xe7os como ressuscitar os mortos (n\xedvel 5)."},{name:"Inseto Gigante",level:4,classes:["Druida"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea transforma at\xe9 dez centop\xe9ias, tr\xeas aranhas, cinco vespas ou um escorpi\xe3o dentro do alcance em vers\xf5es de suas formas naturais durante a dura\xe7\xe3o. Uma centop\xe9ia se torna uma centop\xe9ia gigante, uma aranha se torna uma aranha gigante, uma vespa se torna uma vespa gigante e um escorpi\xe3o se torna um escorpi\xe3o gigante.\n\nCada criatura obedece aos seus comandos verbais e, em combate, eles agem no seu turno a cada rodada. O DM possui as estat\xedsticas dessas criaturas e resolve suas a\xe7\xf5es e momento.\n\nUma criatura permanece em seu tamanho gigante at\xe9 que caia para 0 pontos de vida, ou at\xe9 que voc\xea use uma a\xe7\xe3o para dissipar o efeito sobre ela.\n\nO Mestre pode permitir que voc\xea escolha diferentes alvos. por exemplo, se voc\xea transformar uma abelha, sua vers\xe3o gigante poder\xe1 ter as mesmas estat\xedsticas de uma vespa gigante."},{name:"Globo de Invulnerabilidade",level:6,classes:["Feiticeiro","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Uma barreira im\xf3vel e levemente cintilante surge em um raio de 3 metros ao seu redor e permanece durante todo o tempo.\n\nQualquer magia de 5\xba n\xedvel ou inferior lan\xe7ada de fora da barreira n\xe3o pode afetar criaturas ou objetos dentro dela, mesmo que a magia seja lan\xe7ada usando um n\xedvel superior de espa\xe7o de magia. Tal feiti\xe7o pode atingir criaturas e objetos dentro da barreira, mas o feiti\xe7o n\xe3o tem efeito sobre eles. Da mesma forma, a \xe1rea dentro da barreira \xe9 exclu\xedda das \xe1reas afetadas por tais feiti\xe7os."},{name:"Glifo de Prote\xe7\xe3o",level:3,classes:["Cl\xe9rigo","Mago","Bardo"],school:"Abjura\xe7\xe3o",castingTime:"1 hour",range:"Toque",duration:"At\xe9 ser dissipada ou acionada",description:"Quando voc\xea conjura essa magia, voc\xea inscreve um glifo que mais tarde libera um efeito m\xe1gico. Voc\xea o inscreve em uma superf\xedcie (como uma mesa ou uma se\xe7\xe3o do ch\xe3o ou parede) ou dentro de um objeto que pode ser fechado (como um livro, um pergaminho ou um ba\xfa de tesouro) para ocultar o glifo. O glifo pode cobrir uma \xe1rea n\xe3o superior a 3 metros de di\xe2metro. Se a superf\xedcie ou objeto for movido mais de 3 metros de onde voc\xea lan\xe7ou este feiti\xe7o, o glifo ser\xe1 quebrado e a magia terminar\xe1 sem ser acionada. \n\n O glifo \xe9 quase invis\xedvel e requer um teste bem sucedido de Intelig\xeancia (Investiga\xe7\xe3o) contra seu CD de resist\xeancia de magia para ser encontrado. \n\n Voc\xea decide o que aciona o glifo quando voc\xea conjura uma magia. Para glifos inscritos em uma superf\xedcie, os gatilhos mais t\xedpicos incluem tocar ou ficar sobre o glifo, remover outro objeto que cobre o glifo, aproximar-se a uma certa dist\xe2ncia do glifo ou manipular o objeto no qual o glifo est\xe1 inscrito. Para glifos inscritos em um objeto, os gatilhos mais comuns incluem abrir esse objeto, aproximar-se a uma certa dist\xe2ncia do objeto ou ver ou ler o glifo. Uma vez que um glifo \xe9 acionado, esta magia termina. \n\n Voc\xea pode refinar ainda mais o gatilho para que a magia seja ativada apenas sob certas circunst\xe2ncias ou de acordo com caracter\xedsticas f\xedsicas (como altura ou peso), tipo de criatura (por exemplo, a prote\xe7\xe3o pode ser configurada para afetar aberra\xe7\xf5es ou drow) ou alinhamento. Voc\xea tamb\xe9m pode definir condi\xe7\xf5es para criaturas que n\xe3o acionam o glifo, como aquelas que dizem uma determinada senha. \n\n Ao inscrever o glifo, escolha runas explosivas ou um glifo m\xe1gico. \n\nRunas Explosivas: Quando acionado, o glifo irrompe com energia m\xe1gica em uma esfera de 6 metros de raio centrada no glifo. A esfera espalha cantos ao redorda. Cada criatura da \xe1rea dever\xe1 fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre 5d8 de \xe1cido, frio, fogo, raio ou dano s\xf4nico se falhar no teste de resist\xeancia (sua escolha quando Voc\xea cria o glifo), ou metade do dano se falhar. \n\nGlifo de Feiti\xe7o: Voc\xea pode armazenar um feiti\xe7o preparado de 3\xba n\xedvel ou inferior no glifo, lan\xe7ando-o como parte da cria\xe7\xe3o do glifo. O feiti\xe7o deve atingir uma \xfanica criatura ou \xe1rea. O feiti\xe7o armazenado n\xe3o tem efeito imediato quando lan\xe7ado desta forma. Quando o glifo \xe9 acionado, o feiti\xe7o armazenado \xe9 lan\xe7ado. Se o feiti\xe7o tiver um alvo, ele atingir\xe1 a criatura que acionou o glifo. Se a magia afetar uma \xe1rea, a \xe1rea ser\xe1 centrada naquela criatura. Se o feiti\xe7o invocar criaturas hostis ou criar objetos ou armadilhas prejudiciais, elas aparecem o mais pr\xf3ximo poss\xedvel do intruso e o atacam. Se o feiti\xe7o exigir concentra\xe7\xe3o, ele dura at\xe9 o final de sua dura\xe7\xe3o total."},{name:"Videira Apreensora",level:4,classes:["Patrulheiro","Druida"],school:"Conjura\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea conjura uma videira que brota da solo em um espa\xe7o desocupado de sua escolha que voc\xea possa ver dentro do alcance. Quando voc\xea conjura essa magia, voc\xea pode direcionar a videira para atacar uma criatura a at\xe9 9 metros dela que voc\xea puder ver. Essa criatura deve ter sucesso em um Teste de resist\xeancia de Destreza ou ser\xe1 puxada 6 metros diretamente em dire\xe7\xe3o \xe0 videira.\n\nAt\xe9 o final da magia, voc\xea pode direcionar a videira para atacar a mesma criatura ou outra como b\xf4nus de a\xe7\xe3o em cada um de seus turnos."},{name:"Invisibilidade Superior",level:4,classes:["Feiticeiro","Mago","Bardo"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea ou uma criatura que voc\xea toca fica invis\xedvel at\xe9 o fim da magia. Qualquer coisa que o alvo esteja vestindo ou carregando \xe9 invis\xedvel, desde que esteja na pessoa do alvo."},{name:"Restaura\xe7\xe3o Superior",level:5,classes:["Cl\xe9rigo","Druida","Bardo"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"Voc\xea imbui uma criatura que toca com energia positiva para desfazer um efeito debilitante. Voc\xea pode reduzir o n\xedvel de exaust\xe3o do alvo em um, ou encerrar um dos seguintes efeitos no alvo:\n\nUm efeito que enfeiti\xe7ado ou petrificou o alvoUma maldi\xe7\xe3o, incluindo a sintoniza\xe7\xe3o do alvo com um item m\xe1gico amaldi\xe7oadoQualquer redu\xe7\xe3o em um dos valores de habilidade do alvoUm efeito que reduz ao m\xe1ximo o ponto de vida do alvo"},{name:"Guardi\xe3o da F\xe9",level:4,classes:["Cl\xe9rigo"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"8 horas",description:"Um grande guardi\xe3o espectral aparece e paira enquanto durar em um espa\xe7o desocupado de sua escolha que voc\xea possa ver dentro do alcance. O guardi\xe3o ocupa esse espa\xe7o e \xe9 indistinto, exceto por uma espada brilhante e um escudo estampado com o s\xedmbolo de sua divindade.\n\nQualquer criatura hostil a voc\xea que se mova para um espa\xe7o de at\xe9 3 metros do guardi\xe3o pela primeira vez em um turno dever\xe1 ter sucesso em um Teste de resist\xeancia de Destreza. A criatura leva 20 de dano radiante em um teste de resist\xeancia falho, ou metade do dano em um teste bem-sucedido. O guardi\xe3o desaparece quando causa um total de 60 de dano."},{name:"Guardas e Vigias",level:6,classes:["Mago","Bardo"],school:"Abjura\xe7\xe3o",castingTime:"10 minutes",range:"Toque",duration:"24 horas",description:"Voc\xea cria uma enfermaria que protege at\xe9 2.500 p\xe9s quadrados de \xe1rea \xfatil (uma \xe1rea de 50 p\xe9s quadrados, ou cem quadrados de 1,5 metro ou vinte e cinco quadrados de 3 metros). A \xe1rea protegida pode ter at\xe9 6 metros de altura e ter o formato que voc\xea desejar. Voc\xea pode proteger v\xe1rios andares de uma fortaleza dividindo a \xe1rea entre eles, desde que voc\xea possa entrar em cada \xe1rea cont\xedgua enquanto lan\xe7a o feiti\xe7o.\n\nQuando voc\xea conjura essa magia, voc\xea pode especificar indiv\xedduos que n\xe3o s\xe3o afetados por nenhum ou todos os efeitos que voc\xea escolher. Voc\xea tamb\xe9m pode especificar uma senha que, quando falada em voz alta, torne o locutor imune a esses efeitos. Guardas e sentinelas criam os seguintes efeitos dentro da \xe1rea protegida. Coloque luzes dan\xe7antes (cantrip) em quatro corredores. Voc\xea pode designar um programa simples que as luzes repitam enquanto durarem os guardas e enfermarias. Coloque a boca m\xe1gica (n\xedvel 2) em dois locais. Coloque a nuvem fedorenta (n\xedvel 3) em dois locais. Os vapores aparecem nos locais que voc\xea designar; Eles retornam dentro de 10 minutos se forem dispersos pelo vento enquanto durarem os guardas e enfermarias. Coloque uma rajada de vento constante (n\xedvel 2) em um corredor ou sala. Coloque uma sugest\xe3o (n\xedvel 2) em um local. Voc\xea seleciona uma \xe1rea de at\xe9 1,5 metro quadrado, e qualquer criatura que entre ou passe pela \xe1rea recebe a sugest\xe3o mentalmente. Toda a \xe1rea protegida irradia magia. Uma dissipa\xe7\xe3o de magia (n\xedvel 3) lan\xe7ada em um efeito espec\xedfico, se bem-sucedida, remove apenas esse efeito.\n\nVoc\xea pode criar uma estrutura permanentemente protegida e protegida lan\xe7ando esse feiti\xe7o l\xe1 todos os dias durante um ano."},{name:"Rajada de Vento",level:2,classes:["Feiticeiro","Mago","Druida"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (60-foot line)",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Uma linha de vento forte de 18 metros de comprimento e 3 metros de largura sopra de voc\xea em uma dire\xe7\xe3o que voc\xea escolher durante a dura\xe7\xe3o do feiti\xe7o. Cada criatura que inicia seu turno na linha deve ser bem sucedida em um Teste de resist\xeancia de For\xe7a ou ser empurrada 4,5 metros para longe de voc\xea na dire\xe7\xe3o seguinte \xe0 linha.\n\nQualquer criatura na linha deve gastar 60 cent\xedmetros de movimento para cada 30 cent\xedmetros que se mover ao se aproximar de voc\xea.\n\nA rajada dispersa g\xe1s ou vapor e extingue velas, tochas e chamas desprotegidas semelhantes na \xe1rea. Faz com que chamas protegidas, como as de lanternas, dancem descontroladamente e tem 50% de chance de apag\xe1-las.\n\nComo b\xf4nus de a\xe7\xe3o em cada um de seus turnos antes do t\xe9rmino da magia, voc\xea pode mudar a dire\xe7\xe3o em que a linha sai de voc\xea."},{name:"Terreno Alucinat\xf3rio",level:4,classes:["Bardo","Druida","Bruxo","Mago"],school:"Ilus\xe3o",castingTime:"10 minutes",range:"90 metros",duration:"24 horas",description:"Voc\xea faz com que o terreno natural em um cubo de 150 p\xe9s de alcance pare\xe7a, soe e cheire como algum outro tipo de terreno natural. Assim, campos abertos ou uma estrada podem assemelhar-se a um p\xe2ntano, colina, fenda ou algum outro terreno dif\xedcil ou intransit\xe1vel. Um lago pode parecer um prado gramado, um precip\xedcio como uma encosta suave ou um barranco coberto de pedras como uma estrada larga e lisa. Estruturas fabricadas, equipamentos e criaturas dentro da \xe1rea n\xe3o mudam em apar\xeancia.\n\nAs caracter\xedsticas t\xe1teis do terreno permanecem inalteradas, ent\xe3o as criaturas que entram na \xe1rea provavelmente ver\xe3o atrav\xe9s da ilus\xe3o. Se a diferen\xe7a n\xe3o for \xf3bvia ao toque, uma criatura examinando cuidadosamente a ilus\xe3o pode tentar um teste de Intelig\xeancia (Investiga\xe7\xe3o) contra seu CD de resist\xeancia de magia para desacredit\xe1-la. Uma criatura que discerne a ilus\xe3o pelo que ela \xe9, v\xea-a como uma imagem vaga sobreposta ao terreno."},{name:"Consagrar",level:5,classes:["Cl\xe9rigo"],school:"Evoca\xe7\xe3o",castingTime:"24 hours",range:"Toque",duration:"At\xe9 ser dissipada",description:"Voc\xea toca um ponto e infunde uma \xe1rea ao redorda com poder sagrado (ou profano). A \xe1rea pode ter um raio de at\xe9 18 metros, e o feiti\xe7o falha se o raio incluir uma \xe1rea j\xe1 sob o efeito de um feiti\xe7o sagrado. A \xe1rea afetada est\xe1 sujeita aos seguintes efeitos. Primeiro, celestiais, elementais, fe\xe9ricos, inimigos e mortos-vivos n\xe3o podem entrar na \xe1rea, nem tais criaturas podem encantar, assustar ou possuir criaturas dentro dela. Qualquer criatura enfeiti\xe7ado, amedrontado ou possu\xedda por tal criatura n\xe3o ser\xe1 mais enfeiti\xe7ado, amedrontado ou possu\xeddo ao entrar na \xe1rea. Voc\xea pode excluir um ou mais desses tipos de criaturas deste efeito. Segundo, voc\xea pode vincular um efeito extra \xe0 \xe1rea. Escolha o efeito da lista a seguir ou escolha um efeito oferecido pelo Mestre. Alguns destes efeitos se aplicam \xe0s criaturas da \xe1rea; voc\xea pode designar se o efeito se aplica a todas as criaturas, criaturas que seguem uma divindade ou l\xedder espec\xedfico, ou criaturas de um tipo espec\xedfico, como orcs ou trolls. Quando uma criatura que seria afetada entra na \xe1rea do feiti\xe7o pela primeira vez em um turno ou inicia seu turno ali, ela pode realizar um Teste de resist\xeancia de Carisma. Se obtiver sucesso, a criatura ignora o efeito extra at\xe9 sair da \xe1rea. \n\nCoragem: As criaturas afetadas n\xe3o podem ser amedrontadas enquanto estiverem na \xe1rea. \n\nEscurid\xe3o: A escurid\xe3o preenche a \xe1rea. A luz normal, assim como a luz m\xe1gica criada por magias de n\xedvel inferior ao slot que voc\xea usou para lan\xe7ar esta magia, n\xe3o pode iluminar a \xe1rea. \n\nLuz do dia: A luz brilhante preenche a \xe1rea. A escurid\xe3o m\xe1gica criada por feiti\xe7os de n\xedvel inferior ao slot que voc\xea usou para lan\xe7ar este feiti\xe7o n\xe3o pode extinguir a luz. \n\nProte\xe7\xe3o de Energia: As criaturas afetadas na \xe1rea t\xeam resist\xeancia a um tipo de dano \xe0 sua escolha, exceto concuss\xe3o, perfurante ou cortante. \n\nVulnerabilidade \xe0 Energia: As criaturas afetadas na \xe1rea t\xeam vulnerabilidade a um tipo de dano \xe0 sua escolha, exceto concuss\xe3o, perfurante ou cortante. \n\nDescanso Eterno: Cad\xe1veres enterrados na \xe1rea n\xe3o podem ser transformados em mortos-vivos. \n\nInterfer\xeancia Extradimensional: As criaturas afetadas n\xe3o podem se mover ou viajar usando teletransporte ou por meios extradimensionais ou interplanares. \n\nMedo: As criaturas afetadas ficam amedrontadas enquanto est\xe3o na \xe1rea. \n\nSil\xeancio: Nenhum som pode emanar de dentro da \xe1rea e nenhum som pode alcan\xe7\xe1-la. \n\nL\xednguas: As criaturas afetadas podem se comunicar com qualquer outra criatura na \xe1rea, mesmo que n\xe3o compartilhem uma l\xedngua comum."},{name:"Causar Dano",level:6,classes:["Cl\xe9rigo"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea libera uma doen\xe7a virulenta em uma criatura que voc\xea pode ver dentro do alcance. O alvo dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, s\xe3o necess\xe1rios 14d6 dano necr\xf3tico, ou metade do dano em um teste de resist\xeancia bem-sucedido. O dano n\xe3o pode reduzir os pontos de vida do alvo abaixo de 1. Se o alvo falhar no teste de resist\xeancia, seu ponto de vida m\xe1ximo \xe9 reduzido por 1 hora em uma quantidade igual ao dano necr\xf3tico que sofreu. Qualquer efeito que remova uma doen\xe7a permite que o ponto de vida m\xe1ximo de uma criatura retorne ao normal antes que esse tempo passe."},{name:"Aquecer Metal",level:2,classes:["Druida","Bardo"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Escolha um objeto de metal manufaturado, como uma arma de metal ou uma armadura de metal pesado ou m\xe9dio, que voc\xea possa ver dentro do alcance. Voc\xea faz com que o objeto brilhe em brasa. Qualquer criatura em contato f\xedsico com o objeto sofre 2d8 de dano de fogo quando voc\xea conjura uma magia. At\xe9 o fim da magia, voc\xea pode usar um b\xf4nus de a\xe7\xe3o em cada um dos seus turnos subsequentes para causar esse dano novamente.\n\nSe uma criatura estiver segurando ou usando o objeto e sofrer o dano dele, a criatura dever\xe1 ter sucesso em um Teste de resist\xeancia de Constitui\xe7\xe3o ou largar o objeto, se puder. Caso n\xe3o deixe cair o objeto, ele ter\xe1 manobra de ataque e teste de habilidades at\xe9 o in\xedcio do seu pr\xf3ximo turno."},{name:"Curar",level:6,classes:["Cl\xe9rigo","Druida"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Escolha uma criatura que voc\xea possa ver dentro do alcance. Uma onda de energia positiva percorre a criatura, fazendo com que ela recupere 70 pontos de vida. Este feiti\xe7o tamb\xe9m acaba com a cegueira, a surdez e quaisquer doen\xe7as que afetem o alvo. Este feiti\xe7o n\xe3o tem efeito sobre constructos ou mortos-vivos."},{name:"Banquete dos Her\xf3is",level:6,classes:["Cl\xe9rigo","Druida"],school:"Conjura\xe7\xe3o",castingTime:"10 minutes",range:"9 metros",duration:"Instant\xe2neo",description:"Voc\xea oferece um grande banquete, incluindo comida e bebida magn\xedficas. O banquete leva 1 hora para ser consumido e desaparece ao final desse tempo, e os efeitos ben\xe9ficos n\xe3o se instalam at\xe9 que essa hora termine. At\xe9 doze outras criaturas podem participar do banquete.\n\nUma criatura que participa do banquete ganha v\xe1rios benef\xedcios. A criatura \xe9 curada de todas as doen\xe7as e venenos, torna-se imune ao veneno e ao amedrontado, e faz todo Teste de resist\xeancia de Sabedorias com vantagem. Seu ponto de vida m\xe1ximo tamb\xe9m aumenta em 2d10 e ganha o mesmo n\xfamero de pontos de vida. Esses benef\xedcios duram 24 horas."},{name:"Paralisar Monstro",level:5,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Escolha uma criatura que voc\xea possa ver dentro do alcance. O deve ser aprovado em Teste de resist\xeancia de Sabedoria ou ficar paralisado durante o per\xedodo. Este feiti\xe7o n\xe3o tem efeito em mortos-vivos. Ao final de cada um de seus turnos, o alvo pode fazer outro Teste de resist\xeancia de Sabedoria. Com um sucesso, a magia termina no alvo."},{name:"Tempestade de Gelo",level:4,classes:["Druida","Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"90 metros",duration:"Instant\xe2neo",description:"Uma chuva de gelo duro como rocha atinge a solo em um cilindro de 6 metros de raio e 12 metros de altura centrado em um ponto dentro do alcance. Cada criatura no cilindro deve fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre 2d8 de dano de concuss\xe3o e 4d6 de dano de frio em um teste de resist\xeancia falho, ou metade do dano em um teste bem-sucedido.\n\nGranizo transforma a \xe1rea de efeito da tempestade em terreno dif\xedcil at\xe9 o final do seu pr\xf3ximo turno."},{name:"Praga de Insetos",level:5,classes:["Cl\xe9rigo","Druida","Feiticeiro"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"90 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Gafanhotos que atacam e mordem preenchem uma esfera de 6 metros de raio centrada em um ponto que voc\xea escolher dentro do alcance. A esfera se espalha pelos cantos ao redorda. A esfera permanece enquanto durar e sua \xe1rea fica levemente obscurecida. A \xe1rea da esfera \xe9 um terreno dif\xedcil.\n\nQuando a \xe1rea aparecer, cada criatura nela contida dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Uma criatura sofre 4d10 dano perfurante em um teste de resist\xeancia falho, ou metade do dano se for bem sucedido. Uma criatura tamb\xe9m deve realizar este teste de resist\xeancia quando entrar na \xe1rea da magia pela primeira vez em um turno ou terminar seu turno ali."},{name:"Destravar",level:2,classes:["Feiticeiro","Mago","Bardo"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Escolha um objeto que voc\xea possa ver dentro do alcance. O objeto pode ser uma porta, uma caixa, um ba\xfa, um conjunto de algemas, um cadeado ou outro objeto que contenha um meio mundano ou m\xe1gico que impe\xe7a o acesso.\n\nUm alvo que \xe9 mantido fechado por uma fechadura mundana ou que est\xe1 preso ou barrado torna-se destrancado, destravado ou destravado. Se o objeto tiver v\xe1rios bloqueios, apenas um deles ser\xe1 desbloqueado.\n\nSe voc\xea escolher um alvo que \xe9 mantido fechado com fechadura arcana (n\xedvel 2), esse feiti\xe7o \xe9 suprimido por 10 minutos, per\xedodo durante o qual o alvo pode ser aberto e fechado normalmente.\n\nQuando voc\xea conjura uma magia, uma batida forte, aud\xedvel a uma dist\xe2ncia de at\xe9 300 p\xe9s, emana do objeto alvo."},{name:"Conhecimento Lend\xe1rio",level:5,classes:["Cl\xe9rigo","Mago","Bardo"],school:"Adivinha\xe7\xe3o",castingTime:"10 minutes",range:"Si mesmo",duration:"Instant\xe2neo",description:"Nomeie ou descreva uma pessoa, lugar ou objeto. O feiti\xe7o traz \xe0 sua mente um breve resumo do conhecimento significativo sobre a coisa que voc\xea nomeou. A tradi\xe7\xe3o pode consistir em contos atuais, hist\xf3rias esquecidas ou at\xe9 mesmo conhecimento secreto que nunca foi amplamente conhecido. Se a coisa que voc\xea nomeou n\xe3o for de import\xe2ncia lend\xe1ria, voc\xea n\xe3o obter\xe1 nenhuma informa\xe7\xe3o. Quanto mais informa\xe7\xf5es voc\xea j\xe1 tiver sobre o assunto, mais precisas e detalhadas ser\xe3o as informa\xe7\xf5es que voc\xea receber\xe1.\n\nAs informa\xe7\xf5es que voc\xea aprende s\xe3o precisas, mas podem ser expressas em linguagem figurada. Por exemplo, se voc\xea tiver um machado m\xe1gico misterioso em m\xe3os, o feiti\xe7o pode fornecer esta informa\xe7\xe3o: Ai do malfeitor cuja m\xe3o tocar o machado, pois at\xe9 mesmo o cabo corta a m\xe3o dos malignos. Somente um verdadeiro Filho de Pedra, amante e amado de Moradin, pode despertar os verdadeiros poderes do machado, e somente com a palavra sagrada Rudnogg nos l\xe1bios."},{name:"Levitar",level:2,classes:["Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Uma criatura ou objeto de sua escolha que voc\xea possa ver dentro do alcance sobe verticalmente, at\xe9 6 metros, e permanece suspenso ali durante todo o tempo. O feiti\xe7o pode levitar um alvo que pesa at\xe9 500 quilos. A incriatura volunt\xe1ria que obtiver \xeaxito no Teste de resist\xeancia de Constitui\xe7\xe3o n\xe3o \xe9 afetada.\n\nO alvo s\xf3 pode se mover empurrando ou puxando um objeto fixo ou superf\xedcie ao seu alcance (como uma parede ou teto), o que lhe permite mover-se como se estivesse escalando. Voc\xea pode alterar a altitude do alvo em at\xe9 6 metros em qualquer dire\xe7\xe3o no seu turno. Se voc\xea for o alvo, poder\xe1 subir ou descer como parte do seu movimento. Caso contr\xe1rio, voc\xea pode usar sua a\xe7\xe3o para mover o alvo, que deve permanecer dentro do alcance do feiti\xe7o.\n\nQuando a magia termina, o alvo flutua suavemente at\xe9 a solo se ela ainda estiver no ar."},{name:"Localizar Animais ou Plantas",level:2,classes:["Bardo","Druida","Patrulheiro"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Instant\xe2neo",description:"Descreva ou nomeie um tipo espec\xedfico de besta ou planta. Concentrando-se na voz da natureza em seus arredores, voc\xea aprende a dire\xe7\xe3o e a dist\xe2ncia at\xe9 a criatura ou planta mais pr\xf3xima desse tipo num raio de 8 quil\xf4metros, se houver alguma presente."},{name:"Raio",level:3,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (100-foot line)",duration:"Instant\xe2neo",description:"Um raio formando uma linha de 30 metros de comprimento e 1,5 metro de largura sai de voc\xea na dire\xe7\xe3o que voc\xea escolher. Cada criatura da linha dever\xe1 fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre 8d6 de dano de raio em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso.\n\nO raio incendeia objetos inflam\xe1veis \u200b\u200bna \xe1rea que n\xe3o est\xe3o sendo usados \u200b\u200bou carregados."},{name:"Localizar Criatura",level:4,classes:["Bardo","Cl\xe9rigo","Druida","Paladino","Patrulheiro","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Descreva ou nomeie uma criatura que lhe seja familiar. Voc\xea sente a dire\xe7\xe3o da localiza\xe7\xe3o da criatura, desde que ela esteja a at\xe9 300 metros de voc\xea. Se a criatura estiver se movendo, voc\xea sabe a dire\xe7\xe3o do seu movimento.\n\nO feiti\xe7o pode localizar uma criatura espec\xedfica conhecida por voc\xea, ou a criatura mais pr\xf3xima de um tipo espec\xedfico (como um humano ou um unic\xf3rnio), desde que voc\xea tenha visto tal criatura de perto - a at\xe9 9 metros - pelo menos uma vez. Se a criatura que voc\xea descreveu ou nomeou estiver em uma forma diferente, como sob os efeitos de um feiti\xe7o polimorfo (n\xedvel 4), este feiti\xe7o n\xe3o localiza a criatura.\n\nEste feiti\xe7o n\xe3o pode localizar uma criatura se \xe1gua corrente com pelo menos 3 metros de largura bloquear um caminho direto entre voc\xea e a criatura."},{name:"Localizar Objeto",level:2,classes:["Bardo","Cl\xe9rigo","Druida","Paladino","Patrulheiro","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Descreva ou nomeie um objeto que lhe seja familiar. Voc\xea sente a dire\xe7\xe3o da localiza\xe7\xe3o do objeto, desde que esse objeto esteja a at\xe9 300 metros de voc\xea. Se o objeto estiver em movimento, voc\xea sabe a dire\xe7\xe3o do seu movimento.\n\nO feiti\xe7o pode localizar um objeto espec\xedfico conhecido por voc\xea, desde que voc\xea o tenha visto de perto \u2013 a at\xe9 9 metros \u2013 pelo menos uma vez. Alternativamente, a magia pode localizar o objeto mais pr\xf3ximo de um tipo espec\xedfico, como um certo tipo de roupa, joia, mob\xedlia, ferramenta ou arma.\n\nEste feiti\xe7o n\xe3o consegue localizar um objeto se qualquer espessura de chumbo, mesmo uma folha fina, bloquear um caminho direto entre voc\xea e o objeto."},{name:"Jarro M\xe1gico",level:6,classes:["Mago"],school:"Necromancia",castingTime:"1 minute",range:"Si mesmo",duration:"At\xe9 ser dissipada",description:"Seu corpo cai em um estado catat\xf4nico quando sua alma o deixa e entra no recipiente que voc\xea usou para o componente material do feiti\xe7o. Enquanto sua alma habita o recipiente, voc\xea fica consciente de seus arredores como se estivesse no espa\xe7o do recipiente. Voc\xea n\xe3o pode mover ou usar fatos. A \xfanica a\xe7\xe3o que voc\xea pode realizar \xe9 projetar sua alma at\xe9 30 metros para fora do recipiente, seja retornando ao seu corpo vivo (e encerrando o feiti\xe7o) ou tentando possuir o corpo de um human\xf3ide.\n\nVoc\xea pode tentar possuir qualquer human\xf3ide a at\xe9 30 metros de voc\xea que voc\xea possa ver (criaturas protegidas por um feiti\ufffd\ufffdo de prote\xe7\xe3o contra o mal e o bem (n\xedvel 1) ou c\xedrculo m\xe1gico (n\xedvel 3) n\xe3o podem ser possu\xeddas). O alvo deve fazer um Teste de resist\xeancia de Carisma. Em caso de falha, sua alma se move para o corpo do alvo, e a alma do alvo fica presa no recipiente. Se obtiver sucesso, o alvo resiste aos seus esfor\xe7os para possu\xed-lo e voc\xea n\xe3o poder\xe1 tentar possu\xed-lo novamente por 24 horas.\n\nDepois de possuir o corpo de uma criatura, voc\xea a controla. Suas estat\xedsticas de jogo s\xe3o substitu\ufffd\ufffddas pelas estat\xedsticas da criatura, embora voc\xea mantenha sua tend\xeancia e seus valores de Intelig\xeancia, Sabedoria e Carisma. Voc\xea ret\xe9m o benef\xedcio de seus pr\xf3prios recursos de classe. Se o alvo tiver algum n\xedvel de classe, voc\xea n\xe3o poder\xe1 usar nenhum de seus recursos de classe.\n\nEnquanto isso, a alma da criatura possu\xedda pode perceber o que est\xe1 no recipiente usando seus pr\xf3prios sentidos, mas n\xe3o pode se mover ou realizar a\xe7\xf5es.\n\nEnquanto possuir um corpo, voc\xea pode usar sua a\xe7\xe3o para retornar do corpo hospedeiro para o cont\xeainer se ele estiver a at\xe9 30 metros de voc\xea, devolvendo a alma da criatura hospedeira ao seu corpo. Se o corpo hospedeiro morrer enquanto voc\xea estiver nele, a criatura morre e voc\xea dever\xe1 fazer um Teste de resist\xeancia de Carisma contra sua pr\xf3pria CD de conjura\xe7\xe3o. Se obtiver sucesso, voc\xea retorna ao cont\xeainer se ele estiver a at\xe9 30 metros de voc\xea. Caso contr\xe1rio, voc\xea morre.\n\nSe o recipiente for destru\xeddo ou a magia terminar, sua alma retornar\xe1 imediatamente ao seu corpo. Se seu corpo estiver a mais de 30 metros de voc\xea ou se seu corpo estiver morto quando voc\xea tentar retornar a ele, voc\xea morre. Se a alma de outra criatura estiver no recipiente quando ele for destru\xeddo, a alma da criatura retornar\xe1 ao seu corpo se o corpo estiver vivo e dentro de 30 metros. Caso contr\xe1rio, essa criatura morre.\n\nQuando a magia termina, o cont\xeainer \xe9 destru\xeddo."},{name:"Arma M\xe1gica",level:2,classes:["Paladino","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea toca uma arma n\xe3o-m\xe1gica. At\xe9 o fim da magia, essa arma se torna uma arma m\xe1gica com b\xf4nus de +1 para jogo de ataques e jogadas de dano."},{name:"Boca M\xe1gica",level:2,classes:["Bardo","Mago"],school:"Ilus\xe3o",castingTime:"1 minute",range:"9 metros",duration:"At\xe9 ser dissipada",description:"Voc\xea implanta uma mensagem dentro de um objeto ao alcance, uma mensagem que \xe9 pronunciada quando uma condi\xe7\xe3o de disparo \xe9 atendida. Escolha um objeto que voc\xea possa ver e que n\xe3o esteja sendo usado ou carregado por outra criatura e, em seguida, fale a mensagem, que deve ter 25 palavras ou menos, embora possa ser entregue em at\xe9 dez minutos. Finalmente, determine a circunst\xe2ncia que acionar\xe1 o feiti\xe7o para entregar sua mensagem.\n\nQuando essa circunst\xe2ncia ocorre, uma boca m\xe1gica aparece no objeto e recita a mensagem em sua voz no mesmo volume que voc\xea falou. Se o objeto que voc\xea escolheu tiver uma boca ou algo parecido com uma boca (por exemplo, a boca de uma est\xe1tua) a boca m\xe1gica aparece ali para que as palavras pare\xe7am vir da boca do objeto. Quando voc\xea conjura essa magia, voc\xea pode fazer com que o feiti\xe7o termine ap\xf3s entregar sua mensagem ou ele pode permanecer e repetir sua mensagem sempre que o gatilho ocorrer.\n\nA circunst\xe2ncia desencadeadora pode ser t\xe3o geral ou detalhada quanto voc\xea desejar, mas deve ser baseada em condi\xe7\xf5es visuais ou sonoras que ocorrem a at\xe9 9 metros do objeto. Por exemplo, voc\xea poderia instruir a boca a falar quando alguma criatura se mover a at\xe9 9 metros do objeto ou quando um sino prateado tocar a at\xe9 9 metros."},{name:"Curar Ferimentos em Massa",level:5,classes:["Bardo","Cl\xe9rigo","Druida"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Uma onda de energia curativa sai de um ponto de sua escolha dentro do alcance. Escolha at\xe9 seis criaturas em uma esfera de 9 metros de raio centrada naquele ponto. Cada alvo recupera pontos de vida iguais a 3d8 + seu modificador de atributo de conjura\xe7\xe3o. Este feiti\xe7o n\xe3o tem efeito sobre mortos-vivos ou constructos."},{name:"Sugest\xe3o em Massa",level:6,classes:["Bardo","Feiticeiro","Bruxo","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"24 horas",description:"Voc\xea sugere um curso de atividade (limitado a uma frase ou duas) e influencia magicamente at\xe9 doze criaturas de sua escolha que voc\xea possa ver dentro do alcance e que possam ouvir e compreender voc\xea. Criaturas que n\xe3o podem ser feiti\xe7adas ficam imunes a esse efeito. A sugest\xe3o deve ser formulada de forma a fazer com que o curso da a\xe7\xe3o pare\xe7a razo\xe1vel. Pedir \xe0 criatura que se esfaqueie, se jogue em uma lan\xe7a, se imole ou fa\xe7a algum outro ato obviamente prejudicial anula automaticamente o efeito do feiti\xe7o.\n\nCada alvo dever\xe1 fazer um Teste de resist\xeancia de Sabedoria. Em um teste de resist\xeancia falho, ele prossegue o curso de a\xe7\xe3o que voc\xea descreveu da melhor maneira poss\xedvel. O curso de a\xe7\xe3o sugerido pode continuar durante todo o per\xedodo. Se a atividade sugerida puder ser conclu\xedda em menos tempo, a magia termina quando o sujeito terminar o que foi solicitado.\n\nVoc\xea tamb\xe9m pode especificar condi\xe7\xf5es que desencadear\xe3o uma atividade especial durante a dura\xe7\xe3o. Por exemplo, voc\xea pode sugerir que um grupo de soldados d\xea todo o seu dinheiro ao primeiro mendigo que encontrar. Se a condi\xe7\xe3o n\xe3o for atendida antes do t\xe9rmino da magia, a atividade n\xe3o ser\xe1 realizada.\n\nSe voc\xea ou qualquer um de seus companheiros causar dano a uma criatura afetada por esta magia, a magia termina para aquela criatura."},{name:"Imagem Espelhada",level:2,classes:["Feiticeiro","Bruxo","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"1 minuto",description:"Tr\xeas duplicatas ilus\xf3rias de voc\xea mesmo aparecem em seu espa\xe7o. At\xe9 o final da magia, as duplicatas se movem com voc\xea e imitam suas a\xe7\xf5es, mudando de posi\xe7\xe3o para que seja imposs\xedvel rastrear qual imagem \xe9 real. Voc\xea pode usar sua a\xe7\xe3o para disfalhar as duplicatas ilus\xf3rias.\n\nCada vez que uma criatura atingir voc\xea com um ataque durante a dura\xe7\xe3o da magia, jogue um d20 para determinar se o ataque atinge uma de suas duplicatas.\n\nSe voc\xea tiver tr\xeas duplicatas, dever\xe1 tirar 6 ou superior para alterar o alvo do ataque para uma duplicata. Com duas duplicatas, voc\xea deve obter um 8 ou superior. Com uma duplicata, voc\xea deve tirar 11 ou superior.\n\nA CA de uma duplicata \xe9 igual a 10 + seu Modificador de Destreza. Se um ataque acertar uma duplicata, a duplicata ser\xe1 destru\xedda. Uma duplicata s\xf3 pode ser destru\xedda por um ataque que a acerte. Ignora todos os outros danos e efeitos. A magia termina quando todas as tr\xeas duplicatas s\xe3o destru\xeddas.\n\nUma criatura n\xe3o \xe9 afetada por esta magia se n\xe3o puder ver, se confiar em outros sentidos al\xe9m da vis\xe3o, como a vis\xe3o \xe0s cegas, ou se puder perceber ilus\xf5es como falsas, como acontece com a vis\xe3o verdadeira."},{name:"Enganar",level:5,classes:["Bardo","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea se torna invis\xedvel ao mesmo tempo que um duplo ilus\xf3rio seu aparece onde voc\xea est\xe1. O dobro dura pela dura\xe7\xe3o, mas a invisibilidade termina se voc\xea atacar ou lan\xe7ar um feiti\xe7o.\n\nVoc\xea pode usar sua a\xe7\xe3o para mover seu duplo ilus\xf3rio at\xe9 o dobro de sua velocidade e faz\xea-lo gesticular, falar e se comportar da maneira que voc\xea escolher.\n\nQue voc\xea possa ver atrav\xe9s de seus olhos e ouvir atrav\xe9s de seus ouvidos como se estivesse localizado onde ele est\xe1. Em cada um de seus turnos, como b\xf4nus de a\xe7\xe3o, voc\xea pode passar do uso dos sentidos para o uso dos seus pr\xf3prios sentidos ou vice-versa. Enquanto voc\xea usa seus sentidos, voc\xea fica cego e ensurdecido em rela\xe7\xe3o \xe0 sua pr\xf3pria surrodada."},{name:"Passo Nebuloso",level:2,classes:["Feiticeiro","Bruxo","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Instant\xe2neo",description:"Brevemente cercado por uma n\xe9voa prateada, voc\xea se teletransporta at\xe9 9 metros para um espa\xe7o desocupado que voc\xea possa ver."},{name:"Modificar Mem\xf3ria",level:5,classes:["Bardo","Mago"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea tenta remodelar as mem\xf3rias de outra criatura. Uma criatura que voc\xea possa ver deve fazer um Teste de resist\xeancia de Sabedoria. Se voc\xea est\xe1 lutando contra a criatura, ela tem vantagem no teste de resist\xeancia. Em um teste de resist\xeancia falho, o alvo torna-se feiti\xe7ado por voc\xea durante todo o tempo. O alvo enfeiti\xe7ado est\xe1 incapacitado e inconsciente de seus arredores, embora ainda possa ouvi-lo. Se sofrer algum dano ou for atingido por outro feiti\xe7o, esta magia termina e nenhuma das mem\xf3rias do alvo \xe9 modificada.\n\nEnquanto durar este encanto, poder\xe1 afectar a mem\xf3ria do alvo de um acontecimento que viveu nas \xfaltimas 24 horas e que n\xe3o durou mais de 10 minutos. Voc\xea pode eliminar permanentemente toda a mem\xf3ria do evento, permitir que o alvo relembre o evento com perfeita clareza e detalhes exatos, alterar sua mem\xf3ria dos detalhes do evento ou criar uma mem\xf3ria de algum outro evento.\n\nVoc\xea deve falar com o alvo para descrever como suas mem\xf3rias s\xe3o afetadas, e ele deve ser capaz de compreender sua linguagem para que as mem\xf3rias modificadas criem ra\xedzes. Sua mente preenche quaisquer lacunas nos detalhes da sua descri\xe7\xe3o. Se a magia terminar antes de voc\xea terminar de descrever as mem\xf3rias modificadas, a mem\xf3ria da criatura n\xe3o ser\xe1 alterada. Caso contr\xe1rio, as mem\xf3rias modificadas ser\xe3o mantidas quando a magia terminar.\n\nUma mem\xf3ria modificada n\xe3o afeta necessariamente o comportamento de uma criatura, especialmente se a mem\xf3ria contradizer as inclina\xe7\xf5es, tend\xeancias ou cren\xe7as naturais da criatura. Uma mem\xf3ria modificada il\xf3gica, como implantar uma mem\xf3ria de quanto a criatura gostava de se banhar em \xe1cido, \xe9 desfalecida, talvez como um sonho ruim. O Mestre pode considerar uma mem\xf3ria modificada absurda demais para afetar uma criatura de maneira significativa.\n\nUm feiti\xe7o de remo\xe7\xe3o de maldi\xe7\xe3o (n\xedvel 3) ou restaura\xe7\xe3o superior (n\xedvel 5) lan\xe7ado no alvo restaura a verdadeira mem\xf3ria da criatura."},{name:"Raio de Lua",level:2,classes:["Druida"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Um feixe prateado de luz p\xe1lida brilha em um cilindro de raio metro 1,5 e 12 metros de altura centrado em um ponto dentro do alcance. At\xe9 a magia terminar, uma luz fraca preenche o cilindro.\n\nQuando uma criatura entra na \xe1rea da magia pela primeira vez em um turno ou inicia seu turno l\xe1, ela \xe9 envolvida por chamas fantasmag\xf3ricas que causam uma dor lancinante e deve fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. S\xe3o necess\xe1rios 2d10 de dano radiante em um teste de resist\xeancia falho, ou metade disso em um teste bem-sucedido.\n\nUm metamorfo faz seu teste de resist\xeancia com desvantagem. Se falhar, ele tamb\xe9m reverte instantaneamente \xe0 sua forma original e n\xe3o pode assumir uma forma diferente at\xe9 deixar os feiti\xe7os leves.\n\nEm cada um dos seus turnos ap\xf3s lan\xe7ar este feiti\xe7o, voc\xea pode usar uma a\xe7\xe3o para mover o feixe 18 metros em qualquer dire\xe7\xe3o."},{name:"Mover a Terra",level:6,classes:["Druida","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 2 horas",description:"Escolha uma \xe1rea de terreno n\xe3o superior a 12 metros de lado dentro do alcance. Voc\xea pode remodelar sujeira, areia ou argila na \xe1rea da maneira que desejar durante o per\xedodo. Voc\xea pode aumentar ou diminuir a eleva\xe7\xe3o da \xe1rea, criar ou preencher uma vala, erguer ou nivelar uma parede ou formar um pilar. A extens\xe3o de tais altera\xe7\xf5es n\xe3o pode exceder metade da maior dimens\xe3o da \xe1rea. Portanto, se voc\xea afetar um quadrado de 12 metros, poder\xe1 criar um pilar de at\xe9 6 metros de altura, aumentar ou diminuir a eleva\xe7\xe3o do quadrado em at\xe9 6 metros, cavar uma trincheira de at\xe9 6 metros de profundidade e assim por diante. Leva 10 minutos para que essas altera\xe7\xf5es sejam conclu\xeddas.\n\nAo final de cada 10 minutos que voc\xea gasta concentrando-se no feiti\xe7o, voc\xea pode escolher uma nova \xe1rea de terreno para afetar.\n\nComo a transforma\xe7\xe3o do terreno ocorre lentamente, as criaturas da \xe1rea geralmente n\xe3o podem ficar presas ou feridas pelo movimento da solo. Este feiti\xe7o n\xe3o pode manipular pedra natural ou constru\xe7\xe3o de pedra. Rochas e estruturas mudam para acomodar o novo terreno. Se a maneira como voc\xea molda o terreno tornar uma estrutura inst\xe1vel, ela poder\xe1 desabar.\n\nDa mesma forma, este feiti\xe7o n\xe3o afeta diretamente o crescimento das plantas. A terra movida carrega consigo qualquer plantaa."},{name:"Passagem sem Rastros",level:2,classes:["Druida","Patrulheiro"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Um v\xe9u de sombras e sil\xeancio irradia de voc\xea, mascarando voc\xea e seus companheiros da detec\xe7\xe3o. Durante a dura\xe7\xe3o, cada criatura que voc\xea escolher a at\xe9 9 metros de voc\xea (incluindo voc\xea) tem um b\xf4nus de +10 em testes de Destreza (Furtividade) e n\xe3o pode ser rastreada exceto por meios m\xe1gicos. Uma criatura que recebe este b\xf4nus n\xe3o deixa rastros ou outros vest\xedgios de sua passagem."},{name:"Passagem Mural",level:5,classes:["Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"1 hora",description:"Uma passagem aparece em um ponto de sua escolha que voc\xea possa ver em uma superf\xedcie de madeira, gesso ou pedra (como uma parede, um teto ou um ch\xe3o) dentro do alcance e dura pela dura\xe7\xe3o. Voc\xea escolhe as dimens\xf5es da abertura: at\xe9 1,5 metro de largura, 8 metros de altura e 20 metros de profundidade. A passagem n\xe3o cria instabilidade na estrutura que a circunda.\n\nQuando a abertura desaparece, quaisquer criaturas ou objetos ainda na passagem criada pela magia s\xe3o ejetados com seguran\xe7a para um espa\xe7o desocupado mais pr\xf3ximo da superf\xedcie onde voc\xea conjura uma magia."},{name:"Assassino Fantasmal",level:4,classes:["Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea entra nos pesadelos de uma criatura que voc\xea pode ver dentro do alcance e cria uma manifesta\xe7\xe3o ilus\xf3ria de seus medos mais profundos, vis\xedveis apenas para essa criatura. O alvo deve fazer um Teste de resist\xeancia de Sabedoria. Em um teste de resist\xeancia falho, o alvo fica amedrontado durante todo o tempo. No in\xedcio de cada turno do alvo antes da magia terminar, o alvo deve ter sucesso em um Teste de resist\xeancia de Sabedoria ou sofrer 4d10 dano ps\xedquico. Em um teste de resist\xeancia bem sucedido, a magia termina."},{name:"For\xe7a Fantasmag\xf3rica",level:2,classes:["Bardo","Feiticeiro","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea cria uma ilus\xe3o que se enra\xedza na mente de uma criatura que voc\xea pode ver dentro do alcance. O alvo deve fazer um Teste de resist\xeancia de Intelig\xeancia. Em um teste de resist\xeancia falho, voc\xea cria um objeto fantasmag\xf3rico, criatura ou outro fen\xf4meno vis\xedvel de sua escolha que n\xe3o seja maior que um cubo de 30 metros e que seja percept\xedvel apenas pelo alvo durante a dura\xe7\xe3o. Este feiti\xe7o n\xe3o tem efeito sobre mortos-vivos ou constructos.\n\nO fantasma inclui som, temperatura e outros est\xedmulos, tamb\xe9m evidentes apenas para a criatura.\n\nO alvo pode usar sua a\xe7\xe3o para examinar o fantasma com um teste de Intelig\xeancia (Investiga\xe7\xe3o) contra seu CD de resist\xeancia de magia. Se o teste for bem-sucedido, o alvo percebe que o fantasma \xe9 uma ilus\xe3o e a magia termina.\n\nEnquanto um alvo \xe9 afetado pelo feiti\xe7o, o alvo trata o fantasma como se fosse real. O alvo racionaliza quaisquer resultados il\xf3gicos da intera\xe7\xe3o com o fantasma. Por exemplo, um alvo que tenta atravessar uma ponte fantasmag\xf3rica que atravessa um abismo cai ao pisar na ponte. Se o alvo sobreviver \xe0 queda, ele ainda acredita que a ponte existe e apresenta alguma outra explica\xe7\xe3o para sua queda \u2013 ela foi empurrada, escorregou ou um vento forte pode t\xea-la derrubado.\n\nUm alvo afetado est\xe1 t\xe3o convencido da realidade do fantasma que pode at\xe9 sofrer danos causados \u200b\u200bpela ilus\xe3o. Um fantasma criado para aparecer como uma criatura pode atacar o alvo. De forma similar. um fantasma criado para parecer fogo, uma po\xe7a de \xe1cido ou lava pode queimar o alvo. A cada rodada do seu turno, o fantasma pode causar 1d6 de dano ps\xedquico ao alvo se ele estiver na \xe1rea do fantasma ou at\xe9 1,5 metro do fantasma, desde que a ilus\xe3o seja de uma criatura ou perigo que possa logicamente causar dano, como atacando. O alvo percebe o dano como um tipo apropriado \xe0 ilus\xe3o."},{name:"Aliado Planar",level:6,classes:["Cl\xe9rigo"],school:"Conjura\xe7\xe3o",castingTime:"10 minutes",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea implora por ajuda a uma entidade de outro mundo. O ser deve ser conhecido por voc\xea: um deus, um primordial, um pr\xedncipe dem\xf4nio ou algum outro ser de poder c\xf3smico. Essa entidade envia um celestial, um elemental ou um inimigo leal a ela para ajud\xe1-lo, fazendo a criatura aparecer em um espa\xe7o desocupado dentro do alcance. Se voc\xea souber o nome de uma criatura espec\xedfica, poder\xe1 pronunci\xe1-lo quando conjurar essa magia para solicitar aquela criatura, embora voc\xea possa obter uma criatura diferente de qualquer maneira (a escolha do Mestre).\n\nQuando a criatura aparece, ela n\xe3o \xe9 compelida a se comportar de nenhuma maneira espec\xedfica. Voc\xea pode pedir \xe0 criatura que realize um servi\xe7o em troca de pagamento, mas ela n\xe3o \xe9 obrigada a faz\xea-lo. A tarefa solicitada pode variar de simples (voar-nos atrav\xe9s do abismo ou ajudar-nos a travar uma batalha) a complexa (espionar nossos inimigos ou proteger-nos durante nossa incurs\xe3o na masmorra). Voc\xea deve ser capaz de se comunicar com a criatura para negociar seus servi\xe7os.\n\nO pagamento pode assumir diversas formas. Um celestial pode exigir uma doa\xe7\xe3o consider\xe1vel de ouro ou itens m\xe1gicos para um templo aliado, enquanto um inimigo pode exigir um sacrif\xedcio vivo ou um presente de tesouro. Algumas criaturas podem trocar seus servi\xe7os por uma miss\xe3o realizada por voc\xea. Como regra geral, uma tarefa que pode ser medida em minutos exige um pagamento no valor de 100 po por minuto. Uma tarefa medida em horas requer 1.000 po por hora. E uma tarefa medida em dias (at\xe9 10 dias) requer 10.000 po por dia. O Mestre pode ajustar esses pagamentos com base nas circunst\xe2ncias sob as quais voc\xea conjura a magia. Se a tarefa estiver alinhada com o esp\xedrito da criatura, o pagamento poder\xe1 ser reduzido pela metade ou at\xe9 mesmo dispensado. Tarefas n\xe3o perigosas normalmente exigem apenas metade do pagamento sugerido, enquanto tarefas especialmente perigosas podem exigir um presente maior. As criaturas raramente aceitam tarefas que pare\xe7am suicidas.\n\nAp\xf3s a criatura completar a tarefa, ou quando a dura\xe7\xe3o do servi\xe7o acordado expirar, a criatura retorna ao seu plano natal ap\xf3s apresentar um relat\xf3rio a voc\xea, se for apropriado para a tarefa e se poss\xedvel. Se voc\xea n\xe3o conseguir chegar a um acordo sobre o pre\xe7o do servi\xe7o da criatura, a criatura retornar\xe1 imediatamente ao seu plano natal.\n\nUma criatura alistada para se juntar ao seu grupo conta como membro dele, recebendo uma parcela integral dos pontos de experi\xeancia concedidos."},{name:"V\xednculo Planar",level:5,classes:["Bardo","Cl\xe9rigo","Druida","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 hour",range:"18 metros",duration:"24 horas",description:"Com este feiti\xe7o, voc\xea tenta vincular um celestial, um elemental, um fe\xe9rico ou um inimigo ao seu servi\xe7o. A criatura deve estar dentro do alcance durante todo o lan\xe7amento do feiti\xe7o. (Normalmente, a criatura \xe9 primeiro convocada para o centro de um c\xedrculo m\xe1gico invertido para mant\xea-la presa enquanto o feiti\xe7o \xe9 lan\xe7ado.) Ao completar a conjura\xe7\xe3o, o alvo deve fazer um Teste de resist\xeancia de Carisma. Em um teste de resist\xeancia falho, certamente servir\xe1 para voc\xea durante todo o tempo. Se a criatura foi invocada ou criada por outra magia, a dura\xe7\xe3o daquela magia \xe9 estendida para corresponder \xe0 dura\ufffd\ufffd\xe3o desta magia.\n\nUma criatura presa deve seguir suas instru\xe7\xf5es da melhor maneira poss\xedvel. Voc\xea pode comandar a criatura para acompanh\xe1-lo em uma aventura, para proteger um local ou para entregar uma mensagem. A criatura obedece \xe0 letra de suas instru\xe7\xf5es, mas se for hostil a voc\xea, ela se esfor\xe7ar\xe1 para distorcer suas palavras para atingir seus pr\xf3prios objetivos. Se a criatura seguir completamente suas instru\xe7\xf5es antes que a magia termine, ela viajar\xe1 at\xe9 voc\xea para relatar esse fato se voc\xea estiver no mesmo plano de exist\xeancia. Se voc\xea estiver em um plano de exist\xeancia diferente, ele retornar\xe1 ao local onde voc\xea o amarrou e permanecer\xe1 l\xe1 at\xe9 a magia terminar."},{name:"Polimorfismo",level:4,classes:["Bardo","Druida","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Este feiti\xe7o transforma uma criatura que voc\xea pode ver dentro do alcance em uma nova forma. Uma incriatura volunt\xe1ria deve fazer um Teste de resist\xeancia de Sabedoria para evitar o efeito. Um metamorfo \xe9 automaticamente bem-sucedido neste teste de resist\xeancia.\n\nA transforma\xe7\xe3o dura enquanto durar, ou at\xe9 que o alvo caia para 0 pontos de vida ou morra. A nova forma pode ser qualquer besta cujo n\xedvel de desafio seja igual ou inferior ao do alvo (ou ao n\xedvel do alvo, se n\xe3o tiver n\xedvel de desafio). As estat\xedsticas de jogo do alvo, incluindo pontua\xe7\xf5es de habilidades mentais, s\xe3o substitu\xeddas pelas estat\xedsticas do besta escolhido. Ele mant\xe9m seu alinhamento e personalidade.\n\nO alvo assume os pontos de vida da sua nova forma. Ao retornar \xe0 sua forma normal, a criatura retorna ao n\xfamero de pontos de vida que tinha antes de se transformar. Se reverter como resultado de cair para 0 pontos de vida, qualquer dano excessivo ser\xe1 transferido para sua forma normal.\n\nContanto que o dano excessivo n\xe3o reduza a forma normal da criatura a 0 pontos de vida, ela n\xe3o ser\ufffd\ufffd derrubada inconsciente.\n\nA criatura \xe9 limitada nas a\xe7\xf5es que pode realizar pela natureza de sua nova forma e n\xe3o pode falar, lan\xe7ar feiti\xe7os ou realizar qualquer outra a\xe7\xe3o que exija m\xe3os ou fala.\n\nO equipamento do alvo se funde \xe0 nova forma. A criatura n\xe3o pode ativar, usar, empunhar ou de qualquer outra forma se beneficiar de qualquer um de seus equipamentos."},{name:"Ilus\xe3o Programada",level:6,classes:["Bardo","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"At\xe9 ser dissipada",description:"Voc\xea cria a ilus\xe3o de um objeto, uma criatura ou algum outro fen\xf4meno vis\xedvel dentro do alcance que \xe9 ativado quando ocorre uma condi\xe7\xe3o espec\xedfica. A ilus\xe3o \xe9 impercept\xedvel at\xe9 ent\xe3o. N\xe3o deve ser maior que um cubo de 9 metros, e voc\xea decide quando conjurar uma magia, como a ilus\xe3o se comporta e que sons ela emite. Esta performance roteirizada pode durar at\xe9 5 minutos.\n\nQuando a condi\xe7\xe3o que voc\xea especificou ocorre, a ilus\xe3o surge e funciona da maneira que voc\xea descreveu. Assim que a ilus\xe3o termina de funcionar, ela desaparece e permanece inativa por 10 minutos. Ap\xf3s este tempo, a ilus\xe3o pode ser ativada novamente. A condi\xe7\xe3o de disparo pode ser t\xe3o geral ou detalhada quanto voc\xea desejar, por\xe9m deve ser baseada em condi\xe7\xf5es visuais ou sonoras que ocorrem a at\xe9 9 metros da \xe1rea. Por exemplo, voc\xea poderia criar uma ilus\xe3o de si mesmo para aparecer e alertar outros que tentassem abrir uma porta com armadilha, ou voc\xea poderia configurar a ilus\xe3o para ser acionada somente quando uma criatura disser a palavra ou frase correta.\n\nA intera\xe7\xe3o f\xedsica com a imagem revela que ela \xe9 uma ilus\xe3o, pois coisas podem passar por ela. Uma criatura que use sua a\xe7\xe3o para examinar a imagem pode determinar que se trata de uma ilus\xe3o com um teste bem-sucedido de Intelig\xeancia (Investiga\xe7\xe3o) contra seu CD de resist\xeancia de magia. Se uma criatura discernir a ilus\xe3o pelo que ela \xe9, a criatura poder\xe1 ver atrav\xe9s da imagem, e qualquer ru\xeddo que ela fizer soar\xe1 vazio para a criatura."},{name:"Ressuscitar os Mortos",level:5,classes:["Cl\xe9rigo","Paladino","Bardo"],school:"Necromancia",castingTime:"1 hour",range:"Toque",duration:"Instant\xe2neo",description:"Voc\xea devolve \xe0 vida uma criatura morta que voc\xea toca, desde que ela esteja morta h\xe1 n\xe3o mais de 10 dias. Se a alma da criatura estiver disposta e tiver liberdade para se juntar ao corpo, a criatura retorna \xe0 vida com 1 ponto de vida.\n\nEste feiti\xe7o tamb\xe9m neutraliza quaisquer venenos e cura doen\xe7as n\xe3o-m\xe1gicas que afetaram a criatura no momento em que ela morreu. Este feiti\xe7o, entretanto, n\xe3o remove doen\xe7as m\xe1gicas, maldi\xe7\xf5es ou efeitos similares; se eles n\xe3o forem removidos antes de lan\xe7ar o feiti\xe7o, eles entrar\xe3o em vigor quando a criatura retornar \xe0 vida. O feiti\xe7o n\xe3o pode devolver a vida a uma criatura morta-vivo.\n\nEste feiti\xe7o fecha todos os ferimentos mortais, mas n\xe3o restaura partes defeituosas do corpo. Se a criatura n\xe3o tiver partes do corpo ou \xf3rg\xe3os essenciais para sua sobreviv\xeancia \u2013 sua cabe\xe7a, por exemplo \u2013 o feiti\xe7o falha automaticamente.\n\nVoltar dos mortos \xe9 uma prova\xe7\xe3o. O alvo sofre uma penalidade de -4 em todos os ataques, testes de resist\xeancia e testes de habilidades. Cada vez que o alvo termina um descanso longo, a penalidade \xe9 reduzida em 1 at\xe9 desaparecer."},{name:"Prote\xe7\xe3o contra Veneno",level:2,classes:["Cl\xe9rigo","Patrulheiro","Paladino","Druida"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"1 hora",description:"Voc\xea toca uma criatura. Se for envenenado, voc\xea neutraliza o veneno. Se mais de um veneno atingir o alvo, voc\xea neutraliza um veneno que voc\xea sabe que est\xe1 presente ou neutraliza um aleatoriamente. Durante a dura\xe7\xe3o, o alvo tem vantagem em testes de resist\xeancia contra ser envenenado, e tem resist\xeancia a dano de veneno."},{name:"Raio de Enfraquecer",level:2,classes:["Bruxo","Mago"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Um raio negro de energia enervante brota do seu dedo em dire\xe7\xe3o a uma criatura dentro do alcance. Fa\xe7a um ataque de magia \xe0 dist\xe2ncia contra o alvo. Sem sucesso, o alvo causa apenas metade do dano com ataques de armas que usam For\xe7a at\xe9 a magia terminar.\n\nAo final de cada um dos turnos do alvo, ele poder\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o contra o feiti\xe7o. Com um sucesso, a magia termina."},{name:"Reencarnar",level:5,classes:["Druida"],school:"Transmuta\xe7\xe3o",castingTime:"1 hour",range:"Toque",duration:"Instant\xe2neo",description:"Voc\xea toca um human\xf3ide morto ou um peda\xe7o de um human\xf3ide morto. Desde que a criatura esteja morta h\xe1 n\xe3o mais que 10 dias, o feiti\xe7o forma um novo corpo adulto para ela e ent\xe3o chama a alma para entrar naquele corpo. Se a alma do alvo n\xe3o estiver livre ou disposta a faz\xea-lo, o feiti\xe7o falha.\n\nA magia cria um novo corpo para a criatura habitar, o que provavelmente faz com que a ra\xe7a da criatura mude. O Mestre rola um d100 e consulta a tabela a seguir para determinar que forma a criatura assume quando restaurada \xe0 vida, ou o Mestre d100Ra\xe7a01-04Drag\xe3onascido05-13An\xe3o, colina14-21An\xe3o, montanha22-25Elfo, escuro26-34Elfo, alto35-42Elfo, madeira43-46Gnomo, floresta47-52Gnomo, rocha53-56Meio-elfo57-60Meio-orc61-68Halfling, p\xe9 leve69-76Halfling, robusto77-96Humano97-100Tiefling A criatura reencarnada relembra sua vida e experi\xeancias anteriores. Ele ret\xe9m as capacidades que tinha em sua forma original, exceto pela troca de sua ra\xe7a original pela nova e pela mudan\xe7a de suas caracter\xedsticas raciais de acordo."},{name:"Truque da Corda",level:2,classes:["Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"1 hora",description:"Voc\xea toca um peda\xe7o de corda que tem at\xe9 18 metros de comprimento. Uma extremidade da corda ent\xe3o sobe no ar at\xe9 que toda a corda fique pendurada perpendicularmente \xe0 solo. Na extremidade superior da corda, uma entrada invis\xedvel se abre para um espa\xe7o extradimensional que dura at\xe9 a magia terminar.\n\nO espa\xe7o extradimensional pode ser alcan\xe7ado subindo at\xe9 o topo da corda. O espa\xe7o pode acomodar at\xe9 oito criaturas m\xe9dias ou menores. A corda pode ser puxada para dentro do espa\xe7o, fazendo com que ela desapare\xe7a da vista fora do espa\xe7o.\n\nAtaques e feiti\xe7os n\xe3o podem atravessar a entrada ou sa\xedda do espa\xe7o extradimensional, mas aqueles que est\xe3o dentro dele podem ver atrav\xe9s de uma janela de metr\xf4 de 3 p\xe9s por 1,5 centrado na corda.\n\nQualquer coisa dentro do espa\xe7o extradimensional desaparece quando a magia termina."},{name:"Raio Ardente",level:2,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Instant\xe2neo",description:"Voc\xea cria tr\xeas raios de fogo e os lan\xe7a em alvos dentro do alcance. Voc\xea pode arremess\xe1-los em um alvo ou em v\xe1rios.\n\nFa\xe7a um ataque de magia \xe0 dist\xe2ncia para cada raio. Sem sucesso, o alvo sofre 2d6 de dano de fogo."},{name:"Escrutinar",level:5,classes:["Bardo","Cl\xe9rigo","Druida","Bruxo","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"10 minutos",range:"1,6 quil\xf4metro",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Que voc\xea possa ver e ouvir uma criatura espec\xedfica que voc\xea escolher e que est\xe1 no mesmo plano de exist\xeancia que voc\xea. O alvo deve fazer um Teste de resist\xeancia de Sabedoria, que \xe9 modificado pelo qu\xe3o bem voc\xea conhece o alvo e pelo tipo de conex\xe3o f\xedsica que voc\xea tem com ele. Se um alvo souber que voc\xea est\xe1 lan\xe7ando este feiti\xe7o, ele poder\xe1 falhar no teste de resist\xeancia voluntariamente se quiser ser observado. KnowledgeSave ModifierSegunda m\xe3o (voc\xea j\xe1 ouviu falar do alvo)+5Primeira m\xe3o (voc\xea conheceu o alvo)0Familiar (voc\xea conhece bem o alvo)-5ConnectionSave ModifierSemelhan\xe7a ou imagem-2Posse ou roupa-4Parte do corpo, mecha de cabelo, peda\xe7o de unha, ou algo parecido-10 Em um teste de resist\xeancia bem-sucedido, o alvo n\xe3o \xe9 afetado, e voc\xea n\xe3o pode usar este feiti\xe7o contra ele novamente por 24 horas. Em um teste de resist\xeancia falho, o feiti\xe7o cria um sensor invis\xedvel a at\xe9 3 metros do alvo. Que voc\xea possa ver e ouvir atrav\xe9s do sensor como se estivesse l\xe1. O sensor se move com o alvo, permanecendo a at\xe9 3 metros dele durante todo o tempo. Uma criatura que pode ver objetos invis\xedveis v\xea o sensor como uma esfera luminosa do tamanho do seu punho.\n\nEm vez de atacar uma criatura, voc\xea pode escolher um local que j\xe1 tenha visto antes como alvo desta magia. Ao fazer isso, o sensor aparece naquele local e n\xe3o se move."},{name:"Apar\xeancia",level:5,classes:["Bardo","Feiticeiro","Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"8 horas",description:"Este feiti\xe7o permite que voc\xea altere a apar\xeancia de qualquer n\xfamero de criaturas que voc\xea possa ver dentro do alcance. Voc\xea d\xe1 a cada alvo escolhido uma apar\xeancia nova e ilus\xf3ria. Um alvo relutante pode fazer um Teste de resist\xeancia de Carisma e, se tiver sucesso, n\xe3o ser\xe1 afetado por este feiti\xe7o.\n\nO feiti\xe7o disfar\xe7a a apar\xeancia f\xedsica, bem como roupas, armaduras, armas e equipamentos. Voc\xea pode fazer com que cada criatura pare\xe7a 30 cent\xedmetros mais baixa ou mais alta e pare\xe7a magra, gorda ou intermedi\xe1ria. Voc\xea n\xe3o pode alterar o tipo de corpo de um alvo, ent\xe3o voc\xea deve escolher uma forma que tenha a mesma disposi\xe7\xe3o b\xe1sica dos membros. Caso contr\xe1rio, a extens\xe3o da ilus\xe3o depende de voc\xea. O feiti\xe7o dura pela dura\xe7\xe3o, a menos que voc\xea use sua a\xe7\xe3o para disfalha-lo antes.\n\nAs mudan\xe7as provocadas por este feiti\xe7o n\xe3o resistem \xe0 inspe\xe7\xe3o f\xedsica. Por exemplo, se voc\xea usar este feiti\xe7o para adicionar um chap\xe9u \xe0 roupa de uma criatura, os objetos passar\xe3o atrav\xe9s do chap\xe9u e qualquer um que o tocar n\xe3o sentir\xe1 nada ou sentir\xe1 a cabe\xe7a e o cabelo da criatura. Se voc\xea usar esse feiti\xe7o para parecer mais magro do que \xe9, a m\xe3o de algu\xe9m que estender a m\xe3o para toc\xe1-lo ir\xe1 esbarrar em voc\xea enquanto aparentemente ainda est\xe1 no ar.\n\nUma criatura pode usar sua a\xe7\xe3o para inspecionar um alvo e fazer um teste de Intelig\xeancia (Investiga\xe7\xe3o) contra seu CD de resist\xeancia de magia. Se conseguir, percebe que o alvo est\xe1 disfar\xe7ado."},{name:"Ver Invisibilidade",level:2,classes:["Bardo","Feiticeiro","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"1 hora",description:"Durante o per\xedodo, voc\xea v\xea criaturas e objetos invis\xedveis como se fossem vis\xedveis, e voc\xea pode ver no Plano Et\xe9reo. Criaturas e objetos et\xe9reos parecem fantasmag\xf3ricos e transl\xfacidos."},{name:"Estilha\xe7ar",level:2,classes:["Feiticeiro","Bruxo","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Um barulho repentino e alto, dolorosamente intenso, irrompe de um ponto de sua escolha dentro do alcance. Cada criatura numa esfera de 10 p\xe9s de raio centrada nesse ponto deve fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Uma criatura sofre 3d8 de dano s\xf4nico em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso. Uma criatura feita de material inorg\xe2nico como pedra, cristal ou metal tem desvantagem neste teste de resist\xeancia.\n\nUm objeto n\xe3o-m\xe1gico que n\xe3o esteja sendo vestido ou carregado tamb\xe9m sofre o dano se estiver na \xe1rea da magia."},{name:"Escalar como Aranha",level:2,classes:["Feiticeiro","Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"At\xe9 o final da magia, uma criatura volunt\xe1ria que voc\xea toca ganha a habilidade de se mover para cima, para baixo e atrav\xe9s de superf\xedcies verticais e de cabe\xe7a para baixo ao longo do teto, deixando suas m\xe3os livres. O alvo tamb\xe9m ganha uma velocidade de escalada igual \xe0 sua velocidade de caminhada."},{name:"Crescimento de Espinhos",level:2,classes:["Druida","Patrulheiro"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"A solo num raio de 6 metros centrada em um ponto dentro do alcance se contorce e brota espinhos duros e espinhos. A \xe1rea se torna um terreno dif\xedcil durante o per\xedodo. Quando uma criatura se move para dentro da \xe1rea, ela sofre 2d4 dano perfurante para cada 1,5 metro que ela percorre.\n\nA transforma\xe7\xe3o da solo \xe9 camuflada para parecer natural. Qualquer criatura que n\xe3o possa ver a \xe1rea no momento em que a magia \xe9 lan\xe7ada deve fazer um teste de Sabedoria (Percep\xe7\xe3o) contra seu CD de resist\xeancia de magia para reconhecer o terreno como perigoso antes de entrar nele."},{name:"Golpe Atordoante",level:4,classes:["Paladino"],school:"Evoca\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Na pr\xf3xima vez que voc\xea acertar uma criatura com um ataque corpo a corpo com arma durante a dura\xe7\xe3o deste feiti\xe7o, sua arma perfura tanto o corpo quanto a mente, e o ataque causa 4d6 de dano ps\xedquico extra ao alvo. O alvo deve fazer um Teste de resist\xeancia de Sabedoria. Em um teste de resist\xeancia falho, ele tem manobras de ataque e teste de habilidades, e n\xe3o pode sofrer ocorr\xeancias, at\xe9 o final do seu pr\xf3ximo turno."},{name:"Moldar Pedra",level:4,classes:["Cl\xe9rigo","Druida","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"Voc\xea toca um objeto de pedra de tamanho m\xe9dio ou menor ou uma se\xe7\xe3o de pedra de n\xe3o mais que 1,5 metro em qualquer dimens\xe3o e o molda em qualquer formato que se adapte ao seu prop\xf3sito. Assim, por exemplo, voc\xea pode transformar uma pedra grande em uma arma, \xeddolo ou cofre, ou fazer uma pequena passagem atrav\xe9s de uma parede, desde que a parede tenha menos de 1,5 metro de espessura. Voc\xea tamb\xe9m pode moldar uma porta de pedra ou sua moldura para ved\xe1-la. O objeto Voc\xea cria pode ter at\xe9 duas dobradi\xe7as e uma trava, mas detalhes mec\xe2nicos mais finos n\xe3o s\xe3o poss\xedveis."},{name:"Raio de Sol",level:6,classes:["Druida","Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (60-foot line)",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Um feixe de luz brilhante sai da sua m\xe3o em uma linha de 1,5 metros de largura e 18 metros de comprimento. Cada criatura da linha dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, uma criatura sofre 6d8 de dano radiante e fica cega at\xe9 seu pr\xf3ximo turno. Em um teste de resist\xeancia bem-sucedido, ele leva metade do dano e n\xe3o fica cego por esse feiti\xe7o. Mortos-vivos e gosmas t\xeam desvantagem nesse teste de resist\xeancia.\n\nVoc\xea pode criar uma nova linha de brilho conforme sua a\xe7\xe3o em qualquer turno at\xe9 o final da magia.\n\nEnquanto isso, uma part\xedcula de brilho brilhante brilha em sua m\xe3o. Ele emite luz brilhante em um raio de 9 metros e luz fraca por mais 9 metros. Esta luz \xe9 a luz solar."},{name:"Pele de Pedra",level:4,classes:["Druida","Feiticeiro","Patrulheiro","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Este feiti\xe7o transforma a carne de uma criatura volunt\xe1ria que voc\xea toca t\xe3o dura quanto pedra. At\xe9 o fim da magia, o alvo tem resist\xeancia a concuss\xe3o n\xe3o-m\xe1gica, perfura\xe7\xe3o e dano cortante."},{name:"Aljava Veloz",level:5,classes:["Patrulheiro"],school:"Transmuta\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea transmuta sua aljava para que ela produza um suprimento infinito de muni\xe7\xe3o n\xe3o-m\xe1gica, que parece saltar para sua m\xe3o quando voc\xea a pega.\n\nEm cada um dos seus turnos at\xe9 o final da magia, voc\xea pode usar uma a\xe7\xe3o b\xf4nus para fazer dois ataques com uma arma que utiliza muni\xe7\xe3o da aljava. Cada vez que voc\xea faz um ataque \xe0 dist\xe2ncia, sua aljava substitui magicamente a muni\xe7\xe3o que voc\xea usou por uma muni\xe7\xe3o n\xe3o-m\xe1gica semelhante. Quaisquer peda\xe7os de muni\xe7\xe3o criados por este feiti\xe7o se desintegram quando a magia termina. Se a aljava deixar sua posse, a magia termina."},{name:"Telecinese",level:5,classes:["Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea ganha a habilidade de mover ou manipular criaturas ou objetos pelo pensamento. Quando voc\xea conjura uma magia, e conforme sua a\xe7\xe3o a cada rodada durante a dura\xe7\xe3o, voc\xea pode exercer sua vontade em uma criatura ou objeto que voc\xea possa ver dentro do alcance, causando o efeito apropriado abaixo. Voc\xea pode afetar o mesmo alvo rodada ap\xf3s rodada, ou escolher um novo a qualquer momento. Se voc\xea trocar de alvo, o alvo anterior n\xe3o ser\xe1 mais afetado pela magia. \n\nCriatura: Voc\xea pode tentar mover uma criatura enorme ou menor. Fa\xe7a um teste de habilidade com seu atributo de conjura\xe7\xe3o contestado pelo teste de For\xe7a da criatura. Se voc\xea vencer a disputa, voc\xea mover\xe1 a criatura at\xe9 9 metros em qualquer dire\xe7\xe3o, inclusive para cima, mas n\xe3o al\xe9m do alcance desta magia. At\xe9 o final do seu pr\xf3ximo turno, a criatura fica imobilizada em seu controle telecin\xe9tico. Uma criatura levantada fica suspensa no ar. \n\n Nas rodadas subsequentes, voc\xea pode usar sua a\xe7\xe3o para tentar manter seu controle telecin\xe9tico sobre a criatura, repetindo a competi\xe7\xe3o. \n\nObjeto: Voc\xea pode tentar mover um objeto que pese at\xe9 1.000 libras. Se o objeto n\xe3o estiver sendo usado ou carregado, voc\xea o move automaticamente at\xe9 9 metros em qualquer dire\xe7\xe3o, mas n\xe3o al\xe9m do alcance deste feiti\xe7o. \n\n Se o objeto for usado ou carregado por uma criatura, voc\xea deve fazer um teste de habilidade com seu atributo de conjura\xe7\xe3o contestado pelo teste de For\xe7a daquela criatura. Se tiver sucesso, voc\xea puxa o objeto para longe daquela criatura e pode mov\xea-lo at\xe9 9 metros em qualquer dire\xe7\xe3o, mas n\xe3o al\xe9m do alcance desta magia. \n\n Voc\xea pode exercer controle preciso sobre objetos com sua pegada telecin\xe9tica, como manipular uma ferramenta simples, abrir uma porta ou cont\xeainer, guardar ou recuperar um item de um cont\xeainer aberto ou despejar o conte\xfado de um frasco."},{name:"C\xedrculo de Teletransporte",level:5,classes:["Bardo","Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 minute",range:"3 metros",duration:"1 rodada",description:"Ao conjurar uma magia, voc\xea desenha um c\xedrculo de 3 metros de di\xe2metro na solo inscrito com sigilos que ligam sua localiza\xe7\xe3o a um c\xedrculo de teletransporte permanente de sua escolha, cuja sequ\xeancia de sigilos voc\xea conhece e que est\xe1 no mesmo plano de exist\xeancia que voc\xea. Um portal brilhante se abre dentro do c\xedrculo que voc\xea desenhou e permanece aberto at\xe9 o final do seu pr\xf3ximo turno. Qualquer criatura que entre no portal aparece instantaneamente a at\xe9 1,5 metro do c\xedrculo de destino ou no espa\xe7o desocupado mais pr\xf3ximo se esse espa\xe7o estiver ocupado.\n\nMuitos dos principais templos, guildas e outros locais importantes possuem c\xedrculos de teletransporte permanentes inscritos em algum lugar dentro de seus limites. Cada um desses c\xedrculos inclui uma sequ\xeancia \xfanica de sigilos - uma s\xe9rie de runas m\xe1gicas dispostas em um padr\xe3o espec\xedfico. Quando voc\xea ganha a habilidade de lan\xe7ar esta magia pela primeira vez, voc\xea aprende as sequ\xeancias de sigilos para dois destinos no Plano Material, determinados pelo Mestre. Voc\xea pode aprender sequ\xeancias de sigilos adicionais durante suas aventuras. Voc\xea pode memorizar uma nova sequ\xeancia de sigilos depois de estud\xe1-la por 1 minuto.\n\nVoc\xea pode criar um c\xedrculo de teletransporte permanente lan\xe7ando este feiti\xe7o no mesmo local todos os dias durante um ano. Voc\xea n\xe3o precisa usar o c\xedrculo para se teletransportar ao conjurar uma magia dessa maneira."},{name:"Transporte via Plantas",level:6,classes:["Druida"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"3 metros",duration:"1 rodada",description:"Este feiti\xe7o cria uma liga\xe7\xe3o m\xe1gica entre uma planta inanimada Grande ou maior dentro do alcance e outra planta, a qualquer dist\xe2ncia, no mesmo plano de exist\xeancia. Voc\xea deve ter visto ou tocado a planta de destino pelo menos uma vez antes. Enquanto isso, qualquer criatura pode entrar na planta alvo e sair da planta de destino usando 1,5 metro de movimento."},{name:"Passo Arb\xf3reo",level:5,classes:["Druida","Patrulheiro"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea ganha a habilidade de entrar em uma \xe1rvore e passar de dentro dela para outra \xe1rvore do mesmo tipo em um raio de 150 metros. Ambas as \xe1rvores devem estar vivas e ter pelo menos o mesmo tamanho que voc\xea. Voc\xea deve usar 1,5 metro de movimento para entrar em uma \xe1rvore. Voc\xea sabe instantaneamente a localiza\xe7\xe3o de todas as outras \xe1rvores do mesmo tipo em um raio de 500 p\xe9s e, como parte do movimento usado para entrar na \xe1rvore, pode passar por uma dessas \xe1rvores ou sair da \xe1rvore em que est\xe1. Voc\xea aparece em um local de sua escolha a at\xe9 1,5 metro da \xe1rvore de destino, usando mais 1,5 metro de movimento. Se voc\xea n\xe3o tiver mais movimento, voc\xea aparecer\xe1 a at\xe9 1,5 metro da \xe1rvore que voc\xea inseriu.\n\nVoc\xea pode usar esta habilidade de transporte uma vez por rodada durante toda a dura\xe7\xe3o. Voc\xea deve terminar cada turno fora de uma \xe1rvore."},{name:"Vis\xe3o Verdadeira",level:6,classes:["Bardo","Cl\xe9rigo","Feiticeiro","Bruxo","Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"1 hora",description:"Este feiti\xe7o d\xe1 \xe0 criatura volunt\xe1ria que voc\xea toca a habilidade de ver as coisas como elas realmente s\xe3o. Durante esse per\xedodo, a criatura tem vis\xe3o verdadeira, percebe portas secretas escondidas por magia e pode ver o Plano Et\xe9reo, tudo em um alcance de 36 metros."},{name:"Toque Vamp\xedrico",level:3,classes:["Bruxo","Mago"],school:"Necromancia",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"O toque de sua m\xe3o envolta em sombras pode sugar a for\xe7a vital de outras pessoas para curar suas feridas. Fa\xe7a um ataque de magia corpo a corpo contra uma criatura ao seu alcance. Sem sucesso, o alvo sofre 3d6 de dano necr\xf3tico e voc\xea recupera pontos de vida iguais \xe0 metade da quantidade de dano necr\xf3tico causado. At\xe9 o fim da magia, voc\xea pode fazer o ataque novamente em cada um de seus turnos como uma a\xe7\xe3o."},{name:"Muro de Fogo",level:4,classes:["Druida","Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea cria uma parede de fogo em uma superf\xedcie s\xf3lida dentro do alcance. Voc\xea pode fazer uma parede de at\xe9 18 metros de comprimento, 6 metros de altura e 30 cent\xedmetros de espessura, ou uma parede circular de at\xe9 6 metros de di\xe2metro, 6 metros de altura e 30 cent\xedmetros de espessura. A parede \xe9 opaca e dura enquanto durar.\n\nQuando a parede aparecer, cada criatura dentro de sua \xe1rea dever\xe1 fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, uma criatura sofre 5d8 dano de fogo, ou metade do dano em um teste de resist\xeancia bem sucedido.\n\nUm lado da parede, selecionado por voc\xea quando voc\xea conjura essa magia, causa 5d8 de dano de fogo a cada criatura que termina seu turno a at\xe9 3 metros daquele lado ou dentro da parede. Uma criatura sofre o mesmo dano quando entra na parede pela primeira vez em um turno ou termina seu turno ali. O outro lado da parede n\xe3o causa dano."},{name:"Muro de Gelo",level:6,classes:["Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea cria uma parede de gelo em uma superf\xedcie s\xf3lida dentro do alcance. Voc\xea pode transform\xe1-lo em uma c\xfapula hemisf\xe9rica ou em uma esfera com um raio de at\xe9 3 metros, ou pode moldar uma superf\xedcie plana composta por dez pain\xe9is quadrados de 3 metros. Cada painel deve ser cont\xedguo a outro painel. Em qualquer forma, a parede tem 30 cent\xedmetros de espessura e dura enquanto durar.\n\nSe a parede cortar o espa\xe7o de uma criatura quando ela aparecer, a criatura dentro de sua \xe1rea ser\xe1 empurrada para um lado da parede e dever\xe1 fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, a criatura sofre 10d6 dano de frio, ou metade do dano em um teste de resist\xeancia bem sucedido.\n\nA parede \xe9 um objeto que pode ser danificado e, portanto, rompido. Possui AC 12 e 30 pontos de vida por trecho de 3 metros, sendo vulner\xe1vel a dano de fogo. Reduzir uma sec\xe7\xe3o de parede de 3 metros a 0 pontos de vida destr\xf3i-a e deixa para tr\xe1s uma camada de ar gelado no espa\xe7o que a parede ocupava. Uma criatura que se mova pela camada de ar gelado pela primeira vez em uma curva deve fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Essa criatura sofre 5d6 de dano de frio em um teste de resist\xeancia falho, ou metade do dano em um teste bem-sucedido."},{name:"Muro de For\xe7a",level:5,classes:["Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Uma parede invis\xedvel de for\xe7a surge em um ponto que voc\xea escolhe dentro do alcance. A parede aparece em qualquer orienta\xe7\xe3o que voc\xea escolher, como uma barreira horizontal ou vertical ou em \xe2ngulo. Pode flutuar livremente ou repousar sobre uma superf\xedcie s\xf3lida. Voc\xea pode transform\xe1-lo em uma c\xfapula hemisf\xe9rica ou em uma esfera com um raio de at\xe9 3 metros, ou pode moldar uma superf\xedcie plana composta por dez pain\xe9is de 3 metros por 3 metros. Cada painel deve ser cont\xedguo a outro painel. De qualquer forma, a parede tem 1/4 de polegada de espessura. Dura enquanto durar. Se a parede cortar o espa\xe7o de uma criatura quando ela aparecer, a criatura ser\xe1 empurrada para um lado da parede (voc\xea escolhe qual lado).\n\nNada pode passar fisicamente pela parede. \xc9 imune a todos os danos e n\xe3o pode ser dissipado por dissipar magia (n\xedvel 3). No entanto, um feiti\xe7o de desintegra\xe7\xe3o (n\xedvel 6) destr\xf3i a parede instantaneamente. A parede tamb\xe9m se estende at\xe9 o Plano Et\xe9reo, bloqueando a viagem et\xe9rea atrav\xe9s da parede."},{name:"Muro de Pedra",level:5,classes:["Druida","Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Uma parede n\xe3o-m\xe1gica de pedra s\xf3lida surge em um ponto que voc\xea escolher dentro do alcance. A parede tem 15 cent\xedmetros de espessura e \xe9 composta por dez pain\xe9is de 3 metros por 3 metros. Cada painel deve ser cont\xedguo a pelo menos um outro painel. Alternativamente, voc\xea pode criar pain\xe9is de 3 metros por 20 p\xe9s com apenas 3 polegadas de espessura.\n\nSe a parede cortar o espa\xe7o de uma criatura quando ela aparecer, a criatura ser\xe1 empurrada para um lado da parede (sua escolha). Se uma criatura for cercada por todos os lados pela parede (ou pela parede e outra superf\xedcie s\xf3lida), essa criatura pode fazer um Teste de resist\xeancia de Destreza. Em caso de sucesso, ele pode usar sua ocorr\xeancia para aumentar sua velocidade e n\xe3o ficar mais cercado pela parede.\n\nA parede pode ter qualquer formato que voc\xea desejar, embora n\xe3o possa ocupar o mesmo espa\xe7o que uma criatura ou objeto. A parede n\xe3o precisa ser vertical ou apoiada em uma base s\xf3lida. Deve, no entanto, fundir-se e ser solidamente suportado pela pedra existente. Assim, voc\xea pode usar este feiti\xe7o para transpor um abismo ou criar uma rampa.\n\nSe voc\xea criar um v\xe3o maior que 20 p\xe9s de comprimento, dever\xe1 reduzir pela metade o tamanho de cada painel para criar suportes. Voc\xea pode moldar a parede de maneira grosseira para criar ameias, ameias e assim por diante.\n\nA parede \xe9 um objeto feito de pedra que pode ser danificado e assim rompido. Cada painel tem AC 15 e 30 pontos de vida por polegada de espessura. Reduzir um painel a 0 pontos de vida o destr\xf3i e pode causar o colapso dos pain\xe9is conectados a crit\xe9rio do Mestre.\n\nSe voc\xea mantiver sua concentra\xe7\xe3o neste feiti\xe7o durante toda a dura\xe7\xe3o, o muro se tornar\xe1 permanente e n\xe3o poder\xe1 ser dissipado. Caso contr\xe1rio, a parede desaparece quando a magia termina."},{name:"Muro de Espinhos",level:6,classes:["Druida"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea cria uma parede de arbustos resistentes, flex\xedveis e emaranhados, cheios de espinhos pontiagudos. A parede aparece dentro do alcance em uma superf\xedcie s\xf3lida e dura enquanto durar. Voc\xea escolhe fazer a parede com at\xe9 18 metros de comprimento, 3 metros de altura e 1,5 metro de espessura ou um c\xedrculo com 20 p\xe9s de di\xe2metro e at\xe9 20 p\xe9s de altura e 1,5 metro de espessura. A parede bloqueia a linha de vis\xe3o.\n\nQuando a parede aparecer, cada criatura dentro de sua \xe1rea dever\xe1 fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, uma criatura sofre 7d8 dano perfurante, ou metade do dano em um teste de resist\xeancia bem sucedido.\n\nUma criatura pode atravessar a parede, embora de forma lenta e dolorosa. Para cada 30 cent\xedmetros que uma criatura se move atrav\xe9s da parede, ela deve gastar 1,2 metros de movimento. Al\xe9m disso, a primeira vez que uma criatura entra na parede em um turno ou termina seu turno ali, a criatura deve fazer um Teste de resist\xeancia de Destreza. S\xe3o necess\xe1rios 7d8 de dano cortante em um teste de resist\xeancia falho, ou metade do dano em um teste bem-sucedido."},{name:"Respirar na \xc1gua",level:3,classes:["Druida","Patrulheiro","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"24 horas",description:"Este feiti\xe7o concede a at\xe9 dez criaturas volunt\xe1rias que voc\xea possa ver dentro do alcance a habilidade de respirar debaixo d'\xe1gua at\xe9 o fim da magia. As criaturas afetadas tamb\xe9m mant\xeam seu modo normal de respira\xe7\xe3o."},{name:"Caminhar nas \xc1guas",level:3,classes:["Cl\xe9rigo","Druida","Patrulheiro","Feiticeiro"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"1 hora",description:"Este feiti\xe7o concede a habilidade de se mover atrav\xe9s de qualquer superf\xedcie l\xedquida - como \xe1gua, \xe1cido, lama, neve, areia movedi\xe7a ou lava - como se fosse uma solo s\xf3lida e inofensiva (criaturas que atravessam a lava derretida ainda podem sofrer danos da cura). At\xe9 dez criaturas volunt\xe1rias que voc\xea pode ver dentro do alcance ganham essa habilidade durante o per\xedodo.\n\nSe voc\xea atingir uma criatura submersa em um l\xedquido, a magia carrega o alvo para a superf\xedcie do l\xedquido a uma velocidade de 18 metros por rodada."},{name:"Teia",level:2,classes:["Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea conjura uma massa de teia grossa e pegajosa em um ponto de sua escolha dentro do alcance. As teias preenchem um cubo de 6 metros a partir desse ponto durante toda a dura\xe7\xe3o. As teias s\xe3o terrenos dif\xedceis e obscurecem levemente sua \xe1rea.\n\nSe as teias n\xe3o estiverem ancoradas entre duas massas s\xf3lidas (como paredes ou \xe1rvores) ou espalhadas por um ch\xe3o, parede ou teto, a teia conjurada colapsar\xe1 sobre si mesma e a magia terminar\xe1 no in\xedcio do seu pr\xf3ximo turno. As teias colocadas sobre uma superf\xedcie plana t\xeam uma profundidade de 1,5 metro.\n\nCada criatura que inicia seu turno nas teias ou que nelas entra durante seu turno deve fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, a criatura fica imobilizada enquanto permanecer nas teias ou at\xe9 se libertar.\n\nUma criatura imobilizada pelas teias pode usar sua a\xe7\xe3o para fazer um teste de For\xe7a contra seu CD de resist\xeancia de magia. Se tiver sucesso, n\xe3o fica mais imobilizado.\n\nAs teias s\xe3o inflam\xe1veis. Qualquer metro c\xfabico de teia exposto ao fogo queima em 1 rodada, causando 2d4 dano de fogo a qualquer criatura que iniciar seu turno no fogo."},{name:"Caminhar no Vento",level:6,classes:["Druida"],school:"Transmuta\xe7\xe3o",castingTime:"1 minute",range:"9 metros",duration:"8 horas",description:"Voc\xea e at\xe9 dez criaturas volunt\xe1rias que voc\xea pode ver dentro do alcance assumem uma forma gasosa durante o per\xedodo, aparecendo como tufos de nuvem. Enquanto estiver nesta forma de nuvem, uma criatura tem uma velocidade de v\xf4o de 90 metros e tem resist\xeancia a danos de armas n\xe3o-m\xe1gicas. As \xfanicas a\xe7\xf5es que uma criatura pode assumir nesta forma s\xe3o a a\xe7\xe3o Dash ou reverter \xe0 sua forma normal. A revers\xe3o leva 1 minuto, durante o qual a criatura fica incapacitada e n\xe3o consegue se mover. At\xe9 o fim da magia, uma criatura pode reverter para a forma de nuvem, o que tamb\xe9m requer a transforma\xe7\xe3o de 1 minuto.\n\nSe uma criatura estiver na forma de nuvem e voando quando o efeito terminar, a criatura desce 18 metros por rodada durante 1 minuto at\xe9 pousar, o que ela faz com seguran\xe7a. Se n\xe3o conseguir pousar ap\xf3s 1 minuto, a criatura percorrer\xe1 a dist\xe2ncia restante."},{name:"Muro de Vento",level:3,classes:["Druida","Patrulheiro"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Uma parede de vento forte surge da solo em um ponto que voc\xea escolhe dentro do alcance. Voc\xea pode fazer a parede com at\xe9 50 metros de comprimento, 4,5 metros de altura e 1 metro de espessura. Voc\xea pode moldar a parede da maneira que desejar, desde que fa\xe7a um caminho cont\xednuo ao longo da solo. A parede dura enquanto durar.\n\nQuando a parede aparecer, cada criatura dentro de sua \xe1rea dever\xe1 fazer um Teste de resist\xeancia de For\xe7a. Uma criatura sofre 3d8 de dano de concuss\xe3o em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso.\n\nO vento forte mant\xe9m a neblina, a fuma\xe7a e outros gases afastados. Criaturas ou objetos voadores pequenos ou menores n\xe3o podem passar pela parede. Materiais soltos e leves trazidos para a parede voam para cima. Flechas, dardos e outros proj\xe9teis comuns lan\xe7ados em alvos atr\xe1s da parede s\xe3o desviados para cima e automaticamente falham. (Pedregulhos lan\xe7ados por gigantes ou m\xe1quinas de cerco, e proj\xe9teis semelhantes, n\xe3o s\xe3o afetados.) Criaturas em forma gasosa n\xe3o podem passar por ele."},{name:"Palavra de Retorno",level:6,classes:["Cl\xe9rigo"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"2 metros",duration:"Instant\xe2neo",description:"Voc\xea e at\xe9 cinco criaturas volunt\xe1rias a at\xe9 1,5 metro de voc\xea se teletransportam instantaneamente para um santu\xe1rio previamente designado. Voc\xea e quaisquer criaturas que se teletransportem com voc\xea aparecem no espa\xe7o desocupado mais pr\xf3ximo do local que voc\xea designou quando preparou seu santu\xe1rio (veja abaixo). Se voc\xea lan\xe7ar esta magia sem primeiro preparar um santu\xe1rio, a magia n\xe3o ter\xe1 efeito.\n\nVoc\xea deve designar um santu\xe1rio lan\xe7ando esta magia dentro de um local, como um templo, dedicado ou fortemente ligado \xe0 sua divindade. Se voc\xea tentar lan\xe7ar a magia dessa maneira em uma \xe1rea que n\xe3o seja dedicada \xe0 sua divindade, a magia n\xe3o ter\xe1 efeito."},{name:"Zona da Verdade",level:2,classes:["Bardo","Cl\xe9rigo","Paladino"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"10 minutos",description:"Voc\xea cria uma zona m\xe1gica que protege contra o engano em uma esfera de raio de 4,5 metros centrada em um ponto de sua escolha dentro do alcance. At\xe9 a magia terminar, uma criatura que entre na \xe1rea do feiti\xe7o pela primeira vez no turno ou inicie seu turno l\xe1 dever\xe1 fazer um Teste de resist\xeancia de Carisma. Em um teste de resist\xeancia falho, uma criatura n\xe3o pode falar uma mentira deliberada enquanto estiver no raio. voc\xea sabe se cada criatura \xe9 bem-sucedida ou falha em seu teste de resist\xeancia.\n\nUma criatura afetada est\xe1 ciente do feiti\xe7o e pode, portanto, evitar responder perguntas \xe0s quais normalmente responderia com uma mentira. Tal criatura pode ser evasiva em suas respostas, desde que permane\xe7a dentro dos limites da verdade."},{name:"Tremor de Terra",level:1,classes:["Bardo","Druida","Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (10-foot radius)",duration:"Instant\xe2neo",description:"Voc\xea causa um tremor na solo num raio de 3 metros. Cada criatura que n\xe3o seja voc\xea naquela \xe1rea deve fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, uma criatura sofre 1d6 de dano de concuss\xe3o e \xe9 derrubada. Se a solo naquela \xe1rea for de terra solta ou pedra, torna-se um terreno dif\xedcil at\xe9 ser limpo."},{name:"Pirotecnia",level:2,classes:["Bardo","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Escolha uma \xe1rea de chama n\xe3o m\xe1gica que voc\xea possa ver e que caiba dentro de um cubo de 1,5 metro dentro do alcance. Voc\xea pode apagar o fogo naquela \xe1rea, e voc\xea cria fogos de artif\xedcio ou fuma\xe7a ao fazer isso. \n\nFogos de artif\xedcio: O alvo explode com uma deslumbrante exibi\xe7\xe3o de cores. Cada criatura a at\xe9 3 metros do alvo deve ter sucesso em um Teste de resist\xeancia de Constitui\xe7\xe3o ou ficar\xe1 cega at\xe9 o final do seu pr\xf3ximo turno. \n\nFuma\xe7a: Uma espessa fuma\xe7a preta se espalha do alvo em um raio de 6 metros, movendo cantos ao redorda. A \xe1rea da fuma\xe7a est\xe1 fortemente obscurecida. A fuma\xe7a persiste por 1 minuto ou at\xe9 que um vento forte a disperse."},{name:"Escrever no C\xe9u",level:2,classes:["Bardo","Druida","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Sight",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea faz com que at\xe9 dez palavras se formem em uma parte do c\xe9u que voc\xea possa ver. As palavras parecem ser feitas de nuvens e permanecem no lugar durante a dura\xe7\xe3o do feiti\xe7o. As palavras se dissipam quando a magia termina. Um vento forte pode dispersar as nuvens e encerrar o feiti\xe7o mais cedo."},{name:"Trovejada",level:0,classes:["Bardo","Druida","Feiticeiro","Bruxo","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Self (5-foot radius)",duration:"Instant\xe2neo",description:"Voc\xea cria uma explos\xe3o de som estrondoso, que pode ser ouvido a 30 metros de dist\xe2ncia. Cada criatura que n\xe3o seja voc\xea a at\xe9 1,5 metro de dist\xe2ncia deve fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, a criatura sofre 1d6 de dano s\xf4nico.\n\nO dano da magia aumenta em 1d6 quando voc\xea atinge o 5\xba n\xedvel (2d6), 11\xba n\xedvel (3d6) e 17\xba n\xedvel (4d6)."},{name:"Vento de Prote\xe7\xe3o",level:2,classes:["Bardo","Druida","Feiticeiro"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Um vento forte (20 milhas por hora) sopra ao redorda em um raio de 3 metros e se move com voc\xea, permanecendo centrado em voc\xea. O vento dura a dura\xe7\xe3o da magia. Ele ensurdece voc\xea e outras criaturas em sua \xe1rea. Ele extingue chamas desprotegidas em sua \xe1rea, do tamanho de tochas ou menores. A \xe1rea \xe9 um terreno dif\xedcil para outras criaturas al\xe9m de voc\xea."},{name:"Controlar Chamas",level:0,classes:["Druida","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea escolhe uma chama n\xe3o m\xe1gica que voc\xea possa ver dentro do alcance e que caiba dentro de um cubo de 1,5 metro. Voc\xea o afeta de uma das seguintes maneiras: Voc\xea expande instantaneamente a chama 1,5 metro em uma dire\xe7\xe3o, desde que haja madeira ou outro combust\xedvel no novo local.  Voc\xea apaga instantaneamente as chamas dentro do cubo.  Voc\xea dobra ou reduz pela metade a \xe1rea de luz brilhante e fraca emitida pela chama, altera sua cor ou ambos. A mudan\xe7a dura 1 hora.  Voc\xea faz com que formas simples \u2013 como a forma vaga de uma criatura, um objeto inanimado ou um local \u2013 apare\xe7am dentro das chamas e sejam animadas como voc\xea quiser. As formas duram 1 hora.  Se voc\xea lan\xe7ar este feiti\xe7o v\xe1rias vezes, voc\xea pode ter at\xe9 tr\xeas de seus efeitos n\xe3o-Instant\xe2neos ativos por vez, e voc\xea pode disfalhar tal efeito como uma a\xe7\xe3o."},{name:"Criar Fogueira",level:0,classes:["Druida","Feiticeiro","Bruxo","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea cria uma fogueira na solo que voc\xea pode ver dentro do alcance. At\xe9 a magia terminar, a fogueira preenche um cubo de 1,5 metros. Qualquer criatura no espa\xe7o da fogueira quando voc\xea conjurar uma magia deve ter sucesso em um Teste de resist\xeancia de Destreza ou sofrer 1d8 de dano de fogo. Uma criatura tamb\xe9m deve fazer o teste de resist\xeancia quando entrar no espa\xe7o da fogueira pela primeira vez em um turno ou terminar seu turno ali.\n\nO dano da magia aumenta em 1d8 quando voc\xea atinge o 5\xba n\xedvel (2d8), 11\xba n\xedvel (3d8) e 17\xba n\xedvel (4d8)."},{name:"Queimadura de Gelo",level:0,classes:["Druida","Feiticeiro","Bruxo","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea causa a forma\xe7\xe3o de gelo entorpecente em uma criatura que voc\xea pode ver dentro do alcance. O alvo dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, o alvo sofre 1d6 de dano de frio, e tem preven\xe7\xe3o na pr\xf3xima jogada de ataque com arma que fizer antes do final do seu pr\xf3ximo turno.\n\nO dano da magia aumenta em 1d6 quando voc\xea atinge o 5\xba n\xedvel (2d6), 11\xba n\xedvel (3d6) e 17\xba n\xedvel (4d6)."},{name:"Rajada",level:0,classes:["Druida","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Instant\xe2neo",description:"Voc\xea agarra o ar e o obriga a criar um dos seguintes efeitos em um ponto que voc\xea possa ver dentro do alcance: Uma criatura M\xe9dia ou menor que voc\xea escolher deve ter sucesso em um Teste de resist\xeancia de For\xe7a ou ser empurrada at\xe9 1,5 metro de dist\xe2ncia de voc\xea. Voc\xea cria uma pequena rajada de ar capaz de mover um objeto que n\xe3o \xe9 segurado nem carregado e que n\xe3o pesa mais do que 5 libras. O objeto \xe9 empurrado at\xe9 3 metros de dist\xe2ncia de voc\xea. Ele n\xe3o \xe9 empurrado com for\xe7a suficiente para causar danos. Voc\xea cria um efeito sensorial inofensivo usando o ar, como fazer com que as folhas farfalhem, o vento feche as venezianas ou suas roupas ondulem com a brisa."},{name:"Pedra M\xe1gica",level:0,classes:["Druida","Bruxo"],school:"Transmuta\xe7\xe3o",castingTime:"1 bonus a\xe7\xe3o",range:"Toque",duration:"1 minuto",description:"Voc\xea toca de uma a tr\xeas pedras e as imbui de magia. Voc\xea ou outra pessoa pode fazer um ataque de magia \xe0 dist\xe2ncia com uma das pedras, jogando-a ou arremessando-a com uma funda. Se lan\xe7ado, tem alcance de 18 metros. Se outra pessoa atacar com a pedra, esse atacante adiciona seu modificador de atributo de conjura\xe7\xe3o, e n\xe3o o do atacante, \xe0 jogada de ataque. Sem sucesso, o alvo leva dano de concuss\xe3o igual a 1d6 + seu modificador de atributo de conjura\xe7\xe3o. Sucesso ou falha, o feiti\xe7o termina ent\xe3o na pedra.\n\nSe voc\xea conjurar esta magia novamente, a magia termina mais cedo em quaisquer pedras ainda afetadas por ela."},{name:"Moldar a Terra",level:0,classes:["Druida","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Instant\xe2neo",description:"Voc\xea escolhe uma por\xe7\xe3o de terra ou pedra que voc\xea possa ver dentro do alcance e que caiba dentro de um cubo de 1,5 metro. Voc\xea o manipula de uma das seguintes maneiras: Se voc\xea atingir uma \xe1rea de terra solta, poder\xe1 escav\xe1-la instantaneamente, mov\xea-la ao longo da solo e deposit\xe1-la a at\xe9 1,5 metro de dist\xe2ncia. Esse movimento n\xe3o tem for\xe7a suficiente para causar danos. Voc\xea faz com que formas, cores ou ambas apare\xe7am na terra ou na pedra, soletrando palavras, criando imagens ou moldando padr\xf5es. As mudan\xe7as duram 1 hora. Se a sujeira ou pedra que voc\xea atingir estiver na solo, voc\xea far\xe1 com que ela se torne um terreno dif\xedcil. Alternativamente, voc\xea pode fazer com que a solo se torne um terreno normal se j\xe1 for um terreno dif\xedcil. Essa mudan\xe7a dura 1 hora. Se voc\xea lan\xe7ar este feiti\xe7o m\xfaltiplas vezes, voc\xea n\xe3o poder\xe1 ter mais do que dois de seus efeitos n\xe3o Instant\xe2neos ativos por vez, e poder\xe1 disfalhar tal efeito como uma a\xe7\xe3o."},{name:"Modelar \xc1gua",level:0,classes:["Druida","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Instant\xe2neo",description:"Voc\xea escolhe uma \xe1rea de \xe1gua que voc\xea possa ver dentro do alcance e que caiba dentro de um cubo de 1,5 metro. Voc\xea o manipula de uma das seguintes maneiras: Voc\xea move instantaneamente ou altera o fluxo da \xe1gua conforme direciona, at\xe9 1,5 metro em qualquer dire\xe7\xe3o. Este movimento n\xe3o tem for\xe7a suficiente para causar danos.  Voc\xea faz com que a \xe1gua tenha formas simples e se anime conforme sua dire\xe7\xe3o. Essa mudan\xe7a dura 1 hora.  Voc\xea altera a cor ou opacidade da \xe1gua. A \xe1gua deve ser trocada da mesma forma durante todo o processo. Essa mudan\xe7a dura 1 hora.  Voc\xea congela a \xe1gua, desde que nela n\xe3o haja criaturas. A \xe1gua descongela em 1 hora.  Se voc\xea lan\xe7ar este feiti\xe7o m\xfaltiplas vezes, voc\xea n\xe3o poder\xe1 ter mais do que dois de seus efeitos n\xe3o Instant\xe2neos ativos por vez, e poder\xe1 disfalhar tal efeito como uma a\xe7\xe3o."},{name:"Absorver Elementos",level:1,classes:["Druida","Patrulheiro","Mago"],school:"Abjura\xe7\xe3o",castingTime:"1 rea\xe7\xe3o, tomada quando voc\xea \xe9 atingido por um ataque ou alvo do feiti\xe7o m\xedssil m\xe1gico",range:"Si mesmo",duration:"1 rodada",description:"O feiti\xe7o captura parte da energia recebida, diminuindo seu efeito sobre voc\xea e armazenando-a para seu pr\xf3ximo ataque corpo a corpo. Voc\xea tem resist\xeancia ao tipo de dano desencadeado at\xe9 o in\xedcio do seu pr\xf3ximo turno. Al\xe9m disso, na primeira vez que voc\xea tiver sucesso com um ataque corpo a corpo em seu pr\xf3ximo turno, o alvo sofre 1d6 de dano extra do tipo desencadeante e a magia termina."},{name:"V\xednculo com a Besta",level:1,classes:["Druida","Patrulheiro"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea estabelece um v\xednculo telep\xe1tico com um besta que voc\xea toca que \xe9 amig\xe1vel com voc\xea ou enfeiti\xe7ado por voc\xea. O feiti\xe7o falha se a Intelig\xeancia do besta for 4 ou superior. At\xe9 a magia terminar, o link estar\xe1 ativo enquanto voc\xea e o besta estiverem na linha de vis\xe3o um do outro. Atrav\xe9s do link, o besta pode entender suas mensagens telep\xe1ticas para ele e pode comunicar telepaticamente emo\xe7\xf5es e conceitos simples para voc\xea. Enquanto o link estiver ativo, o besta ganha vantagem no jogo de ataques contra qualquer criatura a at\xe9 1,5 metro de dist\xe2ncia que voc\xea possa ver."},{name:"Faca de Gelo",level:1,classes:["Druida","Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Instant\xe2neo",description:"Voc\xea cria um peda\xe7o de gelo e o arremessa em uma criatura dentro do alcance. Fa\xe7a um ataque de magia \xe0 dist\xe2ncia contra o alvo. Sem sucesso, o alvo leva 1d10 dano perfurante. Sucesso ou falha, o fragmento ent\xe3o explode. O alvo e cada criatura a at\xe9 1,5 metro do ponto onde o gelo explodiu devem ter sucesso em um Teste de resist\xeancia de Destreza ou sofrer 2d6 dano de frio."},{name:"Prender \xe0 Terra",level:2,classes:["Druida","Feiticeiro","Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"90 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Escolha uma criatura que voc\xea possa ver dentro do alcance. Tiras amarelas de energia m\xe1gica giram em torno da criatura. O alvo deve ter sucesso em um Teste de resist\xeancia de For\xe7a ou sua velocidade de v\xf4o (se houver) ser\xe1 reduzida a 0 p\xe9s durante a dura\xe7\xe3o da magia. Uma criatura a\xe9rea afetada por este feiti\xe7o desce 18 metros por rodada at\xe9 atingir a solo ou a magia termina."},{name:"Redemoinho de Poeira",level:2,classes:["Druida","Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Escolha um cubo de ar desocupado de 1,5 metro que voc\xea possa ver dentro do alcance. Uma for\xe7a elemental que se assemelha a um redemoinho de poeira aparece no cubo e dura pela dura\xe7\xe3o do feiti\xe7o.\n\nQualquer criatura que termine seu turno a at\xe9 1,5 metro do redemoinho deve fazer um Teste de resist\xeancia de For\xe7a. Em um teste de resist\xeancia falho, a criatura sofre 1d8 de dano de concuss\xe3o e \xe9 empurrada 3 metros para longe. Em um teste de resist\xeancia bem-sucedido, a criatura leva metade do dano e n\xe3o \xe9 empurrada.\n\nComo a\xe7\xe3o b\xf4nus, voc\xea pode mover o redemoinho at\xe9 9 metros em qualquer dire\xe7\xe3o. Se o redemoinho se mover sobre areia, poeira, terra solta ou cascalho pequeno, ele suga o material e forma uma nuvem de detritos com raio de 3 metros que dura at\xe9 o in\xedcio do seu pr\xf3ximo turno. A nuvem obscurece fortemente sua \xe1rea."},{name:"Catapulta",level:1,classes:["Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Instant\xe2neo",description:"Escolha um objeto pesando de 1 a 5 libras dentro do alcance que n\xe3o esteja sendo usado ou carregado. O objeto voa em linha reta at\xe9 27 metros na dire\xe7\xe3o que voc\xea escolher antes de cair na solo, parando precocemente caso colida contra uma superf\xedcie s\xf3lida. Se o objeto atingir uma criatura, essa criatura dever\xe1 fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, o objeto atinge o alvo e para de se mover. Em ambos os casos, tanto o objeto quanto a criatura ou superf\xedcie s\xf3lida sofrem 3d8 de dano de concuss\xe3o."},{name:"Controlar Ventos",level:5,classes:["Druida","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"90 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea assume o controle do ar em um cubo de 30 metros que voc\xea pode ver dentro do alcance. Escolha um dos seguintes efeitos quando voc\xea conjurar uma magia. O efeito dura a dura\xe7\xe3o da magia, a menos que voc\xea use sua a\xe7\xe3o em um turno posterior para mudar para um efeito diferente. Voc\xea tamb\xe9m pode usar sua a\xe7\xe3o para interromper temporariamente o efeito ou reiniciar um que voc\xea interrompeu. \n\nRajadas: Um vento sopra dentro do cubo, soprando continuamente na dire\xe7\xe3o horizontal que voc\xea designar. Voc\xea escolhe a intensidade do vento: calmo, moderado ou forte. Se o vento for moderado ou forte, o ataque \xe0 dist\xe2ncia com armas que entram ou saem do cubo ou passam por ele t\xeam desvantagens em sua estrat\xe9gia de ataque. Se o vento estiver forte, qualquer criatura que se mova contra o vento dever\xe1 gastar 1 metro extra de movimento para cada p\xe9 movido. \n\nCorrente descendente: Voc\xea faz com que uma rajada sustentada de vento forte sopre para baixo a partir do topo do cubo. Ataque \xe0 dist\xe2ncia com armas que passam pelo cubo ou que s\xe3o feitas contra alvos dentro dele t\xeam desvantagem em seu ataque de ataques. Uma criatura deve fazer um Teste de resist\xeancia de For\xe7a se voar para dentro do cubo pela primeira vez em um turno ou come\xe7ar seu turno voando. Em um teste de resist\xeancia falho, a criatura \xe9 derrubada. \n\nCorrente ascendente: Voc\xea causa uma corrente ascendente sustentada dentro do cubo, subindo a partir da parte inferior do cubo. Criaturas que finalizam uma queda dentro do cubo sofrem apenas metade do dano da queda. Quando uma criatura no cubo d\xe1 um salto vertical, a criatura pode saltar at\xe9 3 metros acima do normal."},{name:"Bones of the Earth",level:6,classes:["Druida"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Instant\xe2neo",description:"Voc\xea faz com que at\xe9 seis pilares de pedra explodam de lugares na solo que voc\xea pode ver dentro do alcance. Cada pilar \xe9 um cilindro com di\xe2metro de 1,5 metro e altura de at\xe9 9 metros. A solo onde aparece um pilar deve ser larga o suficiente para seu di\xe2metro, e voc\xea pode alvo solo sob uma criatura se essa criatura for M\xe9dia ou menor. Cada pilar possui AC 5 e 30 pontos de vida. Ao ser reduzido a 0 pontos de vida, um pilar desfaz-se em escombros, o que cria uma \xe1rea de terreno dif\xedcil com um raio de 3 metros. Os escombros duram at\xe9 serem removidos.\n\nSe um pilar for criado sob uma criatura, essa criatura dever\xe1 ter sucesso em um Teste de resist\xeancia de Destreza ou ser\xe1 levantada pelo pilar. Uma criatura pode optar por falhar no salvamento.\n\nSe um pilar for impedido de atingir sua altura total por causa de um teto ou outro obst\xe1culo, uma criatura no pilar sofre 6d6 de dano de concuss\xe3o e fica imobilizada, presa entre o pilar e o obst\xe1culo. A criatura imobilizada pode usar uma a\xe7\xe3o para fazer um teste de For\xe7a ou Destreza (a escolha da criatura) contra a CD teste de resist\xeancia da magia. Se obtiver sucesso, a criatura n\xe3o estar\xe1 mais imobilizada e dever\xe1 sair do pilar ou cair dele."},{name:"Terra em Erup\xe7\xe3o",level:3,classes:["Druida","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Instant\xe2neo",description:"Escolha um ponto que voc\xea possa ver na \xe1rea dentro do alcance. Uma fonte de terra agitada e pedra irrompe num cubo de 6 metros centrado naquele ponto. Cada criatura daquela \xe1rea dever\xe1 fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre 3d12 de dano de concuss\xe3o em um teste de resist\xeancia falho, ou metade do dano em um teste bem sucedido. Al\xe9m disso, a solo naquela \xe1rea torna-se um terreno dif\xedcil at\xe9 ser removida. Cada por\xe7\xe3o de 1,5 metro quadrado da \xe1rea requer pelo menos 1 minuto para ser limpa manualmente."},{name:"Perdi\xe7\xe3o Elemental",level:4,classes:["Druida","Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Escolha uma criatura que voc\xea possa ver dentro do alcance e escolha um dos seguintes tipos de dano: \xe1cido, frio, fogo, raio ou trov\xe3o. O alvo deve ter sucesso em um Teste de resist\xeancia de Constitui\xe7\xe3o ou ser afetado pelo feiti\xe7o durante sua dura\xe7\xe3o. Na primeira vez em cada turno o alvo afetado sofre dano do tipo escolhido, o alvo sofre 2d6 de dano extra daquele tipo. Al\xe9m disso, o alvo perde qualquer resist\xeancia a esse tipo de dano at\xe9 o fim da magia."},{name:"Flechas em Chamas",level:3,classes:["Druida","Patrulheiro","Feiticeiro","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Concentra\xe7\xe3o, at\xe9 1 hora",description:"Voc\xea toca uma aljava contendo flechas ou virotes. Quando um alvo \xe9 atingido por um ataque \xe0 dist\xe2ncia com arma usando uma muni\xe7\xe3o retirada da aljava, o alvo sofre 1d6 de dano de fogo extra. A magia do feiti\xe7o termina na muni\xe7\xe3o quando ela tiver sucesso ou falha, e a magia termina quando doze pe\xe7as de muni\xe7\xe3o forem retiradas da aljava."},{name:"Investidura de Chamas",level:6,classes:["Druida","Feiticeiro","Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Chamas percorrem seu corpo, lan\xe7ando luz brilhante em um raio de 9 metros e penumbra por mais 9 metros durante a dura\xe7\xe3o do feiti\xe7o. As chamas n\xe3o fazem mal a voc\xea. At\xe9 a magia terminar, voc\xea ganha os seguintes benef\xedcios: Voc\xea \xe9 imune a dano de fogo e tem resist\xeancia a dano de frio. Qualquer criatura que se mova at\xe9 1,5 metro de voc\xea pela primeira vez em um turno ou termine seu turno l\xe1 leva 1d10 dano de fogo. Voc\xea pode usar sua a\xe7\xe3o para criar uma linha de fogo de 4,5 metros de comprimento e 1,5 metro de largura estendendo-se de voc\xea na dire\xe7\xe3o que voc\xea escolher. Cada criatura da linha dever\xe1 fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre 4d8 de dano de fogo em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso."},{name:"Investidura de Gelo",level:6,classes:["Druida","Feiticeiro","Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"At\xe9 a magia terminar, o gelo cobre seu corpo e voc\xea ganha os seguintes benef\xedcios: Voc\xea \xe9 imune ao dano de frio e tem resist\xeancia ao dano de fogo. Voc\xea pode se mover por terreno dif\xedcil criado por gelo ou neve sem gastar movimento extra. O raio se move com voc\xea. Voc\xea pode usar sua a\xe7\xe3o para criar um cone de vento gelado de 4,5 metros estendendo-se de sua m\xe3o estendida na dire\xe7\xe3o que voc\xea escolher. Cada criatura do cone dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Uma criatura sofre 4d6 de dano de frio em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso. Uma criatura que falhar no teste de resist\xeancia contra este efeito ter\xe1 sua velocidade reduzida pela metade at\xe9 o in\xedcio do seu pr\xf3ximo turno."},{name:"Investidura de Pedra",level:6,classes:["Druida","Feiticeiro","Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"At\xe9 o fim da magia, peda\xe7os de rocha se espalham por seu corpo e voc\xea ganha os seguintes benef\xedcios: Voc\xea tem resist\xeancia a concuss\xe3o, perfura\xe7\xe3o e dano cortante de armas n\xe3o-m\xe1gicas. Voc\xea pode usar sua a\xe7\xe3o para criar um pequeno terremoto na solo em um raio de 4,5 metros centrado em voc\xea. Outras criaturas nessa solo devem ter sucesso em um Teste de resist\xeancia de Destreza ou ser\xe3o derrubadas. Voc\xea pode se mover por terreno dif\xedcil feito de terra ou pedra sem gastar movimento extra. Voc\xea pode se mover atrav\xe9s de terra s\xf3lida ou pedra como se fosse ar e sem desestabiliz\xe1-la, mas n\xe3o pode terminar seu movimento a\xed. Se voc\xea fizer isso, voc\xea ser\xe1 ejetado para o espa\xe7o desocupado mais pr\xf3ximo, esta magia termina, e voc\xea ficar\xe1 atordoado at\xe9 o final do seu pr\xf3ximo turno."},{name:"Investidura de Vento",level:6,classes:["Druida","Feiticeiro","Bruxo","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"At\xe9 a magia terminar, o vento gira em torno de voc\xea, e voc\xea ganha os seguintes benef\xedcios: Ataque \xe0 dist\xe2ncia com armas feito contra voc\xea tem preven\xe7\xe3o na jogada de ataque. Voc\xea ganha uma velocidade de v\xf4o de 18 metros. Se voc\xea ainda estiver voando quando a magia terminar, voc\xea cair\xe1, a menos que possa de alguma forma evit\xe1-la. Voc\xea pode usar sua a\xe7\xe3o para criar um cubo de 4,5 metros de vento rodopiante centrado em um ponto que voc\xea possa ver a at\xe9 18 metros de voc\xea. Cada criatura daquela \xe1rea dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Uma criatura sofre 2d10 de dano de concuss\xe3o em um teste de resist\xeancia falho, ou metade do dano em caso de sucesso. Se uma criatura Grande ou menor falhar no salvamento, essa criatura tamb\xe9m ser\xe1 empurrada at\xe9 3 metros de dist\xe2ncia do centro do cubo."},{name:"Maelstrom",level:5,classes:["Druida"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Uma massa de \xe1gua com profundidade de 1,5 metro aparece e gira em um raio de 9 metros centrado em um ponto que voc\xea possa ver dentro do alcance. O ponto deve estar em uma solo ou em um corpo d\u2019\xe1gua. At\xe9 o final da magia, aquela \xe1rea \xe9 um terreno dif\xedcil, e qualquer criatura que iniciar seu turno l\xe1 deve ter sucesso em um Teste de resist\xeancia de For\xe7a ou sofrer 6d6 de dano de concuss\xe3o e ser puxada 3 metros em dire\xe7\xe3o ao centro."},{name:"Prote\xe7\xe3o Primordial",level:6,classes:["Druida"],school:"Abjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Si mesmo",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea tem resist\xeancia a \xe1cido, frio, fogo, raio e dano s\xf4nico enquanto durar o feiti\xe7o.\n\nAo sofrer dano de um desses tipos, voc\xea pode usar sua ocorr\xeancia para ganhar imunidade a esse tipo de dano, inclusive contra o dano desencadeador. Se voc\xea fizer isso, as resist\xeancias terminam e voc\xea ter\xe1 imunidade at\xe9 o final do seu pr\xf3ximo turno, momento em que a magia termina."},{name:"Onda de Mar\xe9",level:3,classes:["Druida","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Instant\xe2neo",description:"Voc\xea evoca uma onda de \xe1gua que cai sobre uma \xe1rea dentro do alcance. A \xe1rea pode ter at\xe9 9 metros de comprimento, at\xe9 3 metros de largura e at\xe9 3 metros de altura. Cada criatura daquela \xe1rea dever\xe1 fazer um Teste de resist\xeancia de Destreza. Em caso de falha, uma criatura sofre 4d8 de dano de concuss\xe3o e \xe9 derrubada. Em caso de sucesso, a criatura sofre metade do dano e n\xe3o \xe9 derrubada. A \xe1gua ent\xe3o se espalha pela solo em todas as dire\xe7\xf5es, extinguindo chamas desprotegidas em sua \xe1rea e em at\xe9 9 metros dela."},{name:"Transmutar Rocha",level:5,classes:["Druida","Mago"],school:"Transmuta\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Instant\xe2neo",description:"Voc\xea escolhe uma \xe1rea de pedra ou lama que voc\xea possa ver, que caiba em um cubo de 12 metros e esteja dentro do alcance, e escolha um dos seguintes efeitos. \n\nTransmutar Rocha em Lama: Rocha n\xe3o-m\xe1gica de qualquer tipo na \xe1rea torna-se um volume igual de lama espessa e fluida que permanece durante a dura\xe7\xe3o da magia. \n\n A solo na \xe1rea do feiti\xe7o fica lamacenta o suficiente para que as criaturas possam afundar nela. Cada p\xe9 que uma criatura move pela lama custa 4 p\xe9s de movimento, e qualquer criatura na solo quando voc\xea conjura uma magia deve fazer um Teste de resist\xeancia de For\xe7a. Uma criatura tamb\xe9m deve fazer o teste de resist\xeancia quando entrar na \xe1rea pela primeira vez em um turno ou terminar seu turno ali. Em um teste de resist\xeancia falho, uma criatura afunda na lama e fica imobilizada, embora possa usar uma a\xe7\xe3o para acabar com a condi\xe7\xe3o imobilizada em si mesma, libertando-se da lama. \n\n Se voc\xea conjurar magia no teto, a lama cai. Qualquer criatura debaixo da lama quando cair deve fazer um Teste de resist\xeancia de Destreza. Uma criatura sofre 4d8 de dano de concuss\xe3o em um teste de resist\xeancia falho, ou metade do dano em um teste bem-sucedido. \n\nTransmute Lama em Pedra. Lama n\xe3o-m\xe1gica ou areia movedi\xe7a em uma \xe1rea com n\xe3o mais que 3 metros de profundidade se transforma em pedra macia durante a dura\xe7\xe3o da magia. Qualquer criatura na lama ao se transformar deve fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia bem-sucedido, uma criatura \xe9 desviada com seguran\xe7a para a superf\xedcie em um espa\xe7o desocupado. Em um teste de resist\xeancia falho, uma criatura fica imobilizada pela rocha. Uma criatura imobilizada, ou outra criatura ao alcance, pode usar uma a\xe7\xe3o para tentar quebrar a rocha, obtendo sucesso em um teste de For\xe7a CD 20 ou causando dano a ela. A pedra tem AC 15 e 25 pontos de vida, e \xe9 imune a veneno e dano ps\xedquico."},{name:"Muro de \xc1gua",level:3,classes:["Druida","Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea evoca uma parede de \xe1gua na solo em um ponto que voc\xea pode ver dentro do alcance. Voc\xea pode fazer a parede com at\xe9 9 metros de comprimento, 3 metros de altura e 30 cent\xedmetros de espessura, ou pode fazer uma parede circular de at\xe9 6 metros de di\xe2metro, 6 metros de altura e 30 cent\xedmetros de espessura. A parede desaparece quando a magia termina. O espa\xe7o da parede \xe9 um terreno dif\xedcil.\n\nQualquer ataque \xe0 dist\xe2ncia com arma que entre no espa\xe7o da parede tem interfer\xeancia na jogada de ataque, e o dano de fogo \xe9 reduzido pela metade se o efeito do fogo passar pela parede para atingir seu alvo. Feiti\xe7os que causam dano de frio que passam pela parede fazem com que a \xe1rea da parede pela qual eles passam congele (pelo menos uma se\xe7\xe3o de 1,5 metro quadrado est\xe1 congelada). Cada trecho congelado de 1,5 metro quadrado possui AC 5 e 15 pontos de vida. Reduzir uma se\xe7\xe3o congelada a 0 pontos de vida a destr\xf3i. Quando uma sec\xe7\xe3o \xe9 destru\xedda, a \xe1gua da parede n\xe3o a enche."},{name:"Esfera de \xc1gua",level:4,classes:["Druida","Feiticeiro","Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea evoca uma esfera de \xe1gua com um raio de 3 metros em um ponto que voc\xea pode ver dentro do alcance. A esfera pode pairar no ar, mas n\xe3o mais que 3 metros da solo. A esfera permanece durante a dura\xe7\xe3o da magia.\n\nQualquer criatura no espa\xe7o da esfera dever\xe1 fazer um Teste de resist\xeancia de For\xe7a. Em um teste de resist\xeancia bem sucedido, uma criatura \xe9 ejetada daquele espa\xe7o para o espa\xe7o desocupado mais pr\xf3ximo fora dele. Uma criatura Enorme ou maior obt\xe9m sucesso no teste de resist\xeancia automaticamente. Em um teste de resist\xeancia falho, uma criatura \xe9 imobilizada pela esfera e \xe9 engolfada pela \xe1gua. Ao final de cada um de seus turnos, um alvo imobilizado pode repetir o teste de resist\xeancia.\n\nA esfera pode conter no m\xe1ximo quatro criaturas M\xe9dias ou menores ou uma criatura Grande. Se a esfera reter uma criatura acima desses n\xfameros, uma criatura aleat\xf3ria que j\xe1 estava imobilizada pela esfera cai dela e cai ca\xedda em um espa\xe7o a at\xe9 1,5 metro dela.\n\nComo a\xe7\xe3o, voc\xea pode mover a esfera at\ufffd\ufffd 9 metros em linha reta. Se ele se mover sobre um po\xe7o, penhasco ou outra queda, ele desce com seguran\xe7a at\xe9 pairar 3 metros sobre a solo. Qualquer criatura imobilizada pela esfera se move com ela. Voc\xea pode enfiar a esfera em criaturas, for\xe7ando-as a fazer o teste de resist\xeancia, mas n\xe3o mais do que uma vez por turno.\n\nQuando a magia termina, a esfera cai na solo e apaga todas as chamas normais a at\xe9 9 metros dela. Qualquer criatura imobilizada pela esfera \xe9 derrubada no espa\xe7o onde cai."},{name:"Redemoinho",level:7,classes:["Druida","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"90 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Um redemoinho uiva at\xe9 um ponto na solo que voc\xea especifica. O redemoinho \xe9 um cilindro de 3 metros de raio e 9 metros de altura centrado nesse ponto. At\xe9 a magia terminar, voc\xea pode usar sua a\xe7\xe3o para mover o redemoinho at\xe9 9 metros em qualquer dire\xe7\xe3o ao longo da solo. O redemoinho suga quaisquer objetos M\xe9dios ou menores que n\xe3o estejam presos a nada e que n\xe3o sejam usados \u200b\u200bou carregados por ningu\xe9m.\n\nUma criatura deve fazer um Teste de resist\xeancia de Destreza na primeira vez em um turno em que ela entrar no redemoinho ou em que o redemoinho entrar em seu espa\xe7o, inclusive quando o redemoinho aparecer pela primeira vez. Uma criatura sofre 10d6 de dano de concuss\xe3o em um teste de resist\xeancia falho, ou metade do dano em um teste bem sucedido. Al\xe9m disso, uma criatura Grande ou menor que falhar no teste dever\xe1 ter sucesso em um Teste de resist\xeancia de For\xe7a ou ficar\xe1 imobilizada no redemoinho at\xe9 o fim da magia. Quando uma criatura inicia seu turno imobilizada pelo redemoinho, a criatura \xe9 puxada 1,5 metro para cima dentro dele, a menos que a criatura esteja no topo. Uma criatura imobilizada se move com o redemoinho e cai quando a magia termina, a menos que a criatura tenha algum meio de permanecer no ar.\n\nUma criatura imobilizada pode usar uma a\xe7\xe3o para fazer um teste de For\xe7a ou Destreza contra seu CD de resist\xeancia de magia. Se tiver sucesso, a criatura n\xe3o fica mais imobilizada pelo redemoinho e \xe9 arremessada 3d6 \xd7 3 metros para longe dele em uma dire\xe7\xe3o aleat\xf3ria."},{name:"Imola\xe7\xe3o",level:5,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"As chamas envolvem uma criatura que voc\xea pode ver dentro do alcance. O alvo deve fazer um Teste de resist\xeancia de Destreza. S\xe3o necess\xe1rios 7d6 dano de fogo em um teste de resist\xeancia falho, ou metade do dano em um teste bem sucedido. Em um teste de resist\xeancia falho, o alvo tamb\xe9m queima enquanto durar o feiti\xe7o. O alvo em chamas emite luz brilhante em um raio de 9 metros e luz fraca por mais 9 metros. Ao final de cada um de seus turnos, o alvo repete o teste de resist\xeancia. S\xe3o necess\xe1rios 3d6 de dano de fogo em um teste de resist\xeancia falho, e a magia termina com sucesso. Essas chamas m\xe1gicas n\xe3o podem ser extintas por meios n\xe3o m\xe1gicos.\n\nSe o dano deste feiti\xe7o reduzir um alvo a 0 pontos de vida, o alvo se transforma em cinzas."},{name:"Esfera da Tempestade",level:4,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Uma esfera de ar rodopiante com 6 metros de raio surge centrada em um ponto que voc\xea escolher dentro do alcance. A esfera permanece durante a dura\xe7\xe3o da magia. Cada criatura na esfera quando aparecer ou terminar seu turno nela dever\xe1 ter sucesso em um Teste de resist\xeancia de For\xe7a ou sofrer 2d6 dano de concuss\xe3o. O espa\xe7o da esfera \xe9 um terreno dif\xedcil.\n\nAt\xe9 o final da magia, voc\xea pode usar um b\xf4nus de a\xe7\xe3o em cada um de seus turnos para fazer com que um raio salte do centro da esfera em dire\xe7\xe3o a uma criatura que voc\xea escolher at\xe9 18 metros do centro. Fa\xe7a um ataque de magia \xe0 dist\xe2ncia. Voc\xea tem vantagem na jogada de ataque se o alvo estiver na esfera. Sem sucesso, o alvo leva 4d6 dano de raio.\n\nCriaturas a at\xe9 9 metros da esfera possuem interfer\xeancia em testes de Sabedoria (Percep\xe7\xe3o) feitos para ouvir."},{name:"Esfera Vitri\xf3lica",level:4,classes:["Feiticeiro","Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"45 metros",duration:"Instant\xe2neo",description:"Voc\xea aponta para um lugar dentro do alcance, e uma bola brilhante de \xe1cido esmeralda de 30 cent\xedmetros de altura atinge l\xe1 e explode em um raio de 6 metros. Cada criatura daquela \xe1rea dever\xe1 fazer um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, uma criatura sofre 10d4 dano de \xe1cido e 5d4 dano de \xe1cido no final de seu pr\xf3ximo turno. Em um teste de resist\xeancia bem sucedido, uma criatura sofre metade do dano inicial e nenhum dano no final do seu pr\xf3ximo turno."},{name:"Muro de Areia",level:3,classes:["Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 10 minutos",description:"Voc\xea evoca uma parede de areia rodopiante na solo em um ponto que voc\xea pode ver dentro do alcance. Voc\xea pode fazer a parede com at\xe9 9 metros de comprimento, 3 metros de altura e 3 metros de espessura, e ela desaparece quando a magia termina. Bloqueia a linha de vis\xe3o, mas n\xe3o o movimento. Uma criatura fica cega enquanto estiver no espa\xe7o da parede e deve gastar 90 cm de movimento para cada 30 cm que se mover at\xe9 l\xe1."},{name:"M\xe3o Arcana",level:5,classes:["Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"36 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea cria uma m\xe3o grande de for\xe7a transl\xfacida e cintilante em um espa\xe7o desocupado que voc\xea pode ver dentro do alcance. A m\xe3o dura a dura\xe7\xe3o do feiti\xe7o e se move sob seu comando, imitando os movimentos de sua pr\xf3pria m\xe3o. \n\n A m\xe3o \xe9 um objeto que tem CA 20 e pontos de vida iguais ao seu ponto de vida m\xe1ximo. Se cair para 0 pontos de vida, a magia termina. Possui For\xe7a 26 (+8) e Destreza 10 (+0). A m\xe3o n\xe3o preenche seu espa\xe7o. \n\n Quando voc\xea conjura uma magia e como b\xf4nus de a\xe7\xe3o em seus turnos subsequentes, voc\xea pode mover a m\xe3o at\xe9 18 metros e ent\xe3o causar um dos seguintes efeitos com ela. \n\n Punho Cerrado: A m\xe3o atinge uma criatura ou objeto a at\xe9 1,5 metro dela. Fa\xe7a um ataque de magia corpo a corpo para a m\xe3o usando as estat\xedsticas do jogo. Sem sucesso, o alvo leva 4d8 de dano de for\xe7a. \n\n M\xe3o Forte A m\xe3o tenta empurrar uma criatura at\xe9 1,5 metro dela na dire\xe7\xe3o que voc\xea escolher. Fa\xe7a um teste com a For\xe7a da m\xe3o contestada pelo teste de For\xe7a (Atletismo) do alvo. Se o alvo for M\xe9dio ou menor, voc\xea tem vantagem no teste. Se voc\xea tiver sucesso, a m\xe3o empurra o alvo at\xe9 1,5 metro mais um n\xfamero de p\xe9s igual a cinco vezes o seu modificador de atributo de conjura\xe7\xe3o. O ponteiro se move com o alvo para ficar a at\xe9 1,5 metro dele. \n\n M\xe3o Agarrada: A m\xe3o tenta agarrar uma criatura Enorme ou menor a at\xe9 1,5 metro dela. Voc\xea usa o valor de For\xe7a da m\xe3o para resolver o agarrar. Se o alvo for M\xe9dio ou menor, voc\xea tem vantagem no teste. Enquanto a m\xe3o est\xe1 agarrando o alvo, voc\xea pode usar uma a\xe7\xe3o b\xf4nus para que a m\xe3o o esmague. Ao fazer isso, o alvo recebe dano de concuss\xe3o igual a 2d6 + seu modificador de atributo de conjura\xe7\xe3o. \n\n M\xe3o Interposta: A m\xe3o se interp\xf5e entre voc\xea e uma criatura que voc\xea escolher at\xe9 que voc\xea d\xea um comando diferente \xe0 m\xe3o. A m\xe3o se move para ficar entre voc\xea e o alvo, proporcionando meia cobertura contra o alvo. O alvo n\xe3o pode se mover pelo espa\xe7o da m\xe3o se seu valor de For\xe7a for menor ou igual ao valor de For\xe7a da m\xe3o. Se o seu valor de For\xe7a for maior que o valor de For\xe7a da m\xe3o, o alvo pode se mover em sua dire\xe7\xe3o atrav\xe9s do espa\xe7o da m\xe3o, mas esse espa\xe7o \xe9 um terreno dif\xedcil para o alvo."},{name:"Espada Arcana",level:7,classes:["Mago","Bardo"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"18 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Voc\xea cria um plano de for\xe7a em forma de espada que paira dentro do alcance. Dura enquanto durar. \n\n Quando a espada aparecer, voc\xea faz um ataque de magia corpo a corpo contra um alvo de sua escolha a at\xe9 1,5 metro da espada. Sem sucesso. o alvo leva 3d10 dano de for\xe7a. At\xe9 o fim da magia, voc\xea pode usar um b\xf4nus de a\xe7\xe3o em cada um de seus turnos para mover a espada at\xe9 20 p\xe9s para um local que voc\xea possa ver e repetir este ataque contra o mesmo alvo ou outro diferente."},{name:"Esfera Congelante",level:6,classes:["Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"90 metros",duration:"Instant\xe2neo",description:"Um globo gelado de energia fria vai da ponta dos dedos at\xe9 um ponto de sua escolha dentro do alcance, onde explode em uma esfera de 18 metros de raio. Cada criatura dentro da \xe1rea dever\xe1 fazer um Teste de resist\xeancia de Constitui\xe7\xe3o. Em um teste de resist\xeancia falho, uma criatura sofre 10d6 de dano de frio. Em um teste de resist\xeancia bem-sucedido, \xe9 preciso metade do dano. \n\n Se o globo atingir um corpo de \xe1gua ou um l\xedquido que seja principalmente \xe1gua (sem incluir criaturas \xe0 base de \xe1gua), ele congela o l\xedquido a uma profundidade de 15 cent\xedmetros em uma \xe1rea de 9 metros quadrados. Este gelo dura 1 minuto. Criaturas que nadavam na superf\xedcie da \xe1gua congelada ficam presas no gelo. Uma criatura presa pode usar uma a\xe7\xe3o para fazer um teste de For\xe7a contra seu CD de resist\xeancia de magia para se libertar. \n\n Voc\xea pode evitar disparar o globo ap\xf3s completar o feiti\xe7o, se desejar. Um pequeno globo do tamanho de uma pedra de funda, fresco ao toque, aparece em sua m\xe3o. A qualquer momento, voc\xea ou uma criatura para quem voc\xea deu o globo pode arremess\xe1-lo (a um alcance de 12 metros) ou arremess\xe1-lo com uma funda (ao alcance normal da funda). Ele se estilha\xe7a com o impacto, com o mesmo efeito do lan\xe7amento normal do feiti\xe7o. Voc\xea tamb\xe9m pode pousar o globo sem quebr\xe1-lo. Depois de 1 minuto, se o globo ainda n\xe3o estiver quebrado, ele explode."},{name:"Riso Horr\xedvel",level:1,classes:["Mago","Bardo"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Uma criatura de sua escolha que voc\xea possa ver dentro do alcance percebe tudo como hilariamente engra\xe7ado e cai na gargalhada se esse feiti\xe7o o afetar. O deve ter sucesso em um Teste de resist\xeancia de Sabedoria de queda ca\xedda, ficando incapacitado e incapaz de ficar em p\xe9 durante todo o tempo. Uma criatura com valor de Intelig\xeancia igual ou inferior a 4 n\xe3o \xe9 afetada. \n\n Ao final de cada um de seus turnos, e cada vez que sofrer dano, o alvo pode fazer outro Teste de resist\xeancia de Sabedoria. O alvo tem vantagem no teste de resist\xeancia se for desencadeado por dano. Com um sucesso, a magia termina."},{name:"Ba\xfa Secreto",level:4,classes:["Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"Instant\xe2neo",description:"Voc\xea esconde um ba\xfa e todo o seu conte\xfado no Plano Et\xe9reo. Voc\xea deve tocar no ba\xfa e na r\xe9plica em miniatura que serve como componente material para o feiti\xe7o. O ba\xfa pode conter at\xe9 12 p\xe9s c\xfabicos de material inanimado (3 p\xe9s por 2 p\xe9s por 2 p\xe9s). \n\n Enquanto o ba\xfa permanece no Plano Et\xe9reo, voc\xea pode usar uma a\xe7\xe3o e tocar na r\xe9plica para recuperar o ba\xfa. Ele aparece em um espa\xe7o desocupado na solo a at\xe9 1,5 metro de voc\xea. Voc\xea pode enviar o ba\xfa de volta ao Plano Et\xe9reo usando uma a\xe7\xe3o e tocando tanto no ba\xfa quanto na r\xe9plica. \n\n Ap\xf3s 60 dias, h\xe1 uma chance cumulativa de 5% por dia de que o efeito do feiti\xe7o termine. Este efeito termina se voc\xea lan\xe7ar esta magia novamente, se a r\xe9plica do ba\xfa menor for destru\xedda ou se voc\xea decidir encerrar a magia como uma a\xe7\xe3o. Se a magia terminar e o ba\xfa maior estiver no Plano Et\xe9reo, ele estar\xe1 irremediavelmente perdido."},{name:"Mans\xe3o Magn\xedfica",level:7,classes:["Mago","Bardo"],school:"Conjura\xe7\xe3o",castingTime:"1 minute",range:"90 metros",duration:"24 horas",description:"Voc\xea conjura uma morada extradimensional ao alcance que dura por toda a dura\xe7\xe3o. Voc\xea escolhe onde sua \xfanica entrada est\xe1 localizada. A entrada brilha levemente e tem 1,5 metros de largura e 3 metros de altura. Voc\xea e qualquer criatura que voc\xea designar ao conjurar uma magia podem entrar na morada extradimensional desde que o portal permane\xe7a aberto. Voc\xea pode abrir ou fechar o portal se estiver a at\xe9 9 metros dele. Enquanto fechado, o portal fica invis\xedvel. \n\n Al\xe9m do portal h\xe1 um magn\xedfico foyer com in\xfameras c\xe2maras. A atmosfera \xe9 limpa, fresca e quente. \n\n Voc\xea pode criar a planta que quiser, mas o espa\xe7o n\xe3o pode ultrapassar 50 cubos, sendo cada cubo 3 metros de cada lado. O local \xe9 mobiliado e decorado como voc\xea escolher. Cont\xe9m comida suficiente para servir um banquete de nove pratos para at\xe9 100 pessoas. Uma equipe de 100 servidores quase transparentes atende todos que entram. Voc\xea decide a apar\xeancia visual desses servos e seus trajes. Eles s\xe3o completamente obedientes \xe0s suas ordens. Cada servo pode realizar qualquer tarefa que um servo humano normal poderia realizar, mas n\xe3o pode atacar ou realizar qualquer a\xe7\xe3o que possa prejudicar diretamente outra criatura. Assim, os servos podem buscar coisas, limpar, consertar, dobrar roupas, acender fogueiras, servir comida, servir vinho e assim por diante. Os servos podem ir a qualquer lugar da mans\xe3o, mas n\xe3o podem sair dela. M\xf3veis e outros objetos criados por este feiti\xe7o se dissipam em fuma\xe7a se forem removidos da mans\xe3o. Quando a magia termina, quaisquer criaturas dentro do espa\xe7o extradimensional s\xe3o expulsas para os espa\xe7os abertos mais pr\xf3ximos da entrada."},{name:"Arcanist's Magic Aura",level:2,classes:["Mago"],school:"Ilus\xe3o",castingTime:"1 a\xe7\xe3o",range:"Toque",duration:"24 horas",description:"Voc\xea coloca uma ilus\xe3o em uma criatura ou objeto que voc\xea toca para que os feiti\xe7os de adivinha\xe7\xe3o revelem informa\xe7\xf5es falsas sobre ele. O alvo pode ser uma criatura volunt\xe1ria ou um objeto que n\xe3o est\xe1 sendo carregado ou usado por outra criatura.\n Ao conjurar uma magia, escolha um ou ambos os efeitos a seguir. O efeito dura enquanto durar. Se voc\xea lan\xe7ar este feiti\xe7o na mesma criatura ou objeto todos os dias durante 30 dias, aplicando o mesmo efeito a cada vez, a ilus\xe3o durar\xe1 at\xe9 ser dissipada. \n\n Falsa Aura: Voc\xea altera a forma como o alvo aparece para magias e efeitos m\xe1gicos, como detectar magia, que detectam auras m\xe1gicas. Voc\xea pode fazer um objeto n\xe3o-m\xe1gico parecer m\xe1gico, um objeto m\xe1gico parecer n\xe3o-m\xe1gico ou alterar a aura m\xe1gica do objeto para que ele pare\xe7a pertencer a uma escola espec\xedfica de magia que voc\xea escolher. Quando voc\xea usa esse efeito em um objeto, voc\xea pode tornar a falsa magia aparente para qualquer criatura que manuseie o item. \n\n M\xe1scara: Voc\xea altera a forma como o alvo aparece para magias e efeitos m\xe1gicos que detectam tipos de criaturas, como o Sentido Divino de um paladino ou o gatilho de uma magia de s\xedmbolo. Voc\xea escolhe um tipo de criatura e outras magias e efeitos m\xe1gicos tratam o alvo como se fosse uma criatura daquele tipo ou daquela tend\xeancia."},{name:"Santu\xe1rio Privado",level:4,classes:["Mago"],school:"Abjura\xe7\xe3o",castingTime:"10 minutes",range:"36 metros",duration:"24 horas",description:"Voc\xea coloca uma ilus\xe3o em uma criatura ou objeto que voc\xea toca para que os feiti\xe7os de adivinha\xe7\xe3o revelem informa\xe7\xf5es falsas sobre ele. O alvo pode ser uma criatura volunt\xe1ria ou um objeto que n\xe3o est\xe1 sendo carregado ou usado por outra criatura.\n Ao conjurar uma magia, escolha um ou ambos os efeitos a seguir. O efeito dura enquanto durar. Se voc\xea lan\xe7ar este feiti\xe7o na mesma criatura ou objeto todos os dias durante 30 dias, aplicando o mesmo efeito a cada vez, a ilus\xe3o durar\xe1 at\xe9 ser dissipada. \n\n Falsa Aura: Voc\xea altera a forma como o alvo aparece para magias e efeitos m\xe1gicos, como detectar magia, que detectam auras m\xe1gicas. Voc\xea pode fazer um objeto n\xe3o-m\xe1gico parecer m\xe1gico, um objeto m\xe1gico parecer n\xe3o-m\xe1gico ou alterar a aura m\xe1gica do objeto para que ele pare\xe7a pertencer a uma escola espec\xedfica de magia que voc\xea escolher. Quando voc\xea usa esse efeito em um objeto, voc\xea pode tornar a falsa magia aparente para qualquer criatura que manuseie o item. \n\n M\xe1scara: Voc\xea altera a forma como o alvo aparece para magias e efeitos m\xe1gicos que detectam tipos de criaturas, como o Sentido Divino de um paladino ou o gatilho de uma magia de s\xedmbolo. Voc\xea escolhe um tipo de criatura e outras magias e efeitos m\xe1gicos tratam o alvo como se fosse uma criatura daquele tipo ou daquela tend\xeancia."},{name:"Tent\xe1culos Negros",level:4,classes:["Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"27 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Contorcendo-se, tent\xe1culos de \xe9bano preenchem um quadrado de 6 metros de altura que voc\xea pode ver dentro do alcance. Enquanto isso, esses tent\xe1culos transformam a solo da \xe1rea em terreno dif\xedcil.\n \nQuando uma criatura entra na \xe1rea afetada pela primeira vez em um turno ou inicia seu turno l\xe1, a criatura deve ter sucesso em um Teste de resist\xeancia de Destreza ou sofrer 3d6 de dano de concuss\xe3o e ser imobilizada pelos tent\xe1culos at\xe9 o fim da magia. Uma criatura que inicia seu turno na \xe1rea e j\xe1 est\xe1 imobilizada pelos tent\xe1culos sofre 3d6 dano de concuss\xe3o. \n\n Uma criatura imobilizada pelos tent\xe1culos pode usar sua a\xe7\xe3o para fazer um teste de For\xe7a ou Destreza (\xe0 sua escolha) contra seu CD de resist\xeancia de magia. Com um sucesso, ele se liberta."},{name:"Disco Flutuante",level:1,classes:["Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"1 hora",description:"Este feiti\xe7o cria um plano de for\xe7a circular e horizontal, com 3 p\xe9s de di\xe2metro e 1 polegada de espessura, que flutua 3 p\xe9s acima da solo em um espa\xe7o desocupado de sua escolha que voc\xea possa ver dentro do alcance. O disco permanece durante todo o tempo e pode conter at\xe9 500 libras. Se for colocado mais peso sobre ele, a magia termina e tudo que est\xe1 no disco cai na solo. \n\n O disco fica im\xf3vel enquanto voc\xea estiver a at\xe9 6 metros dele. Se voc\xea se afastar mais de 6 metros dele, o disco o seguir\xe1 e permanecer\xe1 a 6 metros de voc\xea. Ele pode atravessar terrenos irregulares, subir ou descer escadas, declives e similares, mas n\xe3o pode atravessar uma mudan\xe7a de eleva\xe7\xe3o de 3 metros ou mais. Por exemplo, o disco n\xe3o pode se mover atrav\xe9s de um po\xe7o com 3 metros de profundidade, nem poderia sair desse po\xe7o se fosse criado no fundo. \n\n Se voc\xea se mover mais de 30 metros do disco (normalmente porque ele n\xe3o consegue se mover, ao redor um obst\xe1culo para segui-lo), a magia termina."},{name:"Convoca\xe7\xe3o Instant\xe2nea",level:6,classes:["Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 minute",range:"Toque",duration:"At\xe9 ser dissipada",description:"Voc\xea toca um objeto pesando 4,5 quilos ou menos cuja maior dimens\xe3o \xe9 de 1,80 metro ou menos. O feiti\xe7o deixa uma marca invis\xedvel em sua superf\xedcie e inscreve invisivelmente o nome do item na safira que voc\xea usa como componente material. Cada vez que voc\xea lan\xe7a este feiti\xe7o, voc\xea deve usar uma safira diferente. \n\n A qualquer momento, voc\xea pode usar sua a\xe7\xe3o para falar o nome do item e esmagar a safira. O item aparece instantaneamente em sua m\xe3o, independentemente da dist\xe2ncia f\xedsica ou plana, e a magia termina. \n\n Se outra criatura estiver segurando ou carregando o item, esmagar a safira n\xe3o transporta o item para voc\xea, mas em vez disso voc\xea aprende quem \xe9 a criatura que possui o objeto e aproximadamente onde essa criatura est\xe1 localizada naquele momento. \n\n Dissipar magia ou um efeito similar aplicado com sucesso \xe0 safira encerra o efeito desta magia."},{name:"V\xednculo Telep\xe1tico",level:6,classes:["Mago"],school:"Adivinha\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"1 hora",description:"Voc\xea estabelece um v\xednculo telep\xe1tico entre at\xe9 oito criaturas volunt\xe1rias de sua escolha dentro do alcance, ligando psiquicamente cada criatura a todas as outras durante o per\xedodo. Criaturas com valores de Intelig\xeancia de 2 ou menos n\xe3o s\xe3o afetadas por este feiti\xe7o. \n\n At\xe9 a magia terminar, os alvos podem se comunicar telepaticamente atrav\xe9s do v\xednculo, tenham ou n\xe3o uma linguagem comum. A comunica\xe7\xe3o\u2060 \xe9 poss\xedvel a qualquer dist\xe2ncia, embora n\xe3o possa se estender a outros planos de exist\xeancia."},{name:"C\xe3o Fiel",level:5,classes:["Mago"],school:"Conjura\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"8 horas",description:"Voc\xea conjura um c\xe3o de guarda fantasma em um espa\xe7o desocupado que voc\xea pode ver dentro do alcance, onde permanece durante todo o tempo, at\xe9 que voc\xea o desfa\xe7a como uma a\xe7\xe3o, ou at\xe9 que voc\xea se afaste mais de 30 metros dele. \n\n O c\xe3o \xe9 invis\xedvel para todas as criaturas, exceto voc\xea, e n\xe3o pode ser ferido. Quando uma criatura pequena ou maior chega a at\xe9 9 metros dela sem primeiro falar a senha que voc\xea especificou. Quando voc\xea conjura essa magia, o c\xe3o come\xe7a a latir alto. O c\xe3o v\xea criaturas invis\xedveis e pode ver o Plano Et\xe9reo. Ignora as ilus\xf5es. \n\n No in\xedcio de cada um de seus turnos, o c\xe3o tenta morder uma criatura a at\xe9 1,5 metro dela que seja hostil a voc\xea. O b\xf4nus de ataque do c\xe3o \xe9 igual ao seu modificador de atributo de conjura\xe7\xe3o + seu b\xf4nus de profici\xeancia. Sem sucesso, causa 4d8 dano perfurante."},{name:"Esfera Resiliente",level:4,classes:["Mago"],school:"Evoca\xe7\xe3o",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Uma esfera de for\xe7a cintilante envolve uma criatura ou objeto de tamanho Grande ou menor dentro do alcance. Uma incriatura volunt\xe1ria dever\xe1 realizar um Teste de resist\xeancia de Destreza. Em um teste de resist\xeancia falho, a criatura fica encerrada durante todo o tempo. \n\n Nada, nem objetos f\xedsicos, energia ou outros efeitos m\xe1gicos, pode passar atrav\xe9s da barreira, para dentro ou para fora, embora uma criatura na esfera possa respirar ali. A esfera \xe9 imune a todos os danos, e uma criatura ou objeto dentro dela n\xe3o pode ser danificado por ataques ou efeitos originados de fora, nem uma criatura dentro da esfera pode danificar nada fora dela. \n\n A esfera n\xe3o tem peso e \xe9 grande o suficiente para conter a criatura ou objeto dentro dela. Uma criatura enclausurada pode usar sua a\xe7\xe3o para empurrar as paredes da esfera e, assim, rolar a esfera at\xe9 metade da velocidade da criatura. Da mesma forma, o globo pode ser apanhado e movido por outras criaturas. \n\n Um feiti\xe7o de desintegra\xe7\xe3o que atinge o globo o destr\xf3i sem danificar nada dentro dele."},{name:"Dan\xe7a Irresist\xedvel",level:6,classes:["Mago","Bardo"],school:"Encantamento",castingTime:"1 a\xe7\xe3o",range:"9 metros",duration:"Concentra\xe7\xe3o, at\xe9 1 minuto",description:"Escolha uma criatura que voc\xea possa ver dentro do alcance. O alvo come\xe7a uma dan\xe7a c\xf4mica no local - arrastando os p\xe9s, batendo os p\xe9s e saltitando durante todo o tempo. Criaturas que n\xe3o podem ser feiti\xe7adas ficam imunes a esse feiti\xe7o. \n\n Uma criatura dan\xe7ante deve usar todo o seu movimento para dan\xe7ar sem sair do seu espa\xe7o e tem manobras em Teste de resist\xeancia de Destrezas e jogada de ataques. Enquanto o alvo for afetado por este feiti\xe7o, outras criaturas ter\xe3o vantagem em jogar de ataques contra ele. Como a\xe7\xe3o, uma criatura dan\xe7ante faz um Teste de resist\xeancia de Sabedoria para recuperar o controle de si mesma. Em um teste de resist\xeancia bem sucedido, a magia termina."},{name:"Cabana Pequena",level:3,classes:["Mago","Bardo"],school:"Evoca\xe7\xe3o",castingTime:"1 minute",range:"Self (10-foot radius hemisphere)",duration:"8 horas",description:"Uma c\xfapula de for\xe7a im\xf3vel com raio de 3 metros surge ao redorda e acima de voc\xea e permanece estacion\xe1ria durante todo o tempo. A magia termina se voc\xea sair da \xe1rea. \n\n Nove criaturas de tamanho m\xe9dio ou menor podem caber dentro da c\xfapula com voc\xea. A magia falha se sua \xe1rea incluir uma criatura maior ou mais de nove criaturas. Criaturas e objetos\u2060 dentro da c\xfapula Quando voc\xea conjura essa magia pode se mover livremente atrav\xe9s dela. Todas as outras criaturas e objetos est\xe3o impedidos de passar por ele. Feiti\xe7os e outros efeitos m\xe1gicos n\xe3o podem se estender atrav\xe9s da c\xfapula ou ser lan\xe7ados atrav\xe9s dela. A atmosfera no interior do espa\xe7o \xe9 confort\xe1vel e seca, independentemente do clima exterior. \n\n At\xe9 a magia terminar, voc\xea pode comandar o interior para ficar mal iluminado ou escuro. A c\xfapula \xe9 opaca por fora, da cor que voc\xea escolher, mas \xe9 transparente por dentro."}]},484,[]);
